    static Vector2 AiGrandmasterEventSteer(Vector2 from)
    {
        if (activeEvent == FloorEventType.None || eventCountdown <= 0f) return Vector2.Zero;
        if (AiGrandmasterShouldHoldForEvent()) return Vector2.Zero;
        return activeEvent switch
        {
            FloorEventType.CrimsonCrumble => AiEventSteer_CrimsonCrumble(from),
            FloorEventType.SafeZoneRush => AiEventSteer_SafeZoneRush(from),
            FloorEventType.Checkerfall => AiEventSteer_Checkerfall(from),
            FloorEventType.RingCollapse => AiEventSteer_RingCollapse(from),
            FloorEventType.StoneIslands => AiEventSteer_StoneIslands(from),
            FloorEventType.ScatterPits => AiEventSteer_ScatterPits(from),
            FloorEventType.MossRot => AiEventSteer_MossRot(from),
            FloorEventType.MarkedStrike => AiEventSteer_MarkedStrike(from),
            FloorEventType.CenterSnare => AiEventSteer_CenterSnare(from),
            FloorEventType.BlightStorm => AiEventSteer_BlightStorm(from),
            FloorEventType.TideSurge => AiEventSteer_TideSurge(from),
            FloorEventType.TideRift => AiEventSteer_TideRift(from),
            FloorEventType.TideRecede => AiEventSteer_TideRecede(from),
            FloorEventType.TideColumn => AiEventSteer_TideColumn(from),
            FloorEventType.TideEcho => AiEventSteer_TideEcho(from),
            FloorEventType.TideUndertow => AiEventSteer_TideUndertow(from),
            FloorEventType.TideCrest => AiEventSteer_TideCrest(from),
            FloorEventType.TideWall => AiEventSteer_TideWall(from),
            FloorEventType.TideAnchor => AiEventSteer_TideAnchor(from),
            FloorEventType.TideFoam => AiEventSteer_TideFoam(from),
            FloorEventType.EmberRain => AiEventSteer_EmberRain(from),
            FloorEventType.EmberGate => AiEventSteer_EmberGate(from),
            FloorEventType.EmberPulse => AiEventSteer_EmberPulse(from),
            FloorEventType.EmberCross => AiEventSteer_EmberCross(from),
            FloorEventType.EmberBridge => AiEventSteer_EmberBridge(from),
            FloorEventType.EmberFury => AiEventSteer_EmberFury(from),
            FloorEventType.EmberSnake => AiEventSteer_EmberSnake(from),
            FloorEventType.EmberHive => AiEventSteer_EmberHive(from),
            FloorEventType.EmberTide => AiEventSteer_EmberTide(from),
            FloorEventType.EmberCage => AiEventSteer_EmberCage(from),
            FloorEventType.EmberQuake => AiEventSteer_EmberQuake(from),
            FloorEventType.EmberBloom => AiEventSteer_EmberBloom(from),
            FloorEventType.EmberAltar => AiEventSteer_EmberAltar(from),
            FloorEventType.CryptSeal => AiEventSteer_CryptSeal(from),
            FloorEventType.CryptWail => AiEventSteer_CryptWail(from),
            FloorEventType.CryptTorch => AiEventSteer_CryptTorch(from),
            FloorEventType.CryptChains => AiEventSteer_CryptChains(from),
            FloorEventType.CryptMist => AiEventSteer_CryptMist(from),
            FloorEventType.CryptTomb => AiEventSteer_CryptTomb(from),
            FloorEventType.CryptShroud => AiEventSteer_CryptShroud(from),
            FloorEventType.CryptGlimpse => AiEventSteer_CryptGlimpse(from),
            FloorEventType.CryptRattle => AiEventSteer_CryptRattle(from),
            FloorEventType.CryptEcho => AiEventSteer_CryptEcho(from),
            FloorEventType.CryptGrave => AiEventSteer_CryptGrave(from),
            FloorEventType.CryptLantern => AiEventSteer_CryptLantern(from),
            FloorEventType.CryptVeil => AiEventSteer_CryptVeil(from),
            FloorEventType.TideWhirlpool => AiEventSteer_TideWhirlpool(from),
            FloorEventType.TideBeacon => AiEventSteer_TideBeacon(from),
            FloorEventType.TideStrike => AiEventSteer_TideStrike(from),
            FloorEventType.CrownTrial => AiEventSteer_CrownTrial(from),
            FloorEventType.CrownFall => AiEventSteer_CrownFall(from),
            FloorEventType.CrownShard => AiEventSteer_CrownShard(from),
            FloorEventType.CrownThrone => AiEventSteer_CrownThrone(from),
            FloorEventType.CrownEdict => AiEventSteer_CrownEdict(from),
            FloorEventType.CrownRot => AiEventSteer_CrownRot(from),
            FloorEventType.CrownBolt => AiEventSteer_CrownBolt(from),
            FloorEventType.CrownRing => AiEventSteer_CrownRing(from),
            FloorEventType.CrownIsles => AiEventSteer_CrownIsles(from),
            FloorEventType.CrownStorm => AiEventSteer_CrownStorm(from),
            FloorEventType.CrownCoronation => AiEventSteer_CrownCoronation(from),
            FloorEventType.CrownUsurpation => AiEventSteer_CrownUsurpation(from),
            FloorEventType.CrownReckoning => AiEventSteer_CrownReckoning(from),
            FloorEventType.None => Vector2.Zero,
            _ => DirectionToSafeZoneInterior(from),
        };
    }

    static void ResolveAiGrandmasterAbilities(float dt)
    {
        aiVerdictRequest = false;
        aiBannerRequest = false;
        if (state != GameState.Playing) return;

        bool eventLive = activeEvent != FloorEventType.None && eventCountdown > 0f;
        var evProf = eventLive ? AiEventProfileFor(activeEvent) : default;
        bool criticalTile = AiVoidDashUrgency(playerPos) > 0.72f || IsFeetTileWeak();
        bool swarmed = AiEnemiesThreatening(playerPos, 160f) >= 3;
        bool bossNear = NearestBossDistance(playerPos) < 240f;

        if (HasEquippedAbility(AbilityType.Verdict) && IsVerdictUnlocked() && verdictCooldown <= 0f && verdictHaltTimer <= 0f)
        {
            bool wantVerdict = false;
            if (eventLive && eventCountdown < evProf.PanicThreshold && !AiGrandmasterShouldHoldForEvent()) wantVerdict = true;
            if (eventLive && TryGetTileUnder(playerPos, out int vx, out int vy) && tiles[vx, vy].EventMarked) wantVerdict = true;
            if (criticalTile && eventLive && eventCountdown < 2.8f) wantVerdict = true;
            if (AiIsMassCollapseEvent() && !AiPlayerInLargestClusterInterior() && eventCountdown < 2.5f) wantVerdict = true;
            if (bossNear && eventLive && waveNumber >= 25 && eventCountdown < 1.8f) wantVerdict = true;
            if (AiIsTrapped(playerPos) && eventLive) wantVerdict = true;
            if (wantVerdict && Raylib.GetTime() - aiLastVerdictAttempt > 0.45f)
            {
                aiVerdictRequest = true;
                aiLastVerdictAttempt = (float)Raylib.GetTime();
            }
        }

        if (HasEquippedAbility(AbilityType.BannerOfStillness) && bannerCooldown <= 0f && !bannerActive && bannerPlantTimer <= 0f)
        {
            bool wantBanner = false;
            if (swarmed && !criticalTile && TryGetTileUnder(playerPos, out int bx, out int by))
            {
                float dur = tiles[bx, by].Durability / MaxDurability;
                if (dur > 0.62f && aiTileHazard[bx, by] < 0.35f && AiCountViableWalkExits(playerPos, 64f) >= 2) wantBanner = true;
            }
            if (bossNear && !criticalTile && AiCountViableWalkExits(playerPos, 64f) >= 2) wantBanner = true;
            if (wantBanner && aiPhase is AiSurvivalPhase.Combat or AiSurvivalPhase.BossFight)
            {
                aiBannerRequest = true;
                aiBannerTarget = playerPos;
            }
        }

        aiOathPrimed = HasEquippedAbility(AbilityType.OathOfTheBailey) && !oathUsedThisRun && criticalTile;
    }

    static Vector2 AiGrandmasterCombatRetreat(Vector2 from, float dt)
    {
        if (reloadTimer <= 0f) { aiCombatRetreatTimer = 0f; return Vector2.Zero; }
        aiCombatRetreatTimer += dt;
        if (AiEnemiesThreatening(from, 150f) == 0) return Vector2.Zero;
        Vector2 flee = ComputeUrgentEnemyFlee(from);
        if (flee == Vector2.Zero) flee = AiGrandmasterBehaviorSteer(from);
        return flee * MathF.Min(1f, 0.55f + aiCombatRetreatTimer);
    }

    static int AiGrandmasterSelectPriorityTarget()
    {
        int best = -1;
        float bestScore = float.NegativeInfinity;
        for (int i = 0; i < enemies.Count; i++)
        {
            Enemy e = enemies[i];
            if (e.Dead || e.Spawn < 0.5f) continue;
            var def = GetDef(e.Type);
            var prof = AiBehaviorProfileFor(def.Behavior);
            float d = Vector2.Distance(playerPos, e.Position);
            float score = prof.Priority * 200f - d;
            if (def.Boss) score += 420f;
            if (def.InstaCollapse) score += 180f;
            if (prof.TileThreat > 1.5f) score += 160f;
            score += AiEvaluateEnemyThreat(playerPos, in e) * 0.12f;
            if (score > bestScore) { bestScore = score; best = i; }
        }
        aiFocusEnemyIndex = best;
        return best;
    }

    static float AiGrandmasterLookaheadScore(Vector2 pos, float seconds)
    {
        float score = 0f;
        if (!TryGetTileUnder(pos, out int tx, out int ty)) return -99999f;
        score += aiPredictedValue[tx, ty];
        score -= aiPredictedHazard[tx, ty] * 320f;
        score -= AiEnemyZonePenalty(pos);
        score -= NearestBossDistance(pos) * 0.22f;
        score += AiCountViableWalkExits(pos, 64f) * 45f;
        if (activeEvent != FloorEventType.None && eventCountdown > 0f && tiles[tx, ty].EventMarked) score -= 5000f;
        score -= seconds * 12f;
        return score;
    }

    static Vector2 AiGrandmasterLookaheadSteer(Vector2 from, Vector2 baseDir)
    {
        if (baseDir == Vector2.Zero) return Vector2.Zero;
        float baseAngle = MathF.Atan2(baseDir.Y, baseDir.X);
        float bestScore = float.NegativeInfinity;
        Vector2 best = baseDir;
        float speed = EffMoveSpeed();
        for (int i = -7; i <= 7; i++)
        {
            float angle = baseAngle + i * (MathF.PI / 24f);
            Vector2 dir = new Vector2(MathF.Cos(angle), MathF.Sin(angle));
            Vector2 probe = from + dir * speed * 0.35f;
            float s0 = AiGrandmasterLookaheadScore(probe, 0.35f);
            Vector2 probe2 = from + dir * speed * 0.75f;
            float s1 = AiGrandmasterLookaheadScore(probe2, 0.75f);
            float total = s0 * 0.45f + s1 * 0.55f;
            if (total > bestScore) { bestScore = total; best = dir; }
        }
        return best;
    }

    static Vector2 AiGrandmasterBossSteer(Vector2 from)
    {
        float bossDist = NearestBossDistance(from);
        if (bossDist > 260f) return Vector2.Zero;
        Vector2 steer = Vector2.Zero;
        foreach (Enemy e in enemies)
        {
            if (e.Dead || e.Spawn < 0.5f) continue;
            if (!GetDef(e.Type).Boss) continue;
            Vector2 away = from - e.Position;
            float d = away.Length();
            if (d < 0.01f) continue;
            Vector2 dir = away / d;
            float orbitDist = 150f + e.Radius;
            if (d < orbitDist * 0.75f) steer += dir * 2.4f;
            else if (d < orbitDist * 1.2f)
            {
                Vector2 tangent = new Vector2(-dir.Y, dir.X);
                steer += tangent * 1.1f;
            }
            else steer += dir * (95f / (d + 20f));
        }
        if (steer.LengthSquared() < 0.001f) return Vector2.Zero;
        return SafeNormalize(steer);
    }

    static Vector2 AiGrandmasterBlendSteering(Vector2 from, Vector2 baseMove, float dt)
    {
        Vector2 move = baseMove;

        if (bannerActive && IsInBannerZone(from) && aiPhase is not AiSurvivalPhase.EventActive and not AiSurvivalPhase.TileCritical)
        {
            move *= 0.28f;
        }

        Vector2 eventSteer = AiGrandmasterEventSteer(from);
        if (eventSteer != Vector2.Zero) move = eventSteer;
        else
        {
            Vector2 path = AiPathfindSteer(from, dt);
            if (path != Vector2.Zero) move = Vector2.Lerp(move, path, 0.38f + aiWaveConservatism * 0.18f);
        }

        Vector2 behavior = AiGrandmasterBehaviorSteer(from);
        if (behavior != Vector2.Zero)
        {
            float behaviorW = aiPhase switch
            {
                AiSurvivalPhase.BossFight => 0.58f,
                AiSurvivalPhase.LastStand => 0.52f,
                AiSurvivalPhase.Combat => 0.42f,
                _ => 0.34f,
            };
            move = Vector2.Lerp(move, behavior, behaviorW);
        }

        Vector2 boss = AiGrandmasterBossSteer(from);
        if (boss != Vector2.Zero) move = Vector2.Lerp(move, boss, 0.62f);

        Vector2 retreat = AiGrandmasterCombatRetreat(from, dt);
        if (retreat != Vector2.Zero) move = Vector2.Lerp(move, retreat, 0.72f);

        float scenarioScore = aiScenarioScoreCache;
        Vector2 scenario = AiScenarioMatrixSteer(from);
        if (scenario != Vector2.Zero)
        {
            move = Vector2.Lerp(move, scenario, MathF.Min(0.58f, scenarioScore * 0.13f));
        }

        if (move != Vector2.Zero)
            move = AiGrandmasterLookaheadSteer(from, SafeNormalize(move));
        return move;
    }

    static void UpdateAiGrandmasterDashLogic(float dt, ref float dashUrgency)
    {
        float behaviorDash = 0f;
        foreach (Enemy e in enemies)
        {
            if (e.Dead || e.Spawn < 0.5f) continue;
            var prof = AiBehaviorProfileFor(GetDef(e.Type).Behavior);
            if (!prof.PreemptDash) continue;
            float margin = AiEnemyZoneMargin(playerPos, e);
            if (margin < TileSize * 0.25f) behaviorDash = MathF.Max(behaviorDash, 0.88f);
        }

        dashUrgency = MathF.Max(dashUrgency, behaviorDash);
        dashUrgency = MathF.Max(dashUrgency, AiCollapseEventDashUrgency(playerPos) * 1.05f);
        if (aiPhase == AiSurvivalPhase.LastStand) dashUrgency = MathF.Max(dashUrgency, 0.95f);
        if (aiPredictFieldsValid && TryGetTileUnder(playerPos, out int px, out int py))
        {
            if (aiPredictedHazard[px, py] > 0.82f) dashUrgency = MathF.Max(dashUrgency, 0.9f);
        }
    }

    static void RunAiGrandmasterBrain(float dt)
    {
        aiScenarioFlagsDirty = true;
        UpdateAiWaveConservatism();
        EvaluateAiSurvivalPhase();
        RebuildAiPredictiveFields(dt);
        ResolveAiGrandmasterAbilities(dt);
        AiGrandmasterSelectPriorityTarget();
        aiScenarioScoreCache = AiEvaluateScenarioMatrix(playerPos);
    }

    static float AiEvaluateEnemyThreat(Vector2 from, in Enemy e)
    {
        var def = GetDef(e.Type);
        var prof = AiBehaviorProfileFor(def.Behavior);
        float d = Vector2.Distance(from, e.Position);
        float margin = AiEnemyZoneMargin(from, e);
        float threat = prof.Priority * 100f + def.TileDecay * 2.4f;
        if (def.Boss) threat += 260f;
        if (def.InstaCollapse) threat += 140f;
        if (margin < 0f) threat += (-margin + 8f) * prof.ZoneMul * 18f;
        threat += MathF.Max(0f, prof.KiteDist - d) * 0.35f;
        if (TryGetTileUnder(from, out int fx, out int fy))
        {
            threat += aiTileHazard[fx, fy] * 80f * prof.TileThreat;
            threat += (1f - tiles[fx, fy].Durability / MaxDurability) * 60f * prof.TileThreat;
        }
        if (TryGetTileUnder(e.Position, out int ex, out int ey))
        {
            threat += aiTileHazard[ex, ey] * 40f;
            if (tiles[ex, ey].EventMarked) threat += 90f;
        }
        threat += AiEnemiesThreatening(from, 120f + def.Radius) * 12f;
        if (waveNumber >= def.MinWave + 10) threat *= 1.08f + aiWaveConservatism * 0.05f;
        return threat;
    }

    static float AiGrandmasterAggregateEnemyThreat(Vector2 from)
    {
        float total = 0f;
        foreach (Enemy e in enemies)
        {
            if (e.Dead || e.Spawn < 0.5f) continue;
            total += AiEvaluateEnemyThreat(from, in e);
        }
        return total;
    }

    static void RefreshAiScenarioThreatFlags()
    {
        if (!aiScenarioFlagsDirty) return;
        aiScenarioFlagsDirty = false;
        aiScenarioHasCrusher = false;
        aiScenarioHasLeech = false;
        aiScenarioHasFast = false;
        foreach (Enemy e in enemies)
        {
            if (e.Dead || e.Spawn < 0.5f) continue;
            var def = GetDef(e.Type);
            if (def.Behavior is EnemyBehavior.CrushTiles or EnemyBehavior.BossSmash) aiScenarioHasCrusher = true;
            if (def.Behavior == EnemyBehavior.TileLeech) aiScenarioHasLeech = true;
            if (def.Behavior == EnemyBehavior.FastChase && Vector2.Distance(playerPos, e.Position) < 120f) aiScenarioHasFast = true;
        }
    }

    static float AiScenarioPhaseMultiplier()
    {
        return aiPhase switch
        {
            AiSurvivalPhase.LastStand => 1.48f,
            AiSurvivalPhase.TileCritical => 1.28f,
            AiSurvivalPhase.BossFight => 1.18f,
            AiSurvivalPhase.EventActive => 1.22f,
            AiSurvivalPhase.EventPrep => 1.08f,
            AiSurvivalPhase.Combat => 1.05f,
            AiSurvivalPhase.Patrol => 0.92f,
            AiSurvivalPhase.Calm => 0.82f,
            _ => 1f,
        };
    }

    static float AiEvaluateScenarioMatrix(Vector2 from)
    {
        RefreshAiScenarioThreatFlags();
        int bucket = Math.Clamp(waveNumber / 10, 0, 15);
        float waveScale = 1f + bucket * 0.04f + aiWaveConservatism * 0.14f;
        float phaseMul = AiScenarioPhaseMultiplier();
        float sum = 0f;

        float voidUrgency = AiVoidDashUrgency(from);
        if (voidUrgency >= 0.35f || IsFeetTileWeak())
        {
            float w = 0.85f + voidUrgency;
            if (AiCountViableWalkExits(from, 60f) <= 1) w += 0.9f;
            sum += w * phaseMul * waveScale;
        }

        int swarm = AiEnemiesThreatening(from, 170f);
        if (swarm >= 3)
        {
            float w = 0.55f + swarm * 0.12f;
            if (AiIsInsideEnemyDangerZone(from)) w += 0.75f;
            sum += w * phaseMul * waveScale;
        }

        if (activeEvent != FloorEventType.None && eventCountdown > 0f
            && TryGetTileUnder(from, out int tx, out int ty) && tiles[tx, ty].EventMarked)
        {
            sum += (1.1f + (3f - MathF.Min(eventCountdown, 3f)) * 0.2f) * phaseMul * waveScale;
        }

        if (reloadTimer > 0f)
        {
            float w = 0.45f + reloadTimer * 0.25f;
            if (AiEnemiesThreatening(from, 140f) >= 1) w += 0.65f;
            sum += w * phaseMul * waveScale;
        }

        if (TryGetTileUnder(from, out int ex, out int ey) && AiIsNearGridEdge(ex, ey))
        {
            sum += (0.7f + (AiEdgeMarginTiles - AiEdgeMargin(ex, ey)) * 0.25f) * phaseMul * waveScale;
        }

        float bossDist = NearestBossDistance(from);
        if (bossDist <= 220f)
        {
            sum += (1.2f + (220f - bossDist) * 0.004f) * phaseMul * waveScale;
        }

        if (aiScenarioHasCrusher && TryGetTileUnder(from, out int cx, out int cy))
        {
            sum += (0.95f + AiBehaviorTilePressureAt(cx, cy) * 0.02f) * phaseMul * waveScale;
        }

        if (aiScenarioHasLeech)
        {
            sum += (0.8f + aiWaveConservatism * 0.3f) * phaseMul * waveScale;
        }

        if (aiScenarioHasFast)
        {
            sum += 0.72f * phaseMul * waveScale;
        }

        if (AiIsTrapped(from))
        {
            sum += (1.35f + AiEnemiesThreatening(from, 160f) * 0.1f) * phaseMul * waveScale;
        }

        if (bannerActive && IsInBannerZone(from))
        {
            sum *= 0.55f;
        }

        aiScenarioScoreCache = sum;
        return sum;
    }

    static Vector2 AiScenarioMatrixSteer(Vector2 from)
    {
        float score = aiScenarioScoreCache > 0f ? aiScenarioScoreCache : AiEvaluateScenarioMatrix(from);
        if (score < 0.45f) return Vector2.Zero;
        Vector2 steer = Vector2.Zero;
        if (AiVoidDashUrgency(from) > 0.4f) steer += ComputeUrgentVoidFlee(from);
        if (AiEnemiesThreatening(from, 160f) >= 2) steer += ComputeUrgentEnemyFlee(from);
        if (activeEvent != FloorEventType.None && eventCountdown > 0f) steer += AiGrandmasterEventSteer(from);
        if (steer == Vector2.Zero) steer += DirectionToNearestSafeTile(from);
        return SafeNormalize(steer) * MathF.Min(score * 0.35f, 1.65f);
    }

    static float AiWaveSurvivalTuning(int wave)
    {
        float baseTuning = Math.Clamp((wave - 8) * 0.012f, 0f, 1.35f);
        if (AiVoidDashUrgency(playerPos) > 0.5f) baseTuning += 0.12f;
        return Math.Clamp(baseTuning, 0f, 1.45f);
    }
    // ---------------------------------------------------------------- Upgrade effects

    static float EffMoveSpeed() => PlayerSpeed * (1f + upgradeLevels[UpSwift] * 0.05f);
    static float EffDashCooldown() => MathF.Max(0.45f, DashCooldown * (1f - upgradeLevels[UpDash] * 0.08f));
    static float FableMult()
    {
        float mult = 1f + upgradeLevels[UpFortune] * 0.15f;
        if (autoFire) mult *= 0.75f;
        return mult;
    }
    static float EffPlayerDecay() => PlayerDurabilityDecayRate * (1f - upgradeLevels[UpFeet] * 0.08f);

    static float EffFireCooldown(in Gun g)
    {
        float rate = 1f + upgradeLevels[UpRapid] * 0.12f;
        if (IsInBannerZone(playerPos)) rate *= BannerFireRateMul;
        return g.FireCooldown / rate;
    }
    static float EffDamage(in Gun g) => g.Damage + upgradeLevels[UpThorns] * 0.75f;
    static int EffCount(in Gun g) => g.Count + upgradeLevels[UpSplit];
    static int EffPierce(in Gun g) => g.Pierce + upgradeLevels[UpPierce];
    static float EffParalyzeRadius() => ParalyzeRadiusBase + upgradeLevels[UpParalyzeReach] * 22f;
    static float EffParalyzeDuration() => ParalyzeDurationBase + upgradeLevels[UpParalyzeHold] * 0.4f;
    static float EffParalyzeCooldown() => ParalyzeCooldown;

    static Color BodyColor() => aiPilotEnabled ? AutoPilotBody : BodyPalette[bodyColorIndex];
    static Color BodyBright() => aiPilotEnabled ? AutoPilotBright : Lighten(BodyPalette[bodyColorIndex], 0.5f);

    static int UpgradeCost(int i) => UpgradeBaseCost[i] * (upgradeLevels[i] + 1);

    // ---------------------------------------------------------------- Update

    static void Update()
    {
        float dt = Raylib.GetFrameTime();
        menuTime += dt;

        UpdateCursorLock();
        UpdateWindowChrome();

        UpdateMotes(dt);
        scoreDisplay += (score - scoreDisplay) * (1f - MathF.Exp(-10f * dt));
        flash *= MathF.Exp(-6f * dt);
        impactFlash *= MathF.Exp(-32f * dt);
        zoomPunch *= MathF.Exp(-9f * dt);
        UpdateGfx(dt);
        if (levelUpBannerTimer > 0f) levelUpBannerTimer -= dt;

        if (Raylib.IsKeyPressed(KeyboardKey.F3))
        {
            showFps = !showFps;
        }

        if (Raylib.IsKeyPressed(KeyboardKey.Backslash))
        {
            aiPilotEnabled = !aiPilotEnabled;
            aiGameOverTimer = 0f;
            if (aiPilotEnabled)
            {
                aiPilotBannerTimer = 8f;
            }

            if (aiPilotEnabled && state == GameState.MainMenu)
            {
                ResetGame();
            }
            else if (state == GameState.Playing)
            {
                SpawnFloatingText(
                    playerPos + new Vector2(0, -28f),
                    aiPilotEnabled ? "GRANDMASTER PILOT ON" : "AUTO-PILOT OFF",
                    aiPilotEnabled ? UiAccent : WithAlpha(Color.White, 0.7f),
                    16);
                if (aiPilotEnabled)
                {
                    SpawnFloatingText(
                        playerPos + new Vector2(0, -50f),
                        "Grandmaster survival AI engaged",
                        new Color(196, 168, 108, 255),
                        13);
                }
            }
        }

        switch (state)
        {
            case GameState.MainMenu:
                if (Raylib.IsKeyPressed(KeyboardKey.Enter) || Raylib.IsKeyPressed(KeyboardKey.Space))
                {
                    ResetGame();
                }
                else if (Raylib.IsKeyPressed(KeyboardKey.C))
                {
                    state = GameState.Customize;
                }
                else if (Raylib.IsKeyPressed(KeyboardKey.S))
                {
                    state = GameState.Settings;
                }
                break;

            case GameState.Playing:
                if (Raylib.IsKeyPressed(KeyboardKey.Escape))
                {
                    state = GameState.Paused;
                    break;
                }
                if (ProcessHitStop(dt))
                {
                    break;
                }

                trauma = Math.Max(0f, trauma - TraumaDecay * dt);
                UpdateParticles(dt);
                UpdateTrails(dt);
                UpdateFloaters(dt);
                UpdateTiles(dt);

                if (comboTimer > 0f)
                {
                    comboTimer -= dt;
                    if (comboTimer <= 0f) combo = 0;
                }
                if (waveBannerTimer > 0f) waveBannerTimer -= dt;
                if (aiPilotEnabled && aiPilotBannerTimer > 0f) aiPilotBannerTimer -= dt;

                if (aiPilotEnabled)
                {
                    UpdateAiPilot(dt);
                }

                UpdateAbilities(dt);
                UpdatePlayer(dt);
                UpdateFloorEvents(dt);
                UpdateBlight(dt);
                UpdateWaves(dt);
                UpdateEnemies(dt);
                UpdateWeapon(dt);
                UpdateProjectiles(dt);
                ReapEnemies();
                break;

            case GameState.Paused:
                if (Raylib.IsKeyPressed(KeyboardKey.Escape) || Raylib.IsKeyPressed(KeyboardKey.Enter))
                {
                    state = GameState.Playing;
                }
                break;

            case GameState.GameOver:
                trauma = Math.Max(0f, trauma - TraumaDecay * dt);
                UpdateParticles(dt);
                UpdateTrails(dt);
                UpdateFloaters(dt);
                UpdateProjectiles(dt);
                UpdateTiles(dt);
                if (aiPilotEnabled)
                {
                    aiGameOverTimer += dt;
                    if (aiGameOverTimer >= 0.6f)
                    {
                        ResetGame();
                    }
                }
                else if (Raylib.IsKeyPressed(KeyboardKey.R)) ResetGame();
                else if (Raylib.IsKeyPressed(KeyboardKey.Escape)) state = GameState.MainMenu;
                break;

            case GameState.Customize:
                if (Raylib.IsKeyPressed(KeyboardKey.Escape)) { SaveGame(); state = GameState.MainMenu; }
                else if (Raylib.IsKeyPressed(KeyboardKey.One)) customizeTab = CustomizeTab.Cosmetics;
                else if (Raylib.IsKeyPressed(KeyboardKey.Two)) customizeTab = CustomizeTab.Weapons;
                else if (Raylib.IsKeyPressed(KeyboardKey.Three)) customizeTab = CustomizeTab.Upgrades;
                else if (Raylib.IsKeyPressed(KeyboardKey.Four)) customizeTab = CustomizeTab.Abilities;
                else if (Raylib.IsKeyPressed(KeyboardKey.Five)) customizeTab = CustomizeTab.Rank;
                if (state == GameState.Customize)
                {
                    float wheel = Raylib.GetMouseWheelMove();
                    if (wheel != 0f)
                    {
                        customizeScroll = Math.Clamp(customizeScroll - wheel * 42f, 0f, ArmoryScrollMax());
                    }
                }
                break;

            case GameState.Settings:
                if (rebindTarget != RebindTarget.None)
                {
                    int k = Raylib.GetKeyPressed();
                    if (k != 0)
                    {
                        switch (rebindTarget)
                        {
                            case RebindTarget.Fire: fireKey = (KeyboardKey)k; break;
                            case RebindTarget.Ability1: abilityKey1 = (KeyboardKey)k; break;
                            case RebindTarget.Ability2: abilityKey2 = (KeyboardKey)k; break;
                            default: throw new UnreachableException();
                        }
                        rebindTarget = RebindTarget.None;
                        SaveGame();
                    }
                }
                else if (Raylib.IsKeyPressed(KeyboardKey.Escape)) { SaveGame(); state = GameState.MainMenu; }
                else
                {
                    float wheel = Raylib.GetMouseWheelMove();
                    if (wheel != 0f)
                    {
                        settingsScroll = Math.Clamp(settingsScroll - wheel * 42f, 0f, SettingsScrollMax());
                    }
                }
                break;

            default:
                throw new UnreachableException();
        }

        UpdateCursorLock();
    }

    static void UpdateMotes(float dt)
    {
        float time = (float)Raylib.GetTime();
        for (int i = 0; i < motes.Length; i++)
        {
            Mote m = motes[i];
            if (m.IsLeaf)
            {
                m.Position.Y += m.Speed * dt;
                m.Position.X += MathF.Sin(time * 0.8f + m.Phase) * 18f * dt;
                m.Spin += 40f * dt;
            }
            else
            {
                m.Position.Y -= m.Speed * dt * 0.4f;
                m.Position.X += MathF.Sin(time * 1.4f + m.Phase) * 12f * dt;
            }

            if (m.Position.Y < -8f)
            {
                m.Position.Y = WindowHeight + 8f;
                m.Position.X = Rng.Next(0, WindowWidth);
            }
            else if (m.Position.Y > WindowHeight + 8f)
            {
                m.Position.Y = -8f;
                m.Position.X = Rng.Next(0, WindowWidth);
            }

            motes[i] = m;
        }
    }

    static bool IsTileInMossRotZone(int x)
    {
        bool left = x < GridSize / 2;
        return floorRotSide < 0.5f ? left : !left;
    }

    static bool IsCollapsedVoid(int x, int y)
    {
        if (x < 0 || x >= GridSize || y < 0 || y >= GridSize) return false;
        return tiles[x, y].State == 2 && tiles[x, y].Collapse >= 1f;
    }

    static bool IsTileInBannerZone(int x, int y) =>
        bannerActive && bannerTimer > 0f && IsInBannerZone(TileCenter(x, y));

    static void UpdateTiles(float dt)
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                ref Tile tile = ref tiles[x, y];

                if (tile.State == 2)
                {
                    if (tile.Collapse < 1f)
                    {
                        tile.Collapse = Math.Min(1f, tile.Collapse + dt / CollapseTime);
                    }

                    if (tile.RegrowTimer > 0f)
                    {
                        tile.RegrowTimer -= dt;
                        if (tile.RegrowTimer <= 0f)
                        {
                            tile.State = 0;
                            tile.Durability = MaxDurability;
                            tile.Collapse = 0f;
                            tile.UntouchedTimer = 0f;
                            tile.EventMarked = false;
                            SpawnRegrowBurst(TileCenter(x, y));
                        }
                    }

                    continue;
                }

                tile.UntouchedTimer += dt;
                if (tile.UntouchedTimer >= TileIdleRegenDelay && tile.Durability < MaxDurability)
                {
                    tile.Durability = Math.Min(MaxDurability, tile.Durability + TileIdleRegenRate * dt);
                    if (tile.Durability >= MaxDurability * 0.6f) tile.State = 0;
                }

                if (floorRotTimer > 0f && IsTileInMossRotZone(x))
                {
                    if (!IsTileInBannerZone(x, y))
                    {
                        ApplyTileDamage(ref tile, MossRotAreaDecayRate, dt, out bool rotCollapsed, markTouched: false);
                    }
                }
            }
        }
    }

    static Vector2 TileCenter(int x, int y) =>
        new Vector2(x * TileSize + TileSize / 2f, y * TileSize + TileSize / 2f);

    static void SpawnRegrowBurst(Vector2 pos)
    {
        for (int i = 0; i < 8; i++)
        {
            float angle = i * MathF.PI * 2f / 8f;
            particles.Add(new Particle
            {
                Position = pos,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 90f,
                Color = MossLight,
                Alpha = 0.9f,
                Fade = 1f / 0.35f,
                Size = 3f + Rng.NextSingle() * 2f,
                Drag = 3f,
                Glow = true,
            });
        }
    }

    static void CollapseTile(ref Tile tile, bool regrow = true)
    {
        if (tile.State == 2) return;
        tile.Durability = 0f;
        tile.State = 2;
        tile.Collapse = 0f;
        tile.EventMarked = false;
        tile.RegrowTimer = regrow ? TileRegrowTime : 0f;
    }

    static float TileDecayMultiplier(int x, int y)
    {
        if (floorRotTimer <= 0f) return 1f;
        bool left = x < GridSize / 2;
        bool affected = floorRotSide < 0.5f ? left : !left;
        return affected ? 2.8f : 1f;
    }

    static void UpdatePlayer(float dt)
    {
        bool dashing = dashTimer > 0f;

        if (dashing)
        {
            dashTimer -= dt;
            playerPos += lastMoveDirection * DashSpeed * dt;
            playerVel = lastMoveDirection * DashSpeed;
            trails.Add(new DashTrail { Position = playerPos, Alpha = 0.75f, Radius = PlayerRadius });
            if (dashTimer <= 0f) dashCooldown = EffDashCooldown();
        }
        else
        {
            dashCooldown = Math.Max(0f, dashCooldown - dt);

            Vector2 move = Vector2.Zero;
            if (aiPilotEnabled && state == GameState.Playing)
            {
                move = aiMove;
            }
            else
            {
                if (Raylib.IsKeyDown(KeyboardKey.W)) move.Y -= 1f;
                if (Raylib.IsKeyDown(KeyboardKey.S)) move.Y += 1f;
                if (Raylib.IsKeyDown(KeyboardKey.A)) move.X -= 1f;
                if (Raylib.IsKeyDown(KeyboardKey.D)) move.X += 1f;
            }

            if (move != Vector2.Zero)
            {
                move = Vector2.Normalize(move);
                lastMoveDirection = move;
            }

            Vector2 targetVel = move * EffMoveSpeed();
            playerVel = Vector2.Lerp(playerVel, targetVel, 1f - MathF.Exp(-PlayerAccel * dt));
            playerPos += playerVel * dt;

            SpawnWalkDust(dt);
        }

        playerPos.X = Math.Clamp(playerPos.X, PlayerRadius, WindowWidth - PlayerRadius);
        playerPos.Y = Math.Clamp(playerPos.Y, PlayerRadius, WindowHeight - PlayerRadius);

        if (dashing || abilityIFrameTimer > 0f)
        {
            return; // i-frames — leap over the earth pit or oath ward
        }

        if (TryGetTileUnder(playerPos, out int tileX, out int tileY))
        {
            ref Tile tile = ref tiles[tileX, tileY];
            if (tile.State == 2)
            {
                TriggerGameOver(DeathCause.FellThrough);
                return;
            }

            if (ShouldSkipWarningTileDamage(tileX, tileY)) return;
            if (IsTileInBannerZone(tileX, tileY)) return;

            ApplyTileDamage(ref tile, EffPlayerDecay() * TileDecayMultiplier(tileX, tileY), dt, out bool collapsed);
            if (collapsed) TriggerGameOver(DeathCause.FloorGaveWay);
        }
    }

    static bool ShouldSkipWarningTileDamage(int tileX, int tileY)
    {
        if ((activeEvent != FloorEventType.StoneIslands && activeEvent != FloorEventType.TideAnchor
                && activeEvent != FloorEventType.CrownIsles) || eventCountdown <= 0f) return false;
        return tiles[tileX, tileY].EventMarked;
    }

    static void UpdateWeaponAim(float dt)
    {
        if (state == GameState.Playing && cursorLocked)
        {
            Vector2 delta = Raylib.GetMouseDelta();
            bool manualAim = !autoFire && !aiPilotEnabled;
            if (manualAim && delta.LengthSquared() > 0.05f)
            {
                Vector2 aim = weaponAimDir.LengthSquared() > 0.01f ? weaponAimDir : lastMoveDirection;
                if (aim.LengthSquared() < 0.01f) aim = Vector2.UnitY;
                float angle = MathF.Atan2(aim.Y, aim.X) + delta.X * 0.024f;
                weaponAimDir = new Vector2(MathF.Cos(angle), MathF.Sin(angle));
                weaponAimTarget = playerPos + weaponAimDir * 120f;
                weaponRecoil = MathF.Max(0f, weaponRecoil - 52f * dt);
                return;
            }
        }

        Vector2 desired;
        int target = aiPilotEnabled && aiFocusEnemyIndex >= 0 ? aiFocusEnemyIndex : NearestEnemyIndex(playerPos);
        if (pendingBurstShots > 0)
        {
            desired = SafeNormalize(pendingBurstTarget - playerPos);
        }
        else if (target >= 0)
        {
            desired = SafeNormalize(enemies[target].Position - playerPos);
            weaponAimTarget = enemies[target].Position;
        }
        else if (lastMoveDirection.LengthSquared() > 0.01f)
        {
            desired = SafeNormalize(lastMoveDirection);
            weaponAimTarget = playerPos + desired * 120f;
        }
        else if (weaponAimDir.LengthSquared() > 0.01f)
        {
            desired = weaponAimDir;
            weaponAimTarget = playerPos + desired * 120f;
        }
        else
        {
            desired = Vector2.UnitY;
            weaponAimTarget = playerPos + desired * 120f;
        }

        float snap = 1f - MathF.Exp(-24f * dt);
        if (weaponAimDir.LengthSquared() < 0.01f)
        {
            weaponAimDir = desired;
        }
        else
        {
            weaponAimDir = SafeNormalize(Vector2.Lerp(weaponAimDir, desired, snap));
        }

        weaponRecoil = MathF.Max(0f, weaponRecoil - 52f * dt);
    }

    static Vector2 GetPlayerMuzzlePos()
    {
        float bodyR = PlayerRadius + (dashTimer > 0f ? 3f : 0f);
        var (grip, _, _, rot, scale) = ComputeEquippedWeaponPose(
            playerPos, bodyR, (float)Raylib.GetTime(), dashTimer > 0f);
        return GetEquippedMuzzleWorld(grip, scale, rot, equippedGun);
    }

    static void KickWeaponRecoil(in Gun g, float strength = 1f)
    {
        float kick = g.Style switch
        {
            GunFireStyle.Laser => 5.5f,
            GunFireStyle.Mortar => 17f,
            GunFireStyle.Sniper => 13f,
            GunFireStyle.Buckshot => 10f,
            GunFireStyle.FlailArc => 8f,
            GunFireStyle.Lance => 9f,
            GunFireStyle.Volley => 7f,
            GunFireStyle.Burst => 6f,
            GunFireStyle.RingPulse => 11f,
            GunFireStyle.CrossBurst => 11f,
            _ => 6.5f,
        };
        weaponRecoil = Math.Min(weaponRecoil + kick * strength, 26f);
    }

    static void SnapWeaponAim(Vector2 targetPos)
    {
        Vector2 delta = targetPos - playerPos;
        if (delta.LengthSquared() > 1f)
        {
            weaponAimDir = SafeNormalize(delta);
            weaponAimTarget = targetPos;
        }
    }

    static int GetMagazineSize(in Gun g)
    {
        int size = g.Style switch
        {
            GunFireStyle.Laser => 8,
            GunFireStyle.Sniper => 10,
            GunFireStyle.Mortar => 12,
            GunFireStyle.Buckshot => 14,
            GunFireStyle.Repeater => 40,
            GunFireStyle.Volley => 20,
            GunFireStyle.Burst => 28,
            GunFireStyle.Lance => 16,
            GunFireStyle.RingPulse => 22,
            GunFireStyle.CrossBurst => 22,
            GunFireStyle.Homing => 18,
            GunFireStyle.FlailArc => 24,
            GunFireStyle.DriftOrb => 20,
            GunFireStyle.ArcFan => 25,
            _ => 25,
        };
        if (g.FireCooldown < 0.2f) size = (int)(size * 1.15f);
        else if (g.FireCooldown > 0.55f) size = Math.Max(6, size - 3);
        return Math.Clamp(size, 6, 50);
    }

    static float GetReloadTime(in Gun g)
    {
        float time = g.Style switch
        {
            GunFireStyle.Laser => 5f,
            GunFireStyle.Sniper => 4.6f,
            GunFireStyle.Mortar => 4.8f,
            GunFireStyle.Buckshot => 4f,
            GunFireStyle.Repeater => 3.2f,
            GunFireStyle.Volley => 3.5f,
            GunFireStyle.Burst => 3.4f,
            GunFireStyle.Lance => 4.2f,
            GunFireStyle.RingPulse => 3.6f,
            GunFireStyle.CrossBurst => 3.6f,
            GunFireStyle.Homing => 3.8f,
            GunFireStyle.FlailArc => 3.7f,
            GunFireStyle.DriftOrb => 3.9f,
            GunFireStyle.ArcFan => 3.5f,
            _ => 3.5f,
        };
        time += Math.Clamp(g.FireCooldown - 0.3f, 0f, 0.4f);
        return Math.Clamp(time, 3f, 5f);
    }

    static void UpdateCursorLock()
    {
        bool shouldLock = state == GameState.Playing;
        if (shouldLock == cursorLocked) return;
        cursorLocked = shouldLock;
        if (shouldLock) Raylib.DisableCursor();
        else Raylib.EnableCursor();
    }

    static void TryStartReload()
    {
        if (reloadTimer > 0f || pendingBurstShots > 0) return;
        ref readonly Gun g = ref Guns[equippedGun];
        if (ammoInMag >= GetMagazineSize(in g)) return;
        reloadTimer = GetReloadTime(in g);
    }

    static void UpdateReload(float dt)
    {
        if (reloadTimer <= 0f) return;
        reloadTimer -= dt;
        if (reloadTimer > 0f) return;
        reloadTimer = 0f;
        ammoInMag = GetMagazineSize(in Guns[equippedGun]);
    }

    static bool TryConsumeAmmoForShot()
    {
        if (reloadTimer > 0f) return false;
        if (ammoInMag <= 0)
        {
            TryStartReload();
            return false;
        }
        ammoInMag--;
        if (ammoInMag <= 0) TryStartReload();
        return true;
    }

    static void UpdateWeapon(float dt)
    {
        UpdateWeaponAim(dt);
        UpdateReload(dt);

        if (state == GameState.Playing && Raylib.IsMouseButtonPressed(MouseButton.Right))
        {
            TryStartReload();
        }

        if (pendingBurstShots > 0)
        {
            pendingBurstTimer -= dt;
            if (pendingBurstTimer <= 0f)
            {
                ref readonly Gun burstGun = ref Guns[pendingBurstGun];
                FireWeaponShot(in burstGun, pendingBurstTarget, pendingBurstShots == 1);
                pendingBurstShots--;
                pendingBurstTimer = burstGun.BurstGap > 0f ? burstGun.BurstGap : 0.07f;
                if (pendingBurstShots <= 0)
                {
                    fireTimer = EffFireCooldown(in burstGun);
                }
            }
            return;
        }

        fireTimer -= dt;
        if (fireTimer < -0.5f) fireTimer = -0.5f;

        if (reloadTimer > 0f) return;

        bool wantFire = (state == GameState.Playing && Raylib.IsMouseButtonDown(MouseButton.Left))
            || autoFire
            || Raylib.IsKeyDown(fireKey)
            || (aiPilotEnabled && state == GameState.Playing);
        if (!wantFire || fireTimer > 0f)
        {
            return;
        }

        if (ammoInMag <= 0)
        {
            TryStartReload();
            return;
        }

        int target = aiPilotEnabled && aiFocusEnemyIndex >= 0 ? aiFocusEnemyIndex : NearestEnemyIndex(playerPos);
        if (target < 0 && Guns[equippedGun].Style != GunFireStyle.RingPulse && Guns[equippedGun].Style != GunFireStyle.CrossBurst)
        {
            return;
        }

        Vector2 aim = target >= 0 ? enemies[target].Position : playerPos + lastMoveDirection * 120f;
        ref readonly Gun g = ref Guns[equippedGun];
        FireWeapon(in g, aim, equippedGun);
    }

    static void FireWeapon(in Gun g, Vector2 targetPos, int gunIndex)
    {
        if (!TryConsumeAmmoForShot()) return;

        SnapWeaponAim(targetPos);

        switch (g.Style)
        {
            case GunFireStyle.Burst:
            case GunFireStyle.Volley:
                pendingBurstShots = Math.Max(1, g.BurstCount);
                pendingBurstGun = gunIndex;
                pendingBurstTarget = targetPos;
                pendingBurstTimer = 0f;
                FireWeaponShot(in g, targetPos, pendingBurstShots == 1);
                pendingBurstShots--;
                pendingBurstTimer = g.BurstGap > 0f ? g.BurstGap : 0.07f;
                break;
            case GunFireStyle.Laser:
                FireLaserBeam(in g, targetPos);
                fireTimer = EffFireCooldown(in g);
                break;
            default:
                FireWeaponPattern(in g, targetPos);
                fireTimer = EffFireCooldown(in g);
                break;
        }
    }

    static void FireWeaponPattern(in Gun g, Vector2 targetPos)
    {
        switch (g.Style)
        {
            case GunFireStyle.ArcFan:
            {
                int shots = Math.Max(3, g.BurstCount);
                float spread = 70f * MathF.PI / 180f;
                Vector2 dir = SafeNormalize(targetPos - playerPos);
                float baseAngle = MathF.Atan2(dir.Y, dir.X);
                for (int i = 0; i < shots; i++)
                {
                    float frac = shots == 1 ? 0.5f : i / (float)(shots - 1);
                    float angle = baseAngle + (frac - 0.5f) * spread;
                    SpawnProjectile(in g, angle, EffDamage(in g), EffPierce(in g), g.Speed, 4f, g.Homing, GunFireStyle.ArcFan);
                }
                break;
            }
            case GunFireStyle.Buckshot:
            {
                int pellets = Math.Max(4, EffCount(in g));
                float spread = (g.Spread + upgradeLevels[UpSplit] * 4f + 18f) * MathF.PI / 180f;
                float baseAngle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                for (int i = 0; i < pellets; i++)
                {
                    float frac = pellets == 1 ? 0.5f : i / (float)(pellets - 1);
                    float angle = baseAngle + (frac - 0.5f) * spread;
                    SpawnProjectile(in g, angle, EffDamage(in g) * 0.75f, 1, g.Speed * 0.82f, 3.2f, 0f, GunFireStyle.Buckshot);
                }
                break;
            }
            case GunFireStyle.Homing:
                FireWeaponShot(in g, targetPos, true);
                break;
            case GunFireStyle.Lance:
            {
                float angle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                SpawnProjectile(in g, angle, EffDamage(in g) * 1.35f, EffPierce(in g) + 2, g.Speed * 1.25f, 6.5f, 0f, GunFireStyle.Lance);
                break;
            }
            case GunFireStyle.Repeater:
            {
                float angle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                SpawnProjectile(in g, angle, EffDamage(in g) * 0.85f, EffPierce(in g), g.Speed * 1.1f, 3f, 0f, GunFireStyle.Repeater);
                break;
            }
            case GunFireStyle.Sniper:
            {
                float angle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                SpawnProjectile(in g, angle, EffDamage(in g) * 2.4f, Math.Max(2, EffPierce(in g)), g.Speed * 1.55f, 3.5f, 0f, GunFireStyle.Sniper);
                break;
            }
            case GunFireStyle.RingPulse:
            {
                int rays = 8;
                for (int i = 0; i < rays; i++)
                {
                    float angle = i * MathF.PI * 2f / rays;
                    SpawnProjectile(in g, angle, EffDamage(in g) * 0.9f, 1, g.Speed * 0.95f, 4f, 0f, GunFireStyle.RingPulse);
                }
                break;
            }
            case GunFireStyle.CrossBurst:
            {
                for (int i = 0; i < 4; i++)
                {
                    float angle = i * MathF.PI * 0.5f;
                    SpawnProjectile(in g, angle, EffDamage(in g), EffPierce(in g), g.Speed, 4.2f, 0f, GunFireStyle.CrossBurst);
                }
                break;
            }
            case GunFireStyle.Mortar:
            {
                float angle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                SpawnProjectile(in g, angle, EffDamage(in g) * 1.8f, 0, g.Speed * 0.55f, 8f, 0f, GunFireStyle.Mortar);
                break;
            }
            case GunFireStyle.DriftOrb:
            {
                float angle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                SpawnProjectile(in g, angle, EffDamage(in g), EffPierce(in g), g.Speed * 0.65f, 5.5f, Math.Max(1.8f, g.Homing), GunFireStyle.DriftOrb);
                break;
            }
            case GunFireStyle.FlailArc:
            {
                float baseAngle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
                for (int i = -1; i <= 1; i++)
                {
                    float angle = baseAngle + i * 0.42f;
                    SpawnProjectile(in g, angle, EffDamage(in g) * 1.1f, EffPierce(in g), g.Speed * 0.9f, 5f, 0f, GunFireStyle.FlailArc, spinRate: 6f + i * 2f);
                }
                break;
            }
            default:
                FireWeaponShot(in g, targetPos, true);
                break;
        }

        Vector2 muzzleDir = SafeNormalize(targetPos - playerPos);
        Vector2 muzzlePos = GetPlayerMuzzlePos();
        SpawnWeaponFireFx(g.Style, muzzlePos, muzzleDir, g.Color, g.Name);
        AddTrauma(GunStyleTrauma(g.Style));
        KickWeaponRecoil(in g, 0.7f);
    }

    static void FireWeaponShot(in Gun g, Vector2 targetPos, bool finalBurstShot)
    {
        SnapWeaponAim(targetPos);
        float baseAngle = MathF.Atan2(targetPos.Y - playerPos.Y, targetPos.X - playerPos.X);
        float spread = (g.Spread + upgradeLevels[UpSplit] * 4f) * MathF.PI / 180f;
        int count = g.Style is GunFireStyle.Burst or GunFireStyle.Volley ? 1 : EffCount(in g);

        for (int i = 0; i < count; i++)
        {
            float frac = count == 1 ? 0.5f : i / (float)(count - 1);
            float angle = baseAngle + (frac - 0.5f) * spread;
            float homing = g.Style == GunFireStyle.Homing ? Math.Max(2.5f, g.Homing) : g.Homing;
            float size = g.Style == GunFireStyle.Homing ? 6f : g.Style == GunFireStyle.Repeater ? 3f : 4.5f;
            SpawnProjectile(in g, angle, EffDamage(in g), EffPierce(in g), g.Speed, size, homing, g.Style);
        }

        if (finalBurstShot)
        {
            Vector2 muzzleDir = new Vector2(MathF.Cos(baseAngle), MathF.Sin(baseAngle));
            Vector2 muzzlePos = GetPlayerMuzzlePos();
            SpawnWeaponFireFx(g.Style, muzzlePos, muzzleDir, g.Color, g.Name);
            AddTrauma(GunStyleTrauma(g.Style) * 0.65f);
        }

        KickWeaponRecoil(in g, finalBurstShot ? 1f : 0.42f);
    }

    static void SpawnProjectile(in Gun g, float angle, float damage, int pierce, float speed, float size,
        float homing, GunFireStyle style, float spinRate = 0f)
    {
        var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed;
        float life = style == GunFireStyle.Mortar ? 2.2f : style == GunFireStyle.DriftOrb ? 2.6f : 1.4f;
        projectiles.Add(new Projectile
        {
            Position = playerPos + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * (PlayerRadius + 4f),
            Velocity = vel,
            Color = g.Color,
            Life = life,
            SpawnLife = life,
            Size = size,
            Damage = damage,
            Pierce = pierce,
            Homing = homing,
            Style = style,
            SpinRate = spinRate,
        });
        SpawnProjectileBirthFx(style, playerPos + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * (PlayerRadius + 4f), vel, g.Color);
    }

    static void FireLaserBeam(in Gun g, Vector2 targetPos)
    {
        SnapWeaponAim(targetPos);
        Vector2 dir = SafeNormalize(targetPos - playerPos);
        Vector2 start = GetPlayerMuzzlePos();
        Vector2 end = start + dir * 920f;
        float damage = EffDamage(in g) * 1.6f;
        DamageBeam(start, end, 7f, damage, g.Color);

        projectiles.Add(new Projectile
        {
            Position = start,
            Velocity = Vector2.Zero,
            Color = g.Color,
            Life = 0.28f,
            SpawnLife = 0.28f,
            Size = 7f,
            Damage = 0f,
            Pierce = 0,
            Homing = 0f,
            Style = GunFireStyle.Laser,
            BeamEnd = end,
            BeamWidth = 9f,
        });

        SpawnWeaponFireFx(GunFireStyle.Laser, start, dir, g.Color, g.Name);
        SpawnLaserBeamFx(start, end, g.Color);
        AddTrauma(0.32f);
        TriggerImpact(ImpactTier.Medium, Lighten(g.Color, 0.45f));
        AddFlash(Lighten(g.Color, 0.3f), 0.14f);
        KickWeaponRecoil(in g, 0.85f);
    }

    static void DamageBeam(Vector2 start, Vector2 end, float width, float damage, Color color)
    {
        Vector2 seg = end - start;
        float lenSq = seg.LengthSquared();
        if (lenSq < 1f) return;

        int beamHits = 0;
        for (int e = 0; e < enemies.Count; e++)
        {
            Enemy en = enemies[e];
            if (en.Dead || en.Spawn < 0.5f) continue;

            float t = Math.Clamp(Vector2.Dot(en.Position - start, seg) / lenSq, 0f, 1f);
            Vector2 closest = start + seg * t;
            float dist = Vector2.Distance(en.Position, closest);
            if (dist > width + en.Radius) continue;

            en.Hp -= damage;
            en.Hit = 0.12f;
            if (en.Hp <= 0f) en.Dead = true;
            enemies[e] = en;
            SpawnHitSpark(closest, color);
            beamHits++;
        }

        if (beamHits >= 3)
        {
            TriggerImpact(ImpactTier.Medium, color);
        }
        else if (beamHits > 0)
        {
            TriggerImpact(ImpactTier.Light, color);
        }
    }

    static void UpdateProjectiles(float dt)
    {
        for (int i = projectiles.Count - 1; i >= 0; i--)
        {
            Projectile p = projectiles[i];
            p.Life -= dt;

            if (p.Style == GunFireStyle.Laser)
            {
                if (p.Life <= 0f) projectiles.RemoveAt(i);
                else projectiles[i] = p;
                continue;
            }

            if (p.SpinRate != 0f)
            {
                float ang = MathF.Atan2(p.Velocity.Y, p.Velocity.X) + p.SpinRate * dt;
                float spd = p.Velocity.Length();
                p.Velocity = new Vector2(MathF.Cos(ang), MathF.Sin(ang)) * spd;
            }

            if (p.Homing > 0f)
            {
                int t = NearestEnemyIndex(p.Position);
                if (t >= 0)
                {
                    Vector2 desired = Vector2.Normalize(enemies[t].Position - p.Position) * p.Velocity.Length();
                    p.Velocity = Vector2.Lerp(p.Velocity, desired, 1f - MathF.Exp(-p.Homing * dt));
                }
            }

            if (p.Style == GunFireStyle.DriftOrb)
            {
                p.Size = Math.Min(10f, p.Size + dt * 2.2f);
            }

            p.Position += p.Velocity * dt;

            if (Rng.NextSingle() < ProjectileTrailChance(p.Style) && p.Style != GunFireStyle.Mortar)
            {
                SpawnProjectileTrailFx(p);
            }

            bool dead = p.Life <= 0f
                || p.Position.X < -20f || p.Position.X > WindowWidth + 20f
                || p.Position.Y < -20f || p.Position.Y > WindowHeight + 20f;

            if (!dead)
            {
                for (int e = 0; e < enemies.Count; e++)
                {
                    Enemy en = enemies[e];
                    if (en.Dead || en.Spawn < 0.5f) continue;

                    float rr = p.Size + en.Radius;
                    if (Vector2.DistanceSquared(p.Position, en.Position) > rr * rr) continue;

                    float dmg = p.Damage;
                    if (p.Style == GunFireStyle.Mortar)
                    {
                        dmg *= 1.35f;
                        SpawnExplosion(p.Position, p.Color, 42);
                    }

                    en.Hp -= dmg;
                    en.Hit = 0.12f;
                    enemies[e] = en;
                    SpawnProjectileHitFx(p.Style, p.Position, p.Velocity, p.Color, dmg);

                    if (!en.Dead)
                    {
                        RegisterWeaponImpact(p.Position, p.Color, dmg, p.Style);
                    }

                    if (en.Hp <= 0f)
                    {
                        en.Dead = true;
                        enemies[e] = en;
                    }

                    p.Pierce--;
                    if (p.Pierce < 0 || p.Style == GunFireStyle.Mortar)
                    {
                        dead = true;
                    }
                    break;
                }
            }

            if (dead) projectiles.RemoveAt(i);
            else projectiles[i] = p;
        }
    }

    static int NearestEnemyIndex(Vector2 from)
    {
        int best = -1;
        float bestDist = float.MaxValue;
        for (int i = 0; i < enemies.Count; i++)
        {
            Enemy e = enemies[i];
            if (e.Dead || e.Spawn < 0.5f) continue;
            float d = Vector2.DistanceSquared(from, e.Position);
            if (d < bestDist)
            {
                bestDist = d;
                best = i;
            }
        }
        return best;
    }

