                eventCountdown = 5.8f;
                break;
            case FloorEventType.CrownEdict:
                eventSide = Rng.Next(4);
                ConfigureSafeZoneRush();
                eventCountdown = 2.7f;
                break;
            case FloorEventType.CrownRot:
                floorRotSide = Rng.Next(2);
                floorRotTimer = 9.2f;
                eventCountdown = 9.2f;
                break;
            case FloorEventType.CrownBolt:
                markedStrikeCount = MarkRandomTilesList(14);
                eventCountdown = MarkedStrikeTelegraphTime;
                eventStep = 0;
                break;
            case FloorEventType.CrownRing:
                MarkRing(2);
                eventCountdown = 5.3f;
                break;
            case FloorEventType.CrownIsles:
                MarkSafeIslands(SafeIslandCount);
                eventEpicenter = playerPos;
                eventCountdown = 5.7f;
                break;
            case FloorEventType.CrownStorm:
                BlightRandomTiles(0.47f);
                eventCountdown = 5.3f;
                eventBlightBoltTimer = 0.32f;
                break;
            case FloorEventType.CrownCoronation:
                MarkOutsideCenter(2);
                eventCountdown = 5.5f;
                break;
            case FloorEventType.CrownUsurpation:
                MarkCrownCross();
                eventCountdown = 4.8f;
                break;
            case FloorEventType.CrownReckoning:
                MarkCrownDiagonalBands();
                eventCountdown = 5f;
                break;
            case FloorEventType.None:
                break;
            default:
                throw new UnreachableException();
        }

        eventStartCountdown = eventCountdown;
    }

    static void ClearEventMarks()
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                tiles[x, y].EventMarked = false;
            }
        }
    }

    static void MarkRandomTiles(float ratio)
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                ref Tile t = ref tiles[x, y];
                if (t.State != 2 && Rng.NextSingle() < ratio)
                {
                    t.EventMarked = true;
                }
            }
        }
    }

    static int MarkRandomTilesList(int count)
    {
        var coords = new List<(int x, int y)>();
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State != 2) coords.Add((x, y));
            }
        }
        for (int i = coords.Count - 1; i > 0; i--)
        {
            int j = Rng.Next(i + 1);
            (coords[i], coords[j]) = (coords[j], coords[i]);
        }

        int n = Math.Min(count, coords.Count);
        for (int i = 0; i < n; i++)
        {
            tiles[coords[i].x, coords[i].y].EventMarked = true;
            markedStrikeOrder[i] = coords[i].x + coords[i].y * GridSize;
        }
        return n;
    }

    static void MarkCheckerboard()
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State != 2 && ((x + y) / 2) % 2 == 0)
                {
                    tiles[x, y].EventMarked = true;
                }
            }
        }
    }

    static void MarkRing(int thickness)
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                bool edge = x < thickness || y < thickness || x >= GridSize - thickness || y >= GridSize - thickness;
                if (edge && tiles[x, y].State != 2) tiles[x, y].EventMarked = true;
            }
        }
    }

    static void MarkSafeIslands(int islandCount)
    {
        int size = SafeIslandSize;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                tiles[x, y].EventMarked = true;
            }
        }

        int placed = 0;
        int attempts = 0;
        int maxAttempts = islandCount * 120;
        while (placed < islandCount && attempts < maxAttempts)
        {
            attempts++;
            int x = Rng.Next(0, GridSize - size + 1);
            int y = Rng.Next(0, GridSize - size + 1);
            if (!CanPlaceSafeIsland(x, y, size)) continue;

            for (int dy = 0; dy < size; dy++)
            {
                for (int dx = 0; dx < size; dx++)
                {
                    tiles[x + dx, y + dy].EventMarked = false;
                }
            }

            placed++;
        }
    }

    static bool CanPlaceSafeIsland(int x, int y, int size)
    {
        for (int dy = 0; dy < size; dy++)
        {
            for (int dx = 0; dx < size; dx++)
            {
                ref Tile tile = ref tiles[x + dx, y + dy];
                if (tile.State == 2 || !tile.EventMarked) return false;
            }
        }

        return true;
    }

    static bool PlayerOnSafeIsland()
    {
        if (!TryGetTileUnder(playerPos, out int tx, out int ty)) return false;
        return !tiles[tx, ty].EventMarked && tiles[tx, ty].State != 2;
    }

    static void BlightRandomTiles(float ratio)
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                ref Tile t = ref tiles[x, y];
                if (t.State == 2) continue;
                if (Rng.NextSingle() < ratio)
                {
                    t.State = 1;
                    t.Durability = Math.Min(t.Durability, MaxDurability * 0.38f);
                    t.EventMarked = true;
                }
            }
        }
    }

    static bool IsTideStaggeredCollapse(FloorEventType ev) => ev is
        FloorEventType.TideSurge or FloorEventType.TideRift or FloorEventType.TideRecede
        or FloorEventType.TideColumn or FloorEventType.TideEcho or FloorEventType.TideUndertow
        or FloorEventType.TideCrest or FloorEventType.TideWall or FloorEventType.TideAnchor;

    static void UpdateTideTelegraphCollapse(float dt, FloorEventType ev)
    {
        if (eventPhase == 0)
        {
            eventCountdown -= dt;
            if (eventCountdown <= 0f) BeginEventCollapsePhase(ev);
        }
        else
        {
            ProcessStaggeredCollapse(dt, ev, EventCollapseInterval(ev));
        }
    }

    static void MarkTideRift()
    {
        int cx = GridSize / 2;
        int cy = GridSize / 2;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                tiles[x, y].EventMarked = Math.Abs(x - cx) <= 1 || Math.Abs(y - cy) <= 1;
            }
        }
    }

    static void MarkTideColumns(int columnCount)
    {
        var cols = new HashSet<int>();
        while (cols.Count < columnCount)
        {
            cols.Add(Rng.Next(0, GridSize));
        }

        foreach (int col in cols)
        {
            for (int y = 0; y < GridSize; y++)
            {
                if (tiles[col, y].State != 2) tiles[col, y].EventMarked = true;
            }
        }
    }

    static void MarkTideEcho()
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                if ((x - y + GridSize * 3) % 4 == 0) tiles[x, y].EventMarked = true;
            }
        }
    }

    static void MarkTideWallHalf(int side)
    {
        int half = GridSize / 2;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                bool marked = side switch
                {
                    0 => x < half,
                    1 => x >= half,
                    2 => y < half,
                    _ => y >= half,
                };
                tiles[x, y].EventMarked = marked;
            }
        }
    }

    static int MarkTideStrikeChannel()
    {
        eventTideRowStrike = Rng.Next(2) == 0;
        int line = Rng.Next(GridSize);
        eventSide = line;
        var coords = new List<(int x, int y, float sort)>();
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                bool onLine = eventTideRowStrike ? y == line : x == line;
                if (!onLine) continue;
                tiles[x, y].EventMarked = true;
                coords.Add((x, y, eventTideRowStrike ? x : y));
            }
        }

        coords.Sort((a, b) => a.sort.CompareTo(b.sort));
        for (int i = 0; i < coords.Count; i++)
        {
            markedStrikeOrder[i] = coords[i].x + coords[i].y * GridSize;
        }

        return coords.Count;
    }

    static void SoftenTideFoamTiles(float ratio)
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                ref Tile t = ref tiles[x, y];
                if (t.State == 2) continue;
                if (Rng.NextSingle() < ratio)
                {
                    t.State = 1;
                    t.Durability = Math.Min(t.Durability, MaxDurability * 0.35f);
                    t.EventMarked = true;
                }
            }
        }
    }

    static void ConfigureTideBeacon()
    {
        float band = SafeRushBandPx();
        eventSafeRect = eventSide switch
        {
            0 => new Rectangle(0f, 0f, band, band),
            1 => new Rectangle(WindowWidth - band, 0f, band, band),
            2 => new Rectangle(0f, WindowHeight - band, band, band),
            3 => new Rectangle(WindowWidth - band, WindowHeight - band, band, band),
            _ => throw new UnreachableException(),
        };
        eventDangerRect = default;
    }

    static void ConfigureTideWhirlpool()
    {
        float m = CenterSnareMarginPx();
        eventDangerRect = new Rectangle(m, m, WindowWidth - m * 2f, WindowHeight - m * 2f);
        eventSafeRect = default;
    }

    static float CurrentTideWhirlpoolMarginPx()
    {
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 1f;
        float tiles = CenterSnareMarginTiles + (GridSize / 2.2f - CenterSnareMarginTiles) * (1f - urgency * 0.6f);
        return tiles * TileSize;
    }

    static void RefreshTideWhirlpoolRect()
    {
        float m = CurrentTideWhirlpoolMarginPx();
        eventDangerRect = new Rectangle(m, m, WindowWidth - m * 2f, WindowHeight - m * 2f);
    }

    static bool PlayerInTideWhirlpoolDanger()
        => Raylib.CheckCollisionCircleRec(playerPos, PlayerRadius, eventDangerRect);

    static string TideBeaconHint() => eventSide switch
    {
        0 => "SAFE: NORTHWEST CORNER",
        1 => "SAFE: NORTHEAST CORNER",
        2 => "SAFE: SOUTHWEST CORNER",
        3 => "SAFE: SOUTHEAST CORNER",
        _ => "",
    };

    static string TideWallHint() => eventSide switch
    {
        0 => "FLEE EAST — WALL FROM WEST",
        1 => "FLEE WEST — WALL FROM EAST",
        2 => "FLEE SOUTH — WALL FROM NORTH",
        3 => "FLEE NORTH — WALL FROM SOUTH",
        _ => "",
    };

    static Vector2 DirectionAwayFromArenaCenter()
    {
        Vector2 center = new Vector2(WindowWidth / 2f, WindowHeight / 2f);
        return SafeNormalize(playerPos - center);
    }

    static void SpawnTideBeaconTrail()
    {
        if (playerInEventSafeZone) return;
        Vector2 target = new Vector2(
            eventSafeRect.X + eventSafeRect.Width * 0.5f,
            eventSafeRect.Y + eventSafeRect.Height * 0.5f);
        Vector2 dir = SafeNormalize(target - playerPos);
        particles.Add(new Particle
        {
            Position = playerPos + dir * (PlayerRadius + 4f),
            Velocity = dir * 150f,
            Color = EventAccentColor(FloorEventType.TideBeacon),
            Alpha = 0.65f,
            Fade = 1f / 0.3f,
            Size = 3f,
            Drag = 3f,
            Glow = true,
        });
    }

    static bool IsEmberStaggeredCollapse(FloorEventType ev) => ev is
        FloorEventType.EmberRain or FloorEventType.EmberPulse or FloorEventType.EmberCross
        or FloorEventType.EmberBridge or FloorEventType.EmberHive or FloorEventType.EmberFury
        or FloorEventType.EmberSnake or FloorEventType.EmberQuake or FloorEventType.EmberBloom;

    static int EmberEpicenterTx() => Math.Clamp((int)(eventEpicenter.X / TileSize), 0, GridSize - 1);
    static int EmberEpicenterTy() => Math.Clamp((int)(eventEpicenter.Y / TileSize), 0, GridSize - 1);

    static void MarkAllThenUnmark(Func<int, int, bool> keepSafe)
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                tiles[x, y].EventMarked = !keepSafe(x, y);
            }
        }
    }

    static void ConfigureEmberGate()
    {
        eventSide = Rng.Next(2);
        int lane = Rng.Next(3, GridSize - 3);
        if (eventSide == 0)
        {
            MarkAllThenUnmark((x, _) => x >= lane && x < lane + EmberGateCorridorTiles);
            eventSafeRect = new Rectangle(lane * TileSize, 0f, EmberGateCorridorTiles * TileSize, WindowHeight);
        }
        else
        {
            MarkAllThenUnmark((_, y) => y >= lane && y < lane + EmberGateCorridorTiles);
            eventSafeRect = new Rectangle(0f, lane * TileSize, WindowWidth, EmberGateCorridorTiles * TileSize);
        }
    }

    static void MarkEmberCross()
    {
        int mid = GridSize / 2;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                bool arm = Math.Abs(x - mid) <= 1 || Math.Abs(y - mid) <= 1;
                tiles[x, y].EventMarked = arm;
            }
        }
    }

    static void MarkEmberBridges()
    {
        int bridgeA = 5;
        int bridgeB = GridSize - 7;
        MarkAllThenUnmark((_, y) => (y >= bridgeA && y < bridgeA + 2) || (y >= bridgeB && y < bridgeB + 2));
    }

    static void MarkEmberHive()
    {
        int cx = GridSize / 2;
        int cy = GridSize / 2;
        eventEpicenter = TileCenter(cx, cy);
        MarkAllThenUnmark((x, y) => Math.Abs(x - cx) <= EmberHiveRadius && Math.Abs(y - cy) <= EmberHiveRadius);
    }

    static void MarkEmberAltar()
    {
        int ax = EmberEpicenterTx();
        int ay = EmberEpicenterTy();
        MarkAllThenUnmark((x, y) => x == ax && y == ay);
        eventSafeRect = new Rectangle(ax * TileSize, ay * TileSize, TileSize, TileSize);
    }

    static void InitEmberSnakePath()
    {
        int x = Rng.Next(0, GridSize);
        int y = Rng.Next(0, GridSize);
        markedStrikeCount = Math.Min(EmberSnakeLength, GridSize * GridSize);
        for (int i = 0; i < markedStrikeCount; i++)
        {
            markedStrikeOrder[i] = x + y * GridSize;
            int dir = Rng.Next(4);
            int nx = x + (dir == 0 ? -1 : dir == 1 ? 1 : 0);
            int ny = y + (dir == 2 ? -1 : dir == 3 ? 1 : 0);
            if (nx < 0 || nx >= GridSize || ny < 0 || ny >= GridSize)
            {
                dir = Rng.Next(4);
                nx = x + (dir == 0 ? -1 : dir == 1 ? 1 : 0);
                ny = y + (dir == 2 ? -1 : dir == 3 ? 1 : 0);
                nx = Math.Clamp(nx, 0, GridSize - 1);
                ny = Math.Clamp(ny, 0, GridSize - 1);
            }
            x = nx;
            y = ny;
        }
        eventStep = 0;
    }

    static void InitEmberBloomSeeds()
    {
        markedStrikeCount = EmberBloomSeedCount;
        var used = new HashSet<int>();
        for (int i = 0; i < markedStrikeCount; i++)
        {
            int idx;
            do idx = Rng.Next(0, GridSize * GridSize);
            while (!used.Add(idx));
            markedStrikeOrder[i] = idx;
        }
        eventStep = 0;
    }

    static void EmberRainAdvanceColumn(Color accent)
    {
        if (eventStep >= GridSize) return;
        int col = eventSide == 0 ? eventStep : GridSize - 1 - eventStep;
        for (int y = 0; y < GridSize; y++)
        {
            if (tiles[col, y].State != 2) tiles[col, y].EventMarked = true;
        }
        Vector2 beamPos = TileCenter(col, GridSize / 2);
        SpawnEventSkyBeam(beamPos, accent, 18f, 0.22f);
        SpawnEventShockwave(beamPos, accent, 48f, 0.35f);
        eventStep++;
    }

    static void EmberPulseExpandRing(Color accent)
    {
        int cx = EmberEpicenterTx();
        int cy = EmberEpicenterTy();
        int ring = eventStep;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;
                int dist = Math.Max(Math.Abs(x - cx), Math.Abs(y - cy));
                if (dist == ring) tiles[x, y].EventMarked = true;
            }
        }
        float ringPx = (ring + 0.5f) * TileSize;
        SpawnEventShockwave(eventEpicenter, accent, ringPx, 0.4f);
        eventStep++;
    }

    static void EmberSnakeAdvance(Color accent)
    {
        if (eventStep >= markedStrikeCount) return;
        int idx = markedStrikeOrder[eventStep];
        int sx = idx % GridSize;
        int sy = idx / GridSize;
        if (tiles[sx, sy].State != 2) tiles[sx, sy].EventMarked = true;
        Vector2 head = TileCenter(sx, sy);
        SpawnGfxLightPulse(head, accent, 36f, 0.8f, 0.14f);
        eventStep++;
    }

    static void EmberBloomExpand(Color accent)
    {
        int radius = eventStep;
        for (int s = 0; s < markedStrikeCount; s++)
        {
            int idx = markedStrikeOrder[s];
            int sx = idx % GridSize;
            int sy = idx / GridSize;
            for (int y = 0; y < GridSize; y++)
            {
                for (int x = 0; x < GridSize; x++)
                {
                    if (tiles[x, y].State == 2) continue;
                    int dist = Math.Max(Math.Abs(x - sx), Math.Abs(y - sy));
                    if (dist <= radius) tiles[x, y].EventMarked = true;
                }
            }
        }
        SpawnEventShockwave(eventEpicenter, accent, (radius + 1) * TileSize * 0.45f, 0.32f);
        eventStep++;
    }

    static void EmberQuakeStrike(Color accent)
    {
        var marked = new List<(int x, int y)>();
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].EventMarked && tiles[x, y].State != 2) marked.Add((x, y));
            }
        }
        if (marked.Count == 0) return;
        (int qx, int qy) = marked[Rng.Next(marked.Count)];
        tiles[qx, qy].EventMarked = false;
        CollapseTileWithEventFx(qx, qy, accent);
        Vector2 pos = TileCenter(qx, qy);
        SpawnEventShockwave(pos, accent, 44f, 0.28f);
        AddTrauma(0.06f);
    }

    static void UpdateEmberFury(float dt, Color accent)
    {
        if (!TryGetTileUnder(playerPos, out int tx, out int ty)) return;
        int idx = tx + ty * GridSize;
        if (idx != emberFuryTileIdx)
        {
            emberFuryTileIdx = idx;
            emberFuryStandTimer = 0f;
            return;
        }

        emberFuryStandTimer += dt;
        if (emberFuryStandTimer < EmberFuryStandTime) return;
        if (tiles[tx, ty].State == 2 || tiles[tx, ty].EventMarked) return;

        tiles[tx, ty].EventMarked = true;
        emberFuryStandTimer = 0f;
        SpawnGfxLightPulse(TileCenter(tx, ty), accent, 52f, 1f, 0.16f);
        SpawnFloatingText(TileCenter(tx, ty), "IGNITE!", accent, 14);
        AddFlash(accent, 0.1f);
    }

    static void RefreshEmberTideRects()
    {
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 1f;
        float tidePx = urgency * (WindowHeight - 60f);
        if (eventSide == 2)
        {
            eventDangerRect = new Rectangle(0f, WindowHeight - tidePx, WindowWidth, tidePx);
            eventSafeRect = new Rectangle(0f, 0f, WindowWidth, Math.Max(40f, WindowHeight - tidePx));
        }
        else
        {
            eventDangerRect = new Rectangle(0f, 0f, WindowWidth, tidePx);
            eventSafeRect = new Rectangle(0f, tidePx, WindowWidth, Math.Max(40f, WindowHeight - tidePx));
        }
    }

    static void RefreshEmberCageRect()
    {
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 1f;
        float marginTiles = 2.5f + urgency * 5.5f;
        float m = marginTiles * TileSize;
        eventSafeRect = new Rectangle(m, m, WindowWidth - m * 2f, WindowHeight - m * 2f);
    }

    static bool PlayerInEmberAltar()
    {
        if (!TryGetTileUnder(playerPos, out int tx, out int ty)) return false;
        return tx == EmberEpicenterTx() && ty == EmberEpicenterTy() && !tiles[tx, ty].EventMarked;
    }

    static void UpdateEmberTelegraphCollapse(float dt, FloorEventType ev)
    {
        if (eventPhase == 0)
        {
            eventCountdown -= dt;
            if (eventCountdown <= 0f) BeginEventCollapsePhase(ev);
        }
        else
        {
            ProcessStaggeredCollapse(dt, ev, EventCollapseInterval(ev));
        }
    }

    static void CollapseMarkedTiles()
    {
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                ref Tile t = ref tiles[x, y];
                if (t.EventMarked && t.State != 2)
                {
                    CollapseTile(ref t);
                }
            }
        }
        AddTrauma(0.4f);
        AddFlash(Danger, 0.18f);
    }

    static void UpdateActiveFloorEvent(float dt)
    {
        if (BannerFreezesEvents()) dt = 0f;
        UpdateEventVfx(dt);
        Color accent = EventAccentColor(activeEvent);
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 1f;

        if (urgency > 0.35f && Rng.NextSingle() < dt * (2f + urgency * 6f))
        {
            AddTrauma(dt * 0.08f * urgency);
        }

        switch (activeEvent)
        {
            case FloorEventType.CrimsonCrumble:
            case FloorEventType.Checkerfall:
            case FloorEventType.RingCollapse:
            case FloorEventType.StoneIslands:
            case FloorEventType.ScatterPits:
                if (eventPhase == 0)
                {
                    eventCountdown -= dt;
                    if (eventCountdown <= 0f)
                    {
                        BeginEventCollapsePhase(activeEvent);
                    }
                }
                else
                {
                    ProcessStaggeredCollapse(dt, activeEvent, EventCollapseInterval(activeEvent));
                }
                break;

            case FloorEventType.SafeZoneRush:
                RefreshSafeZoneRushRect();
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (!playerInEventSafeZone && Rng.NextSingle() < dt * 14f)
                {
                    SpawnSafeZoneRushTrail();
                }

                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect))
                    {
                        TriggerGameOver(DeathCause.SafeZoneFailed);
                        return;
                    }

                    SpawnEventShockwave(playerPos, UiAccent, 180f);
                    SpawnFloatingText(playerPos, "SANCTIFIED!", UiAccent, 22);
                    TriggerImpact(ImpactTier.Medium, UiAccent);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.MossRot:
                eventCountdown -= dt;
                if (Rng.NextSingle() < dt * 18f)
                {
                    float half = WindowWidth / 2f;
                    float rx = floorRotSide < 0.5f ? Rng.NextSingle() * half : half + Rng.NextSingle() * half;
                    float ry = Rng.NextSingle() * WindowHeight;
                    SpawnBlightSpores(new Vector2(rx, ry));
                }

                if (eventCountdown <= 0f)
                {
                    EndFloorEvent();
                }
                break;

            case FloorEventType.MarkedStrike:
                if (eventStep < markedStrikeCount)
                {
                    int idx = markedStrikeOrder[eventStep];
                    int mx = idx % GridSize;
                    int my = idx / GridSize;
                    Vector2 target = TileCenter(mx, my);

                    if (eventPhase == 0)
                    {
                        eventCountdown -= dt;
                        if (eventSkyBeams.Count == 0 || eventSkyBeams[^1].Life < 0.05f)
                        {
                            SpawnEventSkyBeam(target, accent, 12f, MarkedStrikeTelegraphTime * 0.95f, charging: true);
                        }

                        if (eventCountdown <= 0f)
                        {
                            eventPhase = 1;
                            eventCountdown = MarkedStrikeFireTime;
                            eventSkyBeams.Clear();
                            SpawnEventSkyBeam(target, accent, 38f, 0.16f, charging: false);
                            AddFlash(Lighten(accent, 0.35f), 0.18f);
                            SpawnGfxLightPulse(target, Color.White, 140f, 1.1f, 0.12f);
                            TriggerImpact(ImpactTier.Light, accent);
                        }
                    }
                    else
                    {
                        eventCountdown -= dt;
                        if (eventCountdown <= 0f)
                        {
                            if (tiles[mx, my].State != 2)
                            {
                                CollapseTileWithEventFx(mx, my, accent);
                                SpawnEventShockwave(target, accent, 52f, 0.22f);
                            }

                            eventStep++;
                            eventPhase = 0;
                            eventCountdown = MarkedStrikeStrikeGap;
                        }
                    }
                }
                else
                {
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CenterSnare:
                RefreshCenterSnareRects();
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInCenterSnareSafe();

                if (eventCountdown <= 0f)
                {
                    if (!PlayerInCenterSnareSafe())
                    {
                        TriggerGameOver(DeathCause.CenterSnare);
                        return;
                    }

                    SpawnEventShockwave(playerPos, UiAccent, 160f);
                    SpawnFloatingText(playerPos, "WALL RUNNER!", UiAccent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.BlightStorm:
                eventCountdown -= dt;
                eventBlightBoltTimer -= dt;

                for (int y = 0; y < GridSize; y++)
                {
                    for (int x = 0; x < GridSize; x++)
                    {
                        ref Tile t = ref tiles[x, y];
                        if (!t.EventMarked || t.State == 2) continue;
                        ApplyTileDamage(ref t, 14f + urgency * 10f, dt, out _, markTouched: false);
                    }
                }

                if (eventBlightBoltTimer <= 0f)
                {
                    eventBlightBoltTimer = 0.28f + Rng.NextSingle() * 0.22f;
                    int bx = Rng.Next(0, GridSize);
                    int by = Rng.Next(0, GridSize);
                    if (tiles[bx, by].EventMarked && tiles[bx, by].State != 2)
                    {
                        Vector2 boltPos = TileCenter(bx, by);
                        SpawnEventSkyBeam(boltPos, accent, 22f, 0.18f);
                        ApplyTileDamage(ref tiles[bx, by], 28f, 0.16f, out _, markTouched: false);
                        SpawnGfxLightPulse(boltPos, Lighten(accent, 0.4f), 80f, 0.9f, 0.15f);
                        AddFlash(accent, 0.08f);
                    }
                }

                if (eventCountdown <= 0f)
                {
                    if (eventPhase == 0)
                    {
                        BeginEventCollapsePhase(FloorEventType.BlightStorm);
                    }
                    else
                    {
                        ProcessStaggeredCollapse(dt, FloorEventType.BlightStorm, EventCollapseInterval(FloorEventType.BlightStorm));
                    }
                }
                break;

            case FloorEventType.TideSurge:
            case FloorEventType.TideRift:
            case FloorEventType.TideRecede:
            case FloorEventType.TideColumn:
            case FloorEventType.TideEcho:
            case FloorEventType.TideUndertow:
            case FloorEventType.TideCrest:
            case FloorEventType.TideWall:
            case FloorEventType.TideAnchor:
                UpdateTideTelegraphCollapse(dt, activeEvent);
                break;

            case FloorEventType.TideFoam:
                eventCountdown -= dt;
                eventBlightBoltTimer -= dt;

                for (int y = 0; y < GridSize; y++)
                {
                    for (int x = 0; x < GridSize; x++)
                    {
                        ref Tile t = ref tiles[x, y];
                        if (!t.EventMarked || t.State == 2) continue;
                        ApplyTileDamage(ref t, 12f + urgency * 9f, dt, out _, markTouched: false);
                    }
                }

                if (eventBlightBoltTimer <= 0f)
                {
                    eventBlightBoltTimer = 0.32f + Rng.NextSingle() * 0.2f;
                    int bx = Rng.Next(0, GridSize);
                    int by = Rng.Next(0, GridSize);
                    if (tiles[bx, by].EventMarked && tiles[bx, by].State != 2)
                    {
                        Vector2 boltPos = TileCenter(bx, by);
                        SpawnEventSkyBeam(boltPos, accent, 18f, 0.2f, charging: true);
                        ApplyTileDamage(ref tiles[bx, by], 22f, 0.14f, out _, markTouched: false);
                        SpawnGfxLightPulse(boltPos, Lighten(accent, 0.35f), 70f, 0.85f, 0.14f);
                    }
                }

                if (eventCountdown <= 0f)
                {
                    if (eventPhase == 0)
                    {
                        BeginEventCollapsePhase(FloorEventType.TideFoam);
                    }
                    else
                    {
                        ProcessStaggeredCollapse(dt, FloorEventType.TideFoam, EventCollapseInterval(FloorEventType.TideFoam));
                    }
                }
                break;

            case FloorEventType.TideWhirlpool:
                RefreshTideWhirlpoolRect();
                eventCountdown -= dt;
                playerInEventSafeZone = !PlayerInTideWhirlpoolDanger();
                if (eventCountdown <= 0f)
                {
                    if (PlayerInTideWhirlpoolDanger())
                    {
                        TriggerGameOver(DeathCause.TideDrowned);
                        return;
                    }

                    SpawnEventShockwave(playerPos, accent, 150f);
                    SpawnFloatingText(playerPos, "VORTEX ESCAPED!", accent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.TideBeacon:
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (!playerInEventSafeZone && Rng.NextSingle() < dt * 14f)
                {
                    SpawnTideBeaconTrail();
                }

                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect))
                    {
                        TriggerGameOver(DeathCause.TideBeaconLost);
                        return;
                    }

                    SpawnEventShockwave(playerPos, accent, 160f);
                    SpawnFloatingText(playerPos, "BEACON REACHED!", accent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.TideStrike:
                if (eventStep < markedStrikeCount)
                {
                    int tidx = markedStrikeOrder[eventStep];
                    int tmx = tidx % GridSize;
                    int tmy = tidx / GridSize;
                    Vector2 ttarget = TileCenter(tmx, tmy);

                    if (eventPhase == 0)
                    {
                        eventCountdown -= dt;
                        if (eventSkyBeams.Count == 0 || eventSkyBeams[^1].Life < 0.05f)
                        {
                            SpawnEventSkyBeam(ttarget, accent, 12f, MarkedStrikeTelegraphTime * 0.95f, charging: true);
                        }

                        if (eventCountdown <= 0f)
                        {
                            eventPhase = 1;
                            eventCountdown = MarkedStrikeFireTime;
                            eventSkyBeams.Clear();
                            SpawnEventSkyBeam(ttarget, accent, 34f, 0.16f, charging: false);
                            AddFlash(Lighten(accent, 0.35f), 0.16f);
                            SpawnGfxLightPulse(ttarget, Color.White, 120f, 1f, 0.12f);
                            TriggerImpact(ImpactTier.Light, accent);
                        }
                    }
                    else
                    {
                        eventCountdown -= dt;
                        if (eventCountdown <= 0f)
                        {
                            if (tiles[tmx, tmy].State != 2)
                            {
                                CollapseTileWithEventFx(tmx, tmy, accent);
                                SpawnEventShockwave(ttarget, accent, 48f, 0.22f);
                            }

                            eventStep++;
                            eventPhase = 0;
                            eventCountdown = MarkedStrikeStrikeGap;
                        }
                    }
                }
                else
                {
                    EndFloorEvent();
                }
                break;

            case FloorEventType.EmberRain:
                eventActionTimer -= dt;
                while (eventActionTimer <= 0f && eventStep < GridSize)
                {
                    EmberRainAdvanceColumn(accent);
                    eventActionTimer += EmberRainColumnInterval;
                }
                UpdateEmberTelegraphCollapse(dt, FloorEventType.EmberRain);
                break;

            case FloorEventType.EmberGate:
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect))
                    {
                        TriggerGameOver(DeathCause.SafeZoneFailed);
                        return;
                    }
                    SpawnEventShockwave(playerPos, accent, 160f);
                    SpawnFloatingText(playerPos, "THROUGH!", accent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.EmberPulse:
                eventActionTimer -= dt;
                while (eventActionTimer <= 0f && eventStep < GridSize / 2 + 2)
                {
                    EmberPulseExpandRing(accent);
                    eventActionTimer += EmberPulseInterval;
                }
                UpdateEmberTelegraphCollapse(dt, FloorEventType.EmberPulse);
                break;

            case FloorEventType.EmberCross:
            case FloorEventType.EmberBridge:
            case FloorEventType.EmberHive:
                UpdateEmberTelegraphCollapse(dt, activeEvent);
                break;

            case FloorEventType.EmberFury:
                UpdateEmberFury(dt, accent);
                UpdateEmberTelegraphCollapse(dt, FloorEventType.EmberFury);
                break;

            case FloorEventType.EmberSnake:
                eventActionTimer -= dt;
                while (eventActionTimer <= 0f && eventStep < markedStrikeCount)
                {
                    EmberSnakeAdvance(accent);
                    eventActionTimer += EmberSnakeStepInterval;
                }
                UpdateEmberTelegraphCollapse(dt, FloorEventType.EmberSnake);
                break;

            case FloorEventType.EmberTide:
                RefreshEmberTideRects();
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect) || Raylib.CheckCollisionCircleRec(playerPos, PlayerRadius, eventDangerRect))
                    {
                        TriggerGameOver(DeathCause.SafeZoneFailed);
                        return;
                    }
                    SpawnFloatingText(playerPos, "ABOVE THE TIDE!", accent, 20);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.EmberCage:
                RefreshEmberCageRect();
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect))
                    {
                        TriggerGameOver(DeathCause.CenterSnare);
                        return;
                    }
                    SpawnFloatingText(playerPos, "CAGE HELD!", accent, 20);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.EmberQuake:
                eventActionTimer -= dt;
                while (eventActionTimer <= 0f && eventCountdown > 0.15f)
                {
                    EmberQuakeStrike(accent);
                    eventActionTimer += EmberQuakeInterval;
                }
                UpdateEmberTelegraphCollapse(dt, FloorEventType.EmberQuake);
                break;

            case FloorEventType.EmberBloom:
                eventActionTimer -= dt;
                while (eventActionTimer <= 0f && eventStep < 6)
                {
                    EmberBloomExpand(accent);
                    eventActionTimer += EmberBloomInterval;
                }
                UpdateEmberTelegraphCollapse(dt, FloorEventType.EmberBloom);
                break;

            case FloorEventType.EmberAltar:
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInEmberAltar();
                if (eventCountdown <= 0f)
                {
                    if (!PlayerInEmberAltar())
                    {
                        TriggerGameOver(DeathCause.SafeZoneFailed);
                        return;
                    }
                    SpawnEventShockwave(playerPos, accent, 140f);
                    SpawnFloatingText(playerPos, "ALTAR CLAIMED!", accent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CryptSeal:
            case FloorEventType.CryptWail:
            case FloorEventType.CryptTorch:
            case FloorEventType.CryptChains:
            case FloorEventType.CryptGlimpse:
            case FloorEventType.CryptRattle:
            case FloorEventType.CryptEcho:
            case FloorEventType.CryptShroud:
            case FloorEventType.CryptLantern:
            case FloorEventType.CryptTomb:
                if (activeEvent == FloorEventType.CryptWail && eventPhase == 0 && Rng.NextSingle() < dt * 5f)
                {
                    float wavePos = eventSide switch
                    {
                        0 => eventCountdown / eventStartCountdown * WindowWidth,
                        1 => WindowWidth - eventCountdown / eventStartCountdown * WindowWidth,
                        2 => eventCountdown / eventStartCountdown * WindowHeight,
                        _ => WindowHeight - eventCountdown / eventStartCountdown * WindowHeight,
                    };
                    Vector2 wailCenter = eventSide < 2
                        ? new Vector2(wavePos, WindowHeight / 2f)
                        : new Vector2(WindowWidth / 2f, wavePos);
                    SpawnEventShockwave(wailCenter, accent, 64f, 0.28f);
                }

                if (eventPhase == 0)
                {
                    eventCountdown -= dt;
                    if (eventCountdown <= 0f)
                    {
                        BeginEventCollapsePhase(activeEvent);
                    }
                }
                else
                {
                    ProcessStaggeredCollapse(dt, activeEvent, EventCollapseInterval(activeEvent));
                }
                break;

            case FloorEventType.CryptMist:
                eventCountdown -= dt;
                eventBlightBoltTimer -= dt;
                if (Rng.NextSingle() < dt * 14f)
                {
                    float half = WindowWidth / 2f;
                    float rx = floorRotSide < 0.5f ? Rng.NextSingle() * half : half + Rng.NextSingle() * half;
                    float ry = Rng.NextSingle() * WindowHeight;
                    SpawnBlightSpores(new Vector2(rx, ry));
                }

                for (int y = 0; y < GridSize; y++)
                {
                    for (int x = 0; x < GridSize; x++)
                    {
                        ref Tile t = ref tiles[x, y];
                        if (!t.EventMarked || t.State == 2) continue;
                        ApplyTileDamage(ref t, 12f + urgency * 9f, dt, out _, markTouched: false);
                    }
                }

                if (eventBlightBoltTimer <= 0f)
                {
                    eventBlightBoltTimer = 0.32f + Rng.NextSingle() * 0.2f;
                    int bx = Rng.Next(0, GridSize);
                    int by = Rng.Next(0, GridSize);
                    if (tiles[bx, by].EventMarked && tiles[bx, by].State != 2)
                    {
                        Vector2 boltPos = TileCenter(bx, by);
                        SpawnEventSkyBeam(boltPos, accent, 18f, 0.2f, charging: true);
                        ApplyTileDamage(ref tiles[bx, by], 24f, 0.14f, out _, markTouched: false);
                        SpawnGfxLightPulse(boltPos, Lighten(accent, 0.35f), 70f, 0.85f, 0.14f);
                    }
                }

                if (eventCountdown <= 0f)
                {
                    if (eventPhase == 0)
                    {
                        BeginEventCollapsePhase(FloorEventType.CryptMist);
                    }
                    else
                    {
                        ProcessStaggeredCollapse(dt, FloorEventType.CryptMist, EventCollapseInterval(FloorEventType.CryptMist));
                    }
                }
                break;

            case FloorEventType.CryptGrave:
                if (eventStep < markedStrikeCount)
                {
                    int idx = markedStrikeOrder[eventStep];
                    int mx = idx % GridSize;
                    int my = idx / GridSize;
                    Vector2 target = TileCenter(mx, my);

                    if (eventPhase == 0)
                    {
                        eventCountdown -= dt;
                        if (eventSkyBeams.Count == 0 || eventSkyBeams[^1].Life < 0.05f)
                        {
                            SpawnEventSkyBeam(target, accent, 10f, CryptGraveTelegraphTime * 0.95f, charging: true);
                        }

                        if (eventCountdown <= 0f)
                        {
                            eventPhase = 1;
                            eventCountdown = CryptGraveFireTime;
                            eventSkyBeams.Clear();
                            SpawnEventSkyBeam(target, accent, 32f, 0.14f, charging: false);
                            AddFlash(Lighten(accent, 0.3f), 0.16f);
                            SpawnGfxLightPulse(target, new Color(220, 210, 240, 255), 120f, 1f, 0.1f);
                            TriggerImpact(ImpactTier.Light, accent);
                        }
                    }
                    else
                    {
                        eventCountdown -= dt;
                        if (eventCountdown <= 0f)
                        {
                            if (tiles[mx, my].State != 2)
                            {
                                CollapseTileWithEventFx(mx, my, accent);
                                SpawnEventShockwave(target, accent, 44f, 0.2f);
                            }

                            eventStep++;
                            eventPhase = 0;
                            eventCountdown = CryptGraveStrikeGap;
                        }
                    }
                }
                else
                {
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CryptVeil:
                eventActionTimer -= dt;
                if (eventActionTimer <= 0f)
                {
                    eventActionTimer = CryptVeilRotateInterval;
                    eventSide = (eventSide + 1) % 4;
                    ConfigureCryptVeil();
                    AddFlash(accent, 0.08f);
                    Vector2 veilCenter = new Vector2(
                        eventSafeRect.X + eventSafeRect.Width * 0.5f,
                        eventSafeRect.Y + eventSafeRect.Height * 0.5f);
                    SpawnEventShockwave(veilCenter, accent, 88f, 0.32f);
                }

                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect))
                    {
                        TriggerGameOver(DeathCause.SafeZoneFailed);
                        return;
                    }

                    SpawnEventShockwave(playerPos, accent, 150f);
                    SpawnFloatingText(playerPos, "VEILED!", accent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CrownTrial:
            case FloorEventType.CrownFall:
            case FloorEventType.CrownShard:
            case FloorEventType.CrownRing:
            case FloorEventType.CrownIsles:
            case FloorEventType.CrownCoronation:
            case FloorEventType.CrownUsurpation:
            case FloorEventType.CrownReckoning:
                UpdateEmberTelegraphCollapse(dt, activeEvent);
                break;

            case FloorEventType.CrownThrone:
                if (eventPhase == 0)
                {
                    eventCountdown -= dt;
                    playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                    if (eventCountdown <= 0f)
                    {
                        if (!PlayerInSafeRect(eventSafeRect))
                        {
                            TriggerGameOver(DeathCause.SafeZoneFailed);
                            return;
                        }

                        SpawnEventShockwave(playerPos, accent, 170f);
                        SpawnFloatingText(playerPos, "CROWNED!", accent, 22);
                        BeginEventCollapsePhase(FloorEventType.CrownThrone);
                    }
                }
                else
                {
                    ProcessStaggeredCollapse(dt, FloorEventType.CrownThrone, EventCollapseInterval(FloorEventType.CrownThrone));
                }
                break;

            case FloorEventType.CrownEdict:
                RefreshSafeZoneRushRect();
                eventCountdown -= dt;
                playerInEventSafeZone = PlayerInSafeRect(eventSafeRect);
                if (!playerInEventSafeZone && Rng.NextSingle() < dt * 14f)
                {
                    SpawnSafeZoneRushTrail();
                }

                if (eventCountdown <= 0f)
                {
                    if (!PlayerInSafeRect(eventSafeRect))
                    {
                        TriggerGameOver(DeathCause.SafeZoneFailed);
                        return;
                    }

                    SpawnEventShockwave(playerPos, accent, 180f);
                    SpawnFloatingText(playerPos, "ROYAL DECREE!", accent, 22);
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CrownRot:
                eventCountdown -= dt;
                if (Rng.NextSingle() < dt * 18f)
                {
                    float half = WindowWidth / 2f;
                    float rx = floorRotSide < 0.5f ? Rng.NextSingle() * half : half + Rng.NextSingle() * half;
                    float ry = Rng.NextSingle() * WindowHeight;
                    SpawnBlightSpores(new Vector2(rx, ry));
                }

                if (eventCountdown <= 0f)
                {
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CrownBolt:
                if (eventStep < markedStrikeCount)
                {
                    int cidx = markedStrikeOrder[eventStep];
                    int cmx = cidx % GridSize;
                    int cmy = cidx / GridSize;
                    Vector2 ctarget = TileCenter(cmx, cmy);

                    if (eventPhase == 0)
                    {
                        eventCountdown -= dt;
                        if (eventSkyBeams.Count == 0 || eventSkyBeams[^1].Life < 0.05f)
                        {
                            SpawnEventSkyBeam(ctarget, accent, 14f, MarkedStrikeTelegraphTime * 0.95f, charging: true);
                        }

                        if (eventCountdown <= 0f)
                        {
                            eventPhase = 1;
                            eventCountdown = MarkedStrikeFireTime;
                            eventSkyBeams.Clear();
                            SpawnEventSkyBeam(ctarget, accent, 42f, 0.16f, charging: false);
                            AddFlash(Lighten(accent, 0.4f), 0.2f);
                            SpawnGfxLightPulse(ctarget, Color.White, 150f, 1.15f, 0.12f);
                            TriggerImpact(ImpactTier.Light, accent);
                        }
                    }
                    else
                    {
                        eventCountdown -= dt;
                        if (eventCountdown <= 0f)
                        {
                            if (tiles[cmx, cmy].State != 2)
                            {
                                CollapseTileWithEventFx(cmx, cmy, accent);
                                SpawnEventShockwave(ctarget, accent, 56f, 0.24f);
                            }

                            eventStep++;
                            eventPhase = 0;
                            eventCountdown = MarkedStrikeStrikeGap;
                        }
                    }
                }
                else
                {
                    EndFloorEvent();
                }
                break;

            case FloorEventType.CrownStorm:
                eventCountdown -= dt;
                eventBlightBoltTimer -= dt;

                for (int cy = 0; cy < GridSize; cy++)
                {
                    for (int cx = 0; cx < GridSize; cx++)
                    {
                        ref Tile ct = ref tiles[cx, cy];
                        if (!ct.EventMarked || ct.State == 2) continue;
                        ApplyTileDamage(ref ct, 13f + urgency * 11f, dt, out _, markTouched: false);
                    }
                }

                if (eventBlightBoltTimer <= 0f)
                {
                    eventBlightBoltTimer = 0.26f + Rng.NextSingle() * 0.2f;
                    int cbx = Rng.Next(0, GridSize);
                    int cby = Rng.Next(0, GridSize);
                    if (tiles[cbx, cby].EventMarked && tiles[cbx, cby].State != 2)
                    {
                        Vector2 cboltPos = TileCenter(cbx, cby);
                        SpawnEventSkyBeam(cboltPos, accent, 24f, 0.18f);
                        ApplyTileDamage(ref tiles[cbx, cby], 30f, 0.16f, out _, markTouched: false);
                        SpawnGfxLightPulse(cboltPos, Lighten(accent, 0.45f), 88f, 0.95f, 0.15f);
                        AddFlash(accent, 0.09f);
                    }
                }

                if (eventCountdown <= 0f)
                {
                    if (eventPhase == 0)
                    {
                        BeginEventCollapsePhase(FloorEventType.CrownStorm);
                    }
                    else
                    {
                        ProcessStaggeredCollapse(dt, FloorEventType.CrownStorm, EventCollapseInterval(FloorEventType.BlightStorm));
                    }
                }
                break;

            case FloorEventType.None:
                break;

            default:
                throw new UnreachableException();
        }
    }

    static void EndFloorEvent()
    {
        activeEvent = FloorEventType.None;
        eventTimer = 0f;
        eventPhase = 0;
        eventActionTimer = 0f;
        eventTileQueue.Clear();
        eventShockwaves.Clear();
        eventSkyBeams.Clear();
        playerInEventSafeZone = false;
        emberFuryTileIdx = -1;
        emberFuryStandTimer = 0f;
        ClearEventMarks();
    }

    static float SafeRushBandPx() => SafeRushBandTiles * TileSize;
    static float CenterSnareMarginPx() => CenterSnareMarginTiles * TileSize;

    static void ConfigureSafeZoneRush()
    {
        float band = SafeRushBandPx();
        eventSafeRect = eventSide switch
        {
            0 => new Rectangle(0f, 0f, band, WindowHeight),
            1 => new Rectangle(WindowWidth - band, 0f, band, WindowHeight),
            2 => new Rectangle(0f, 0f, WindowWidth, band),
            3 => new Rectangle(0f, WindowHeight - band, WindowWidth, band),
            _ => throw new UnreachableException(),
        };
        eventDangerRect = default;
    }

    static void ConfigureCenterSnare()
    {
        float m = CenterSnareMarginPx();
        eventDangerRect = new Rectangle(m, m, WindowWidth - m * 2f, WindowHeight - m * 2f);
        eventSafeRect = default;
    }

    static bool PlayerInSafeRect(Rectangle safe)
    {
        if (safe.Width <= 0f || safe.Height <= 0f) return false;
        return Raylib.CheckCollisionCircleRec(playerPos, PlayerRadius, safe);
    }

    static bool PlayerInCenterSnareSafe()
    {
        float m = CurrentCenterSnareMarginPx();
        return playerPos.X - PlayerRadius < m
            || playerPos.X + PlayerRadius > WindowWidth - m
            || playerPos.Y - PlayerRadius < m
            || playerPos.Y + PlayerRadius > WindowHeight - m;
    }

    static string SafeZoneRushHint() => eventSide switch
    {
        0 => "SAFE: LEFT EDGE",
        1 => "SAFE: RIGHT EDGE",
        2 => "SAFE: TOP EDGE",
        3 => "SAFE: BOTTOM EDGE",
        _ => "",
    };

    static void DrawCenterSnareSafeBands(float time)
    {
        float m = CurrentCenterSnareMarginPx();
        float pulse = 0.18f + MathF.Sin(time * 8f) * 0.08f;
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 0f;
        Color fill = WithAlpha(UiAccent, 0.06f + pulse * 0.04f + urgency * 0.04f);
        Color border = WithAlpha(UiAccent, 0.12f + pulse * 0.08f + urgency * 0.06f);

        var top = new Rectangle(0f, 0f, WindowWidth, m);
        var bottom = new Rectangle(0f, WindowHeight - m, WindowWidth, m);
        var left = new Rectangle(0f, m, m, WindowHeight - m * 2f);
        var right = new Rectangle(WindowWidth - m, m, m, WindowHeight - m * 2f);

        Raylib.DrawRectangleRec(top, fill);
        Raylib.DrawRectangleRec(bottom, fill);
        Raylib.DrawRectangleRec(left, fill);
        Raylib.DrawRectangleRec(right, fill);

        DrawPulseFrameLite(top, border, 0.02f, 5f, 0.1f);
        DrawPulseFrameLite(bottom, border, 0.02f, 5f, 0.1f);
        DrawPulseFrameLite(left, border, 0.02f, 5f, 0.1f);
        DrawPulseFrameLite(right, border, 0.02f, 5f, 0.1f);
    }

    static void UpdateBlight(float dt)
    {
        blightTimer += dt;
        if (blightTimer < 10f) return;

        blightTimer = 0f;
        int bx = Rng.Next(1, GridSize - 1);
        int by = Rng.Next(1, GridSize - 1);

        for (int i = -1; i <= 1; i++)
        {
            for (int j = -1; j <= 1; j++)
            {
                ref Tile tile = ref tiles[bx + i, by + j];
                if (tile.State == 0)
                {
                    tile.State = 1;
                    tile.Durability = Math.Min(tile.Durability, MaxDurability * 0.45f);
                }
            }
        }

        AddTrauma(0.32f);
        AddFlash(Amber, 0.18f);
        SpawnBlightSpores(new Vector2((bx + 0.5f) * TileSize, (by + 0.5f) * TileSize));
    }

    static bool IsBossWave(int wave) => wave == 10 || (wave >= 25 && wave % 25 == 0);

    static bool IsTitanBossWave(int wave) => wave >= 50 && wave % 50 == 0;

    // Linear ramp: gentle early waves, full pressure by ~wave 100.
    static float WaveEnemyScale(int wave) => MathF.Min(1f, 0.35f + wave * 0.0065f);

    static float WaveSpeedBonus(int wave)
    {
        float eased = MathF.Max(0f, wave - 3f);
        return eased * 1.35f * WaveEnemyScale(wave);
    }

    static int WaveSwarmCount(int wave) => 1 + Math.Min(6, Math.Max(0, (wave + 2) / 3));

    static int WaveGruntsPerSwarm(int wave, int swarmIndex)
    {
        int baseCount = 1 + (int)(wave * 0.1f) + swarmIndex / 2;
        int cap = 4 + (int)(wave * 0.08f);
        return Math.Clamp(baseCount, 1, Math.Min(cap, 14));
    }

    static void UpdateWaves(float dt)
    {
        if (waveInProgress)
        {
            if (swarmCooldown > 0f)
            {
                swarmCooldown -= dt;
            }

            if (swarmCooldown <= 0f && waveSwarmIndex < waveSwarmTotal)
            {
                SpawnWaveSwarm();
                waveSwarmIndex++;
                swarmCooldown = SwarmIntervalBase + 1.4f + Rng.NextSingle() * 0.9f - waveNumber * 0.022f;
                swarmCooldown = MathF.Max(1.35f, swarmCooldown);
                waveSubtext = $"SWARM {waveSwarmIndex}/{waveSwarmTotal}";
            }
            else if (waveSwarmIndex >= waveSwarmTotal && CountLivingEnemies() == 0)
            {
                CompleteWave();
            }

            return;
        }

        betweenWaveTimer += dt;
        float pause = MathF.Max(BetweenWavePause, 5.2f - waveNumber * 0.035f);
        if (betweenWaveTimer < pause) return;

        betweenWaveTimer = 0f;
        BeginWave();
    }

    static int CountLivingEnemies()
    {
        int n = 0;
        foreach (Enemy e in enemies)
        {
            if (!e.Dead && e.Spawn >= 0.5f) n++;
        }
        return n;
    }

    static void BeginWave()
    {
        waveNumber++;
        waveInProgress = true;
        waveSwarmIndex = 0;
        waveSwarmTotal = WaveSwarmCount(waveNumber);
        swarmCooldown = 0.35f;
        waveBannerTimer = WaveBannerTime;
        waveSubtext = IsBossWave(waveNumber)
            ? IsTitanBossWave(waveNumber) ? "THE TITAN WALKS THE WALLS" : "BOSSES AT THE GATE"
            : "FOOTSTEPS ON THE STONE";
        AddFlash(UiAccent, 0.10f);
        AddTrauma(0.12f);
    }

    static void CompleteWave()
    {
        waveInProgress = false;
        betweenWaveTimer = 0f;
        waveSubtext = "A BREATH BETWEEN WAVES";

        if (waveNumber > 0)
        {
            maxWaveReached = Math.Max(maxWaveReached, waveNumber);
            int reward = (int)MathF.Round((10 + waveNumber * 4) * FableMult());
            fables += reward;
            runFablesEarned += reward;
            int waveXp = 18 + waveNumber * 9;
            GrantXp(waveXp);
            SpawnFloatingText(playerPos + new Vector2(0, -PlayerRadius - 18f), "+" + reward + " fables", Gold, 20);
            SpawnFloatingText(playerPos + new Vector2(0, -PlayerRadius - 38f), "+" + waveXp + " xp", UiAccent, 16);
        }
    }

    static void SpawnWaveSwarm()
    {
        float speedBonus = WaveSpeedBonus(waveNumber);
        bool lastSwarm = waveSwarmIndex >= waveSwarmTotal - 1;

        if (lastSwarm && IsBossWave(waveNumber))
        {
            if (IsTitanBossWave(waveNumber))
            {
                enemies.Add(CreateEnemy(EnemyType.GroveTitan, RandomEdgePosition(GetEnemyRadius(EnemyType.GroveTitan)), speedBonus));
                SpawnFloatingText(new Vector2(WindowWidth / 2f, 120f), "KEEP COLOSSUS!", Danger, 28);
                AddTrauma(0.45f);
            }
            else
            {
                EnemyType boss = Rng.Next(2) == 0 ? EnemyType.BrambleLord : EnemyType.FoxWarden;
                enemies.Add(CreateEnemy(boss, RandomEdgePosition(GetEnemyRadius(boss)), speedBonus));
                SpawnFloatingText(new Vector2(WindowWidth / 2f, 120f), GetEnemyName(boss).ToUpperInvariant() + "!", Danger, 24);
                AddTrauma(0.32f);
            }
        }

        int gruntCount = WaveGruntsPerSwarm(waveNumber, waveSwarmIndex);
        for (int i = 0; i < gruntCount; i++)
        {
            EnemyType type = PickGruntType();
            enemies.Add(CreateEnemy(type, RandomEdgePosition(GetEnemyRadius(type)), speedBonus));
        }
    }

    static ref readonly EnemyDef GetDef(EnemyType type) => ref EnemyCatalog[(int)type];

    static Enemy CreateEnemy(EnemyType type, Vector2 position, float speedBonus)
    {
        ref readonly EnemyDef def = ref GetDef(type);
        float scale = WaveEnemyScale(waveNumber);
        var e = new Enemy
        {
            Type = type,
            Position = position,
            Speed = def.Speed + speedBonus,
            Radius = def.Radius,
            MaxHp = (def.HpBase + def.HpPerWave * waveNumber) * scale,
            Wobble = Rng.NextSingle() * MathF.PI * 2f,
            Spawn = 0f,
            AbilityTimer = def.Boss ? 5f : BehaviorCooldown(def.Behavior),
            Phase = 0f,
            AbilityStep = 0,
            StrikeTx = 0,
            StrikeTy = 0,
            StrikeDepth = 3,
            ParalyzeTimer = 0f,
        };
        e.Hp = e.MaxHp;

        if (def.Behavior == EnemyBehavior.FastChase || def.Behavior == EnemyBehavior.BossDash)
        {
            float cap = def.Behavior == EnemyBehavior.BossDash ? 10f : 14f;
            e.Speed = MathF.Min(e.Speed, EffMoveSpeed() - cap);
        }

        e.Position = SnapEnemyToValidTile(e.Position, e.Radius);
        return e;
    }

    static float BehaviorCooldown(EnemyBehavior b) => b switch
    {
        EnemyBehavior.Hop => 1.1f,
        EnemyBehavior.Phaser => 1.8f,
        EnemyBehavior.Charge => 2.2f,
        EnemyBehavior.PulseBlight => 2.8f,
        EnemyBehavior.BlightTrail => 0.55f,
        EnemyBehavior.CrushTiles => 1.6f,
        EnemyBehavior.Lurker => 0f,
        _ => 0f,
    };

    static bool IsBoss(EnemyType type) => GetDef(type).Boss;

    static float EnemyMaxHp(EnemyType type)
    {
        ref readonly EnemyDef def = ref GetDef(type);
        return (def.HpBase + def.HpPerWave * waveNumber) * WaveEnemyScale(waveNumber);
    }

    static EnemyType PickGruntType()
    {
        EnemyType pick = EnemyType.BrambleStalker;
        int count = 0;
        for (int i = 0; i < EnemyCatalog.Length; i++)
        {
            ref readonly EnemyDef def = ref EnemyCatalog[i];
            if (def.Boss) continue;
            if (def.MinWave > waveNumber) continue;
            count++;
            if (Rng.Next(count) == 0) pick = (EnemyType)i;
        }
        return pick;
    }

    static Vector2 ClampToArena(Vector2 pos, float radius)
    {
        return new Vector2(
            Math.Clamp(pos.X, radius, WindowWidth - radius),
            Math.Clamp(pos.Y, radius, WindowHeight - radius));
    }

    static bool IsTileViable(int x, int y) =>
        x >= 0 && x < GridSize && y >= 0 && y < GridSize && tiles[x, y].State != 2;

    static Vector2 SnapEnemyToValidTile(Vector2 pos, float radius)
    {
        if (TryGetTileUnder(pos, out int tx, out int ty) && IsTileViable(tx, ty))
        {
            return ClampToArena(pos, radius);
        }

        Vector2 best = new Vector2(WindowWidth / 2f, WindowHeight / 2f);
        float bestDist = float.MaxValue;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (!IsTileViable(x, y)) continue;
                Vector2 center = TileCenter(x, y);
                float d = Vector2.DistanceSquared(pos, center);
                if (d < bestDist)
                {
                    bestDist = d;
                    best = center;
                }
            }
        }

        return ClampToArena(best, radius);
    }

    static Vector2 ComputeEnemyMove(ref Enemy enemy, float dt, float time)
    {
        ref readonly EnemyDef def = ref GetDef(enemy.Type);
        Vector2 toPlayer = playerPos - enemy.Position;
        float dist = toPlayer.Length();
        Vector2 dir = dist > 0.01f ? toPlayer / dist : lastMoveDirection;
        Vector2 perp = new Vector2(-dir.Y, dir.X);

        switch (def.Behavior)
        {
            case EnemyBehavior.Chase:
            case EnemyBehavior.TileLeech:
                return dir * enemy.Speed;

            case EnemyBehavior.FastChase:
                return dir * enemy.Speed;

            case EnemyBehavior.CrushTiles:
                return dir * enemy.Speed;

            case EnemyBehavior.Orbit:
            {
                float ring = 130f;
                if (dist > ring + 40f) return dir * enemy.Speed;
                if (dist < ring - 40f) return -dir * enemy.Speed * 0.85f;
                float spin = enemy.Wobble > MathF.PI ? 1f : -1f;
                return perp * enemy.Speed * spin;
            }

            case EnemyBehavior.Zigzag:
            {
                float weave = MathF.Sin(time * 7f + enemy.Wobble) * 0.55f;
                Vector2 step = Vector2.Normalize(dir + perp * weave);
                return step * enemy.Speed;
            }

            case EnemyBehavior.Hop:
            {
                enemy.AbilityTimer -= dt;
                if (enemy.AbilityTimer <= 0f)
                {
                    enemy.Position = ClampToArena(enemy.Position + dir * 88f, enemy.Radius);
                    enemy.Position = SnapEnemyToValidTile(enemy.Position, enemy.Radius);
                    enemy.AbilityTimer = 1.15f + Rng.NextSingle() * 0.4f;
                    enemy.AbilityStep = 0;
                }
                else if (enemy.AbilityTimer < 0.42f)
                {
                    enemy.AbilityStep = 1;
                    Vector2 dest = ClampToArena(enemy.Position + dir * 88f, enemy.Radius);
                    if (TryGetTileUnder(dest, out int dtx, out int dty))
                    {
                        enemy.StrikeTx = dtx;
                        enemy.StrikeTy = dty;
                    }
                }
                else
                {
                    enemy.AbilityStep = 0;
                }
                return dir * enemy.Speed * 0.35f;
            }

            case EnemyBehavior.BlightTrail:
                return dir * enemy.Speed;

            case EnemyBehavior.Kite:
            {
                float prefer = 168f;
                if (dist < prefer - 30f) return -dir * enemy.Speed;
                if (dist > prefer + 40f) return dir * enemy.Speed;
                return perp * enemy.Speed * 0.7f;
            }

            case EnemyBehavior.Charge:
            {
                enemy.AbilityTimer -= dt;
                if (enemy.Phase > 0f)
                {
                    enemy.Phase -= dt;
                    enemy.AbilityStep = 3;
                    return dir * enemy.Speed * 2.1f;
                }
                if (enemy.AbilityStep == 2)
                {
                    if (enemy.AbilityTimer <= 0f)
                    {
                        enemy.Phase = 0.35f;
                        enemy.AbilityTimer = 2.4f;
                        enemy.AbilityStep = 3;
                        return dir * enemy.Speed * 2.1f;
                    }
                    return dir * enemy.Speed * 0.28f;
                }
                if (enemy.AbilityTimer <= 0f && dist < 260f)
                {
                    enemy.AbilityStep = 2;
                    enemy.AbilityTimer = ChargeTelegraphTime;
                    return dir * enemy.Speed * 0.28f;
                }
                enemy.AbilityStep = 0;
                return dir * enemy.Speed * 0.65f;
            }

            case EnemyBehavior.Lurker:
            {
                if (dist > 200f) return dir * enemy.Speed * 0.45f;
                return dir * enemy.Speed * 1.35f;
            }

            case EnemyBehavior.Phaser:
            {
                enemy.AbilityTimer -= dt;
                if (enemy.AbilityTimer <= 0f)
                {
                    enemy.Position = SnapEnemyToValidTile(enemy.Position + dir * 72f, enemy.Radius);
                    enemy.AbilityTimer = 1.7f + Rng.NextSingle() * 0.6f;
                    enemy.AbilityStep = 0;
                }
                else if (enemy.AbilityTimer < 0.48f)
                {
                    enemy.AbilityStep = 1;
                    Vector2 dest = ClampToArena(enemy.Position + dir * 72f, enemy.Radius);
                    if (TryGetTileUnder(dest, out int dtx, out int dty))
                    {
                        enemy.StrikeTx = dtx;
                        enemy.StrikeTy = dty;
                    }
                }
                else
                {
                    enemy.AbilityStep = 0;
                }
                return dir * enemy.Speed * 0.5f;
            }

            case EnemyBehavior.PulseBlight:
            case EnemyBehavior.Sapper:
            case EnemyBehavior.Rotburst:
            case EnemyBehavior.Splitter:
                return dir * enemy.Speed * 0.8f;

            case EnemyBehavior.BossBlight:
            case EnemyBehavior.BossDash:
                return dir * enemy.Speed;

            case EnemyBehavior.BossSmash:
                return enemy.AbilityStep > 0 ? dir * enemy.Speed * 0.22f : dir * enemy.Speed * 0.62f;

            default:
                return dir * enemy.Speed;
        }
    }

    static void TickEnemyBehavior(ref Enemy enemy, float dt, float time)
    {
        ref readonly EnemyDef def = ref GetDef(enemy.Type);

        if (def.Behavior == EnemyBehavior.CrushTiles)
        {
            if (enemy.AbilityStep == 1)
            {
                enemy.AbilityTimer -= dt;
                if (enemy.AbilityTimer <= 0f)
                {
                    if (IsTileViable(enemy.StrikeTx, enemy.StrikeTy))
                    {
                        CollapseTile(ref tiles[enemy.StrikeTx, enemy.StrikeTy]);
                        AddFlash(Danger, 0.06f);
                    }
                    enemy.AbilityStep = 0;
                    enemy.AbilityTimer = CrushCooldown;
                }
            }
            else
            {
                enemy.AbilityTimer -= dt;
                if (enemy.AbilityTimer <= 0f
                    && TryGetTileUnder(enemy.Position, out int tx, out int ty)
                    && IsTileViable(tx, ty))
                {
                    enemy.StrikeTx = tx;
                    enemy.StrikeTy = ty;
                    enemy.AbilityStep = 1;
                    enemy.AbilityTimer = CrushTelegraphTime;
                }
            }
        }

        if (def.Behavior == EnemyBehavior.BlightTrail)
        {
            enemy.AbilityTimer -= dt;
            if (enemy.AbilityTimer <= 0f && TryGetTileUnder(enemy.Position, out int bx, out int by))
            {
                enemy.AbilityTimer = 0.55f;
                ref Tile t = ref tiles[bx, by];
                if (t.State == 0)
                {
                    t.State = 1;
                    t.Durability = Math.Min(t.Durability, MaxDurability * 0.5f);
                }
            }
        }

        if (def.Behavior == EnemyBehavior.PulseBlight || def.Behavior == EnemyBehavior.BossBlight)
        {
            enemy.AbilityTimer -= dt;
            if (enemy.AbilityTimer <= 0f)
            {
                enemy.AbilityTimer = def.Boss ? 5.2f : 2.8f;
                BlightArea(enemy.Position, def.Boss ? 1 : 1);
            }
        }

        if (def.Behavior == EnemyBehavior.Sapper && TryGetTileUnder(enemy.Position, out int sx, out int sy))
        {
            for (int j = -1; j <= 1; j++)
            {
                for (int i = -1; i <= 1; i++)
                {
                    int tx = sx + i, ty = sy + j;
                    if (!IsTileViable(tx, ty)) continue;
                    ref Tile t = ref tiles[tx, ty];
                    ApplyTileDamage(ref t, 8f * TileDecayMultiplier(tx, ty), dt, out _);
                }
            }
        }

        if (def.Behavior == EnemyBehavior.BossDash)
        {
            if (enemy.AbilityStep == 1)
            {
                enemy.AbilityTimer -= dt;
                if (enemy.AbilityTimer <= 0f)
                {
                    Vector2 toPlayer = playerPos - enemy.Position;
                    if (toPlayer.LengthSquared() > 1f)
                    {
                        enemy.Vel = Vector2.Normalize(toPlayer) * enemy.Speed * 1.12f;
                    }
                    enemy.AbilityStep = 0;
                    enemy.AbilityTimer = 3.8f;
                    AddFlash(new Color(220, 120, 60, 255), 0.06f);
                }
            }
            else
            {
                enemy.AbilityTimer -= dt;
                if (enemy.AbilityTimer <= 0f)
                {
                    enemy.AbilityStep = 1;
                    enemy.AbilityTimer = BossTelegraphTime;
                }
            }
        }

        if (def.Behavior == EnemyBehavior.BossSmash)
        {
            TickGroveTitanCuts(ref enemy, dt);
        }
    }

    static void TickGroveTitanCuts(ref Enemy enemy, float dt)
    {
        if (enemy.AbilityStep == 0)
        {
            enemy.AbilityTimer -= dt;
            if (enemy.AbilityTimer > 0f) return;

            if (!TryGetTileUnder(playerPos, out int px, out int py)) return;

            enemy.StrikeTx = px;
            enemy.StrikeTy = py;
            enemy.StrikeDepth = 2 + Rng.Next(2);
            enemy.AbilityStep = 1;
            enemy.AbilityTimer = BossCutTelegraphTime;
            return;
        }

        enemy.AbilityTimer -= dt;
        if (enemy.AbilityTimer > 0f) return;

        switch (enemy.AbilityStep)
        {
            case 1:
                CollapseBossCutLane(enemy.StrikeTx, enemy.StrikeTy, 0, 1, enemy.StrikeDepth);
                enemy.AbilityStep = 2;
                enemy.AbilityTimer = BossCutTelegraphTime;
                AddFlash(Danger, 0.05f);
                break;
            case 2:
                CollapseBossCutLane(enemy.StrikeTx, enemy.StrikeTy, 0, -1, enemy.StrikeDepth);
                enemy.AbilityStep = 3;
                enemy.AbilityTimer = BossCutTelegraphTime;
                AddFlash(Danger, 0.05f);
                break;
            case 3:
                CollapseBossCutLane(enemy.StrikeTx, enemy.StrikeTy, -1, 0, enemy.StrikeDepth);
                CollapseBossCutLane(enemy.StrikeTx, enemy.StrikeTy, 1, 0, enemy.StrikeDepth);
                enemy.AbilityStep = 0;
                enemy.AbilityTimer = BossCutComboCooldown;
                AddTrauma(0.22f);
                AddFlash(Danger, 0.08f);
                break;
            default:
                enemy.AbilityStep = 0;
                enemy.AbilityTimer = BossCutComboCooldown;
                break;
        }
    }

    static void CollapseBossCutLane(int originX, int originY, int dirX, int dirY, int depth)
    {
        for (int i = 1; i <= depth; i++)
        {
            int x = originX + dirX * i;
            int y = originY + dirY * i;
            if (x < 0 || x >= GridSize || y < 0 || y >= GridSize) continue;
            if (tiles[x, y].State == 2) continue;
            CollapseTile(ref tiles[x, y]);
        }
    }

    static void DrawBossCutLaneTelegraph(int originX, int originY, int dirX, int dirY, int depth, float time, float intensity)
    {
        float pulse = MathF.Sin(time * 14f) * 0.5f + 0.5f;
        for (int i = 1; i <= depth; i++)
        {
            int x = originX + dirX * i;
            int y = originY + dirY * i;
            if (x < 0 || x >= GridSize || y < 0 || y >= GridSize) continue;
            if (tiles[x, y].State == 2) continue;
            var r = new Rectangle(x * TileSize + 2f, y * TileSize + 2f, TileSize - 4f, TileSize - 4f);
            Raylib.DrawRectangleRec(r, WithAlpha(Danger, (0.2f + intensity * 0.45f) + pulse * 0.15f));
            DrawPulseFrame(r, Danger, 0.1f, 12f, 0.2f + intensity * 0.35f);
        }
    }

    static void BlightArea(Vector2 pos, int radius)
    {
        if (!TryGetTileUnder(pos, out int bx, out int by)) return;
        for (int j = -radius; j <= radius; j++)
        {
            for (int i = -radius; i <= radius; i++)
            {
                int tx = bx + i, ty = by + j;
                if (!IsTileViable(tx, ty)) continue;
                ref Tile t = ref tiles[tx, ty];
                if (t.State == 0)
                {
                    t.State = 1;
                    t.Durability = Math.Min(t.Durability, MaxDurability * 0.38f);
                }
            }
        }
        SpawnBlightSpores(pos);
    }

    static void UpdateEnemies(float dt)
    {
        float time = (float)Raylib.GetTime();
        bool playerDashing = dashTimer > 0f || abilityIFrameTimer > 0f;

        for (int i = 0; i < enemies.Count; i++)
        {
            Enemy enemy = enemies[i];
            if (enemy.Dead) continue;

            if (enemy.Hit > 0f) enemy.Hit = Math.Max(0f, enemy.Hit - dt);

            if (enemy.ParalyzeTimer > 0f)
            {
                enemy.ParalyzeTimer = Math.Max(0f, enemy.ParalyzeTimer - dt);
                enemies[i] = enemy;
                continue;
            }

            ref readonly EnemyDef def = ref GetDef(enemy.Type);

            if (enemy.Spawn < 1f)
            {
                enemy.Spawn = Math.Min(1f, enemy.Spawn + dt / (def.Boss ? 0.65f : 0.35f));
                enemies[i] = enemy;
                continue;
            }

            TickEnemyBehavior(ref enemy, dt, time);

            Vector2 step = ComputeEnemyMove(ref enemy, dt, time);
            enemy.Vel = Vector2.Lerp(enemy.Vel, step, 1f - MathF.Exp(-12f * dt));
            float bannerMul = IsInBannerZone(enemy.Position) ? BannerEnemySlow : 1f;
            enemy.Position += enemy.Vel * dt * bannerMul;
            enemy.Position = ClampToArena(enemy.Position, enemy.Radius);

            if (TryGetTileUnder(enemy.Position, out int voidX, out int voidY) && tiles[voidX, voidY].State == 2)
            {
                enemy.Position = SnapEnemyToValidTile(enemy.Position, enemy.Radius);
            }

            float touchDistance = PlayerRadius + enemy.Radius;
            if (!playerDashing && Vector2.DistanceSquared(playerPos, enemy.Position) <= touchDistance * touchDistance)
            {
                enemies[i] = enemy;
                TriggerGameOver(DeathCause.EnemyGrasp, GetEnemyName(enemy.Type));
                return;
            }

            if (TryGetTileUnder(enemy.Position, out int tileX, out int tileY))
            {
                ref Tile tile = ref tiles[tileX, tileY];
                if (tile.State == 2)
                {
                    enemy.Position = SnapEnemyToValidTile(enemy.Position, enemy.Radius);
                    enemies[i] = enemy;
                    continue;
                }

                if (def.InstaCollapse)
                {
                    InstantlyCollapseTile(ref tile, out _);
                }
                else if (def.Behavior == EnemyBehavior.CrushTiles)
                {
                    // Tile collapse handled in TickEnemyBehavior with telegraph.
                }
                else if (def.TileDecay > 0f)
                {
                    ApplyTileDamage(ref tile, def.TileDecay * TileDecayMultiplier(tileX, tileY), dt, out _);
                }
            }

            enemies[i] = enemy;
        }
    }

    static void ReapEnemies()
    {
        for (int i = enemies.Count - 1; i >= 0; i--)
        {
            if (enemies[i].Dead)
            {
                Enemy dead = enemies[i];
                OnEnemyDeathExtra(dead);
                KillRewards(dead);
                enemies.RemoveAt(i);
            }
        }
    }

    static void OnEnemyDeathExtra(Enemy enemy)
    {
        ref readonly EnemyDef def = ref GetDef(enemy.Type);
        if (def.Behavior == EnemyBehavior.Rotburst)
        {
            BlightArea(enemy.Position, 1);
        }
        else if (def.Behavior == EnemyBehavior.Splitter)
        {
            for (int k = 0; k < 2; k++)
            {
                Vector2 off = new Vector2(Rng.Next(-24, 25), Rng.Next(-24, 25));
                enemies.Add(CreateEnemy(EnemyType.AcornSwarm, enemy.Position + off, 0f));
            }
        }
    }

    static void ApplyTileDamage(ref Tile tile, float decayRate, float dt, out bool collapsed, bool markTouched = true)
    {
        collapsed = false;
        if (tile.State == 2) return;

        if (markTouched) tile.UntouchedTimer = 0f;
        tile.Durability -= decayRate * dt;
        if (tile.Durability <= 0f)
        {
            tile.Durability = 0f;
            CollapseTile(ref tile);
            collapsed = true;
            return;
        }

        if (tile.Durability < MaxDurability * 0.6f) tile.State = 1;
    }

    static void InstantlyCollapseTile(ref Tile tile, out bool collapsed)
    {
        if (tile.State == 2) { collapsed = false; return; }
        CollapseTile(ref tile);
        collapsed = true;
    }

    static void KillRewards(Enemy enemy)
    {
        ref readonly EnemyDef def = ref GetDef(enemy.Type);
        Color c = def.Color;
        bool boss = def.Boss;
        bool big = boss || def.InstaCollapse || def.Radius >= 19f;

        combo++;
        comboTimer = ComboWindow;
        int gained = PointsPerEnemyKill * Math.Max(1, combo);
        if (boss) gained = (int)(gained * 2.5f);
        else if (big) gained = (int)(gained * 1.4f);
        score += gained;

        int fableGain = (int)MathF.Round((boss ? 8 : big ? 3 : 1) * FableMult());
        if (fableGain < 1) fableGain = 1;
        fables += fableGain;
        runFablesEarned += fableGain;

        int xpGain = boss ? 16 : big ? 7 : 3;
        if (combo >= 3) xpGain += 2;
        GrantXp(xpGain);

        runKillCount++;
        TryUnlockVerdictByKills();

        SpawnExplosion(enemy.Position, c, boss ? 72 : big ? 52 : 32);
        SpawnGfxLightPulse(enemy.Position, c, boss ? 320f : big ? 240f : 170f, boss ? 1.85f : 1.15f, boss ? 0.75f : 0.48f);
        SpawnFloatingText(enemy.Position, "+" + gained, combo >= 2 ? ComboColor(combo) : Color.White, combo >= 2 ? 24 : 18);
        if (boss)
        {
            SpawnFloatingText(enemy.Position + new Vector2(0, -22f), "+" + fableGain + " fables", Gold, 18);
        }

        AddTrauma(boss ? 0.95f : big ? 0.68f : 0.38f);
        zoomPunch = Math.Max(zoomPunch, boss ? 0.13f : big ? 0.085f : 0.055f);
        TriggerImpact(boss ? ImpactTier.Major : big ? ImpactTier.Medium : ImpactTier.Light, c);
    }

    static void TriggerGameOver(DeathCause cause = DeathCause.Unknown, string detail = "")
    {
        if (state == GameState.GameOver) return;
        if (TryOathOfTheBailey(cause)) return;

        lastDeathCause = cause;
        lastDeathDetail = detail;
        state = GameState.GameOver;
        EndFloorEvent();
        AddTrauma(1f);
        zoomPunch = Math.Max(zoomPunch, 0.09f);
        impactFlashColor = Danger;
        TriggerImpact(ImpactTier.Major, Danger);
        flash = 0.9f;
        flashColor = Danger;
        SpawnExplosion(playerPos, BodyColor(), 36);

        lastRunNewBest = score > highScore;
        if (score > highScore) highScore = score;
        maxWaveReached = Math.Max(maxWaveReached, waveNumber);
        GrantXp(Math.Max(8, waveNumber * 10));
        SaveGame();
    }

    // ---------------------------------------------------------------- Spawners

    static void SpawnExplosion(Vector2 origin, Color baseColor, int count)
    {
        SpawnGfxLightPulse(origin, baseColor, 90f + count * 2.8f, 0.75f + count * 0.014f, 0.32f + Math.Min(count, 50) * 0.005f);

        for (int i = 0; i < count; i++)
        {
            float angle = Rng.NextSingle() * MathF.PI * 2f;
            float speed = Rng.Next(90, 340);
            bool glow = i % 3 == 0;
            particles.Add(new Particle
            {
                Position = origin,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                Color = glow ? Lighten(baseColor, 0.5f) : baseColor,
                Alpha = 1f,
                Fade = 1f / (0.42f + Rng.NextSingle() * 0.55f),
                Rotation = Rng.NextSingle() * 360f,
                Spin = (Rng.NextSingle() - 0.5f) * 420f,
                Size = glow ? 8f + Rng.NextSingle() * 7f : 3.5f + Rng.NextSingle() * 5f,
                Drag = 2.2f,
                Glow = glow,
            });
        }
    }

    static void SpawnHitSpark(Vector2 origin, Color color)
    {
        for (int i = 0; i < 12; i++)
        {
            float angle = Rng.NextSingle() * MathF.PI * 2f;
            particles.Add(new Particle
            {
                Position = origin,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * Rng.Next(70, 200),
                Color = Lighten(color, 0.35f + Rng.NextSingle() * 0.2f),
                Alpha = 1f,
                Fade = 1f / (0.22f + Rng.NextSingle() * 0.18f),
                Size = 2.5f + Rng.NextSingle() * 4f,
                Drag = 3.5f,
                Glow = i % 2 == 0,
            });
        }
    }

    static float GunStyleTrauma(GunFireStyle style) => style switch
    {
        GunFireStyle.Standard => 0.12f,
        GunFireStyle.ArcFan => 0.16f,
        GunFireStyle.Buckshot => 0.18f,
        GunFireStyle.Homing => 0.14f,
        GunFireStyle.Lance => 0.2f,
        GunFireStyle.Repeater => 0.1f,
        GunFireStyle.Volley => 0.15f,
        GunFireStyle.Burst => 0.13f,
        GunFireStyle.Laser => 0.32f,
        GunFireStyle.Sniper => 0.22f,
        GunFireStyle.RingPulse => 0.19f,
        GunFireStyle.CrossBurst => 0.17f,
        GunFireStyle.Mortar => 0.24f,
        GunFireStyle.DriftOrb => 0.15f,
        GunFireStyle.FlailArc => 0.18f,
        _ => throw new UnreachableException(),
    };

    static float ProjectileTrailChance(GunFireStyle style) => style switch
    {
        GunFireStyle.Repeater => 0.92f,
        GunFireStyle.Burst => 0.88f,
        GunFireStyle.Volley => 0.86f,
        GunFireStyle.Buckshot => 0.78f,
        GunFireStyle.Sniper => 0.72f,
        GunFireStyle.Lance => 0.8f,
        GunFireStyle.FlailArc => 0.85f,
        GunFireStyle.DriftOrb => 0.95f,
        GunFireStyle.Homing => 0.9f,
        GunFireStyle.RingPulse => 0.82f,
        GunFireStyle.CrossBurst => 0.84f,
        GunFireStyle.Mortar => 0f,
        GunFireStyle.Laser => 0f,
        _ => 0.75f,
    };

    static int GunStyleSeed(string gunName) => gunName.GetHashCode(StringComparison.Ordinal);

    static void SpawnWeaponFireFx(GunFireStyle style, Vector2 pos, Vector2 dir, Color color, string gunName)
    {
        int seed = GunStyleSeed(gunName);
        Color hot = Lighten(color, 0.42f);
        Color core = Lighten(color, 0.65f);
        float aim = MathF.Atan2(dir.Y, dir.X);

        switch (style)
        {
            case GunFireStyle.Standard:
                SpawnConeBurst(pos, dir, color, hot, 10 + seed % 4, 80f, 160f);
                SpawnGfxLightPulse(pos, hot, 48f + seed % 20, 0.55f, 0.14f);
                break;
            case GunFireStyle.ArcFan:
                for (int i = -2; i <= 2; i++)
                {
                    float a = aim + i * 0.22f;
                    var d = new Vector2(MathF.Cos(a), MathF.Sin(a));
                    SpawnConeBurst(pos, d, color, hot, 4, 60f, 120f);
                }
                SpawnGfxLightPulse(pos, hot, 72f, 0.7f, 0.16f);
                break;
            case GunFireStyle.Buckshot:
                SpawnConeBurst(pos, dir, color, hot, 18 + seed % 6, 50f, 190f);
                for (int i = 0; i < 6; i++)
                {
                    float a = aim + (Hash(seed + i) - 0.5f) * 0.9f;
                    SpawnSpark(pos, a, 90f, 220f, WithAlpha(hot, 0.85f), 3f);
                }
                break;
            case GunFireStyle.Homing:
                SpawnGfxLightPulse(pos, hot, 58f, 0.65f, 0.2f);
                for (int i = 0; i < 8; i++)
                {
                    float a = i * MathF.PI * 2f / 8f;
                    SpawnSpark(pos, a, 20f, 45f, WithAlpha(color, 0.7f), 2.5f);
                }
                SpawnConeBurst(pos, dir, color, core, 8, 70f, 130f);
                break;
            case GunFireStyle.Lance:
                SpawnLanceMuzzle(pos, dir, color, hot);
                SpawnGfxLightPulse(pos, core, 95f, 0.95f, 0.2f);
                AddFlash(hot, 0.1f);
                break;
            case GunFireStyle.Repeater:
                SpawnConeBurst(pos, dir, color, hot, 6, 90f, 150f);
                SpawnSpark(pos, aim, 120f, 180f, core, 2.5f);
                break;
            case GunFireStyle.Volley:
                SpawnConeBurst(pos, dir, color, hot, 9, 70f, 140f);
                SpawnGfxLightPulse(pos, hot, 52f, 0.5f, 0.12f);
                break;
            case GunFireStyle.Burst:
                SpawnConeBurst(pos, dir, color, hot, 12, 75f, 165f);
                SpawnGfxLightPulse(pos, core, 64f, 0.62f, 0.15f);
                break;
            case GunFireStyle.Laser:
                SpawnLaserMuzzle(pos, dir, color, hot, core);
                break;
            case GunFireStyle.Sniper:
                SpawnSniperMuzzle(pos, dir, color, hot, core);
                AddFlash(core, 0.12f);
                zoomPunch = Math.Max(zoomPunch, 0.035f);
                break;
            case GunFireStyle.RingPulse:
                for (int i = 0; i < 12; i++)
                {
                    float a = i * MathF.PI * 2f / 12f;
                    SpawnSpark(pos, a, 55f, 110f, color, 3.5f);
                }
                SpawnGfxLightPulse(pos, hot, 88f, 0.85f, 0.22f);
                break;
            case GunFireStyle.CrossBurst:
                for (int i = 0; i < 4; i++)
                {
                    float a = aim + i * MathF.PI * 0.5f;
                    SpawnSpark(pos, a, 80f, 150f, hot, 4f);
                }
                SpawnGfxLightPulse(pos, core, 76f, 0.78f, 0.18f);
                break;
            case GunFireStyle.Mortar:
                SpawnGfxLightPulse(pos, hot, 68f, 0.72f, 0.2f);
                SpawnConeBurst(pos, dir, color, hot, 14, 40f, 90f);
                break;
            case GunFireStyle.DriftOrb:
                SpawnGfxLightPulse(pos, hot, 62f, 0.8f, 0.24f);
                for (int i = 0; i < 10; i++)
                {
                    float a = i * MathF.PI * 2f / 10f + aim;
                    SpawnSpark(pos, a, 25f, 55f, WithAlpha(core, 0.75f), 3f);
                }
                break;
            case GunFireStyle.FlailArc:
                for (int i = -1; i <= 1; i++)
                {
                    float a = aim + i * 0.5f;
                    SpawnSpark(pos, a, 70f, 130f, color, 4f);
                }
                SpawnGfxLightPulse(pos, hot, 70f, 0.68f, 0.17f);
                break;
            default:
                throw new UnreachableException();
        }
    }

    static void SpawnConeBurst(Vector2 pos, Vector2 dir, Color color, Color hot, int count, float minSpd, float maxSpd)
    {
        float aim = MathF.Atan2(dir.Y, dir.X);
        for (int i = 0; i < count; i++)
        {
            float spread = (Hash(i * 991 + (int)(pos.X + pos.Y)) - 0.5f) * 0.55f;
            float a = aim + spread;
            float spd = minSpd + Rng.NextSingle() * (maxSpd - minSpd);
            particles.Add(new Particle
            {
                Position = pos,
                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                Color = i % 3 == 0 ? hot : color,
                Alpha = 1f,
                Fade = 1f / (0.14f + Rng.NextSingle() * 0.16f),
                Size = 3f + Rng.NextSingle() * 4f,
                Drag = 4.5f,
                Glow = true,
            });
        }
    }

    static void SpawnSpark(Vector2 pos, float angle, float minSpd, float maxSpd, Color color, float size)
    {
        float spd = minSpd + Rng.NextSingle() * (maxSpd - minSpd);
        particles.Add(new Particle
        {
            Position = pos,
            Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * spd,
            Color = color,
            Alpha = 1f,
            Fade = 1f / 0.2f,
            Size = size,
            Drag = 4f,
            Glow = true,
        });
    }

    static void SpawnLanceMuzzle(Vector2 pos, Vector2 dir, Color color, Color hot)
    {
        float aim = MathF.Atan2(dir.Y, dir.X);
        for (int i = 0; i < 16; i++)
        {
            float t = i / 15f;
            SpawnSpark(pos + dir * (8f + t * 22f), aim, 40f + t * 80f, 90f + t * 120f, i % 2 == 0 ? hot : color, 2.5f + t * 2f);
        }
    }

    static void SpawnSniperMuzzle(Vector2 pos, Vector2 dir, Color color, Color hot, Color core)
    {
        float aim = MathF.Atan2(dir.Y, dir.X);
        SpawnSpark(pos, aim, 200f, 320f, core, 2f);
        SpawnSpark(pos, aim, 140f, 200f, hot, 3f);
        SpawnGfxLightPulse(pos, hot, 110f, 1.1f, 0.18f);
        for (int i = 0; i < 5; i++)
        {
            float a = aim + (i - 2) * 0.08f;
            SpawnSpark(pos, a, 60f, 100f, WithAlpha(color, 0.6f), 2f);
        }
    }

    static void SpawnLaserMuzzle(Vector2 pos, Vector2 dir, Color color, Color hot, Color core)
    {
        SpawnGfxLightPulse(pos, core, 120f, 1.4f, 0.24f);
        SpawnConeBurst(pos, dir, color, hot, 14, 30f, 110f);
    }

    static void SpawnLaserBeamFx(Vector2 start, Vector2 end, Color color)
    {
        Vector2 seg = end - start;
        float len = seg.Length();
        if (len < 1f) return;

        int sparks = (int)(len / 28f);
        for (int i = 0; i < sparks; i++)
        {
            float t = (i + Rng.NextSingle() * 0.4f) / sparks;
            Vector2 p = start + seg * t;
            SpawnGfxLightPulse(p, Lighten(color, 0.35f), 24f, 0.35f, 0.08f);
        }
        SpawnGfxLightPulse(end, Lighten(color, 0.5f), 64f, 0.9f, 0.16f);
    }

    static void SpawnProjectileBirthFx(GunFireStyle style, Vector2 pos, Vector2 vel, Color color)
    {
        switch (style)
        {
            case GunFireStyle.Mortar:
                SpawnGfxLightPulse(pos, Lighten(color, 0.3f), 36f, 0.45f, 0.12f);
                break;
            case GunFireStyle.RingPulse:
            case GunFireStyle.CrossBurst:
                SpawnGfxLightPulse(pos, color, 28f, 0.4f, 0.1f);
                break;
            case GunFireStyle.Sniper:
            case GunFireStyle.Lance:
                SpawnSpark(pos, MathF.Atan2(vel.Y, vel.X), 30f, 60f, Lighten(color, 0.5f), 2f);
                break;
            default:
                break;
        }
    }

    static void SpawnProjectileTrailFx(Projectile p)
    {
        Color trail = WithAlpha(Lighten(p.Color, 0.25f), 0.75f);
        switch (p.Style)
        {
            case GunFireStyle.Buckshot:
                trail = WithAlpha(p.Color, 0.55f);
                particles.Add(new Particle
                {
                    Position = p.Position,
                    Velocity = -p.Velocity * 0.08f,
                    Color = trail,
                    Alpha = 0.8f,
                    Fade = 1f / 0.18f,
                    Size = p.Size * 0.55f,
                    Drag = 6f,
                    Glow = false,
                });
                break;
            case GunFireStyle.Homing:
            case GunFireStyle.DriftOrb:
                particles.Add(new Particle
                {
                    Position = p.Position,
                    Velocity = Vector2.Zero,
                    Color = trail,
                    Alpha = 0.85f,
                    Fade = 1f / 0.35f,
                    Size = p.Size * (p.Style == GunFireStyle.DriftOrb ? 1.1f : 0.85f),
                    Drag = 3f,
                    Glow = true,
                });
                break;
            case GunFireStyle.FlailArc:
                particles.Add(new Particle
                {
                    Position = p.Position,
                    Velocity = new Vector2(-p.Velocity.Y, p.Velocity.X) * 0.04f,
                    Color = trail,
                    Alpha = 0.7f,
                    Fade = 1f / 0.2f,
                    Size = p.Size * 0.7f,
                    Drag = 5f,
                    Glow = true,
                });
                break;
            default:
                particles.Add(new Particle
                {
                    Position = p.Position,
                    Velocity = Vector2.Zero,
                    Color = p.Color,
                    Alpha = 0.65f,
                    Fade = 1f / 0.22f,
                    Size = p.Size * 0.85f,
                    Drag = 4f,
                    Glow = true,
                });
                break;
        }
    }

    static void SpawnProjectileHitFx(GunFireStyle style, Vector2 pos, Vector2 vel, Color color, float damage)
    {
        SpawnHitSpark(pos, color);
        switch (style)
        {
            case GunFireStyle.Sniper:
                SpawnGfxLightPulse(pos, Lighten(color, 0.5f), 80f, 1f, 0.2f);
                for (int i = 0; i < 6; i++)
                {
                    float a = MathF.Atan2(vel.Y, vel.X) + MathF.PI + (i - 2.5f) * 0.25f;
                    SpawnSpark(pos, a, 100f, 200f, Lighten(color, 0.4f), 2f);
                }
                break;
            case GunFireStyle.Lance:
                SpawnGfxLightPulse(pos, color, 70f, 0.85f, 0.18f);
                break;
            case GunFireStyle.Buckshot:
                SpawnConeBurst(pos, SafeNormalize(vel), color, Lighten(color, 0.4f), 6, 40f, 100f);
                break;
            case GunFireStyle.FlailArc:
                SpawnConeBurst(pos, SafeNormalize(vel), color, Lighten(color, 0.35f), 8, 50f, 130f);
                break;
            case GunFireStyle.Homing:
            case GunFireStyle.DriftOrb:
                SpawnGfxLightPulse(pos, Lighten(color, 0.45f), 55f, 0.7f, 0.16f);
                break;
            case GunFireStyle.RingPulse:
            case GunFireStyle.CrossBurst:
                SpawnGfxLightPulse(pos, color, 48f, 0.65f, 0.14f);
                break;
            default:
                if (damage >= 18f)
                {
                    SpawnGfxLightPulse(pos, color, 42f, 0.5f, 0.12f);
                }
                break;
        }
    }

    static void SpawnMuzzle(Vector2 pos, Color color)
    {
        SpawnWeaponFireFx(GunFireStyle.Standard, pos, Vector2.UnitX, color, "fallback");
    }

    static void SpawnDashBurst()
    {
        for (int i = 0; i < 28; i++)
        {
            float angle = Rng.NextSingle() * MathF.PI * 2f;
            float speed = Rng.Next(60, 220);
            particles.Add(new Particle
            {
                Position = playerPos,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed - lastMoveDirection * 160f,
                Color = BodyColor(),
                Alpha = 1f,
                Fade = 1f / 0.5f,
                Size = 4f + Rng.NextSingle() * 6f,
                Drag = 2.8f,
                Glow = true,
            });
        }
        SpawnGfxLightPulse(playerPos, BodyBright(), 90f, 0.85f, 0.2f);
        AddTrauma(0.18f);
        zoomPunch = Math.Max(zoomPunch, 0.04f);
    }

    static AbilityType SanitizeAbilitySlot(AbilityType slot) =>
        abilityUnlocked[(int)slot] ? slot : AbilityType.Paralyze;

    static void AssignAbilityToSlot(int slot, AbilityType ability)
    {
        if (!abilityUnlocked[(int)ability]) return;

        ref AbilityType target = ref slot == 0 ? ref abilitySlot1 : ref abilitySlot2;
        ref AbilityType other = ref slot == 0 ? ref abilitySlot2 : ref abilitySlot1;
        if (target == ability) return;

        if (other == ability) other = target;
        target = ability;
        abilitySlotTracked[slot] = ability;
        abilityFillVis[slot] = AbilityReadiness(ability);
        AddFlash(AbilityAccent(ability), 0.14f);
        SaveGame();
    }

    static void SyncAbilitySlotHud(int slot)
    {
        AbilityType equipped = slot == 0 ? abilitySlot1 : abilitySlot2;
        if (abilitySlotTracked[slot] == equipped) return;
        abilitySlotTracked[slot] = equipped;
        abilityFillVis[slot] = AbilityReadiness(equipped);
    }

    static void TryUseAbilityFromSlots(AbilityType ability, bool blockDash)
    {
        if (abilitySlot1 == ability) TryUseAbility(ability, blockDash);
        else if (abilitySlot2 == ability) TryUseAbility(ability, false);
    }

    static bool HasEquippedAbility(AbilityType ability) =>
        abilitySlot1 == ability || abilitySlot2 == ability;

    static bool IsInBannerZone(Vector2 pos) =>
        bannerActive && bannerTimer > 0f && Vector2.Distance(pos, bannerPos) <= BannerRadius;

    static bool BannerFreezesEvents() =>
        bannerActive && bannerTimer > 0f && IsInBannerZone(playerPos);

    static float AbilityReadiness(AbilityType ability)
    {
        return ability switch
        {
            AbilityType.Paralyze => paralyzeCooldown <= 0f ? 1f : 1f - paralyzeCooldown / EffParalyzeCooldown(),
            AbilityType.WindStep => dashCooldown <= 0f && dashTimer <= 0f && bannerPlantTimer <= 0f
                ? 1f : 1f - dashCooldown / EffDashCooldown(),
            AbilityType.OathOfTheBailey => oathUsedThisRun ? 0f : 1f,
            AbilityType.Verdict => verdictCooldown <= 0f && verdictHaltTimer <= 0f && abilityUnlocked[(int)AbilityType.Verdict]
                ? 1f : verdictCooldown > 0f ? 1f - verdictCooldown / VerdictCooldown : 0.15f,
            AbilityType.BannerOfStillness => bannerCooldown <= 0f && bannerPlantTimer <= 0f && !bannerActive
                ? 1f : 1f - bannerCooldown / BannerCooldown,
            _ => 0f,
        };
    }

    static bool IsVerdictUnlocked() => abilityUnlocked[(int)AbilityType.Verdict];

    static void TryUnlockVerdictByKills()
    {
        if (IsVerdictUnlocked() || runKillCount < VerdictUnlockKills) return;
        abilityUnlocked[(int)AbilityType.Verdict] = true;
        if (abilitySlot1 != AbilityType.Verdict && abilitySlot2 != AbilityType.Verdict)
        {
            AssignAbilityToSlot(1, AbilityType.Verdict);
        }
        SaveGame();
        SpawnFloatingText(playerPos + new Vector2(0, -52f), "VERDICT UNLOCKED", AbilityAccent(AbilityType.Verdict), 24);
        SpawnFloatingText(playerPos + new Vector2(0, -28f), "30 FOES JUDGED", Gold, 16);
        AddFlash(AbilityAccent(AbilityType.Verdict), 0.22f);
        TriggerImpact(ImpactTier.Medium, AbilityAccent(AbilityType.Verdict));
    }

    static Color AbilityAccent(AbilityType ability) => ability switch
    {
        AbilityType.Paralyze => new Color(168, 188, 212, 255),
        AbilityType.WindStep => BodyBright(),
        AbilityType.OathOfTheBailey => new Color(196, 176, 120, 255),
        AbilityType.Verdict => new Color(214, 188, 96, 255),
        AbilityType.BannerOfStillness => new Color(148, 196, 168, 255),
        _ => UiAccent,
    };

    static bool TryUnlockAbility(AbilityType ability)
    {
        int i = (int)ability;
        if (abilityUnlocked[i]) return true;
        if (AbilityFableCost[i] < 0) return false;
        int cost = AbilityFableCost[i];
        if (fables < cost) return false;
        fables -= cost;
        abilityUnlocked[i] = true;
        SaveGame();
        AddFlash(Gold, 0.22f);
        return true;
    }

    static void UpdateAbilities(float dt)
    {
        dashBlockedThisFrame = false;
        paralyzeCooldown = Math.Max(0f, paralyzeCooldown - dt);
        verdictCooldown = Math.Max(0f, verdictCooldown - dt);
        if (verdictHaltTimer > 0f) verdictHaltTimer = Math.Max(0f, verdictHaltTimer - dt);
        bannerCooldown = Math.Max(0f, bannerCooldown - dt);
        abilityIFrameTimer = Math.Max(0f, abilityIFrameTimer - dt);
        oathRescueFlashTimer = Math.Max(0f, oathRescueFlashTimer - dt);
        verdictWaveTimer = Math.Max(0f, verdictWaveTimer - dt);
        if (paralyzeBurstTimer > 0f) paralyzeBurstTimer -= dt;

        if (bannerPlantTimer > 0f)
        {
            bannerPlantTimer -= dt;
            if (bannerPlantTimer <= 0f) FinishBannerPlant();
        }

        if (bannerActive)
        {
            bannerTimer -= dt;
            if (bannerTimer <= 0f) bannerActive = false;
        }

        if (state != GameState.Playing) return;

        SyncAbilitySlotHud(0);
        SyncAbilitySlotHud(1);

        if (Raylib.IsKeyPressed(abilityKey1)) TryUseAbility(abilitySlot1, blockDash: true);
        if (Raylib.IsKeyPressed(abilityKey2)) TryUseAbility(abilitySlot2, blockDash: false);

        if (aiPilotEnabled)
        {
            if (aiParalyzeRequest) TryUseAbilityFromSlots(AbilityType.Paralyze, true);
            if (aiDashRequest && !dashBlockedThisFrame)
            {
                TryUseAbilityFromSlots(AbilityType.WindStep, true);
            }
            if (aiBannerRequest && !dashBlockedThisFrame)
            {
                TryUseAbilityFromSlots(AbilityType.BannerOfStillness, false);
            }
            if (aiVerdictRequest && !dashBlockedThisFrame)
            {
                TryUseAbilityFromSlots(AbilityType.Verdict, false);
            }
        }

        if (windDashVfxTimer > 0f) windDashVfxTimer = Math.Max(0f, windDashVfxTimer - dt);
        if (oathTilePulseTimer > 0f) oathTilePulseTimer = Math.Max(0f, oathTilePulseTimer - dt);
    }

    static void TryUseAbility(AbilityType ability, bool blockDash)
    {
        switch (ability)
        {
            case AbilityType.Paralyze:
                if (paralyzeCooldown <= 0f)
                {
                    TriggerParalyze(playerPos);
                    if (blockDash) dashBlockedThisFrame = true;
                }
                break;
            case AbilityType.WindStep:
                TryWindStep();
                break;
            case AbilityType.OathOfTheBailey:
                if (!oathUsedThisRun && HasEquippedAbility(AbilityType.OathOfTheBailey))
                {
                    SpawnFloatingText(playerPos + new Vector2(0, -30f), "OATH STANDS", AbilityAccent(ability), 18);
                    oathRescueFlashTimer = 0.35f;
                }
                break;
            case AbilityType.Verdict:
                TryVerdict();
                break;
            case AbilityType.BannerOfStillness:
                TryPlantBanner();
                break;
            default:
                throw new UnreachableException();
        }
    }

    static void TryWindStep()
    {
        if (dashCooldown > 0f || dashTimer > 0f || bannerPlantTimer > 0f) return;
        if (lastMoveDirection == Vector2.Zero) return;
        dashTimer = DashDuration;
        windDashVfxTimer = DashDuration + 0.12f;
        playerVel = lastMoveDirection * DashSpeed;
        SpawnWindStepBurst();
        AddTrauma(0.16f);
        TriggerImpact(ImpactTier.Light, BodyBright());
    }

    static void SpawnWindStepBurst()
    {
        Color wind = new Color(196, 228, 238, 255);
        Color body = BodyBright();
        for (int i = 0; i < 34; i++)
        {
            float angle = Rng.NextSingle() * MathF.PI * 2f;
            float speed = Rng.Next(80, 280);
            Vector2 back = lastMoveDirection == Vector2.Zero ? Vector2.Zero : -SafeNormalize(lastMoveDirection);
            particles.Add(new Particle
            {
                Position = playerPos + back * PlayerRadius * 0.5f,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed + back * 120f,
                Color = i % 3 == 0 ? wind : body,
                Alpha = 1f,
                Fade = 1f / (0.35f + Rng.NextSingle() * 0.35f),
                Size = 4f + Rng.NextSingle() * 7f,
                Drag = 2.4f,
                Glow = i % 2 == 0,
            });
        }
        for (int streak = 0; streak < 5; streak++)
        {
            Vector2 off = new Vector2(-lastMoveDirection.Y, lastMoveDirection.X) * (streak - 2f) * 8f;
            particles.Add(new Particle
            {
                Position = playerPos + off,
                Velocity = lastMoveDirection * 420f + off * 2f,
                Color = wind,
                Alpha = 0.9f,
                Fade = 1f / 0.22f,
                Size = 3f + streak,
                Drag = 1.2f,
                Glow = true,
            });
        }
        SpawnGfxLightPulse(playerPos, wind, 110f, 0.95f, 0.22f);
        zoomPunch = Math.Max(zoomPunch, 0.045f);
    }

    static void TryPlantBanner()
    {
        if (bannerCooldown > 0f || bannerPlantTimer > 0f || bannerActive) return;
        bannerPlantTimer = BannerPlantTime;
        bannerPos = playerPos;
        playerVel *= 0.2f;
        SpawnBannerPlantVfx(bannerPos);
        AddTrauma(0.14f);
    }

    static void FinishBannerPlant()
    {
        bannerActive = true;
        bannerTimer = BannerDuration;
        bannerCooldown = BannerCooldown;
        SpawnFloatingText(bannerPos + new Vector2(0, -36f), "STILLNESS", AbilityAccent(AbilityType.BannerOfStillness), 22);
        SpawnEventShockwave(bannerPos, AbilityAccent(AbilityType.BannerOfStillness), BannerRadius * 1.35f, 0.75f);
        AddTrauma(0.22f);
        TriggerImpact(ImpactTier.Medium, AbilityAccent(AbilityType.BannerOfStillness));
    }

    static void TryVerdict()
    {
        if (verdictCooldown > 0f || verdictHaltTimer > 0f) return;
        if (!IsVerdictUnlocked() || !HasEquippedAbility(AbilityType.Verdict)) return;

        verdictCooldown = VerdictCooldown;
        verdictHaltTimer = VerdictHaltDuration;
        abilityIFrameTimer = VerdictIFrameTime;
        verdictWaveOrigin = playerPos;
        verdictWaveTimer = VerdictWaveTime;

        if (activeEvent != FloorEventType.None) EndFloorEvent();
        floorRotTimer = 0f;
        floorRotSide = 0f;
        eventCountdown = 0f;
        eventPhase = 0;

        SpawnVerdictVfx(playerPos);
        SpawnFloatingText(playerPos + new Vector2(0, -40f), "VERDICT", AbilityAccent(AbilityType.Verdict), 24);
        SpawnFloatingText(playerPos + new Vector2(0, -18f), "EVENTS HALTED 30s", Color.White, 15);
        AddTrauma(0.42f);
        zoomPunch = Math.Max(zoomPunch, 0.07f);
        TriggerImpact(ImpactTier.Major, AbilityAccent(AbilityType.Verdict));
    }

    static bool TryOathOfTheBailey(DeathCause cause)
    {
        if (cause != DeathCause.FellThrough && cause != DeathCause.FloorGaveWay) return false;
        if (!HasEquippedAbility(AbilityType.OathOfTheBailey) || oathUsedThisRun) return false;
        if (!TryFindNearestSolidTile(playerPos, out Vector2 snap, out int tx, out int ty)) return false;

        oathUsedThisRun = true;
        playerPos = snap;
        playerVel = Vector2.Zero;
        abilityIFrameTimer = OathIFrameTime;
        oathRescueFlashTimer = OathRescueFlashTime;

        ref Tile tile = ref tiles[tx, ty];
        tile.State = 0;
        tile.Durability = MaxDurability;
        tile.Collapse = 0f;
        tile.EventMarked = false;
        tile.RegrowTimer = 0f;
        oathReinforcedTx = tx;
        oathReinforcedTy = ty;
        oathTilePulseTimer = 3.2f;

        SpawnOathRescueVfx(snap, tx, ty);
        SpawnFloatingText(snap + new Vector2(0, -44f), "OATH OF THE BAILEY", AbilityAccent(AbilityType.OathOfTheBailey), 22);
        SpawnFloatingText(snap + new Vector2(0, -20f), "STONE HOLDS", Color.White, 16);
        AddTrauma(0.55f);
        zoomPunch = Math.Max(zoomPunch, 0.09f);
        TriggerImpact(ImpactTier.Major, AbilityAccent(AbilityType.OathOfTheBailey));
        return true;
    }

    static bool TryFindNearestSolidTile(Vector2 from, out Vector2 snapPos, out int tileX, out int tileY)
    {
        snapPos = from;
        tileX = tileY = 0;
        float best = float.MaxValue;
        bool found = false;
        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                ref Tile t = ref tiles[x, y];
                if (t.State == 2 || t.EventMarked) continue;
                if (t.Durability < MaxDurability * 0.12f) continue;
                Vector2 c = TileCenter(x, y);
                float d = Vector2.DistanceSquared(from, c);
                if (d >= best) continue;
                best = d;
                snapPos = c;
                tileX = x;
                tileY = y;
                found = true;
            }
        }
        return found;
    }

    static void SpawnBannerPlantVfx(Vector2 origin)
    {
        Color banner = AbilityAccent(AbilityType.BannerOfStillness);
        for (int i = 0; i < 22; i++)
        {
            float angle = i * (MathF.PI * 2f / 22f);
            particles.Add(new Particle
            {
                Position = origin,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * Rng.Next(60, 180),
                Color = i % 2 == 0 ? banner : Color.White,
                Alpha = 1f,
                Fade = 1f / 0.45f,
                Size = 4f + Rng.NextSingle() * 4f,
                Drag = 3.2f,
                Glow = i % 3 == 0,
            });
        }
        SpawnGfxLightPulse(origin, banner, 70f, 0.7f, 0.18f);
    }

    static void SpawnVerdictVfx(Vector2 origin)
    {
        Color gold = AbilityAccent(AbilityType.Verdict);
        for (int ring = 0; ring < 16; ring++)
        {
            float angle = ring * (MathF.PI * 2f / 16f);
            particles.Add(new Particle
            {
                Position = origin,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 420f,
                Color = gold,
                Alpha = 1f,
                Fade = 1f / 0.55f,
                Size = 6f + Rng.NextSingle() * 5f,
                Drag = 2.4f,
                Glow = true,
            });
        }
        SpawnEventShockwave(origin, gold, 240f, 0.9f);
        SpawnGfxLightPulse(origin, Color.White, 160f, 1.1f, 0.22f);
    }

    static void SpawnOathRescueVfx(Vector2 origin, int tx, int ty)
    {
        Color gold = AbilityAccent(AbilityType.OathOfTheBailey);
        SpawnEventShockwave(origin, gold, 200f, 1f);
        SpawnGfxLightPulse(origin, Color.White, 150f, 1.2f, 0.28f);
        for (int i = 0; i < 36; i++)
        {
            float angle = i * (MathF.PI * 2f / 36f);
            particles.Add(new Particle
            {
                Position = origin + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 18f,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * Rng.Next(90, 260),
                Color = i % 3 == 0 ? gold : new Color(148, 140, 128, 255),
                Alpha = 1f,
                Fade = 1f / (0.5f + Rng.NextSingle() * 0.35f),
                Size = 5f + Rng.NextSingle() * 6f,
                Drag = 2.6f,
                Glow = i % 2 == 0,
            });
        }
        SpawnRegrowBurst(TileCenter(tx, ty));
    }

    static void TriggerParalyze(Vector2 origin)
    {
        float radius = EffParalyzeRadius();
        float duration = EffParalyzeDuration();
        int hit = 0;

        for (int i = 0; i < enemies.Count; i++)
        {
            Enemy enemy = enemies[i];
            if (enemy.Dead || enemy.Spawn < 0.5f) continue;
            if (Vector2.Distance(origin, enemy.Position) > radius + enemy.Radius) continue;

            ref readonly EnemyDef def = ref GetDef(enemy.Type);
            float hold = def.Boss ? duration * 0.55f : duration;
            enemy.ParalyzeTimer = Math.Max(enemy.ParalyzeTimer, hold);
            enemies[i] = enemy;
            hit++;
        }

        paralyzeCooldown = EffParalyzeCooldown();
        paralyzeBurstTimer = ParalyzeBurstTime;
        paralyzeBurstOrigin = origin;
        paralyzeBurstRadius = radius;

        if (aiPilotEnabled)
        {
            aiPostParalyzeGrace = MathF.Max(EffParalyzeDuration() * 0.9f, 1.2f);
        }

        SpawnParalyzeVfx(origin, radius, hit);
        SpawnFloatingText(origin + new Vector2(0, -34f), hit > 0 ? "PARALYZE" : "PARALYZE", new Color(196, 214, 232, 255), 20);
        AddTrauma(hit > 0 ? 0.28f : 0.12f);
        zoomPunch = Math.Max(zoomPunch, 0.045f);
        TriggerImpact(hit > 0 ? ImpactTier.Medium : ImpactTier.Light, new Color(168, 188, 210, 255));
    }

    static void SpawnParalyzeVfx(Vector2 origin, float radius, int hits)
    {
        Color core = new Color(214, 226, 238, 255);
        Color arc = new Color(148, 168, 196, 255);
        int burst = 28 + hits * 4;

        for (int i = 0; i < burst; i++)
        {
            float angle = Rng.NextSingle() * MathF.PI * 2f;
            float dist = radius * (0.25f + Rng.NextSingle() * 0.75f);
            Vector2 pos = origin + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * dist;
            Vector2 vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * Rng.Next(80, 240);
            bool glow = i % 3 == 0;
            particles.Add(new Particle
            {
                Position = pos,
                Velocity = vel,
                Color = glow ? core : arc,
                Alpha = 1f,
                Fade = 1f / (0.35f + Rng.NextSingle() * 0.45f),
                Rotation = Rng.NextSingle() * 360f,
                Spin = (Rng.NextSingle() - 0.5f) * 420f,
                Size = glow ? 6f + Rng.NextSingle() * 5f : 3f + Rng.NextSingle() * 3f,
                Drag = 2.8f,
                Glow = glow,
            });
        }

        for (int ring = 0; ring < 12; ring++)
        {
            float angle = ring * (MathF.PI * 2f / 12f);
            particles.Add(new Particle
            {
                Position = origin + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * radius * 0.92f,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 60f,
                Color = core,
                Alpha = 0.95f,
                Fade = 1f / 0.55f,
                Size = 5f,
                Drag = 4.5f,
                Glow = true,
            });
        }
    }

    static void DrawParalyzeBurst()
    {
        if (paralyzeBurstTimer <= 0f) return;

        float t = 1f - paralyzeBurstTimer / ParalyzeBurstTime;
        float expand = paralyzeBurstRadius * (0.35f + t * 1.15f);
        float fade = 1f - t;
        Color ring = new Color(186, 204, 224, 255);
        Color core = new Color(228, 236, 244, 255);
        Color arc = new Color(132, 168, 214, 255);
        float time = (float)Raylib.GetTime();

        DrawGlow(paralyzeBurstOrigin, expand * 0.55f, core, 0.08f * fade);
        DrawGlowFast(paralyzeBurstOrigin, expand * 0.35f, arc, 0.06f * fade);
        Raylib.DrawRing(paralyzeBurstOrigin, expand * 0.82f, expand, 0f, 360f, 64, WithAlpha(ring, 0.55f * fade));
        Raylib.DrawRing(paralyzeBurstOrigin, expand * 0.55f, expand * 0.72f, 0f, 360f, 48, WithAlpha(Color.White, 0.35f * fade));
        Raylib.DrawCircleV(paralyzeBurstOrigin, 10f + t * 18f, WithAlpha(core, 0.25f * fade));

        for (int i = 0; i < 8; i++)
        {
            float a = time * 9f + i * 1.047f;
            Vector2 end = paralyzeBurstOrigin + new Vector2(MathF.Cos(a), MathF.Sin(a)) * expand * 0.9f;
            Raylib.DrawLineEx(paralyzeBurstOrigin, end, 2.5f, WithAlpha(ring, 0.45f * fade));
            Raylib.DrawCircleV(end, 4f, WithAlpha(core, 0.35f * fade));
        }

        for (int bolt = 0; bolt < 4; bolt++)
        {
            float a0 = time * 11f + bolt * 1.57f;
            Vector2 p0 = paralyzeBurstOrigin + new Vector2(MathF.Cos(a0), MathF.Sin(a0)) * expand * 0.35f;
            Vector2 p1 = paralyzeBurstOrigin + new Vector2(MathF.Cos(a0 + 0.4f), MathF.Sin(a0 + 0.4f)) * expand * 0.75f;
            Vector2 mid = (p0 + p1) * 0.5f + new Vector2(MathF.Cos(a0 + 1.2f), MathF.Sin(a0 + 1.2f)) * 18f;
            Raylib.DrawLineEx(p0, mid, 2f, WithAlpha(Color.White, 0.55f * fade));
            Raylib.DrawLineEx(mid, p1, 2f, WithAlpha(arc, 0.65f * fade));
        }
    }

    static void DrawWindStepAura()
    {
        if (windDashVfxTimer <= 0f && dashTimer <= 0f) return;
        if (!HasEquippedAbility(AbilityType.WindStep)) return;

        float time = (float)Raylib.GetTime();
        Color wind = new Color(186, 224, 236, 255);
        float intensity = dashTimer > 0f ? 1f : windDashVfxTimer / 0.12f;
        Vector2 dir = lastMoveDirection == Vector2.Zero ? Vector2.UnitY : SafeNormalize(lastMoveDirection);
        Vector2 perp = new Vector2(-dir.Y, dir.X);

        for (int i = 0; i < 4; i++)
        {
            float along = -PlayerRadius - i * 14f - MathF.Sin(time * 18f + i) * 4f;
            Vector2 p = playerPos + dir * along + perp * MathF.Sin(time * 12f + i * 1.3f) * 6f;
            float alpha = (0.35f - i * 0.06f) * intensity;
            Raylib.DrawCircleV(p, 7f - i, WithAlpha(wind, alpha));
            DrawGlow(p, 16f, wind, alpha * 0.12f);
        }

        Raylib.DrawCircleLinesV(playerPos, PlayerRadius + 6f + MathF.Sin(time * 14f) * 2f, WithAlpha(wind, 0.45f * intensity));
    }

    static void DrawBannerOfStillness()
    {
        if (!bannerActive && bannerPlantTimer <= 0f) return;
        float time = (float)Raylib.GetTime();
        Color banner = AbilityAccent(AbilityType.BannerOfStillness);
        Color rune = new Color(214, 232, 220, 255);
        Vector2 pos = bannerPos;
        float pulse = MathF.Sin(time * 3.2f) * 0.5f + 0.5f;

        if (bannerPlantTimer > 0f)
        {
            float plantT = 1f - bannerPlantTimer / BannerPlantTime;
            float shaftH = 18f + plantT * 42f;
            Vector2 basePos = pos + new Vector2(0, 8f);
            Vector2 topPos = pos + new Vector2(0, -shaftH);
            Raylib.DrawCircleV(basePos, 10f + plantT * 8f, WithAlpha(banner, 0.2f * plantT));
            Raylib.DrawLineEx(basePos, topPos, 4f, new Color(92, 78, 58, 255));
            Raylib.DrawLineEx(basePos, topPos, 2f, WithAlpha(banner, 0.55f * plantT));
            Raylib.DrawCircleV(topPos, 6f + plantT * 4f, WithAlpha(Color.White, 0.5f + plantT * 0.35f));
            DrawGlow(pos, 24f + plantT * 28f, banner, 0.08f * plantT);
            return;
        }

        float radius = BannerRadius * (0.92f + pulse * 0.04f);
        DrawGlowFast(pos, radius * 0.55f, banner, 0.06f + pulse * 0.04f);
        Raylib.DrawRing(pos, radius * 0.78f, radius, 0f, 360f, 72, WithAlpha(banner, 0.24f + pulse * 0.1f));
        Raylib.DrawRing(pos, radius * 0.42f, radius * 0.58f, 0f, 360f, 48, WithAlpha(Color.White, 0.1f + pulse * 0.06f));

        for (int i = 0; i < 12; i++)
        {
            float a = i * (MathF.PI * 2f / 12f) + time * 0.25f;
            Vector2 rim = pos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * radius * 0.9f;
            Raylib.DrawCircleV(rim, 3f, WithAlpha(rune, 0.25f + pulse * 0.2f));
        }

        float shaft = 58f;
        Vector2 flagPoleBase = pos + new Vector2(0, 10f);
        Vector2 flagTop = pos + new Vector2(0, -shaft);
        Raylib.DrawLineEx(flagPoleBase, flagTop, 5f, new Color(72, 62, 48, 255));
        Raylib.DrawLineEx(flagPoleBase, flagTop, 2f, WithAlpha(new Color(148, 132, 108, 255), 0.8f));
        Vector2 flagMid = flagTop + new Vector2(30f + MathF.Sin(time * 4f) * 5f, 12f);
        Vector2 flagBot = flagTop + new Vector2(26f + MathF.Sin(time * 4f + 0.8f) * 4f, 30f);
        Raylib.DrawTriangle(flagTop, flagMid, flagBot, WithAlpha(banner, 0.92f));
        Raylib.DrawTriangle(flagTop, flagMid, flagBot, WithAlpha(Color.White, 0.08f));
        Raylib.DrawLineEx(flagTop, flagMid, 1.5f, WithAlpha(Color.White, 0.5f));
        Raylib.DrawLineEx(flagMid, flagBot, 1.5f, WithAlpha(Color.White, 0.28f));
        Raylib.DrawCircleV(flagTop + new Vector2(8f, 14f), 4f, WithAlpha(rune, 0.65f));

        for (int i = 0; i < 10; i++)
        {
            float a = time * 0.65f + i * (MathF.PI * 2f / 10f);
            Vector2 mote = pos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * radius * (0.3f + Hash(i) * 0.5f);
            Raylib.DrawCircleV(mote, 2.5f, WithAlpha(Color.White, 0.12f + pulse * 0.22f));
        }

        if (IsInBannerZone(playerPos))
        {
            DrawGlow(playerPos, PlayerRadius + 22f, banner, 0.05f + pulse * 0.04f);
            Raylib.DrawCircleLinesV(playerPos, PlayerRadius + 10f + pulse * 4f, WithAlpha(banner, 0.35f));
        }
    }

    static void DrawOathRescueFlash()
    {
        if (oathRescueFlashTimer <= 0f) return;
        float t = 1f - oathRescueFlashTimer / OathRescueFlashTime;
        float fade = 1f - t;
        Color gold = AbilityAccent(AbilityType.OathOfTheBailey);
        Color stone = new Color(148, 140, 128, 255);
        float ring = 40f + t * 240f;
        DrawGlow(playerPos, ring * 0.45f, gold, 0.14f * fade);
        Raylib.DrawRing(playerPos, ring * 0.72f, ring, 0f, 360f, 64, WithAlpha(gold, 0.58f * fade));
        Raylib.DrawRing(playerPos, ring * 0.35f, ring * 0.55f, 0f, 360f, 48, WithAlpha(Color.White, 0.38f * fade));

        for (int i = 0; i < 8; i++)
        {
            float a = i * (MathF.PI / 4f) + t * 2.4f;
            Vector2 p = playerPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * (24f + t * 42f);
            Raylib.DrawRectanglePro(
                new Rectangle(p.X, p.Y, 10f, 6f),
                new Vector2(5f, 3f), a * (180f / MathF.PI), WithAlpha(stone, 0.55f * fade));
        }

        Raylib.DrawCircleV(playerPos, 14f + t * 8f, WithAlpha(gold, 0.22f * fade));
    }

    static void DrawOathReinforcedTile()
    {
        if (oathTilePulseTimer <= 0f || oathReinforcedTx < 0) return;
        float t = oathTilePulseTimer / 3.2f;
        float pulse = MathF.Sin((1f - t) * MathF.PI * 6f) * 0.5f + 0.5f;
        Vector2 center = TileCenter(oathReinforcedTx, oathReinforcedTy);
        Color gold = AbilityAccent(AbilityType.OathOfTheBailey);
        float half = TileSize * 0.46f;
        var tileRect = new Rectangle(center.X - half, center.Y - half, half * 2f, half * 2f);
        Raylib.DrawRectangleLinesEx(tileRect, 2f, WithAlpha(gold, 0.35f + pulse * 0.45f));
        DrawGlow(center, TileSize * 0.55f, gold, 0.04f + pulse * 0.05f);
        Raylib.DrawCircleV(center, 5f + pulse * 4f, WithAlpha(Color.White, 0.2f + pulse * 0.25f));
    }

    static void DrawVerdictWave()
    {
        if (verdictWaveTimer <= 0f) return;
        float t = 1f - verdictWaveTimer / VerdictWaveTime;
        float fade = 1f - t;
        Color gold = AbilityAccent(AbilityType.Verdict);
        float expand = 60f + t * 380f;
        DrawGlowFast(verdictWaveOrigin, expand * 0.38f, gold, 0.06f * fade);
        Raylib.DrawRing(verdictWaveOrigin, expand * 0.82f, expand, 0f, 360f, 72, WithAlpha(gold, 0.5f * fade));
        Raylib.DrawRing(verdictWaveOrigin, expand * 0.55f, expand * 0.72f, 0f, 360f, 56, WithAlpha(Color.White, 0.32f * fade));
        Raylib.DrawCircleV(verdictWaveOrigin, 12f + t * 20f, WithAlpha(Color.White, 0.25f * fade));
    }

    static void DrawVerdictHaltOverlay()
    {
        if (verdictHaltTimer <= 0f) return;
        float time = (float)Raylib.GetTime();
        float pulse = MathF.Sin(time * 3f) * 0.5f + 0.5f;
        Color gold = AbilityAccent(AbilityType.Verdict);

        Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(gold, 0.03f + pulse * 0.02f));
        Raylib.DrawRectangleLinesEx(new Rectangle(8f, 8f, WindowWidth - 16f, WindowHeight - 16f), 2f, WithAlpha(gold, 0.22f + pulse * 0.18f));

        int cx = WindowWidth / 2;
        string label = "VERDICT  ·  EVENTS HALTED  " + Math.Ceiling(verdictHaltTimer).ToString("0") + "s";
        int lw = Raylib.MeasureText(label, 14);
        var banner = new Rectangle(cx - lw / 2f - 16f, 18f, lw + 32f, 28f);
        DrawRichPanel(banner, WithAlpha(UiPanel, 0.88f), gold, 0.2f, accentStripe: true);
        Raylib.DrawText(label, cx - lw / 2, 24, 14, Color.White);
    }

    static void DrawVerdictTelegraph()
    {
        if (!IsVerdictUnlocked() || !HasEquippedAbility(AbilityType.Verdict)) return;
        if (verdictCooldown > 0f || verdictHaltTimer > 0f) return;
        if (activeEvent == FloorEventType.None && floorRotTimer <= 0f) return;

        float time = (float)Raylib.GetTime();
        float pulse = MathF.Sin(time * 5f) * 0.5f + 0.5f;
        Color gold = AbilityAccent(AbilityType.Verdict);
        ShadowTextCentered("VERDICT READY — END THE EVENT", WindowWidth / 2, WindowHeight - 118, 12, WithAlpha(gold, 0.55f + pulse * 0.35f), 1f);
    }

    static void SpawnWalkDust(float dt)
    {
        if (playerVel.LengthSquared() < 1600f) return;

        stepTimer -= dt;
        if (stepTimer > 0f) return;

        stepTimer = 0.07f;
        Vector2 back = playerVel == Vector2.Zero ? Vector2.Zero : -Vector2.Normalize(playerVel);
        particles.Add(new Particle
        {
            Position = playerPos + back * PlayerRadius,
            Velocity = back * 30f,
            Color = Lighten(Emerald, 0.2f),
            Alpha = 0.5f,
            Fade = 1f / 0.4f,
            Size = 3f,
            Drag = 4f,
            Glow = true,
        });
    }

    static void SpawnBlightSpores(Vector2 origin)
    {
        int count = activeEvent == FloorEventType.BlightStorm ? Rng.Next(10, 16) : Rng.Next(16, 24);
        for (int i = 0; i < count; i++)
        {
            float angle = Rng.NextSingle() * MathF.PI * 2f;
            float speed = Rng.Next(20, 70);
            particles.Add(new Particle
            {
                Position = origin + new Vector2(Rng.Next(-20, 20), Rng.Next(-20, 20)),
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                Color = new Color(138, 96, 48, 255),
                Alpha = 1f,
                Fade = 1f / (0.8f + Rng.NextSingle() * 0.6f),
                Rotation = Rng.NextSingle() * 360f,
                Spin = (Rng.NextSingle() - 0.5f) * 200f,
                Size = 4f + Rng.NextSingle() * 4f,
                Drag = 1.8f,
                Glow = false,
            });
        }
    }

    static void SpawnFloatingText(Vector2 pos, string text, Color color, int size)
    {
        floaters.Add(new FloatingText
        {
            Position = pos,
            Velocity = new Vector2((Rng.NextSingle() - 0.5f) * 30f, -55f),
            Text = text,
            Color = color,
            Life = 0.9f,
            MaxLife = 0.9f,
            Size = size,
        });
    }

    // ---------------------------------------------------------------- Sim helpers

    static void UpdateParticles(float dt)
    {
        // Cap particle count so heavy combat can't balloon the list and tank frame pacing.
        if (particles.Count > MaxParticles)
        {
            particles.RemoveRange(0, particles.Count - MaxParticles);
        }

        float time = (float)Raylib.GetTime();
        for (int i = particles.Count - 1; i >= 0; i--)
        {
            Particle p = particles[i];
            p.Velocity *= MathF.Exp(-p.Drag * dt);
            p.Velocity.Y += MathF.Sin(time * 3f + p.Position.X * 0.05f) * 6f * dt;
            p.Position += p.Velocity * dt;
            p.Rotation += p.Spin * dt;
            p.Alpha -= p.Fade * dt;

            if (p.Alpha <= 0f) particles.RemoveAt(i);
            else particles[i] = p;
        }
    }

    static void UpdateTrails(float dt)
    {
        for (int i = trails.Count - 1; i >= 0; i--)
        {
            DashTrail t = trails[i];
            t.Alpha -= dt * 3.2f;
            if (t.Alpha <= 0f) trails.RemoveAt(i);
            else trails[i] = t;
        }
    }

    static void UpdateFloaters(float dt)
    {
        for (int i = floaters.Count - 1; i >= 0; i--)
        {
            FloatingText f = floaters[i];
            f.Position += f.Velocity * dt;
            f.Velocity *= MathF.Exp(-2.5f * dt);
            f.Life -= dt;
            if (f.Life <= 0f) floaters.RemoveAt(i);
            else floaters[i] = f;
        }
    }

    static void AddTrauma(float amount) => trauma = Math.Clamp(trauma + amount, 0f, 1f);

    enum ImpactTier { Light, Medium, Major }

    static bool ProcessHitStop(float dt)
    {
        if (hitstop <= 0f) return false;

        hitstop = Math.Max(0f, hitstop - dt);
        impactFlash *= MathF.Exp(-34f * dt);
        trauma = Math.Max(0f, trauma - TraumaDecay * dt);
        UpdateParticles(dt);
        UpdateTrails(dt);
        UpdateFloaters(dt);
        return true;
    }

    static void TriggerImpact(ImpactTier tier, Color flashColor)
    {
        impactFlashColor = flashColor;
        switch (tier)
        {
            case ImpactTier.Light:
                hitstop = Math.Max(hitstop, 0.028f);
                impactFlash = Math.Max(impactFlash, 0.55f);
                impactFlashSharp = false;
                AddFlash(flashColor, 0.13f);
                break;
            case ImpactTier.Medium:
                hitstop = Math.Max(hitstop, 0.085f);
                impactFlash = 1f;
                impactFlashSharp = true;
                AddFlash(flashColor, 0.28f);
                zoomPunch = Math.Max(zoomPunch, 0.065f);
                SpawnGfxLightPulse(playerPos, flashColor, 180f, 1.15f, 0.38f);
                break;
            case ImpactTier.Major:
                hitstop = Math.Max(hitstop, 0.16f);
                impactFlash = 1f;
                impactFlashSharp = true;
                impactFlashColor = Color.White;
                AddFlash(flashColor, 0.55f);
                zoomPunch = Math.Max(zoomPunch, 0.12f);
                SpawnGfxLightPulse(playerPos, flashColor, 360f, 1.85f, 0.68f);
                break;
            default:
                throw new UnreachableException();
        }
    }

    static void RegisterWeaponImpact(Vector2 pos, Color color, float damage, GunFireStyle style)
    {
        if (style == GunFireStyle.Mortar)
        {
            TriggerImpact(ImpactTier.Medium, color);
            AddTrauma(0.28f);
            zoomPunch = Math.Max(zoomPunch, 0.075f);
            return;
        }

        if (style == GunFireStyle.Sniper || style == GunFireStyle.Lance)
        {
            TriggerImpact(ImpactTier.Medium, color);
            AddTrauma(0.12f);
            zoomPunch = Math.Max(zoomPunch, 0.035f);
            return;
        }

        if (damage >= 20f)
        {
            TriggerImpact(ImpactTier.Light, color);
            zoomPunch = Math.Max(zoomPunch, 0.028f);
            AddTrauma(0.06f);
        }
        else if (damage >= 12f)
        {
            AddTrauma(0.035f);
            zoomPunch = Math.Max(zoomPunch, 0.016f);
        }
    }

    static void AddFlash(Color c, float amount)
    {
        if (amount >= flash) flashColor = c;
        flash = Math.Max(flash, amount);
    }

    static bool TryGetTileUnder(Vector2 position, out int tileX, out int tileY)
    {
        tileX = (int)(position.X / TileSize);
        tileY = (int)(position.Y / TileSize);
        return tileX >= 0 && tileX < GridSize && tileY >= 0 && tileY < GridSize;
    }

    static Vector2 RandomEdgePosition(float radius)
    {
        int edge = Rng.Next(4);
        return edge switch
        {
            0 => new Vector2(Rng.Next((int)radius, WindowWidth - (int)radius), radius),
            1 => new Vector2(Rng.Next((int)radius, WindowWidth - (int)radius), WindowHeight - radius),
            2 => new Vector2(radius, Rng.Next((int)radius, WindowHeight - (int)radius)),
            3 => new Vector2(WindowWidth - radius, Rng.Next((int)radius, WindowHeight - (int)radius)),
            _ => throw new UnreachableException(),
        };
    }

    static float GetEnemyRadius(EnemyType type) => GetDef(type).Radius;

    static string GetEnemyName(EnemyType type) => GetDef(type).Name;

    static string GetEnemyDesc(EnemyType type) => GetDef(type).Desc;

    static Color GetEnemyColor(EnemyType type) => GetDef(type).Color;

    static int GetEnemySides(EnemyType type) => GetDef(type).Sides;

    static Color ComboColor(int c)
    {
        if (c < 3) return Color.White;
        if (c < 5) return Gold;
        if (c < 8) return new Color(196, 108, 48, 255);
        return Danger;
    }

    static Color WithAlpha(Color c, float a)
    {
        int alpha = (int)Math.Clamp(a * 255f, 0f, 255f);
        return new Color((int)c.R, (int)c.G, (int)c.B, alpha);
    }

    static Color LerpColor(Color a, Color b, float t)
    {
        t = Math.Clamp(t, 0f, 1f);
        return new Color(
            (int)(a.R + (b.R - a.R) * t),
            (int)(a.G + (b.G - a.G) * t),
            (int)(a.B + (b.B - a.B) * t),
            (int)(a.A + (b.A - a.A) * t));
    }

    static Color Darken(Color c, float a) => LerpColor(c, ForestShadow, a);
    static Color Lighten(Color c, float a) => LerpColor(c, Color.White, a);

    static float Hash(int n)
    {
        n = (n << 13) ^ n;
        int m = (n * (n * n * 15731 + 789221) + 1376312589) & 0x7fffffff;
        return 1f - m / 1073741824f;
    }

    static Color TileFill(float durability)
    {
        float t = Math.Clamp(durability / MaxDurability, 0f, 1f);
        return GetTileHealthVisual(t) switch
        {
            TileHealthVisual.Pristine => LerpColor(MossLight, Lighten(Emerald, 0.08f), Math.Clamp((t - 0.92f) / 0.08f, 0f, 1f)),
            TileHealthVisual.Sturdy => LerpColor(MossLight, Emerald, (t - 0.7f) / 0.22f),
            TileHealthVisual.Worn => LerpColor(Amber, MossLight, (t - 0.5f) / 0.2f),
            TileHealthVisual.Cracked => LerpColor(new Color(62, 58, 54, 255), Amber, (t - 0.35f) / 0.15f),
            TileHealthVisual.Fractured => LerpColor(new Color(48, 42, 40, 255), new Color(72, 58, 52, 255), (t - 0.2f) / 0.15f),
            TileHealthVisual.Critical => LerpColor(new Color(36, 30, 28, 255), new Color(58, 44, 40, 255), t / 0.2f),
            _ => Danger,
        };
    }

    static TileHealthVisual GetTileHealthVisual(float ratio)
    {
        if (ratio >= 0.92f) return TileHealthVisual.Pristine;
        if (ratio >= 0.7f) return TileHealthVisual.Sturdy;
        if (ratio >= 0.5f) return TileHealthVisual.Worn;
        if (ratio >= 0.35f) return TileHealthVisual.Cracked;
        if (ratio >= 0.2f) return TileHealthVisual.Fractured;
        return TileHealthVisual.Critical;
    }

    static Color TileHealthAccent(TileHealthVisual band) => band switch
    {
        TileHealthVisual.Pristine => Lighten(MossLight, 0.35f),
        TileHealthVisual.Sturdy => MossLight,
        TileHealthVisual.Worn => Amber,
        TileHealthVisual.Cracked => new Color(88, 72, 58, 255),
        TileHealthVisual.Fractured => new Color(96, 62, 52, 255),
        TileHealthVisual.Critical => new Color(118, 52, 44, 255),
        _ => Danger,
    };

    static void DrawTileStonePattern(Rectangle bodyRect, int x, int y, Color fill, TileHealthVisual band)
    {
        if (band is not (TileHealthVisual.Pristine or TileHealthVisual.Sturdy or TileHealthVisual.Worn)) return;

        float inset = 3f;
        float cellW = (bodyRect.Width - inset * 2f) / 2f - 0.5f;
        float cellH = (bodyRect.Height - inset * 2f) / 2f - 0.5f;
        int seed = x * 48271 + y * 29347;

        for (int gy = 0; gy < 2; gy++)
        {
            for (int gx = 0; gx < 2; gx++)
            {
                float jitter = Hash(seed + gx + gy * 2) * 0.04f;
                bool light = (gx + gy + x + y) % 2 == 0;
                Color cell = light ? Lighten(fill, 0.05f + jitter) : Darken(fill, 0.04f + jitter);
                if (band == TileHealthVisual.Worn && Hash(seed + gx * 3 + gy) > 0.55f)
                {
                    cell = Darken(cell, 0.08f);
                }

                var cellRect = new Rectangle(
                    bodyRect.X + inset + gx * (cellW + 1f),
                    bodyRect.Y + inset + gy * (cellH + 1f),
                    cellW, cellH);
                Raylib.DrawRectangleRounded(cellRect, 0.08f, 4, WithAlpha(cell, band == TileHealthVisual.Pristine ? 0.42f : 0.3f));
            }
        }

        float mortarA = band == TileHealthVisual.Pristine ? 0.18f : 0.12f;
        float midX = bodyRect.X + bodyRect.Width / 2f;
        float midY = bodyRect.Y + bodyRect.Height / 2f;
        Raylib.DrawLineEx(new Vector2(midX, bodyRect.Y + inset), new Vector2(midX, bodyRect.Y + bodyRect.Height - inset), 0.8f,
            WithAlpha(Darken(fill, 0.2f), mortarA));
        Raylib.DrawLineEx(new Vector2(bodyRect.X + inset, midY), new Vector2(bodyRect.X + bodyRect.Width - inset, midY), 0.8f,
            WithAlpha(Darken(fill, 0.2f), mortarA));
    }

    static void DrawTileMossFlecks(Rectangle bodyRect, int x, int y)
    {
        int seed = x * 92821 + y * 68917;
        for (int i = 0; i < 4; i++)
        {
            float fx = bodyRect.X + 5f + Hash(seed + i * 5) * (bodyRect.Width - 10f);
            float fy = bodyRect.Y + 5f + Hash(seed + i * 5 + 2) * (bodyRect.Height - 10f);
            float r = 1f + Hash(seed + i * 5 + 4) * 1.4f;
            Raylib.DrawCircleV(new Vector2(fx, fy), r, WithAlpha(Lighten(MossLight, 0.25f), 0.38f));
            Raylib.DrawCircleV(new Vector2(fx + 0.6f, fy - 0.4f), r * 0.45f, WithAlpha(LeafGold, 0.22f));
        }
    }

    static void DrawTileCornerChips(Rectangle bodyRect, int x, int y, Color fill, float severity)
    {
        int seed = x * 73856093 ^ y * 19349663;
        Color chip = WithAlpha(Darken(fill, 0.35f), 0.45f + severity * 0.35f);
        float s = 3f + severity * 2.5f;

        if (Hash(seed) > 0.25f)
        {
            Raylib.DrawTriangle(
                new Vector2(bodyRect.X + 2f, bodyRect.Y + 2f),
                new Vector2(bodyRect.X + 2f + s, bodyRect.Y + 2f),
                new Vector2(bodyRect.X + 2f, bodyRect.Y + 2f + s),
                chip);
        }
        if (Hash(seed + 11) > 0.35f)
        {
            float br = bodyRect.X + bodyRect.Width;
            float bb = bodyRect.Y + bodyRect.Height;
            Raylib.DrawTriangle(
                new Vector2(br - 2f, bb - 2f),
                new Vector2(br - 2f - s, bb - 2f),
                new Vector2(br - 2f, bb - 2f - s),
                chip);
        }
        if (severity > 0.45f && Hash(seed + 23) > 0.4f)
        {
            float br = bodyRect.X + bodyRect.Width;
            Raylib.DrawTriangle(
                new Vector2(br - 2f, bodyRect.Y + 2f),
                new Vector2(br - 2f - s, bodyRect.Y + 2f),
                new Vector2(br - 2f, bodyRect.Y + 2f + s),
                chip);
        }
    }

    static void DrawTileHealthMeter(Rectangle bodyRect, float ratio, TileHealthVisual band)
    {
        if (band is TileHealthVisual.Pristine or TileHealthVisual.Sturdy) return;

        float barH = 3f;
        float barW = bodyRect.Width - 8f;
        float bx = bodyRect.X + 4f;
        float by = bodyRect.Y + bodyRect.Height - barH - 3f;
        var track = new Rectangle(bx, by, barW, barH);

        Raylib.DrawRectangleRounded(track, 0.5f, 3, WithAlpha(ForestShadow, 0.62f));
        Color barCol = TileHealthAccent(band);
        float fillW = MathF.Max(0f, barW * ratio);
        if (fillW > 0.5f)
        {
            var fill = new Rectangle(bx, by, fillW, barH);
            Raylib.DrawRectangleRounded(fill, 0.5f, 3, WithAlpha(Darken(barCol, 0.15f), 0.88f));
            Raylib.DrawRectangleGradientV((int)fill.X, (int)fill.Y, (int)fill.Width, (int)fill.Height,
                WithAlpha(Lighten(barCol, 0.22f), 0.55f), WithAlpha(barCol, 0.78f));
        }
        Raylib.DrawRectangleRoundedLines(track, 0.5f, 3, WithAlpha(Darken(barCol, 0.2f), 0.5f));
    }

    static void DrawTileHealthSurface(
        int x, int y, float cx, float cy, Rectangle bodyRect, Color fill,
        float ratio, TileHealthVisual band, Tile tile, float time)
    {
        switch (band)
        {
            case TileHealthVisual.Pristine:
                DrawTileStonePattern(bodyRect, x, y, fill, band);
                DrawTileMossFlecks(bodyRect, x, y);
                Raylib.DrawRectangleRoundedLines(bodyRect, 0.12f, 6, WithAlpha(Lighten(MossLight, 0.2f), 0.22f));
                break;

            case TileHealthVisual.Sturdy:
                DrawTileStonePattern(bodyRect, x, y, fill, band);
                if ((x + y) % 5 == 0)
                {
                    DrawTileMossFlecks(bodyRect, x, y);
                }
                break;

            case TileHealthVisual.Worn:
                DrawTileStonePattern(bodyRect, x, y, fill, band);
                DrawTileCornerChips(bodyRect, x, y, fill, 0.25f);
                DrawCracks(cx, cy, x, y, 0.22f, 2);
                DrawTileHealthMeter(bodyRect, ratio, band);
                break;

            case TileHealthVisual.Cracked:
                DrawTileCornerChips(bodyRect, x, y, fill, 0.5f);
                DrawCracks(cx, cy, x, y, 0.48f, 4);
                Raylib.DrawRectangleRounded(bodyRect, 0.12f, 6, WithAlpha(Amber, 0.08f));
                DrawTileHealthMeter(bodyRect, ratio, band);
                break;

            case TileHealthVisual.Fractured:
                DrawTileCornerChips(bodyRect, x, y, fill, 0.72f);
                DrawCracks(cx, cy, x, y, 0.72f, 6);
                DrawFractureWeb(cx, cy, x, y, 0.55f);
                {
                    float dust = MathF.Sin(time * 9f + x + y) * 0.5f + 0.5f;
                    Raylib.DrawCircleV(new Vector2(cx, cy - 2f), 1.2f + dust, WithAlpha(Amber, 0.25f + dust * 0.2f));
                }
                DrawTileHealthMeter(bodyRect, ratio, band);
                if (tile.State == 1)
                {
                    float pulse = MathF.Sin(time * 7f + x + y) * 0.5f + 0.5f;
                    Raylib.DrawRectangleRoundedLines(bodyRect, 0.12f, 6, WithAlpha(TileHealthAccent(band), pulse * 0.55f));
                }
                break;

            case TileHealthVisual.Critical:
                DrawTileCornerChips(bodyRect, x, y, fill, 1f);
                DrawCracks(cx, cy, x, y, 1f, 7);
                DrawFractureWeb(cx, cy, x, y, 0.85f);
                {
                    float pulse = MathF.Sin(time * 11f + x * 1.3f + y) * 0.5f + 0.5f;
                    float wobble = MathF.Sin(time * 14f + x * 2.1f + y * 1.7f) * 0.35f;
                    Raylib.DrawRectangleRounded(
                        new Rectangle(bodyRect.X + wobble, bodyRect.Y, bodyRect.Width, bodyRect.Height),
                        0.12f, 6, WithAlpha(TileHealthAccent(band), 0.12f + pulse * 0.18f));
                    Raylib.DrawRectangleRoundedLines(bodyRect, 0.12f, 6, WithAlpha(TileHealthAccent(band), 0.35f + pulse * 0.45f));
                    for (int d = 0; d < 3; d++)
                    {
                        float da = Hash(x * 991 + y * 677 + d) * MathF.PI * 2f;
                        var dustPos = new Vector2(cx + MathF.Cos(da + time * 2f) * 5f, cy + MathF.Sin(da + time * 2f) * 5f);
                        Raylib.DrawCircleV(dustPos, 1f + pulse * 0.8f, WithAlpha(Amber, 0.2f + pulse * 0.25f));
                    }
                }
                DrawTileHealthMeter(bodyRect, ratio, band);
                break;

            default:
                throw new UnreachableException();
        }
    }

    static void DrawFractureWeb(float cx, float cy, int x, int y, float severity)
    {
        int seed = x * 83492791 ^ y * 41524173;
        Color web = WithAlpha(ForestShadow, severity * 0.65f);
        for (int k = 0; k < 4; k++)
        {
            float a = Hash(seed + k * 13) * MathF.PI * 2f;
            float len = TileSize * (0.18f + Hash(seed + k * 17) * 0.22f);
            var hub = new Vector2(cx + MathF.Cos(a) * 2f, cy + MathF.Sin(a) * 2f);
            var end = new Vector2(cx + MathF.Cos(a + Hash(seed + k) * 0.8f) * len, cy + MathF.Sin(a + Hash(seed + k) * 0.8f) * len);
            Raylib.DrawLineEx(hub, end, 1.2f, web);
            var branch = new Vector2(
                (hub.X + end.X) * 0.5f + MathF.Cos(a + 1.2f) * 4f,
                (hub.Y + end.Y) * 0.5f + MathF.Sin(a + 1.2f) * 4f);
            Raylib.DrawLineEx(hub, branch, 1f, WithAlpha(web, severity * 0.8f));
        }
    }

    static string KeyName(KeyboardKey k)
    {
        int v = (int)k;
        if (v >= 65 && v <= 90) return ((char)v).ToString();
        if (v >= 48 && v <= 57) return ((char)v).ToString();
        return k switch
        {
            KeyboardKey.Space => "SPACE",
            KeyboardKey.LeftShift => "LSHIFT",
            KeyboardKey.LeftControl => "LCTRL",
            KeyboardKey.Enter => "ENTER",
            KeyboardKey.Null => "NONE",
            _ => v.ToString(),
        };
    }

    // ---------------------------------------------------------------- Draw

    static void Draw()
    {
        Raylib.BeginDrawing();
        Raylib.ClearBackground(ForestShadow);

        DrawForestBackground();

        switch (state)
        {
            case GameState.MainMenu:
                DrawMainMenu();
                break;
            case GameState.Playing:
                DrawPlayScene();
                break;
            case GameState.Paused:
                DrawPlayScene();
                DrawPauseMenu();
                break;
            case GameState.GameOver:
                DrawPlayScene();
                DrawGameOverScreen();
                break;
            case GameState.Customize:
                DrawCustomize();
                break;
            case GameState.Settings:
                DrawSettings();
                break;
            default:
                throw new UnreachableException();
        }

        DrawVignette();
        DrawWindowCloseButton();
        if (showFps) DrawFpsOverlay();
        Raylib.EndDrawing();
    }

    static void DrawFpsOverlay()
    {
        int fps = Raylib.GetFPS();
        string text = fps + " FPS";
        int fontSize = 16;
        int w = Raylib.MeasureText(text, fontSize);
        int x = WindowWidth - w - 16;
        int y = WindowHeight - fontSize - 12;
        Color tint = fps >= 60 ? new Color(120, 220, 140, 255)
            : fps >= 30 ? new Color(228, 196, 96, 255)
            : new Color(224, 96, 84, 255);
        Raylib.DrawText(text, x + 1, y + 1, fontSize, WithAlpha(Color.Black, 0.55f));
        Raylib.DrawText(text, x, y, fontSize, tint);
    }

    static Rectangle WindowCloseButtonRect()
        => new(WindowWidth - WindowCloseBtnPad - WindowCloseBtnSize, WindowCloseBtnPad, WindowCloseBtnSize, WindowCloseBtnSize);

    static bool IsWindowDragZone(Vector2 mouse, Rectangle closeBtn)
    {
        if (mouse.Y > WindowDragBarHeight) return false;
        return !Raylib.CheckCollisionPointRec(mouse, closeBtn);
    }

    static void UpdateWindowChrome()
    {
        Vector2 mouse = Raylib.GetMousePosition();
        Rectangle closeBtn = WindowCloseButtonRect();
        windowCloseHovered = Raylib.CheckCollisionPointRec(mouse, closeBtn);

        if (Raylib.IsMouseButtonPressed(MouseButton.Left))
        {
            if (windowCloseHovered)
            {
                Raylib.CloseWindow();
                return;
            }

            if (IsWindowDragZone(mouse, closeBtn))
            {
                windowDragging = true;
            }
        }

        if (!Raylib.IsMouseButtonDown(MouseButton.Left))
        {
            windowDragging = false;
        }

        if (windowDragging)
        {
            Vector2 delta = Raylib.GetMouseDelta();
            Vector2 pos = Raylib.GetWindowPosition();
            Raylib.SetWindowPosition((int)(pos.X + delta.X), (int)(pos.Y + delta.Y));
        }
    }

    static void DrawWindowCloseButton()
    {
        Rectangle btn = WindowCloseButtonRect();
        float cx = btn.X + btn.Width * 0.5f;
        float cy = btn.Y + btn.Height * 0.5f;

        if (windowCloseHovered)
        {
            Raylib.DrawCircleV(new Vector2(cx, cy), btn.Width * 0.52f, new Color(42, 40, 46, 230));
            Raylib.DrawCircleLines((int)cx, (int)cy, btn.Width * 0.52f, WithAlpha(UiBorder, 0.45f));
        }

        float half = 7f;
        Color xCol = windowCloseHovered ? new Color(196, 192, 184, 255) : new Color(68, 66, 62, 255);
        float thick = windowCloseHovered ? 2.3f : 1.9f;
        Raylib.DrawLineEx(new Vector2(cx - half, cy - half), new Vector2(cx + half, cy + half), thick, xCol);
        Raylib.DrawLineEx(new Vector2(cx + half, cy - half), new Vector2(cx - half, cy + half), thick, xCol);
    }

    static void DrawForestBackground()
    {
        Raylib.DrawRectangleGradientV(0, 0, WindowWidth, WindowHeight, CanopyTop, ForestFloor);

        Raylib.DrawRectangleGradientV(0, WindowHeight / 2, WindowWidth, WindowHeight / 2,
            WithAlpha(ActiveTheme.BgMist, 0f),
            WithAlpha(ActiveTheme.BgMist, 0.06f));

        float time = (float)Raylib.GetTime();

        if (state == GameState.MainMenu)
        {
            DrawMenuCastleFraming(time);
            DrawMotes(0.32f);
        }
        else
        {
            DrawEdgeCastle(time, 0.55f);
            DrawMotes();
        }
    }

    // New detailed framing growth for the main menu, perfectly centered.
    static void DrawMenuForestFraming(float time)
    {
        Color leafMid = new Color(42, 64, 44, 255);
        Color barkDark = new Color(48, 36, 26, 255);

        // Ancient framing tree bases in bottom corners (detailed)
        DrawDetailedGroveFraming(new Vector2(30f, WindowHeight - 10f), 1.25f, leafMid, barkDark);
        DrawDetailedGroveFraming(new Vector2(WindowWidth - 30f, WindowHeight - 10f), 1.15f, leafMid, barkDark);

        // Centered creeping vine pattern
        float spin = time * 0.4f;
        int max = 8;
        for (int i = 0; i < max; i++)
        {
            float frac = i / (float)max;
            float rfrac = frac + spin % (1f / max);
            if (rfrac > 1f) rfrac -= 1f;
            float p = EaseOutCubic(rfrac);
            float swing = MathF.Sin(time * 0.8f + i) * 8f * (1f - rfrac);
            Vector2 vineP = new Vector2(WindowWidth / 2f + swing, WindowHeight * 0.9f - WindowHeight * 0.6f * p);
            Color vineCol = WithAlpha(LerpColor(Darken(Emerald, 0.6f), Lighten(MossLight, 0.3f), p), (1f - p) * 0.8f);
            Raylib.DrawCircleV(vineP, 2.5f * (1f - rfrac) + 1f, vineCol);
        }
    }

    static void DrawDetailedGroveFraming(Vector2 root, float scale, Color leafCol, Color trunkCol)
    {
        float h = 100f * scale;
        Vector2 mid = new Vector2(root.X, root.Y - h * 0.35f);
        Vector2 top = new Vector2(root.X, root.Y - h * 0.75f);
        float trunkW = 6f * scale;

        // Trunk base
        Raylib.DrawLineEx(root, top, trunkW, WithAlpha(trunkCol, 0.9f));
        for (int s = -1; s <= 1; s += 2)
        {
            Vector2 offP = new Vector2(root.X + s * trunkW, root.Y - h * 0.15f);
            Raylib.DrawLineEx(root, offP, 3f * scale, WithAlpha(Darken(trunkCol, 0.4f), 0.7f));
        }

        // Detailed vine/leaf canopy
        float rad = 18f * scale;
        Vector2 canopy = new Vector2(root.X, root.Y - h * 0.6f);
        Raylib.DrawCircleV(new Vector2(canopy.X - rad * 0.7f, canopy.Y + rad * 0.1f), rad, WithAlpha(leafCol, 0.75f));
        Raylib.DrawCircleV(new Vector2(canopy.X + rad * 0.8f, canopy.Y - rad * 0.1f), rad * 0.9f, WithAlpha(leafCol, 0.8f));
        Raylib.DrawCircleV(canopy, rad * 1.1f, WithAlpha(Lighten(leafCol, 0.2f), 0.7f));
    }

