    // -------------------------------------------------------------------------
    // Shaped glow system (non-circular)
    // -------------------------------------------------------------------------

    static void DrawEllipticalGlow(Vector2 center, float rx, float ry, float rotationDeg, Color color, float intensity, int layers)
    {
        if (intensity <= 0.0005f) return;
        layers = Math.Clamp(Math.Max(layers, 8), 8, 20);
        for (int i = layers - 1; i >= 0; i--)
        {
            float t0 = i / (float)layers;
            float t1 = (i + 1) / (float)layers;
            float shell = (GlowFalloff(t0) - GlowFalloff(t1)) * intensity * 0.12f;
            if (shell <= 0.0001f) continue;
            Raylib.DrawEllipse((int)center.X, (int)center.Y, rx * t1, ry * t1, WithAlpha(color, shell));
        }
    }

    static void DrawGradientWash(Rectangle area, Color hot, Color cold, Vector2 hotspotNorm, float power)
    {
        if (area.Width < 1f || area.Height < 1f) return;

        power = Math.Max(0.5f, power);
        float hotAlpha = hot.A / 255f * (0.35f + 0.15f / power);
        Color hotTint = WithAlpha(hot, hotAlpha);
        Color clear = WithAlpha(cold, 0f);

        bool vertical = hotspotNorm.Y <= 0.62f;
        if (vertical)
        {
            if (hotspotNorm.Y < 0.45f)
                Raylib.DrawRectangleGradientV((int)area.X, (int)area.Y, (int)area.Width, (int)area.Height, clear, hotTint);
            else
                Raylib.DrawRectangleGradientV((int)area.X, (int)area.Y, (int)area.Width, (int)area.Height, hotTint, clear);
        }
        else if (hotspotNorm.X < 0.45f)
        {
            Raylib.DrawRectangleGradientH((int)area.X, (int)area.Y, (int)area.Width, (int)area.Height, hotTint, clear);
        }
        else
        {
            Raylib.DrawRectangleGradientH((int)area.X, (int)area.Y, (int)area.Width, (int)area.Height, clear, hotTint);
        }

        Vector2 hotspot = new Vector2(area.X + hotspotNorm.X * area.Width, area.Y + hotspotNorm.Y * area.Height);
        DrawEllipticalGlow(hotspot, area.Width * 0.48f, area.Height * 0.42f, 0f, hot, hotAlpha * 0.22f, 8);
    }

    static void DrawLightCone(Vector2 origin, float directionRad, float length, float halfAngleRad, Color color, float intensity)
    {
        int layers = 10;
        for (int layer = layers; layer >= 1; layer--)
        {
            float t = layer / (float)layers;
            float len = length * (0.4f + 0.6f * t);
            float half = halfAngleRad * (0.5f + 0.5f * t);
            float alpha = intensity * GlowFalloff(t) * 0.38f;
            Vector2 tip = new Vector2(origin.X + MathF.Cos(directionRad) * len, origin.Y + MathF.Sin(directionRad) * len);
            Vector2 left = new Vector2(origin.X + MathF.Cos(directionRad - half) * len * 0.15f, origin.Y + MathF.Sin(directionRad - half) * len * 0.15f);
            Vector2 right = new Vector2(origin.X + MathF.Cos(directionRad + half) * len * 0.15f, origin.Y + MathF.Sin(directionRad + half) * len * 0.15f);
            Raylib.DrawTriangle(origin, left, tip, WithAlpha(color, alpha * 0.5f));
            Raylib.DrawTriangle(origin, tip, right, WithAlpha(color, alpha * 0.5f));
            Vector2 farL = new Vector2(origin.X + MathF.Cos(directionRad - half) * len, origin.Y + MathF.Sin(directionRad - half) * len);
            Vector2 farR = new Vector2(origin.X + MathF.Cos(directionRad + half) * len, origin.Y + MathF.Sin(directionRad + half) * len);
            Raylib.DrawTriangle(left, farL, tip, WithAlpha(color, alpha * 0.35f));
            Raylib.DrawTriangle(tip, farR, right, WithAlpha(color, alpha * 0.35f));
        }
    }

    static void DrawWallTorchWash(Vector2 torchPos, Vector2 wallNormal, float time, float phase, float scale)
    {
        float flicker = MathF.Sin(time * 5.4f + phase) * 0.5f + 0.5f;
        float flicker2 = MathF.Sin(time * 8.2f + phase * 1.3f) * 0.5f + 0.5f;
        Color warm = MenuPalette.TorchWarm;
        Vector2 n = Vector2.Normalize(wallNormal);
        Vector2 tangent = new Vector2(-n.Y, n.X);
        float washLen = 90f * scale;
        float washH = 48f * scale;
        Vector2 washBase = torchPos + n * (8f * scale);
        for (int strip = 0; strip < 6; strip++)
        {
            float along = strip / 5f;
            float asym = 0.35f + along * 0.65f;
            Vector2 center = washBase + tangent * ((along - 0.5f) * washLen * 1.4f) + n * (along * washH * 0.6f);
            float rx = (18f + strip * 4f) * scale * asym;
            float ry = (10f + strip * 2f) * scale;
            float rot = MathF.Atan2(tangent.Y, tangent.X) * 180f / MathF.PI;
            float inten = (0.04f + flicker * 0.05f) * (1f - strip * 0.12f);
            DrawEllipticalGlow(center, rx, ry, rot, warm, inten * (0.7f + flicker2 * 0.3f), 3);
        }
        DrawLightCone(torchPos, MathF.Atan2(n.Y, n.X), washH * 1.2f, 0.55f, warm, 0.06f + flicker * 0.05f);
    }

    static void DrawWindowInteriorGlow(Rectangle windowRect, float time, float phase)
    {
        float pulse = MathF.Sin(time * 1.5f + phase) * 0.5f + 0.5f;
        Color warm = new Color(180, 152, 108, 255);
        var inner = new Rectangle(windowRect.X + 3f, windowRect.Y + 4f, windowRect.Width - 6f, windowRect.Height - 8f);
        Raylib.DrawRectangleRounded(inner, 0.12f, 3, WithAlpha(warm, 0.10f + pulse * 0.06f));
        Vector2 center = new Vector2(inner.X + inner.Width / 2f, inner.Y + inner.Height / 2f);
        DrawEllipticalGlow(center, inner.Width * 0.55f, inner.Height * 0.5f, 0f, warm, 0.018f + pulse * 0.012f, 2);
    }

    static void DrawMoonCorona(Vector2 moonPos, float time)
    {
        float pulse = MathF.Sin(time * 0.35f) * 0.5f + 0.5f;
        Color corona = MenuPalette.MoonGlow;
        for (int i = 0; i < 5; i++)
        {
            float rx = 90f + i * 28f;
            float ry = 22f + i * 6f;
            float yOff = i * 4f - 6f;
            float rot = -8f + i * 3f;
            float inten = (0.018f - i * 0.0025f) * (0.85f + pulse * 0.15f);
            DrawEllipticalGlow(new Vector2(moonPos.X, moonPos.Y + yOff), rx, ry, rot, corona, inten, 4);
        }
    }
    // -------------------------------------------------------------------------
    // Night sky
    // -------------------------------------------------------------------------

    static void DrawMenuCastleNightSky(float time)
    {
        int skyH = (int)(WindowHeight * 0.58f);

        // Near-black zenith with a faint cool tint; horizon stays neutral charcoal
        // so the castle wall below reads dark grey rather than blue.
        Color skyTop = new Color(1, 2, 8, 255);
        Color skyUpper = new Color(4, 5, 16, 255);
        Color skyMid = new Color(7, 7, 12, 255);
        Color skyHorizon = new Color(6, 5, 7, 255);

        Raylib.DrawRectangleGradientV(0, 0, WindowWidth, skyH / 2, skyTop, skyUpper);
        Raylib.DrawRectangleGradientV(0, skyH / 2, WindowWidth, skyH / 2, skyUpper, skyMid);
        Raylib.DrawRectangleGradientV(0, skyH - 120, WindowWidth, 120, WithAlpha(skyMid, 0f), WithAlpha(skyHorizon, 0.92f));
        Raylib.DrawRectangleGradientV(0, skyH - 36, WindowWidth, 36, WithAlpha(skyHorizon, 0f), WithAlpha(new Color(4, 4, 5, 255), 0.88f));

        DrawMenuCastleSkyNebula(time, skyH);
        DrawMenuCastleMoonSkyScatter(time);

        DrawMenuCastleStarField(time);
        DrawMenuCastleMilkyWay(time);
        DrawMenuCastleShootingStar(time);

        DrawMenuCastleDistantMountains(time);
        DrawMenuCastleCloudWisps(time);
        DrawMenuCastleNightSkyExtras(time);
    }

    static void DrawMenuCastleSkyNebula(float time, int skyH)
    {
        float pulse = 0.88f + MathF.Sin(time * 0.12f) * 0.08f;
        DrawEllipticalGlow(new Vector2(WindowWidth * 0.32f, skyH * 0.16f), WindowWidth * 0.34f, 72f, -18f,
            new Color(28, 24, 42, 255), 0.009f * pulse, 4);
        DrawEllipticalGlow(new Vector2(WindowWidth * 0.58f, skyH * 0.24f), WindowWidth * 0.26f, 48f, 10f,
            new Color(20, 26, 44, 255), 0.006f * pulse, 3);
        DrawEllipticalGlow(new Vector2(WindowWidth * 0.12f, skyH * 0.30f), 90f, 36f, -32f,
            new Color(16, 18, 34, 255), 0.004f * pulse, 2);
    }

    static void DrawMenuCastleMoonSkyScatter(float time)
    {
        Vector2 moon = MenuCastleMoonPosition;
        float pulse = MathF.Sin(time * 0.35f) * 0.5f + 0.5f;
        DrawEllipticalGlow(new Vector2(moon.X, moon.Y + 36f), 130f, 82f, 0f,
            new Color(120, 128, 148, 255), 0.014f + pulse * 0.004f, 5);
        DrawEllipticalGlow(new Vector2(moon.X - 55f, moon.Y + 72f), 200f, 44f, -10f,
            new Color(72, 78, 92, 255), 0.005f, 3);
    }

    static void DrawMenuCastleStarField(float time)
    {
        float skyLimit = WindowHeight * 0.50f;

        // Deep field — many near-invisible points (realistic magnitude tail)
        const int deepCount = 260;
        for (int i = 0; i < deepCount; i++)
        {
            float sx = Hash(i * 41 + 7) * WindowWidth;
            float sy = Hash(i * 19 + 3) * skyLimit;
            float altitude = 1f - sy / skyLimit;
            float extinction = 0.35f + altitude * 0.65f;
            float twinkle = MathF.Sin(time * (0.25f + Hash(i * 5) * 0.6f) + i * 0.9f) * 0.5f + 0.5f;
            float alpha = (0.015f + twinkle * (0.02f + Hash(i * 31) * 0.03f)) * extinction;
            Raylib.DrawCircleV(new Vector2(sx, sy), 0.35f + Hash(i * 11) * 0.35f, WithAlpha(new Color(190, 196, 210, 255), alpha));
        }

        // Far field — tiny, dense, slow twinkle
        const int farCount = 200;
        for (int i = 0; i < farCount; i++)
        {
            float sx = Hash(i * 47 + 9) * WindowWidth;
            float sy = Hash(i * 23 + 1) * skyLimit;
            float altitude = 1f - sy / skyLimit;
            float extinction = 0.4f + altitude * 0.6f;
            float twinkle = MathF.Sin(time * (0.35f + Hash(i * 5) * 0.9f) + i * 0.9f) * 0.5f + 0.5f;
            float alpha = (0.025f + twinkle * (0.04f + Hash(i * 31) * 0.06f)) * extinction;
            Raylib.DrawCircleV(new Vector2(sx, sy), 0.45f + Hash(i * 11) * 0.5f, WithAlpha(new Color(200, 206, 220, 255), alpha));
        }

        // Mid field — varied color temperature with atmospheric extinction
        const int midCount = 84;
        for (int i = 0; i < midCount; i++)
        {
            float sx = Hash(i * 53 + 11) * WindowWidth;
            float sy = Hash(i * 29 + 5) * skyLimit * 0.96f;
            float altitude = 1f - sy / skyLimit;
            float extinction = 0.45f + altitude * 0.55f;
            float temp = Hash(i * 37);
            Color starCol = temp < 0.14f
                ? new Color(168, 184, 255, 255)
                : temp < 0.38f
                    ? new Color(196, 202, 220, 255)
                    : temp < 0.72f
                        ? new Color(220, 218, 226, 255)
                        : new Color(255, 236, 208, 255);
            float twinkle = MathF.Sin(time * (0.7f + Hash(i * 7) * 1.6f) + i * 1.1f) * 0.5f + 0.5f;
            float r = 0.55f + Hash(i * 13) * 0.95f;
            float alpha = (0.05f + twinkle * (0.08f + Hash(i * 43) * 0.12f)) * extinction;
            Raylib.DrawCircleV(new Vector2(sx, sy), r, WithAlpha(starCol, alpha));
            if (Hash(i * 71) > 0.92f && twinkle > 0.78f)
            {
                float spark = 1.2f + Hash(i * 73) * 1.4f;
                Raylib.DrawLine((int)sx - (int)spark, (int)sy, (int)sx + (int)spark, (int)sy, WithAlpha(starCol, alpha * 0.5f));
                Raylib.DrawLine((int)sx, (int)sy - (int)spark, (int)sx, (int)sy + (int)spark, WithAlpha(starCol, alpha * 0.5f));
            }
        }

        // Bright anchors — a handful of prominent stars
        ReadOnlySpan<(float x, float y, float size, float phase)> anchors =
        [
            (0.14f, 0.08f, 1.5f, 0.0f),
            (0.31f, 0.18f, 1.2f, 1.2f),
            (0.48f, 0.06f, 1.6f, 2.4f),
            (0.67f, 0.14f, 1.3f, 0.8f),
            (0.84f, 0.22f, 1.1f, 3.1f),
            (0.22f, 0.28f, 1.0f, 1.9f),
            (0.91f, 0.09f, 1.4f, 2.7f),
        ];
        for (int a = 0; a < anchors.Length; a++)
        {
            var (nx, ny, size, phase) = anchors[a];
            Vector2 pos = new Vector2(WindowWidth * nx, WindowHeight * ny);
            float tw = MathF.Sin(time * 1.1f + phase) * 0.5f + 0.5f;
            Color col = new Color(220, 228, 248, 255);
            Raylib.DrawCircleV(pos, size, WithAlpha(col, 0.14f + tw * 0.12f));
            DrawEllipticalGlow(pos, size * 3f, size * 2.5f, 0f, col, 0.006f + tw * 0.004f, 2);
        }
    }

    static void DrawMenuCastleMilkyWay(float time)
    {
        float pulse = 0.92f + MathF.Sin(time * 0.1f) * 0.06f;
        const int segments = 22;
        for (int s = 0; s < segments; s++)
        {
            float t = s / (float)(segments - 1);
            float cx = WindowWidth * (0.04f + t * 0.82f);
            float cy = WindowHeight * (0.04f + t * 0.26f) + MathF.Sin(t * MathF.PI) * 18f;
            float rx = 72f + Hash(s * 53) * 56f;
            float ry = 12f + Hash(s * 59) * 10f;
            float rot = -32f + t * 12f + Hash(s * 71) * 6f - 3f;
            float envelope = 0.4f + MathF.Sin(t * MathF.PI) * 0.6f;
            float inten = (0.004f + Hash(s * 61) * 0.007f) * pulse * envelope;
            Color band = LerpColor(new Color(72, 76, 96, 255), new Color(118, 116, 138, 255), Hash(s * 67));
            DrawEllipticalGlow(new Vector2(cx, cy), rx, ry, rot, band, inten, 4);
        }
    }

    static void DrawMenuCastleShootingStar(float time)
    {
        // One slow cycle — a brief streak every ~14 seconds
        float cycle = (time * 0.07f) % 1f;
        if (cycle > 0.12f) return;

        float t = cycle / 0.12f;
        float startX = WindowWidth * (0.55f + Hash(3) * 0.25f);
        float startY = WindowHeight * (0.04f + Hash(7) * 0.10f);
        float len = 90f + Hash(11) * 60f;
        float ang = MathF.PI * 0.72f + Hash(13) * 0.18f;
        Vector2 head = new Vector2(startX + MathF.Cos(ang) * len * t, startY + MathF.Sin(ang) * len * t);
        Vector2 tail = new Vector2(head.X - MathF.Cos(ang) * len * 0.35f, head.Y - MathF.Sin(ang) * len * 0.35f);
        Color streak = new Color(230, 238, 255, 255);
        float fade = 1f - t;
        Raylib.DrawLineEx(tail, head, 1.2f, WithAlpha(streak, fade * 0.55f));
        Raylib.DrawCircleV(head, 1.4f, WithAlpha(streak, fade * 0.75f));
        DrawEllipticalGlow(head, 8f, 4f, ang * 180f / MathF.PI, streak, fade * 0.04f, 2);
    }

    static void DrawMenuCastleDistantMountains(float time)
    {
        Color ridge = new Color(5, 4, 7, 255);
        Color ridgeHi = new Color(10, 9, 13, 255);
        Color ridgeMoon = new Color(16, 16, 20, 255);
        int baseY = (int)(WindowHeight * 0.48f);
        float moonX = WindowWidth * 0.76f;
        for (int m = 0; m < 9; m++)
        {
            float x0 = WindowWidth * (m / 8f) - 40f;
            float x1 = WindowWidth * ((m + 1) / 8f) + 40f;
            float peakY = baseY - 30f - Hash(m * 17) * 55f - MathF.Sin(time * 0.05f + m) * 2f;
            Vector2 p0 = new Vector2(x0, baseY + 20f);
            Vector2 p1 = new Vector2((x0 + x1) * 0.5f, peakY);
            Vector2 p2 = new Vector2(x1, baseY + 16f);
            float moonFacing = Math.Clamp(1f - MathF.Abs(p1.X - moonX) / (WindowWidth * 0.45f), 0f, 1f);
            Color c = LerpColor(LerpColor(ridge, ridgeHi, Hash(m * 29) * 0.35f), ridgeMoon, moonFacing * 0.22f);
            Raylib.DrawTriangle(p0, p2, p1, WithAlpha(c, 0.75f));
            if (moonFacing > 0.35f)
                Raylib.DrawLineEx(p1, p2, 1f, WithAlpha(ridgeHi, 0.10f + moonFacing * 0.12f));
            else
                Raylib.DrawLineEx(p1, p2, 1f, WithAlpha(ridgeHi, 0.15f));
        }

        // Soft ground haze where mountains meet the sky
        Raylib.DrawRectangleGradientV(0, baseY - 8, WindowWidth, 48,
            WithAlpha(new Color(8, 7, 9, 255), 0f), WithAlpha(new Color(8, 7, 9, 255), 0.28f));
    }

    static void DrawMenuCastleCloudWisps(float time)
    {
        Vector2 moon = MenuCastleMoonPosition;
        Color silver = new Color(132, 138, 152, 255);
        Color shadow = new Color(42, 44, 50, 255);
        for (int c = 0; c < 10; c++)
        {
            float drift = time * (4f + c * 1.8f);
            float cx = (Hash(c * 97) * WindowWidth + drift) % (WindowWidth + 180f) - 90f;
            float cy = 32f + c * 18f + MathF.Sin(time * 0.16f + c * 1.2f) * 10f;
            float dx = cx - moon.X;
            float moonLit = Math.Clamp(1f - MathF.Abs(dx) / 240f, 0.15f, 1f);
            for (int w = 0; w < 5; w++)
            {
                float wx = cx + (w - 2f) * 24f;
                float wy = cy + Hash(c * 11 + w) * 8f - 4f;
                float rx = 34f + w * 10f + c * 3f;
                float ry = 9f + w * 2.5f;
                float rot = Hash(c + w) * 14f - 7f;
                DrawEllipticalGlow(new Vector2(wx, wy + 2f), rx * 1.05f, ry * 1.1f, rot, shadow, 0.004f * moonLit, 2);
                DrawEllipticalGlow(new Vector2(wx, wy), rx, ry, rot, silver, 0.008f * moonLit, 3);
            }
        }
    }
    // -------------------------------------------------------------------------
    // Realistic moon
    // -------------------------------------------------------------------------

    static Vector2 MenuCastleMoonPosition => new Vector2(WindowWidth * 0.76f, 64f);

    static void DrawMenuCastleMoon(float time)
    {
        Vector2 moon = MenuCastleMoonPosition;
        float pulse = MathF.Sin(time * 0.35f) * 0.5f + 0.5f;
        Color lit = MenuPalette.MoonGlow;
        Color darkSide = new Color(28, 30, 38, 255);
        Color maria = new Color(72, 74, 82, 255);

        DrawMoonCorona(moon, time);

        // Earthshine on dark hemisphere
        DrawEllipticalGlow(new Vector2(moon.X + 6f, moon.Y + 2f), 22f, 20f, -12f, darkSide, 0.06f + pulse * 0.02f, 3);

        // Main disc
        Raylib.DrawCircleV(moon, 22f, WithAlpha(lit, 0.22f + pulse * 0.06f));
        Raylib.DrawCircleV(moon, 18f, WithAlpha(Color.White, 0.12f + pulse * 0.05f));

        // Gibbous terminator via overlapping circles
        Vector2 shadowCenter = new Vector2(moon.X + 10f, moon.Y - 1f);
        Raylib.DrawCircleV(shadowCenter, 19f, WithAlpha(darkSide, 0.55f));
        Raylib.DrawCircleV(new Vector2(moon.X - 2f, moon.Y), 20f, WithAlpha(lit, 0.35f));

        // Maria patches
        for (int m = 0; m < 6; m++)
        {
            float mx = moon.X + (Hash(m * 13) - 0.5f) * 24f;
            float my = moon.Y + (Hash(m * 17) - 0.5f) * 20f;
            float mrx = 4f + Hash(m * 19) * 5f;
            float mry = 3f + Hash(m * 23) * 4f;
            Raylib.DrawEllipse((int)mx, (int)my, mrx, mry, WithAlpha(maria, 0.2f + Hash(m * 29) * 0.15f));
        }

        // Crater rims and shadows
        for (int cr = 0; cr < 14; cr++)
        {
            float cx = moon.X + (Hash(cr * 37) - 0.5f) * 30f;
            float cy = moon.Y + (Hash(cr * 41) - 0.5f) * 26f;
            float rad = 1.2f + Hash(cr * 43) * 2.8f;
            Raylib.DrawCircleLines((int)cx, (int)cy, rad, WithAlpha(Darken(lit, 0.35f), 0.25f));
            Raylib.DrawCircleV(new Vector2(cx + 0.6f, cy + 0.6f), rad * 0.7f, WithAlpha(darkSide, 0.18f));
        }

        // Limb highlight
        for (int h = 0; h < 8; h++)
        {
            float ang = MathF.PI * 0.15f + h * 0.08f;
            Vector2 lp = new Vector2(moon.X + MathF.Cos(ang) * 19f, moon.Y + MathF.Sin(ang) * 17f);
            Raylib.DrawCircleV(lp, 1.2f, WithAlpha(Color.White, 0.2f));
        }
    }


    // -------------------------------------------------------------------------
    // Ultra masonry pass
    // -------------------------------------------------------------------------

    static void DrawMenuMasonryUltra(Rectangle region, MenuCastlePalette palette, int rows, int cols)
    {
        float rowH = region.Height / rows;
        float colW = region.Width / cols;
        for (int row = 0; row < rows; row++)
        {
            float y = region.Y + row * rowH;
            float offset = (row % 2 == 0 ? 0f : 0.5f) * colW;
            for (int col = -1; col < cols + 1; col++)
            {
                float x = region.X + col * colW + offset;
                var brick = new Rectangle(x + 1.2f, y + 1.2f, colW - 2.4f, rowH - 2.4f);
                if (brick.X + brick.Width < region.X || brick.X > region.X + region.Width) continue;
                int seed = (int)(x * 3.1f) ^ (int)(y * 7.3f) ^ row * 131 ^ col * 97;
                float n = Hash(seed);
                float n2 = Hash(seed + 17);
                Color brickColor = LerpColor(palette.StoneMid, palette.Stone, n * 0.45f + 0.2f);
                brickColor = LerpColor(brickColor, palette.StoneLight, n2 * 0.18f);
                if (n > 0.82f) brickColor = Darken(brickColor, 0.12f);
                Raylib.DrawRectangleRounded(brick, 0.07f + n * 0.04f, 4, WithAlpha(brickColor, 0.38f + n2 * 0.12f));
                // Highlight edge (top-left catch light)
                Raylib.DrawLine((int)brick.X, (int)brick.Y, (int)(brick.X + brick.Width * 0.7f), (int)brick.Y,
                    WithAlpha(palette.StoneHi, 0.08f + n2 * 0.1f));
                Raylib.DrawLine((int)brick.X, (int)brick.Y, (int)brick.X, (int)(brick.Y + brick.Height * 0.6f),
                    WithAlpha(palette.StoneHi, 0.06f + n * 0.08f));
                // Chips and breaks
                if (Hash(seed + 3) > 0.78f)
                {
                    float chipX = brick.X + Hash(seed + 5) * brick.Width * 0.6f;
                    float chipY = brick.Y + Hash(seed + 7) * brick.Height * 0.5f;
                    Raylib.DrawCircleV(new Vector2(chipX, chipY), 1f + Hash(seed + 9), WithAlpha(palette.StoneDeep, 0.35f));
                }
                // Lichen speckles
                for (int lic = 0; lic < 3; lic++)
                {
                    if (Hash(seed + 20 + lic) < 0.72f) continue;
                    float lx = brick.X + Hash(seed + 30 + lic) * brick.Width;
                    float ly = brick.Y + Hash(seed + 40 + lic) * brick.Height;
                    Raylib.DrawCircleV(new Vector2(lx, ly), 0.8f + Hash(seed + 50 + lic),
                        WithAlpha(palette.Lichen, 0.12f + Hash(seed + 60 + lic) * 0.18f));
                }
                // Moisture stain (lower bricks)
                float rowFrac = row / (float)Math.Max(1, rows - 1);
                if (rowFrac > 0.55f && Hash(seed + 71) > 0.55f)
                {
                    var stain = new Rectangle(brick.X + 1f, brick.Y + brick.Height * 0.45f,
                        brick.Width - 2f, brick.Height * 0.5f);
                    DrawGradientWash(stain, WithAlpha(Darken(palette.Stone, 0.2f), 0.2f),
                        WithAlpha(palette.StoneMid, 0f), new Vector2(0.5f, 1f), 1.4f);
                }
            }
        }
        // Mortar grid
        for (int row = 0; row <= rows; row++)
        {
            float y = region.Y + row * rowH;
            Raylib.DrawLine((int)region.X, (int)y, (int)(region.X + region.Width), (int)y, WithAlpha(palette.Mortar, 0.48f));
        }
        for (int col = 0; col <= cols; col++)
        {
            float x = region.X + col * colW;
            Raylib.DrawLine((int)x, (int)region.Y, (int)x, (int)(region.Y + region.Height), WithAlpha(palette.Mortar, 0.32f));
        }
        // Moss in random joints
        for (int j = 0; j < rows * cols / 4; j++)
        {
            float jx = region.X + Hash(j * 19 + 2) * region.Width;
            float jy = region.Y + Hash(j * 23 + 5) * region.Height;
            Raylib.DrawCircleV(new Vector2(jx, jy), 1.5f + Hash(j * 29), WithAlpha(palette.Moss, 0.2f + Hash(j * 31) * 0.25f));
        }
    }

    // -------------------------------------------------------------------------
    // Tower detail helpers
    // -------------------------------------------------------------------------

    static void DrawMenuTowerBellOpening(Vector2 center, float width, float height, MenuCastlePalette p, float time)
    {
float sway = MathF.Sin(time * 0.9f) * 0.5f;
        var arch = new Rectangle(center.X - width / 2f, center.Y - height, width, height);
        Raylib.DrawRectangleRounded(arch, 0.45f, 6, WithAlpha(p.StoneDeep, 0.92f));
        Raylib.DrawRectangleRoundedLines(arch, 0.45f, 6, WithAlpha(p.StoneHi, 0.4f));
        Raylib.DrawLineEx(new Vector2(center.X, arch.Y), new Vector2(center.X, arch.Y + height), 1.5f, WithAlpha(p.Iron, 0.35f));
        Raylib.DrawCircleV(new Vector2(center.X + sway, center.Y - height * 0.35f), 3f, WithAlpha(p.Iron, 0.5f));
    }

    static void DrawMenuTowerMachicolations(Rectangle top, MenuCastlePalette p)
    {
int slots = Math.Max(5, (int)(top.Width / 18f));
        float slotW = top.Width / slots;
        for (int i = 0; i < slots; i++)
        {
            if (i % 2 == 0) continue;
            var slot = new Rectangle(top.X + i * slotW + 2f, top.Y + top.Height * 0.35f, slotW - 4f, top.Height * 0.55f);
            Raylib.DrawRectangleRounded(slot, 0.15f, 3, WithAlpha(p.StoneDeep, 0.85f));
            Raylib.DrawLine((int)slot.X, (int)slot.Y, (int)(slot.X + slot.Width), (int)slot.Y, WithAlpha(p.StoneHi, 0.2f));
        }
    }

    static void DrawMenuTowerCorbelTable(float x, float y, float width, MenuCastlePalette p)
    {
int corbels = Math.Max(6, (int)(width / 12f));
        for (int i = 0; i < corbels; i++)
        {
            float cx = x + i * (width / (corbels - 1));
            float protrude = 3f + Hash(i * 7) * 3f;
            Raylib.DrawTriangle(
                new Vector2(cx - 4f, y),
                new Vector2(cx + 4f, y),
                new Vector2(cx, y - protrude),
                WithAlpha(p.StoneDark, 0.8f));
            Raylib.DrawLineEx(new Vector2(cx, y - protrude), new Vector2(cx, y - protrude - 2f), 1f, WithAlpha(p.StoneHi, 0.25f));
        }
    }

    static void DrawMenuTowerGargoyle(Vector2 pos, bool facingLeft, MenuCastlePalette p)
    {
float dir = facingLeft ? -1f : 1f;
        Raylib.DrawCircleV(pos, 4f, WithAlpha(p.StoneDeep, 0.9f));
        Vector2 snout = new Vector2(pos.X + dir * 8f, pos.Y + 2f);
        Raylib.DrawTriangle(pos, new Vector2(pos.X + dir * 3f, pos.Y - 3f), snout, WithAlpha(p.StoneDark, 0.85f));
        Raylib.DrawCircleV(new Vector2(pos.X - dir, pos.Y - 1f), 1f, WithAlpha(p.StoneHi, 0.4f));
    }

    static void DrawMenuTowerIronRing(Vector2 pos, float radius, MenuCastlePalette p)
    {
Raylib.DrawCircleLines((int)pos.X, (int)pos.Y, radius, WithAlpha(p.Iron, 0.55f));
        Raylib.DrawCircleLines((int)pos.X, (int)pos.Y, radius - 1.5f, WithAlpha(Darken(p.Iron, 0.3f), 0.35f));
        Raylib.DrawCircleV(new Vector2(pos.X + radius * 0.6f, pos.Y), 1.2f, WithAlpha(p.StoneHi, 0.3f));
    }

    static void DrawMenuTowerDrainSpout(Vector2 pos, bool left, MenuCastlePalette p)
    {
float dir = left ? -1f : 1f;
        Raylib.DrawRectangleRounded(new Rectangle(pos.X, pos.Y, 8f * dir, 5f), 0.2f, 2, WithAlpha(p.StoneDark, 0.8f));
        Raylib.DrawLineEx(pos, new Vector2(pos.X + dir * 14f, pos.Y + 10f), 1.5f, WithAlpha(p.StoneDeep, 0.6f));
        for (int drip = 0; drip < 3; drip++)
            Raylib.DrawCircleV(new Vector2(pos.X + dir * (10f + drip * 2f), pos.Y + 12f + drip * 4f), 0.8f, WithAlpha(p.WetSheen, 0.15f));
    }

    static void DrawMenuTowerMoonRimLight(Rectangle body, bool moonSideLeft, MenuCastlePalette p)
    {
float edgeX = moonSideLeft ? body.X + body.Width - 2f : body.X + 2f;
        Raylib.DrawLineEx(new Vector2(edgeX, body.Y + 8f), new Vector2(edgeX, body.Y + body.Height - 8f), 2f, WithAlpha(p.MoonGlow, 0.12f));
        for (int i = 0; i < 6; i++)
        {
            float ty = body.Y + body.Height * (0.15f + i * 0.14f);
            Raylib.DrawCircleV(new Vector2(edgeX + (moonSideLeft ? -1f : 1f), ty), 1.5f, WithAlpha(p.StoneHi, 0.18f));
        }
    }

    static void DrawMenuTowerJointMoss(Rectangle region, MenuCastlePalette p, int density)
    {
for (int i = 0; i < density; i++)
        {
            float mx = region.X + Hash(i * 13 + 1) * region.Width;
            float my = region.Y + Hash(i * 17 + 3) * region.Height;
            float r = 1.5f + Hash(i * 19) * 3f;
            Raylib.DrawCircleV(new Vector2(mx, my), r, WithAlpha(p.Moss, 0.15f + Hash(i * 23) * 0.2f));
            if (Hash(i * 29) > 0.6f)
                Raylib.DrawCircleV(new Vector2(mx + 2f, my - 1f), r * 0.6f, WithAlpha(p.Lichen, 0.12f));
        }
    }

    static void DrawMenuCastleTower(Vector2 origin, float width, float height, MenuCastlePalette p,
        float time, bool left, float phase)
    {
        var body = new Rectangle(origin.X, origin.Y, width, height);
        Raylib.DrawRectangleRounded(body, 0.06f, 10, p.StoneMid);
        Raylib.DrawRectangleRoundedLines(body, 0.06f, 10, WithAlpha(p.StoneLight, 0.75f));
        float shadeX = left ? body.X + body.Width - 10f : body.X;
        Raylib.DrawRectangleGradientH((int)shadeX, (int)body.Y, 10, (int)body.Height,
            WithAlpha(ForestShadow, left ? 0.28f : 0f), WithAlpha(ForestShadow, left ? 0f : 0.28f));
        Raylib.DrawLineEx(new Vector2(left ? body.X + 2f : body.X + body.Width - 2f, body.Y + 6f),
            new Vector2(left ? body.X + 2f : body.X + body.Width - 2f, body.Y + body.Height - 6f), 1.5f,
            WithAlpha(p.MoonGlow, 0.08f + MathF.Sin(time * 0.9f + phase) * 0.03f));
        DrawMenuMasonryUltra(body, p, 12, 6);
        DrawQuoinStripes(body, p.StoneLight, p.StoneHi);
        for (int band = 1; band < 5; band++)
        {
            float by = origin.Y + height * (band * 0.18f);
            Raylib.DrawLine((int)origin.X, (int)by, (int)(origin.X + width), (int)by, WithAlpha(p.StoneLight, 0.18f));
        }
        float roofBase = origin.Y - 8f;
        DrawTowerRoof(origin.X + width / 2f, roofBase - 38f, roofBase, width * 0.52f, p.StoneDark, p.StoneLight, p.StoneHi);
        var battleRect = new Rectangle(origin.X - 4f, origin.Y - 30f, width + 8f, 30f);
        DrawBattlements(battleRect, p.StoneDark, p.StoneLight, p.StoneHi, 1f, time, !left);
        DrawMenuTowerMachicolations(battleRect, p);
        DrawMenuTowerCorbelTable(origin.X + 6f, origin.Y - 32f, width - 12f, p);
        DrawMenuTowerBellOpening(new Vector2(origin.X + width / 2f, origin.Y - 18f), 18f, 22f, p, time);
        float slitX = left ? origin.X + width * 0.72f : origin.X + width * 0.16f;
        DrawMenuArrowSlit(new Vector2(slitX, origin.Y + height * 0.30f), 9f, 32f, p);
        DrawMenuArrowSlit(new Vector2(slitX, origin.Y + height * 0.46f), 9f, 32f, p);

        float winX = origin.X + width * 0.5f - 11f;
        var window = new Rectangle(winX, origin.Y + height * 0.64f, 22f, 30f);
        DrawWindowInteriorGlow(window, time, phase);
        Raylib.DrawRectangleRounded(window, 0.2f, 4, WithAlpha(p.StoneDeep, 0.95f));
        Raylib.DrawRectangleRoundedLines(window, 0.2f, 4, WithAlpha(p.StoneHi, 0.5f));
        Raylib.DrawLine((int)(window.X + window.Width / 2f), (int)window.Y, (int)(window.X + window.Width / 2f), (int)(window.Y + window.Height), WithAlpha(p.StoneDeep, 0.6f));
        Raylib.DrawLine((int)window.X, (int)(window.Y + window.Height * 0.55f), (int)(window.X + window.Width), (int)(window.Y + window.Height * 0.55f), WithAlpha(p.StoneDeep, 0.6f));
        Vector2 gargoylePos = new Vector2(left ? origin.X + width + 4f : origin.X - 4f, origin.Y + height * 0.22f);
        DrawMenuTowerGargoyle(gargoylePos, !left, p);
        DrawMenuTowerIronRing(new Vector2(origin.X + width * 0.5f, origin.Y + height * 0.08f), 5f, p);
        DrawMenuTowerDrainSpout(new Vector2(left ? origin.X + width - 10f : origin.X + 2f, origin.Y + height * 0.78f), left, p);
        DrawMenuTowerJointMoss(body, p, 18);
        DrawMenuTowerMoonRimLight(body, !left, p);
        Vector2 torchMount = new Vector2(left ? origin.X + width - 22f : origin.X + 22f, origin.Y + height * 0.14f);
        DrawCastleTorch(torchMount, time, phase, 1f, left ? TorchMountKind.WallLeft : TorchMountKind.WallRight);
        Vector2 wallN = new Vector2(left ? 1f : -1f, 0.15f);
        DrawWallTorchWash(torchMount, wallN, time, phase, 1f);
    }

    static void DrawMenuArrowSlit(Vector2 pos, float w, float h, MenuCastlePalette p)
    {
        var outer = new Rectangle(pos.X, pos.Y, w, h);
        Raylib.DrawRectangleRounded(outer, 0.15f, 4, WithAlpha(p.StoneDeep, 0.9f));
        Raylib.DrawRectangleRoundedLines(outer, 0.15f, 4, WithAlpha(p.StoneLight, 0.45f));
        var inner = new Rectangle(pos.X + 2f, pos.Y + 4f, w - 4f, h - 8f);
        Raylib.DrawRectangle((int)inner.X, (int)inner.Y, (int)inner.Width, (int)inner.Height, WithAlpha(ForestShadow, 0.95f));
        var cross = new Rectangle(pos.X - 1f, pos.Y + h * 0.42f, w + 2f, h * 0.18f);
        Raylib.DrawRectangleRounded(cross, 0.2f, 3, WithAlpha(p.StoneDeep, 0.95f));
        Raylib.DrawLine((int)pos.X, (int)(pos.Y + 2f), (int)(pos.X + w), (int)(pos.Y + 2f), WithAlpha(p.StoneHi, 0.12f));
    }

    // -------------------------------------------------------------------------
    // Gatehouse ornament
    // -------------------------------------------------------------------------

    static void DrawMenuCastleShieldEmblem(Vector2 center, float time, MenuCastlePalette p)
    {
float pulse = MathF.Sin(time * 1.8f) * 0.5f + 0.5f;
        var shield = new Rectangle(center.X - 16f, center.Y - 20f, 32f, 36f);
        Raylib.DrawRectangleRounded(shield, 0.35f, 6, WithAlpha(Darken(p.StoneLight, 0.25f), 0.6f));
        Raylib.DrawRectangleRoundedLines(shield, 0.35f, 6, WithAlpha(p.StoneHi, 0.45f + pulse * 0.15f));
        for (int i = 0; i < 3; i++)
        {
            float ry = center.Y - 8f + i * 6f;
            Raylib.DrawLineEx(new Vector2(center.X - 10f + i * 2f, ry), new Vector2(center.X + 10f - i * 2f, ry), 1.5f, WithAlpha(p.StoneHi, 0.35f));
        }
        Raylib.DrawLineEx(new Vector2(center.X, center.Y - 14f), new Vector2(center.X, center.Y + 10f), 2f, WithAlpha(p.StoneHi, 0.5f));
    }

    static void DrawMenuCastleBanner(Vector2 top, float time, float phase, MenuCastlePalette p)
    {
        float wave = MathF.Sin(time * 2.4f + phase) * 5f;
        float fold = MathF.Sin(time * 3.3f + phase * 1.2f) * 0.5f + 0.5f;
        var banner = new Rectangle(top.X - 6f, top.Y, 12f, 30f + wave * 0.15f);
        Raylib.DrawRectangleRounded(banner, 0.2f, 3, WithAlpha(Darken(p.StoneLight, 0.35f), 0.55f));
        Raylib.DrawRectangleRounded(banner, 0.2f, 3, WithAlpha(Darken(p.StoneLight, 0.2f), 0.68f));
        for (int foldIdx = 0; foldIdx < 4; foldIdx++)
        {
            float fx = top.X - 4f + foldIdx * 2.5f;
            Color foldCol = LerpColor(p.StoneHi, p.StoneLight, foldIdx / 3f);
            Raylib.DrawLineEx(new Vector2(fx, top.Y), new Vector2(fx + wave * 0.05f + fold * 0.5f, top.Y + banner.Height),
                1f, WithAlpha(foldCol, 0.18f + fold * 0.1f));
        }
        Raylib.DrawLineEx(top, new Vector2(top.X, top.Y - 16f), 1.5f, WithAlpha(p.StoneLight, 0.7f));
        Raylib.DrawCircleV(new Vector2(top.X, top.Y - 16f), 2f, WithAlpha(p.StoneHi, 0.45f));
    }

    static void DrawMenuCastlePennant(Vector2 anchor, float time, MenuCastlePalette p)
    {
        float wave = MathF.Sin(time * 2.2f) * 6f;
        float fold = MathF.Sin(time * 3.1f + 0.8f) * 0.5f + 0.5f;
        Vector2 tip = new Vector2(anchor.X + 36f + wave, anchor.Y + 28f + fold * 3f);
        Raylib.DrawTriangle(anchor, new Vector2(anchor.X + 1f, anchor.Y + 39f), tip + new Vector2(2f, 1f), WithAlpha(p.StoneDark, 0.45f));
        Raylib.DrawTriangle(anchor, new Vector2(anchor.X, anchor.Y + 38f), tip, WithAlpha(p.StoneLight, 0.78f));
        Raylib.DrawLineEx(anchor, new Vector2(anchor.X, anchor.Y + 42f), 2f, WithAlpha(p.StoneHi, 0.85f));
        Raylib.DrawLineEx(anchor, tip, 1.5f, WithAlpha(p.StoneHi, 0.6f));
        Raylib.DrawLineEx(new Vector2(anchor.X + 8f, anchor.Y + 18f), tip, 1f, WithAlpha(p.StoneHi, 0.22f + fold * 0.12f));
        for (int tassel = 0; tassel < 3; tassel++)
            Raylib.DrawCircleV(new Vector2(tip.X - tassel * 4f, tip.Y + tassel * 2f), 1.5f, WithAlpha(p.StoneHi, 0.45f));
    }

    static void DrawMenuCastleTurret(Vector2 origin, float width, float height, MenuCastlePalette p, float time, float phase)
    {
var body = new Rectangle(origin.X, origin.Y, width, height);
        Raylib.DrawRectangleRounded(body, 0.1f, 6, WithAlpha(p.Stone, 0.88f));
        DrawMenuMasonryUltra(body, p, 6, 3);
        DrawTowerRoof(origin.X + width / 2f, origin.Y - 22f, origin.Y + 4f, width * 0.55f, p.StoneDark, p.StoneLight, p.StoneHi);
        DrawBattlements(new Rectangle(origin.X - 2f, origin.Y - 18f, width + 4f, 18f), p.StoneDark, p.StoneLight, p.StoneHi, 0.85f, time, true);
        DrawMenuTowerMoonRimLight(body, false, p);
        DrawMenuArrowSlit(new Vector2(origin.X + width / 2f, origin.Y + height * 0.35f), 6f, 20f, p);
        DrawCastleTorch(new Vector2(origin.X + width / 2f, origin.Y + height * 0.35f), time, phase, 0.75f, TorchMountKind.WallFace);
        DrawMenuTowerIronRing(new Vector2(origin.X + width * 0.5f, origin.Y + height * 0.15f), 3.5f, p);
    }

    static void DrawMenuCastleGate(Vector2 origin, float width, float height, MenuCastlePalette p, float time)
    {
        var arch = new Rectangle(origin.X, origin.Y, width, height);
        Raylib.DrawRectangleRounded(arch, 0.48f, 10, WithAlpha(p.StoneDeep, 0.98f));
        Raylib.DrawRectangleRoundedLines(arch, 0.48f, 10, WithAlpha(p.StoneLight, 0.8f));
        int segments = 13;
        for (int i = 0; i < segments; i++)
        {
            float t = i / (float)(segments - 1);
            float angle = MathF.PI + t * MathF.PI;
            float rx = width * 0.46f;
            float ry = height * 0.22f;
            float cx = origin.X + width / 2f;
            float cy = origin.Y + height * 0.08f;
            Vector2 vp = new Vector2(cx + MathF.Cos(angle) * rx, cy + MathF.Sin(angle) * ry);
            Color vCol = LerpColor(p.StoneDark, p.StoneLight, t);
            Raylib.DrawCircleV(vp, 5f + Hash(i * 7) * 1.5f, WithAlpha(vCol, 0.88f));
            Raylib.DrawCircleV(vp, 3f, WithAlpha(p.StoneHi, 0.15f + Hash(i * 11) * 0.2f));
        }
        float grateTop = origin.Y + height * 0.14f;
        float grateBot = origin.Y + height * 0.92f;
        int bars = 9;
        for (int b = 0; b < bars; b++)
        {
            float bx = origin.X + 10f + b * ((width - 20f) / (bars - 1));
            Raylib.DrawLineEx(new Vector2(bx, grateTop), new Vector2(bx, grateBot), 2.4f, WithAlpha(p.StoneHi, 0.55f));
            for (int rivet = 0; rivet < 5; rivet++)
            {
                float ry = grateTop + rivet * ((grateBot - grateTop) / 4f);
                Raylib.DrawCircleV(new Vector2(bx, ry), 1.2f, WithAlpha(p.Iron, 0.5f));
            }
        }
        for (int r = 0; r < 5; r++)
        {
            float gy = grateTop + r * ((grateBot - grateTop) / 4f);
            Raylib.DrawLineEx(new Vector2(origin.X + 8f, gy), new Vector2(origin.X + width - 8f, gy), 1.8f, WithAlpha(p.StoneLight, 0.4f));
        }
        // Chains
        for (int side = -1; side <= 1; side += 2)
        {
            float cx = origin.X + (side < 0 ? 16f : width - 16f);
            for (int link = 0; link < 8; link++)
            {
                float ly = grateTop + link * 10f;
                Raylib.DrawEllipse((int)cx, (int)ly, 3f, 5f, WithAlpha(p.Iron, 0.45f));
            }
        }
        // Hinge plates
        for (int h = 0; h < 3; h++)
        {
            float hy = origin.Y + height * (0.25f + h * 0.22f);
            Raylib.DrawRectangleRounded(new Rectangle(origin.X + 4f, hy, 10f, 14f), 0.15f, 2, WithAlpha(p.Iron, 0.55f));
            Raylib.DrawRectangleRounded(new Rectangle(origin.X + width - 14f, hy, 10f, 14f), 0.15f, 2, WithAlpha(p.Iron, 0.55f));
        }
        // Murder holes
        for (int mh = 0; mh < 4; mh++)
        {
            float mx = origin.X + width * (0.25f + mh * 0.16f);
            var hole = new Rectangle(mx - 4f, origin.Y + height * 0.05f, 8f, 10f);
            Raylib.DrawRectangleRounded(hole, 0.3f, 2, WithAlpha(ForestShadow, 0.9f));
            Raylib.DrawRectangleRoundedLines(hole, 0.3f, 2, WithAlpha(p.StoneHi, 0.25f));
        }
        var recess = new Rectangle(origin.X + width * 0.16f, origin.Y + height * 0.1f, width * 0.68f, height * 0.78f);
        Raylib.DrawRectangleRounded(recess, 0.38f, 8, WithAlpha(ForestShadow, 0.92f));
        float innerPulse = MathF.Sin(time * 3.2f) * 0.5f + 0.5f;
        DrawGradientWash(recess, WithAlpha(p.TorchWarm, 0.15f + innerPulse * 0.12f), WithAlpha(ForestShadow, 0f), new Vector2(0.5f, 0.7f), 2f);
        Raylib.DrawCircleV(new Vector2(origin.X + width / 2f, origin.Y + height * 0.06f), 7f, WithAlpha(p.StoneHi, 0.75f));
        float colW = 14f;
        Raylib.DrawRectangle((int)origin.X, (int)origin.Y, (int)colW, (int)height, WithAlpha(p.StoneDark, 0.9f));
        Raylib.DrawRectangle((int)(origin.X + width - colW), (int)origin.Y, (int)colW, (int)height, WithAlpha(p.StoneDark, 0.9f));
        Raylib.DrawLineEx(new Vector2(origin.X + 3f, origin.Y), new Vector2(origin.X + 3f, origin.Y + height), 1.5f, WithAlpha(p.StoneHi, 0.35f));
        Raylib.DrawLineEx(new Vector2(origin.X + width - 3f, origin.Y), new Vector2(origin.X + width - 3f, origin.Y + height), 1.5f, WithAlpha(p.StoneHi, 0.35f));
    }

    static void DrawMenuCastleDrawbridge(Vector2 topLeft, float width, float time, MenuCastlePalette p)
    {
        float drop = 10f + MathF.Sin(time * 0.5f) * 1.5f;
        var bridge = new Rectangle(topLeft.X + 8f, topLeft.Y, width - 16f, drop);
        Raylib.DrawRectangleRounded(bridge, 0.08f, 4, WithAlpha(p.StoneDark, 0.88f));
        int planks = 9;
        for (int plank = 0; plank < planks; plank++)
        {
            float px = bridge.X + 4f + plank * ((bridge.Width - 8f) / (planks - 1));
            Raylib.DrawLineEx(new Vector2(px, bridge.Y + 2f), new Vector2(px, bridge.Y + bridge.Height - 2f), 1.5f, WithAlpha(p.StoneLight, 0.28f));
            if (Hash(plank * 7) > 0.4f)
                Raylib.DrawCircleV(new Vector2(px + 2f, bridge.Y + bridge.Height * 0.5f), 1.2f, WithAlpha(p.Iron, 0.45f));
        }
        for (int row = 0; row < 3; row++)
        {
            float py = bridge.Y + 3f + row * (bridge.Height / 3f);
            Raylib.DrawLineEx(new Vector2(bridge.X + 2f, py), new Vector2(bridge.X + bridge.Width - 2f, py), 1f, WithAlpha(Darken(p.StoneLight, 0.2f), 0.25f));
        }
        for (int side = 0; side < 2; side++)
        {
            float cx = side == 0 ? topLeft.X + 14f : topLeft.X + width - 14f;
            Raylib.DrawLineEx(new Vector2(cx, topLeft.Y - 8f), new Vector2(cx, topLeft.Y + drop), 1.2f, WithAlpha(p.StoneLight, 0.35f));
            for (int link = 0; link < 4; link++)
            {
                float ly = topLeft.Y - 4f + link * 4f;
                Raylib.DrawEllipse((int)cx, (int)ly, 2f, 3.5f, WithAlpha(p.Iron, 0.4f));
            }
        }
    }

    static void DrawMenuCastleIvyPatches(float wallY, float wallH, float time, MenuCastlePalette p)
    {
        for (int i = 0; i < 10; i++)
        {
            float x = WindowWidth * (0.06f + i * 0.095f);
            if (MathF.Abs(x - WindowWidth / 2f) < 110f) continue;
            float sway = MathF.Sin(time * 0.6f + i) * 3f;
            for (int v = 0; v < 6; v++)
            {
                float vy = wallY + wallH * (0.1f + v * 0.14f);
                float r = 3.5f - v * 0.35f + Hash(i * 11 + v) * 1.5f;
                Raylib.DrawCircleV(new Vector2(x + sway, vy), r, WithAlpha(p.Moss, 0.3f - v * 0.04f));
            }
        }
    }

    static void DrawMenuCastleFinishingPass(float time, MenuCastlePalette p, float wallY, float wallH,
        float gateX, float gateW, float gateY, float gateH)
    {
        // Weather streaks on stone
        DrawMenuCastleErosionStreaks(new Rectangle(0f, wallY, WindowWidth, wallH), p, time);
        for (int s = 0; s < 24; s++)
        {
            float sx = Hash(s * 37) * WindowWidth;
            float sy = wallY + Hash(s * 41) * wallH;
            float len = 20f + Hash(s * 43) * 40f;
            Raylib.DrawLineEx(new Vector2(sx, sy), new Vector2(sx + Hash(s * 47) * 6f, sy + len), 1f, WithAlpha(p.WetSheen, 0.08f + Hash(s * 51) * 0.1f));
        }
        // Ambient occlusion in recesses
        var gateRecess = new Rectangle(gateX + gateW * 0.1f, gateY + gateH * 0.15f, gateW * 0.8f, gateH * 0.7f);
        DrawGradientWash(gateRecess, WithAlpha(p.StoneDeep, 0.35f), WithAlpha(p.StoneDeep, 0f), new Vector2(0.5f, 0f), 1.5f);
        Raylib.DrawRectangle(0, (int)(wallY - 6f), WindowWidth, 6, WithAlpha(p.StoneDeep, 0.5f));
        // Optional bat silhouettes
        if (Hash((int)(time * 10f)) > 0.3f)
        {
            for (int bat = 0; bat < 4; bat++)
            {
                float bx = WindowWidth * (0.15f + bat * 0.22f) + MathF.Sin(time * 1.2f + bat) * 30f;
                float by = WindowHeight * 0.22f + MathF.Sin(time * 0.8f + bat * 2f) * 20f;
                float wing = MathF.Sin(time * 6f + bat) * 4f;
                Raylib.DrawLineEx(new Vector2(bx - 6f, by), new Vector2(bx - wing, by - 3f), 1.2f, WithAlpha(p.StoneDeep, 0.5f));
                Raylib.DrawLineEx(new Vector2(bx + 6f, by), new Vector2(bx + wing, by - 3f), 1.2f, WithAlpha(p.StoneDeep, 0.5f));
                Raylib.DrawCircleV(new Vector2(bx, by), 1.5f, WithAlpha(p.StoneDeep, 0.55f));
            }
        }
        // Distant keep rim on horizon
        float keepY = wallY - 24f;
        var keep = new Rectangle(WindowWidth * 0.38f, keepY, WindowWidth * 0.24f, 48f);
        Raylib.DrawRectangleRounded(keep, 0.05f, 4, WithAlpha(p.StoneDeep, 0.65f));
        DrawBattlements(new Rectangle(keep.X - 4f, keep.Y - 14f, keep.Width + 8f, 14f), p.StoneDeep, p.StoneLight, p.StoneHi, 0.9f, time, true);
        DrawEllipticalGlow(new Vector2(keep.X + keep.Width / 2f, keep.Y), keep.Width * 0.6f, 8f, 0f, p.MoonGlow, 0.02f, 2);
        DrawMenuCastleMoonlitWallRim(wallY, wallH, p, time);
    }

    // -------------------------------------------------------------------------
    // Main menu castle framing
    // -------------------------------------------------------------------------

    static void DrawMenuCastleFraming(float time)
    {
        MenuCastlePalette p = MenuPalette;
        DrawMenuCastleNightSky(time);
        DrawMenuCastleMoon(time);

        float wallH = WindowHeight * 0.46f;
        float wallY = WindowHeight - wallH;

        DrawMenuCastleHorizonMist(wallY, p, time);
        DrawMenuCastleSilhouetteLayer(wallY, wallH, p, time);

        // Soft atmospheric veil between sky and fortress
        Raylib.DrawRectangleGradientV(0, (int)(wallY - 110f), WindowWidth, 90,
            WithAlpha(p.StoneDeep, 0f), WithAlpha(new Color(18, 17, 16, 255), 0.28f));

        Raylib.DrawRectangleGradientV(0, (int)(wallY - 90f), WindowWidth, 120,
            WithAlpha(p.StoneDeep, 0f), WithAlpha(p.StoneDeep, 0.42f));

        var curtain = new Rectangle(40f, wallY - 18f, WindowWidth - 80f, wallH + 18f);
        Raylib.DrawRectangleRounded(curtain, 0.02f, 6, WithAlpha(p.StoneDeep, 0.55f));
        Raylib.DrawRectangleRoundedLines(curtain, 0.02f, 6, WithAlpha(p.StoneLight, 0.12f));

        Raylib.DrawRectangle(0, (int)wallY, WindowWidth, (int)wallH, p.StoneDark);
        Raylib.DrawRectangleGradientV(0, (int)wallY, WindowWidth, (int)(wallH * 0.35f),
            WithAlpha(p.StoneMid, 0.35f), WithAlpha(p.StoneDark, 0f));
        Raylib.DrawRectangleGradientV(0, (int)(wallY + wallH * 0.55f), WindowWidth, (int)(wallH * 0.45f),
            WithAlpha(p.StoneDark, 0f), WithAlpha(p.StoneDeep, 0.85f));

        DrawMenuMasonryUltra(new Rectangle(0f, wallY, WindowWidth, wallH), p, 11, 20);
        DrawMenuCastleCurtainWallRelief(wallY, wallH, p, time);
        DrawMenuCastleIvyPatches(wallY, wallH, time, p);
        DrawMenuCastleTowerBasePlinths(wallY, wallH, p);

        DrawButtress(new Vector2(0f, wallY), 62f, wallH, p.Stone, p.StoneDark, p.StoneLight, true);
        DrawButtress(new Vector2(WindowWidth - 62f, wallY), 62f, wallH, p.Stone, p.StoneDark, p.StoneLight, false);

        DrawMenuCastleTower(new Vector2(-6f, wallY - 52f), 168f, wallH + 88f, p, time, true, 0f);
        DrawMenuCastleTower(new Vector2(WindowWidth - 162f, wallY - 52f), 168f, wallH + 88f, p, time, false, 0.9f);

        float gatehouseW = 196f;
        float gatehouseH = wallH * 0.92f;
        float gatehouseX = WindowWidth / 2f - gatehouseW / 2f;
        float gatehouseY = WindowHeight - gatehouseH;
        var gatehouse = new Rectangle(gatehouseX, gatehouseY - 34f, gatehouseW, gatehouseH + 34f);
        Raylib.DrawRectangleRounded(gatehouse, 0.04f, 8, p.StoneMid);
        Raylib.DrawRectangleRoundedLines(gatehouse, 0.04f, 8, WithAlpha(p.StoneLight, 0.7f));
        DrawMenuMasonryUltra(gatehouse, p, 8, 7);
        DrawQuoinStripes(gatehouse, p.StoneLight, p.StoneHi);
        DrawMenuCastleShieldEmblem(new Vector2(WindowWidth / 2f, gatehouseY - 8f), time, p);
        DrawMenuCastleGatehouseWindows(gatehouse, p, time);
        DrawMenuCastleLintelShadows(gatehouse, p);
        DrawMenuCastleIronworkDetail(gatehouse, p, 42);

        DrawBattlements(new Rectangle(gatehouseX - 8f, gatehouseY - 58f, gatehouseW + 16f, 32f), p.StoneDark, p.StoneLight, p.StoneHi, 1.1f, time, true);
        DrawMenuCastleTurret(new Vector2(gatehouseX - 22f, gatehouseY - 18f), 44f, 108f, p, time, 1.3f);
        DrawMenuCastleTurret(new Vector2(gatehouseX + gatehouseW - 22f, gatehouseY - 18f), 44f, 108f, p, time, 2.1f);
        DrawMenuCastleBanner(new Vector2(gatehouseX + 8f, gatehouseY - 52f), time, 0f, p);
        DrawMenuCastleBanner(new Vector2(gatehouseX + gatehouseW - 8f, gatehouseY - 52f), time, 1.4f, p);

        float gateW = 108f;
        float gateH = gatehouseH * 0.58f;
        float gateX = WindowWidth / 2f - gateW / 2f;
        float gateY = WindowHeight - gateH - 8f;
        DrawMenuCastleDrawbridge(new Vector2(gateX, gateY + gateH - 4f), gateW, time, p);
        DrawMenuCastleGate(new Vector2(gateX, gateY), gateW, gateH, p, time);
        DrawMenuCastleCourtyardDepth(gateX, gateW, gateY, gateH, p, time);
        DrawMenuCastleDrawbridgeShadow(gateX, gateW, gateY, gateH, p);
        DrawMenuCastlePortcullisShadow(new Vector2(gateX, gateY), gateW, gateH, p);

        float gateFlicker = MathF.Sin(time * 4.6f) * 0.5f + 0.5f;
        Vector2 gateGlow = new Vector2(gateX + gateW / 2f, gateY + gateH * 0.55f);
        DrawEllipticalGlow(gateGlow, gateW * 0.62f, gateH * 0.48f, 0f, p.TorchWarm, 0.06f + gateFlicker * 0.05f, 5);
        DrawLightCone(gateGlow, MathF.PI * 0.5f, gateH * 0.55f, 0.42f, p.TorchWarm, 0.04f + gateFlicker * 0.03f);

        DrawMenuCastlePennant(new Vector2(WindowWidth / 2f, gatehouseY - 62f), time, p);

        DrawMenuCastleWallWalkway(wallY, p);
        DrawMenuCastleRampartTorches(wallY, time, p);

        Raylib.DrawRectangle(0, (int)(wallY - 4f), WindowWidth, 4, WithAlpha(p.StoneDeep, 0.9f));
        Raylib.DrawLine(0, (int)(wallY - 4f), WindowWidth, (int)(wallY - 4f), WithAlpha(p.StoneHi, 0.25f));
        Raylib.DrawLine(0, (int)(wallY - 5f), WindowWidth, (int)(wallY - 5f), WithAlpha(p.StoneLight, 0.08f));

        DrawMenuCurtainWallArrowSlits(wallY, gatehouseX, gatehouseW, p);

        Vector2 torchL = new Vector2(gateX - 42f, gateY + 12f);
        Vector2 torchR = new Vector2(gateX + gateW + 42f, gateY + 12f);
        DrawCastleTorch(torchL, time, 0f, 1.15f, TorchMountKind.WallRight);
        DrawCastleTorch(torchR, time, 1.8f, 1.15f, TorchMountKind.WallLeft);
        DrawCastleTorch(new Vector2(118f, wallY + 48f), time, 3.2f, 0.9f, TorchMountKind.WallFace);
        DrawCastleTorch(new Vector2(WindowWidth - 118f, wallY + 48f), time, 4.5f, 0.9f, TorchMountKind.WallFace);
        DrawWallTorchWash(torchL, new Vector2(0.2f, 0.1f), time, 0f, 1.1f);
        DrawWallTorchWash(torchR, new Vector2(-0.2f, 0.1f), time, 1.8f, 1.1f);
        DrawWallTorchWash(new Vector2(118f, wallY + 48f), new Vector2(0.3f, 0.05f), time, 3.2f, 0.85f);
        DrawWallTorchWash(new Vector2(WindowWidth - 118f, wallY + 48f), new Vector2(-0.3f, 0.05f), time, 4.5f, 0.85f);

        DrawCobbleForeground(new Rectangle(0f, WindowHeight - 38f, WindowWidth, 38f), p.StoneDeep, p.Mortar);
        var wetZone = new Rectangle(gateX - 50f, WindowHeight - 38f, gateW + 100f, 38f);
        Raylib.DrawRectangleGradientV((int)wetZone.X, (int)wetZone.Y, (int)wetZone.Width, (int)wetZone.Height,
            WithAlpha(p.TorchWarm, 0.06f + gateFlicker * 0.05f), WithAlpha(p.StoneDeep, 0f));
        for (int sheen = 0; sheen < 12; sheen++)
        {
            float shx = gateX + Hash(sheen * 13) * gateW;
            Raylib.DrawLineEx(new Vector2(shx, WindowHeight - 36f), new Vector2(shx + 8f, WindowHeight - 30f), 1f, WithAlpha(p.WetSheen, 0.12f + Hash(sheen * 17) * 0.1f));
        }

        DrawMenuCastleFinishingPass(time, p, wallY, wallH, gateX, gateW, gateY, gateH);
        DrawMenuCastleRefinementPass(time, p, wallY, wallH, gateX, gateW, gateY, gateH, gatehouseX, gatehouseW, gatehouseY);
        DrawMenuCastleReleasePass(time, p, wallY, wallH, gateX, gateW, gateY, gateH, gatehouseX, gatehouseW, gatehouseY, gatehouse);
    }

    static void DrawMenuCastleReleasePass(float time, MenuCastlePalette p, float wallY, float wallH,
        float gateX, float gateW, float gateY, float gateH, float gatehouseX, float gatehouseW, float gatehouseY,
        Rectangle gatehouse)
    {
        Vector2 moon = MenuCastleMoonPosition;
        float gateFlicker = MathF.Sin(time * 4.6f) * 0.5f + 0.5f;

        // Ground-hugging ambient occlusion where the wall meets the world
        Raylib.DrawRectangleGradientV(0, (int)(wallY - 6f), WindowWidth, 28,
            WithAlpha(ForestShadow, 0f), WithAlpha(ForestShadow, 0.38f));
        Raylib.DrawRectangleGradientV(0, (int)(WindowHeight - 42f), WindowWidth, 42,
            WithAlpha(ForestShadow, 0.22f), WithAlpha(ForestShadow, 0f));

        // Gatehouse string courses — horizontal masonry bands for visual weight
        for (int course = 0; course < 3; course++)
        {
            float cy = gatehouse.Y + gatehouse.Height * (0.22f + course * 0.22f);
            Raylib.DrawLineEx(new Vector2(gatehouse.X + 8f, cy), new Vector2(gatehouse.X + gatehouse.Width - 8f, cy),
                1f, WithAlpha(p.StoneLight, 0.10f + Hash(course * 9) * 0.08f));
            Raylib.DrawLineEx(new Vector2(gatehouse.X + 8f, cy + 1f), new Vector2(gatehouse.X + gatehouse.Width - 8f, cy + 1f),
                1f, WithAlpha(p.StoneDeep, 0.18f));
        }

        // Quoin corner depth on gatehouse
        Raylib.DrawRectangleGradientH((int)gatehouse.X, (int)gatehouse.Y, 14, (int)gatehouse.Height,
            WithAlpha(ForestShadow, 0.22f), WithAlpha(ForestShadow, 0f));
        Raylib.DrawRectangleGradientH((int)(gatehouse.X + gatehouse.Width - 14f), (int)gatehouse.Y, 14, (int)gatehouse.Height,
            WithAlpha(ForestShadow, 0f), WithAlpha(ForestShadow, 0.22f));

        // Rising embers from gate torches
        Vector2[] emberSources =
        [
            new Vector2(gateX - 42f, gateY + 12f),
            new Vector2(gateX + gateW + 42f, gateY + 12f),
        ];
        for (int e = 0; e < emberSources.Length; e++)
        {
            for (int em = 0; em < 6; em++)
            {
                float life = (time * (1.6f + em * 0.3f) + e * 2f + em * 0.7f) % 1f;
                Vector2 pos = emberSources[e] + new Vector2(MathF.Sin(life * 12f + em) * 8f, -life * 42f);
                Raylib.DrawCircleV(pos, 1.2f - life * 0.6f, WithAlpha(p.TorchWarm, (1f - life) * 0.55f));
            }
        }

        // Moon-silver reflection band on wet forecourt cobbles
        float reflectX = gateX + gateW / 2f + (moon.X - (gateX + gateW / 2f)) * 0.15f;
        DrawEllipticalGlow(new Vector2(reflectX, WindowHeight - 28f), gateW * 0.42f, 10f, 0f,
            p.MoonGlow, 0.016f + MathF.Sin(time * 0.35f) * 0.004f, 3);

        // Alternating merlon top highlights and shadow gaps
        for (int m = 0; m < 22; m++)
        {
            float mx = 48f + m * ((WindowWidth - 96f) / 21f);
            bool lit = m % 2 == 0;
            Raylib.DrawRectangle((int)mx, (int)(wallY - 10f), 9, lit ? 6 : 4,
                WithAlpha(lit ? p.StoneHi : ForestShadow, lit ? 0.14f : 0.28f));
        }

        // Ivy rim highlights catching moon on wall top edge
        for (int iv = 0; iv < 14; iv++)
        {
            float ix = Hash(iv * 41) * WindowWidth;
            float iy = wallY + 8f + Hash(iv * 43) * (wallH * 0.55f);
            if (Hash(iv * 47) > 0.55f)
                Raylib.DrawCircleV(new Vector2(ix, iy), 1.5f + Hash(iv * 53), WithAlpha(p.Lichen, 0.12f + Hash(iv * 59) * 0.12f));
        }

        // Faint warm pulse inside gatehouse arrow-slit windows
        float[] winCols = { gatehouseX + gatehouseW * 0.22f, gatehouseX + gatehouseW * 0.5f, gatehouseX + gatehouseW * 0.78f };
        float winRowY = gatehouse.Y + gatehouse.Height * 0.36f;
        for (int w = 0; w < winCols.Length; w++)
        {
            float pulse = MathF.Sin(time * 1.5f + w * 1.7f) * 0.5f + 0.5f;
            var win = new Rectangle(winCols[w] - 8f, winRowY, 16f, 22f);
            DrawEllipticalGlow(new Vector2(win.X + win.Width / 2f, win.Y + win.Height / 2f),
                win.Width * 0.7f, win.Height * 0.65f, 0f, p.TorchWarm, 0.012f + pulse * 0.01f, 2);
        }

        // Shield emblem polish — subtle gold edge catch
        Vector2 shieldCenter = new Vector2(WindowWidth / 2f, gatehouseY - 8f);
        Raylib.DrawCircleLines((int)shieldCenter.X, (int)(shieldCenter.Y - 2f), 14f, WithAlpha(Gold, 0.12f + gateFlicker * 0.08f));

        // Banner cloth shadow under pennant
        Vector2 pennantAnchor = new Vector2(WindowWidth / 2f, gatehouseY - 62f);
        Raylib.DrawLineEx(pennantAnchor + new Vector2(4f, 4f), pennantAnchor + new Vector2(40f, 34f), 2f, WithAlpha(ForestShadow, 0.25f));

        // Distant silhouette birds crossing the moon path
        for (int bat = 0; bat < 3; bat++)
        {
            float t = (time * 0.08f + bat * 0.31f) % 1f;
            float bx = WindowWidth * (0.1f + t * 0.8f);
            float by = WindowHeight * (0.14f + bat * 0.04f) + MathF.Sin(time * 1.1f + bat) * 8f;
            float wing = MathF.Sin(time * 7f + bat * 2f) * 3.5f;
            Raylib.DrawLineEx(new Vector2(bx - 5f, by), new Vector2(bx - wing, by - 2f), 1f, WithAlpha(p.StoneDeep, 0.4f));
            Raylib.DrawLineEx(new Vector2(bx + 5f, by), new Vector2(bx + wing, by - 2f), 1f, WithAlpha(p.StoneDeep, 0.4f));
        }

        // Tower roof edge highlights on both flanking towers
        ReadOnlySpan<(float x, float y)> towerRims =
        [
            (78f, wallY - 46f),
            (WindowWidth - 78f, wallY - 46f),
        ];
        for (int t = 0; t < towerRims.Length; t++)
        {
            var (tx, ty) = towerRims[t];
            Raylib.DrawLineEx(new Vector2(tx - 28f, ty), new Vector2(tx + 28f, ty - 5f), 1.2f, WithAlpha(p.StoneHi, 0.16f));
            DrawEllipticalGlow(new Vector2(tx, ty - 2f), 34f, 8f, -4f, p.MoonGlow, 0.01f, 2);
        }

        // Portcullis depth shadow behind bars
        var gateDepth = new Rectangle(gateX + gateW * 0.12f, gateY + gateH * 0.18f, gateW * 0.76f, gateH * 0.68f);
        DrawGradientWash(gateDepth, WithAlpha(ForestShadow, 0.5f), WithAlpha(ForestShadow, 0f), new Vector2(0.5f, 0f), 1.6f);
    }

    static void DrawMenuCastleRefinementPass(float time, MenuCastlePalette p, float wallY, float wallH,
        float gateX, float gateW, float gateY, float gateH, float gatehouseX, float gatehouseW, float gatehouseY)
    {
        float moonX = WindowWidth * 0.76f;
        float gateFlicker = MathF.Sin(time * 4.6f) * 0.5f + 0.5f;

        // Chimney smoke drifting from gatehouse towers
        Vector2[] chimneys =
        {
            new Vector2(gatehouseX + 28f, gatehouseY - 36f),
            new Vector2(gatehouseX + gatehouseW - 28f, gatehouseY - 36f),
        };
        for (int c = 0; c < chimneys.Length; c++)
        {
            for (int w = 0; w < 5; w++)
            {
                float drift = time * (0.7f + c * 0.25f) + w * 0.9f;
                float wx = chimneys[c].X + MathF.Sin(drift) * (6f + w * 2.5f);
                float wy = chimneys[c].Y - 10f - w * 9f;
                DrawEllipticalGlow(new Vector2(wx, wy), 8f + w * 3f, 4f + w * 1.5f, Hash(c * 5 + w) * 18f,
                    new Color(52, 50, 48, 255), 0.011f - w * 0.0015f, 2);
            }
        }

        // Iron glints on the portcullis
        float grateTop = gateY + gateH * 0.14f;
        float grateBot = gateY + gateH * 0.92f;
        for (int b = 0; b < 9; b += 2)
        {
            float bx = gateX + 10f + b * ((gateW - 20f) / 8f);
            float gy = grateTop + Hash(b * 13) * (grateBot - grateTop);
            if (Hash(b * 17 + (int)(time * 2.4f)) > 0.82f)
                Raylib.DrawCircleV(new Vector2(bx, gy), 1.6f, WithAlpha(p.StoneHi, 0.45f + gateFlicker * 0.15f));
        }

        // Wet cobble sparkles in the torch-lit forecourt
        for (int s = 0; s < 20; s++)
        {
            float sx = gateX - 44f + Hash(s * 23) * (gateW + 88f);
            float sy = WindowHeight - 33f + Hash(s * 29) * 5f;
            float tw = MathF.Sin(time * 3.8f + s * 1.6f) * 0.5f + 0.5f;
            if (tw > 0.78f)
                Raylib.DrawCircleV(new Vector2(sx, sy), 0.8f + Hash(s * 31), WithAlpha(p.WetSheen, 0.18f + tw * 0.22f));
        }

        // Moonlit caps on the flanking towers and gatehouse
        ReadOnlySpan<Vector2> peaks =
        [
            new Vector2(78f, wallY - 28f),
            new Vector2(WindowWidth - 78f, wallY - 28f),
            new Vector2(gatehouseX + gatehouseW / 2f, gatehouseY - 54f),
        ];
        for (int i = 0; i < peaks.Length; i++)
        {
            float facing = Math.Clamp(1f - MathF.Abs(peaks[i].X - moonX) / 260f, 0.15f, 1f);
            DrawEllipticalGlow(peaks[i], 22f * facing, 7f, -6f, p.MoonGlow, 0.013f * facing, 2);
            Raylib.DrawLineEx(new Vector2(peaks[i].X - 10f, peaks[i].Y + 1f), new Vector2(peaks[i].X + 10f, peaks[i].Y - 3f),
                1f, WithAlpha(p.StoneHi, 0.14f * facing));
        }

        // Keystone catch-light on the gate arch
        Vector2 keystone = new Vector2(gateX + gateW / 2f, gateY + gateH * 0.06f);
        Raylib.DrawCircleV(keystone, 3.5f, WithAlpha(p.StoneHi, 0.32f + MathF.Sin(time * 1.1f) * 0.08f));

        // Warm torch spill across the gatehouse lintel
        var lintelSpill = new Rectangle(gatehouseX + 16f, gatehouseY - 18f, gatehouseW - 32f, 36f);
        Raylib.DrawRectangleGradientV((int)lintelSpill.X, (int)lintelSpill.Y, (int)lintelSpill.Width, (int)lintelSpill.Height,
            WithAlpha(p.TorchWarm, 0f), WithAlpha(p.TorchWarm, 0.035f + gateFlicker * 0.025f));

        // Deep merlon shadow teeth along the wall walk
        for (int m = 0; m < 18; m++)
        {
            float mx = 56f + m * ((WindowWidth - 112f) / 17f);
            Raylib.DrawRectangle((int)mx, (int)(wallY - 7f), 7, 5, WithAlpha(ForestShadow, 0.32f));
        }

        // Drawbridge chain sway and hinge gleam
        for (int side = 0; side < 2; side++)
        {
            float cx = side == 0 ? gateX + 14f : gateX + gateW - 14f;
            float sway = MathF.Sin(time * 1.4f + side * 2.1f) * 2f;
            for (int link = 0; link < 6; link++)
            {
                float ly = gateY + gateH * 0.2f + link * 9f;
                Raylib.DrawEllipse((int)(cx + sway), (int)ly, 2.5f, 4f, WithAlpha(p.Iron, 0.42f));
            }
            Raylib.DrawCircleV(new Vector2(cx + sway, gateY + gateH * 0.18f), 2f, WithAlpha(p.StoneHi, 0.35f));
        }
    }

    // -------------------------------------------------------------------------
    // Additional horizon and wall surface detail
    // -------------------------------------------------------------------------

    static void DrawMenuCastleHorizonMist(float wallY, MenuCastlePalette p, float time)
    {
        for (int layer = 0; layer < 5; layer++)
        {
            float y = wallY - 70f + layer * 14f;
            float alpha = 0.08f + layer * 0.04f;
            float drift = MathF.Sin(time * 0.15f + layer) * 12f;
            for (int wisp = 0; wisp < 6; wisp++)
            {
                float wx = WindowWidth * (wisp / 5f) + drift + Hash(layer * 11 + wisp) * 40f;
                DrawEllipticalGlow(new Vector2(wx, y), 60f + layer * 10f, 14f, layer * 4f, p.MoonGlow, alpha, 2);
            }
        }
    }

    static void DrawMenuCastleSilhouetteLayer(float wallY, float wallH, MenuCastlePalette p, float time)
    {
        float sway = MathF.Sin(time * 0.22f) * 1.2f;
        float fogPulse = 0.26f + MathF.Sin(time * 0.38f) * 0.04f;

        var farKeep = new Rectangle(WindowWidth * 0.30f + sway, wallY - 82f, WindowWidth * 0.40f, 58f);
        Raylib.DrawRectangleRounded(farKeep, 0.04f, 4, WithAlpha(ForestShadow, 0.5f));
        DrawBattlements(new Rectangle(farKeep.X - 5f, farKeep.Y - 11f, farKeep.Width + 10f, 11f),
            p.StoneDeep, p.StoneMid, p.StoneHi, 0.65f, time, true);

        Raylib.DrawRectangleRounded(new Rectangle(-14f, wallY - 42f, 152f, wallH + 74f), 0.05f, 6, WithAlpha(ForestShadow, 0.32f));
        Raylib.DrawRectangleRounded(new Rectangle(WindowWidth - 140f, wallY - 42f, 152f, wallH + 74f), 0.05f, 6, WithAlpha(ForestShadow, 0.32f));

        Raylib.DrawRectangleGradientV(0, (int)(wallY - 32f), WindowWidth, 64,
            WithAlpha(p.StoneDeep, 0f), WithAlpha(ForestShadow, fogPulse));

        for (int spire = 0; spire < 3; spire++)
        {
            float sx = WindowWidth * (0.18f + spire * 0.32f) + MathF.Sin(time * 0.3f + spire) * 4f;
            float sy = wallY - 18f - spire * 6f;
            Raylib.DrawLineEx(new Vector2(sx, sy), new Vector2(sx, sy - 28f - Hash(spire * 7) * 14f), 2f, WithAlpha(ForestShadow, 0.38f));
            Raylib.DrawCircleV(new Vector2(sx, sy - 30f), 2.5f, WithAlpha(p.StoneDeep, 0.45f));
        }
    }

    static void DrawMenuCastleWallWalkway(float wallY, MenuCastlePalette p)
    {
        Raylib.DrawRectangle(0, (int)(wallY - 8f), WindowWidth, 8, WithAlpha(p.StoneDark, 0.75f));
        for (int paver = 0; paver < 40; paver++)
        {
            float px = paver * (WindowWidth / 40f);
            float n = Hash(paver * 19);
            Color c = LerpColor(p.StoneDark, p.StoneMid, n * 0.4f);
            Raylib.DrawRectangle((int)px, (int)(wallY - 7f), (int)(WindowWidth / 40f) - 1, 6, WithAlpha(c, 0.5f));
        }
        Raylib.DrawLine(0, (int)(wallY - 8f), WindowWidth, (int)(wallY - 8f), WithAlpha(p.StoneHi, 0.15f));
    }

    static void DrawMenuCurtainWallArrowSlits(float wallY, float gatehouseX, float gatehouseW, MenuCastlePalette p)
    {
        float gateLeft = gatehouseX - 24f;
        float gateRight = gatehouseX + gatehouseW + 24f;
        float[] rows = { wallY + 50f, wallY + 96f };
        float[] leftCols = { 188f, 236f, 284f };
        float[] rightCols = { WindowWidth - 284f, WindowWidth - 236f, WindowWidth - 188f };

        foreach (float row in rows)
        {
            foreach (float col in leftCols)
            {
                if (col >= gateLeft) continue;
                DrawMenuArrowSlit(new Vector2(col, row), 8f, 30f, p);
            }

            foreach (float col in rightCols)
            {
                if (col <= gateRight) continue;
                DrawMenuArrowSlit(new Vector2(col, row), 8f, 30f, p);
            }
        }
    }

    static void DrawMenuCastleGatehouseWindows(Rectangle gatehouse, MenuCastlePalette p, float time)
    {
        float rowY = gatehouse.Y + gatehouse.Height * 0.36f;
        float[] cols = { gatehouse.X + gatehouse.Width * 0.22f, gatehouse.X + gatehouse.Width * 0.5f, gatehouse.X + gatehouse.Width * 0.78f };
        for (int w = 0; w < cols.Length; w++)
        {
            var win = new Rectangle(cols[w] - 8f, rowY, 16f, 22f);
            DrawWindowInteriorGlow(win, time, w * 1.7f);
            Raylib.DrawRectangleRounded(win, 0.2f, 4, WithAlpha(p.StoneDeep, 0.92f));
            Raylib.DrawRectangleRoundedLines(win, 0.2f, 4, WithAlpha(p.StoneHi, 0.4f));
            Raylib.DrawLine((int)(win.X + win.Width / 2f), (int)win.Y, (int)(win.X + win.Width / 2f), (int)(win.Y + win.Height), WithAlpha(p.StoneDeep, 0.5f));
        }
    }

    static void DrawMenuCastleCurtainWallRelief(float wallY, float wallH, MenuCastlePalette p, float time)
    {
        for (int course = 0; course < 4; course++)
        {
            float cy = wallY + wallH * (0.2f + course * 0.18f);
            Raylib.DrawLine(0, (int)cy, WindowWidth, (int)cy, WithAlpha(p.StoneLight, 0.06f + Hash(course * 7) * 0.06f));
        }

        var wallRegion = new Rectangle(0f, wallY, WindowWidth, wallH);
        DrawMenuCastleStoneDetailOrchestrator(wallRegion, p, time);
    }

    static void DrawMenuCastleTowerBasePlinths(float wallY, float wallH, MenuCastlePalette p)
    {
        DrawMenuTowerCorbelTable(-2f, wallY + wallH - 12f, 180f, p);
        DrawMenuTowerCorbelTable(WindowWidth - 178f, wallY + wallH - 12f, 180f, p);
        for (int block = 0; block < 8; block++)
        {
            float bx = block < 4 ? block * 42f : WindowWidth - (block - 3) * 42f;
            Raylib.DrawRectangleRounded(new Rectangle(bx, wallY + wallH - 16f, 38f, 14f), 0.1f, 3, WithAlpha(p.StoneDark, 0.8f));
            Raylib.DrawLine((int)bx, (int)(wallY + wallH - 16f), (int)(bx + 38f), (int)(wallY + wallH - 16f), WithAlpha(p.StoneHi, 0.2f));
        }
    }

    static void DrawMenuCastleStarCluster(Vector2 center, int seed, float time, float radius)
    {
        int count = 6 + (int)(Hash(seed) * 8f);
        for (int i = 0; i < count; i++)
        {
            float ang = Hash(seed + i * 13) * MathF.PI * 2f;
            float dist = Hash(seed + i * 17) * radius;
            Vector2 pos = new Vector2(center.X + MathF.Cos(ang) * dist, center.Y + MathF.Sin(ang) * dist);
            float tw = MathF.Sin(time * 1.6f + i + seed) * 0.5f + 0.5f;
            Color sc = LerpColor(new Color(176, 188, 228, 255), new Color(228, 218, 196, 255), Hash(seed + i * 23));
            Raylib.DrawCircleV(pos, 0.6f + Hash(seed + i * 29) * 0.6f, WithAlpha(sc, 0.05f + tw * 0.1f));
        }
    }

    static void DrawMenuCastleNightSkyExtras(float time)
    {
        Vector2[] clusters =
        {
            new Vector2(WindowWidth * 0.18f, WindowHeight * 0.12f),
            new Vector2(WindowWidth * 0.42f, WindowHeight * 0.08f),
            new Vector2(WindowWidth * 0.58f, WindowHeight * 0.15f),
            new Vector2(WindowWidth * 0.88f, WindowHeight * 0.1f),
        };
        for (int c = 0; c < clusters.Length; c++)
            DrawMenuCastleStarCluster(clusters[c], c * 97 + 13, time, 28f + c * 6f);

        // Faint atmospheric band just above the horizon — neutral, not blue.
        int bandY = (int)(WindowHeight * 0.46f);
        Raylib.DrawRectangleGradientV(0, bandY - 20, WindowWidth, 40,
            WithAlpha(new Color(10, 9, 11, 255), 0f), WithAlpha(new Color(10, 9, 11, 255), 0.2f));
    }

    static void DrawMenuCastleDrawbridgeShadow(float gateX, float gateW, float gateY, float gateH, MenuCastlePalette p)
    {
        var shadow = new Rectangle(gateX - 12f, gateY + gateH - 6f, gateW + 24f, 14f);
        DrawGradientWash(shadow, WithAlpha(p.StoneDeep, 0.45f), WithAlpha(p.StoneDeep, 0f), new Vector2(0.5f, 0f), 1.4f);
    }

    static void DrawMenuCastlePortcullisShadow(Vector2 gateOrigin, float width, float height, MenuCastlePalette p)
    {
        for (int bar = 0; bar < 9; bar++)
        {
            float bx = gateOrigin.X + 10f + bar * ((width - 20f) / 8f);
            var barShadow = new Rectangle(bx - 2f, gateOrigin.Y + height * 0.2f, 4f, height * 0.72f);
            DrawGradientWash(barShadow, WithAlpha(p.StoneDeep, 0.25f), WithAlpha(p.StoneDeep, 0f), new Vector2(0.5f, 0f), 1.2f);
        }
    }

    static void DrawMenuCastleRampartTorches(float wallY, float time, MenuCastlePalette p)
    {
        float[] positions = { 0.08f, 0.22f, 0.78f, 0.92f };
        for (int i = 0; i < positions.Length; i++)
        {
            Vector2 pos = new Vector2(WindowWidth * positions[i], wallY - 26f);
            DrawCastleTorch(pos, time, i * 2.1f, 0.75f, TorchMountKind.Rampart);
            DrawWallTorchWash(pos, new Vector2(0f, 1f), time, i * 2.1f, 0.75f);
        }
    }

    static void DrawMenuCastleIronworkDetail(Rectangle region, MenuCastlePalette p, int seed)
    {
        for (int rivet = 0; rivet < 16; rivet++)
        {
            float rx = region.X + Hash(seed + rivet * 3) * region.Width;
            float ry = region.Y + Hash(seed + rivet * 5) * region.Height;
            Raylib.DrawCircleV(new Vector2(rx, ry), 1.1f + Hash(seed + rivet * 7) * 0.6f, WithAlpha(p.Iron, 0.45f + Hash(seed + rivet * 11) * 0.2f));
            if (Hash(seed + rivet * 13) > 0.65f)
            {
                Raylib.DrawLineEx(new Vector2(rx - 2f, ry), new Vector2(rx + 2f, ry), 0.6f, WithAlpha(p.StoneHi, 0.25f));
                Raylib.DrawLineEx(new Vector2(rx, ry - 2f), new Vector2(rx, ry + 2f), 0.6f, WithAlpha(Darken(p.Iron, 0.2f), 0.2f));
            }
        }
    }

    static void DrawMenuCastleErosionStreaks(Rectangle region, MenuCastlePalette p, float time)
    {
        for (int streak = 0; streak < 20; streak++)
        {
            float sx = region.X + Hash(streak * 41 + 2) * region.Width;
            float sy = region.Y + Hash(streak * 43 + 4) * region.Height * 0.4f;
            float length = 16f + Hash(streak * 47) * 48f;
            float drip = MathF.Sin(time * 0.2f + streak) * 2f;
            Color streakCol = LerpColor(p.WetSheen, p.StoneDeep, Hash(streak * 53) * 0.5f);
            for (int seg = 0; seg < 5; seg++)
            {
                float t0 = seg / 5f;
                float t1 = (seg + 1) / 5f;
                Vector2 a = new Vector2(sx + drip * t0, sy + length * t0);
                Vector2 b = new Vector2(sx + drip * t1 + Hash(streak + seg) * 2f, sy + length * t1);
                Raylib.DrawLineEx(a, b, 0.8f, WithAlpha(streakCol, 0.12f - seg * 0.015f));
            }
        }
    }

    static void DrawMenuCastleLintelShadows(Rectangle gatehouse, MenuCastlePalette p)
    {
        for (int lintel = 0; lintel < 5; lintel++)
        {
            float ly = gatehouse.Y + gatehouse.Height * (0.18f + lintel * 0.14f);
            var shadow = new Rectangle(gatehouse.X + 4f, ly, gatehouse.Width - 8f, 6f);
            DrawGradientWash(shadow, WithAlpha(p.StoneDeep, 0.35f), WithAlpha(p.StoneDeep, 0f), new Vector2(0.5f, 0f), 1.3f);
            Raylib.DrawLine((int)gatehouse.X, (int)ly, (int)(gatehouse.X + gatehouse.Width), (int)ly, WithAlpha(p.StoneHi, 0.1f));
        }
    }

    static void DrawMenuCastleCourtyardDepth(float gateX, float gateW, float gateY, float gateH, MenuCastlePalette p, float time)
    {
        var court = new Rectangle(gateX + gateW * 0.2f, gateY + gateH * 0.25f, gateW * 0.6f, gateH * 0.55f);
        float pulse = MathF.Sin(time * 2.8f) * 0.5f + 0.5f;
        DrawGradientWash(court, WithAlpha(p.TorchWarm, 0.1f + pulse * 0.08f), WithAlpha(ForestShadow, 0f), new Vector2(0.5f, 0.85f), 2.4f);
        for (int slab = 0; slab < 6; slab++)
        {
            float sy = court.Y + slab * (court.Height / 6f);
            Raylib.DrawLine((int)court.X, (int)sy, (int)(court.X + court.Width), (int)sy, WithAlpha(p.StoneDeep, 0.15f));
        }
    }

