    static void DrawMenuStoneDetailPass5(Rectangle region, MenuCastlePalette palette, float time)
    {
        int count = 17;
        for (int i = 0; i < count; i++)
        {
            float px = region.X + Hash(i * 22) * region.Width;
            float py = region.Y + Hash(i * 36) * region.Height;
