            float px = region.X + Hash(seed) * region.Width;
            float py = region.Y + Hash(seed + 3) * region.Height;
            float n = Hash(seed + 7);
            float n2 = Hash(seed + 11);
            var stain = new Rectangle(px - 2f, py, 4f + n * 8f, 3f + n2 * 6f);
            DrawGradientWash(stain, WithAlpha(new Color(92, 58, 42, 255), 0.16f), WithAlpha(palette.StoneMid, 0f), new Vector2(0.5f, 1f), 1.5f);
            Raylib.DrawLineEx(new Vector2(px, py), new Vector2(px + n * 12f, py + 10f + n2 * 8f), 0.7f, WithAlpha(new Color(78, 48, 36, 255), 0.12f));
        }
    }

