    static void DrawEnemyShaderUnderglow()
    {
        if (!UhdShadersActive) return;

        float time = (float)Raylib.GetTime();
        Raylib.BeginBlendMode(BlendMode.Additive);
        foreach (Enemy e in enemies)
        {
            if (e.Spawn < 0.3f) continue;
            Color c = Lighten(GetEnemyColor(e.Type), 0.52f);
            float r = e.Radius * EaseOutBack(e.Spawn);
            float pulse = MathF.Sin(time * 4.5f + e.Wobble) * 0.5f + 0.5f;
            DrawGlowFast(e.Position, r * 2.4f, c, 0.06f + pulse * 0.04f);
        }
        Raylib.EndBlendMode();
    }

    static void DrawAiPilotBanner()
    {
        if (!aiPilotEnabled || state != GameState.Playing) return;

        float time = (float)Raylib.GetTime();
        int cx = WindowWidth / 2;
        float pulse = MathF.Sin(time * 4f) * 0.5f + 0.5f;
        float prominent = aiPilotBannerTimer > 0f ? MathF.Min(1f, aiPilotBannerTimer / 2f) : 0f;
        float alpha = 0.62f + pulse * 0.12f + prominent * 0.2f;

        const string title = "GRANDMASTER PILOT";
        const string warn = "Deep survival AI — pathfinding, prediction, scenario matrix.";
        int titleSize = prominent > 0.2f ? 15 : 13;
        int warnSize = 11;
        int titleW = Raylib.MeasureText(title, titleSize);
        int warnW = Raylib.MeasureText(warn, warnSize);
        float panelW = MathF.Max(titleW, warnW) + 36f;
        float panelH = prominent > 0.2f ? 46f : 34f;
        var panel = new Rectangle(cx - panelW / 2f, WindowHeight - panelH - 18f, panelW, panelH);

        DrawRichPanel(panel, WithAlpha(UiPanel, alpha * 0.92f), WithAlpha(new Color(196, 168, 108, 255), alpha), 0.22f, accentStripe: true);
        ShadowTextCentered(title, cx, (int)(panel.Y + 8f), titleSize, new Color(196, 168, 108, 255), alpha);
        if (prominent > 0.2f)
        {
            ShadowTextCentered(warn, cx, (int)(panel.Y + 26f), warnSize, WithAlpha(Color.White, 0.72f), alpha);
        }
    }

    static Color SodBase(int x, int y)
    {
        float h = Hash(x * 31 + y * 17);
        float h2 = Hash(x * 47 + y * 71);
        Color baseCol = LerpColor(SodDark, SodMid, h * 0.5f + 0.25f);
        Color warmed = LerpColor(baseCol, new Color(34, 32, 28, 255), h2 * 0.14f);
        Color grain = LerpColor(warmed, Bark, Hash(x * 13 + y * 29) * 0.09f);
        float diag = ((x + y) & 1) == 0 ? 0.02f : -0.02f;
        return Darken(grain, 0.08f + diag);
    }

    static void DrawTileSodGrain(Rectangle rect, int x, int y, Color sod)
    {
        int seed = x * 16127 + y * 31337;
        for (int i = 0; i < 2; i++)
        {
            if (Hash(seed + i * 7) < 0.32f) continue;
            float fx = rect.X + 4f + Hash(seed + i) * (rect.Width - 8f);
            float fy = rect.Y + 4f + Hash(seed + i + 3) * (rect.Height - 8f);
            float w = 3f + Hash(seed + i + 5) * 5f;
            float h = 1.5f + Hash(seed + i + 9) * 2f;
            Color g = Hash(seed + i + 11) > 0.5f ? Lighten(sod, 0.07f) : Darken(sod, 0.09f);
            Raylib.DrawRectangleRounded(new Rectangle(fx, fy, w, h), 0.5f, 2, WithAlpha(g, 0.38f));
        }
    }

    static void DrawArenaBase()
    {
        const float pad = 4f;
        var arena = new Rectangle(pad, pad, WindowWidth - pad * 2f, WindowHeight - pad * 2f);

        Raylib.DrawRectangleRounded(arena, 0.04f, 8, Darken(SodDark, 0.2f));
        Raylib.DrawRectangleGradientV((int)arena.X, (int)arena.Y, (int)arena.Width, (int)arena.Height,
            WithAlpha(Lighten(SodMid, 0.04f), 0.06f), WithAlpha(Darken(SodDark, 0.15f), 0.08f));
        Raylib.DrawRectangleRoundedLines(arena, 0.04f, 8, WithAlpha(Bark, 0.85f));

        var inner = new Rectangle(pad + 5f, pad + 5f, arena.Width - 10f, arena.Height - 10f);
        Raylib.DrawRectangleRoundedLines(inner, 0.03f, 8, WithAlpha(UiBorderLight, 0.35f));
        DrawGradientWash(inner,
            WithAlpha(new Color(200, 188, 164, 255), 0.04f),
            WithAlpha(ForestShadow, 0f),
            new Vector2(0.5f, 0.12f), 2.4f);

        Raylib.DrawCircleV(new Vector2(pad + 14f, pad + 14f), 6f, WithAlpha(MossLight, 0.45f));
        Raylib.DrawCircleV(new Vector2(arena.Width + pad - 14f, pad + 14f), 5f, WithAlpha(MossLight, 0.35f));
        Raylib.DrawCircleV(new Vector2(pad + 14f, arena.Height + pad - 14f), 5f, WithAlpha(MossLight, 0.35f));
        Raylib.DrawCircleV(new Vector2(arena.Width + pad - 14f, arena.Height + pad - 14f), 6f, WithAlpha(MossLight, 0.45f));
    }

    static void DrawTiles()
    {
        const float seam = 0.5f;
        float time = (float)Raylib.GetTime();

        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                Tile tile = tiles[x, y];
                float cx = x * TileSize + TileSize / 2f;
                float cy = y * TileSize + TileSize / 2f;
                float ox = x * TileSize + seam;
                float oy = y * TileSize + seam;
                float size = TileSize - seam * 2f;

                if (tile.State == 2)
                {
                    float e = tile.Collapse;
                    bool mergeL = IsCollapsedVoid(x - 1, y);
                    bool mergeR = IsCollapsedVoid(x + 1, y);
                    bool mergeU = IsCollapsedVoid(x, y - 1);
                    bool mergeD = IsCollapsedVoid(x, y + 1);

                    float left = x * TileSize + (mergeL ? 0f : seam);
                    float top = y * TileSize + (mergeU ? 0f : seam);
                    float right = (x + 1) * TileSize - (mergeR ? 0f : seam);
                    float bottom = (y + 1) * TileSize - (mergeD ? 0f : seam);
                    float w = right - left;
                    float h = bottom - top;
                    var pit = new Rectangle(left, top, w, h);

                    Raylib.DrawRectangle((int)left, (int)top, (int)w, (int)h, LerpColor(EarthPit, ForestShadow, 0.55f));
                    if (w > 6f && h > 6f)
                    {
                        var innerPit = new Rectangle(left + 3f, top + 3f, w - 6f, h - 6f);
                        Raylib.DrawRectangle((int)innerPit.X, (int)innerPit.Y, (int)innerPit.Width, (int)innerPit.Height,
                            LerpColor(EarthPit, Color.Black, 0.45f));
                        Raylib.DrawRectangleGradientV((int)innerPit.X, (int)innerPit.Y, (int)innerPit.Width, (int)innerPit.Height,
                            WithAlpha(Lighten(Bark, 0.1f), 0.12f), WithAlpha(Color.Black, 0.28f));
                    }

                    if (!mergeU && w > 4f)
                    {
                        Raylib.DrawLineEx(new Vector2(left + 2f, top + 2f), new Vector2(right - 2f, top + 2f), 1f,
                            WithAlpha(Lighten(Bark, 0.15f), 0.22f));
                    }

                    if (!mergeL)
                        Raylib.DrawLineEx(new Vector2(left, top), new Vector2(left, bottom), 1.2f, WithAlpha(Darken(Bark, 0.15f), 0.75f));
                    if (!mergeR)
                        Raylib.DrawLineEx(new Vector2(right, top), new Vector2(right, bottom), 1.2f, WithAlpha(Darken(Bark, 0.15f), 0.75f));
                    if (!mergeU)
                        Raylib.DrawLineEx(new Vector2(left, top), new Vector2(right, top), 1.2f, WithAlpha(Darken(Bark, 0.15f), 0.75f));
                    if (!mergeD)
                        Raylib.DrawLineEx(new Vector2(left, bottom), new Vector2(right, bottom), 1.2f, WithAlpha(Darken(Bark, 0.15f), 0.75f));

                    if (e < 1f)
                    {
                        int rings = 4;
                        for (int rIdx = 0; rIdx < rings; rIdx++)
                        {
                            float ringPhase = Math.Clamp(e * rings - rIdx, 0f, 1f);
                            if (ringPhase >= 1f)
                            {
                                continue;
                            }

                            float shrink = (rIdx / (float)rings) + ringPhase * (1f / rings);
                            float rsize = Math.Min(w, h) * (1f - shrink);
                            float drop = ringPhase * 10f + rIdx * 1.5f;
                            var rr = new Rectangle(cx, cy + drop, rsize, rsize);
                            Color shard = WithAlpha(
                                LerpColor(TileFill(MaxDurability * 0.3f), EarthPit, shrink + ringPhase * 0.4f),
                                (1f - ringPhase) * (1f - shrink * 0.4f));
                            Raylib.DrawRectanglePro(rr, new Vector2(rsize / 2f, rsize / 2f),
                                (rIdx + ringPhase) * 40f, shard);
                        }

                        if (e < 0.5f)
                        {
                            float dust = MathF.Sin(time * 20f + x + y) * 0.5f + 0.5f;
                            Raylib.DrawCircleV(new Vector2(cx, cy - 4f), 1.5f + dust * 1.5f,
                                WithAlpha(LeafGold, (0.5f - e) * 0.5f));
                        }
                    }

                    if (tile.RegrowTimer > 0f && tile.Collapse >= 1f)
                    {
                        float regrowPulse = MathF.Sin(time * 4f + x + y) * 0.5f + 0.5f;
                        if (!mergeL)
                            Raylib.DrawLineEx(new Vector2(left, top), new Vector2(left, bottom), 1.5f,
                                WithAlpha(UiAccent, regrowPulse * (1f - tile.RegrowTimer / TileRegrowTime) * 0.75f));
                        if (!mergeR)
                            Raylib.DrawLineEx(new Vector2(right, top), new Vector2(right, bottom), 1.5f,
                                WithAlpha(UiAccent, regrowPulse * (1f - tile.RegrowTimer / TileRegrowTime) * 0.75f));
                    }

                    continue;
                }

                Color fill = TileFill(tile.Durability);
                float ratio = tile.Durability / MaxDurability;
                TileHealthVisual healthBand = GetTileHealthVisual(ratio);
                Color sod = SodBase(x, y);

                if (tile.State == 1)
                {
                    float blightPulse = MathF.Sin(time * 2.4f + (x * 0.6f + y * 0.4f)) * 0.5f + 0.5f;
                    Color rot = LerpColor(fill, ActiveTheme.BlightRot, 0.55f);
                    Color sick = LerpColor(rot, ActiveTheme.BlightSick, blightPulse);
                    fill = sick;
                    sod = LerpColor(sod, Darken(rot, 0.3f), 0.6f);
                }
                else if (healthBand is TileHealthVisual.Worn or TileHealthVisual.Cracked)
                {
                    sod = LerpColor(sod, Darken(fill, 0.12f), 0.25f);
                }
                else if (healthBand is TileHealthVisual.Fractured or TileHealthVisual.Critical)
                {
                    sod = LerpColor(sod, Darken(fill, 0.22f), 0.45f);
                }

                var baseRect = new Rectangle(ox, oy, size, size);
                var bodyRect = new Rectangle(ox + 1.5f, oy + 1.5f, size - 3f, size - 3f);

                Raylib.DrawRectangleRounded(baseRect, 0.1f, 6, sod);
                DrawTileSodGrain(baseRect, x, y, sod);
                Raylib.DrawRectangleRounded(bodyRect, 0.12f, 6, Darken(fill, 0.26f));
                Raylib.DrawRectangleRounded(
                    new Rectangle(bodyRect.X + 1f, bodyRect.Y + 1f, bodyRect.Width - 2f, bodyRect.Height - 2f),
                    0.1f, 6, Darken(fill, 0.08f));

                Raylib.DrawRectangleRoundedLines(
                    new Rectangle(ox + 2f, oy + 2f, size - 4f, size - 4f), 0.12f, 6,
                    WithAlpha(TileSeam, 0.72f));

                float edgeHi = 0.12f;
                float edgeLo = 0.58f;
                float sheenA = 0.02f;
                float sheenLift = 0.08f;

                Raylib.DrawLineEx(
                    new Vector2(ox + 3f, oy + size - 3f),
                    new Vector2(ox + 3f, oy + 3f),
                    1.2f, WithAlpha(Lighten(fill, edgeHi), edgeHi));
                Raylib.DrawLineEx(
                    new Vector2(ox + 3f, oy + 3f),
                    new Vector2(ox + size - 3f, oy + 3f),
                    1.2f, WithAlpha(Lighten(fill, edgeHi), edgeHi));
                Raylib.DrawLineEx(
                    new Vector2(ox + size - 3f, oy + size - 3f),
                    new Vector2(ox + size - 3f, oy + 3f),
                    1f, WithAlpha(Darken(fill, edgeLo), 0.4f));
                Raylib.DrawLineEx(
                    new Vector2(ox + 3f, oy + size - 3f),
                    new Vector2(ox + size - 3f, oy + size - 3f),
                    1f, WithAlpha(Darken(fill, edgeLo), 0.4f));

                var sheen = new Rectangle(ox + 4f, oy + 3f, size - 8f, size * 0.38f);
                float sheenBoost = healthBand == TileHealthVisual.Pristine ? 0.08f
                    : healthBand == TileHealthVisual.Sturdy ? 0.04f : 0f;
                Raylib.DrawRectangleRounded(sheen, 0.6f, 4, WithAlpha(Lighten(fill, sheenLift), sheenA + sheenBoost));

                DrawTileHealthSurface(x, y, cx, cy, bodyRect, fill, ratio, healthBand, tile, time);

                if (tile.State == 1)
                {
                    float vein = MathF.Sin(time * 1.8f + x * 0.9f + y * 0.7f) * 0.5f + 0.5f;
                    Raylib.DrawRectangleRounded(bodyRect, 0.12f, 6, WithAlpha(ActiveTheme.BlightSick, 0.08f + vein * 0.1f));
                    Raylib.DrawRectangleRoundedLines(bodyRect, 0.12f, 6, WithAlpha(Darken(ActiveTheme.BlightRot, 0.1f), 0.28f + vein * 0.2f));
                }

                if (floorRotTimer > 0f && IsTileInMossRotZone(x))
                {
                    float rotPulse = MathF.Sin(time * 3f + x * 0.4f + y * 0.3f) * 0.5f + 0.5f;
                    Color mossRot = new Color(54, 68, 58, 255);
                    Raylib.DrawRectangleRounded(bodyRect, 0.12f, 6, WithAlpha(mossRot, 0.2f + rotPulse * 0.16f));
                }

                if (tile.UntouchedTimer >= TileIdleRegenDelay && tile.Durability < MaxDurability)
                {
                    float regenT = Math.Clamp((tile.UntouchedTimer - TileIdleRegenDelay) / 4f, 0f, 1f);
                    float regenPulse = MathF.Sin(time * 3.5f + x + y) * 0.5f + 0.5f;
                    Raylib.DrawRectangleRoundedLines(bodyRect, 0.12f, 6,
                        WithAlpha(UiAccent, (0.1f + regenPulse * 0.16f) * regenT));
                }

                if (x < GridSize - 1 && !IsCollapsedVoid(x + 1, y))
                {
                    Raylib.DrawRectangle((int)(ox + size), (int)oy, 1, (int)size, TileSeam);
                    Raylib.DrawRectangle((int)(ox + size), (int)oy, 1, (int)(size * 0.35f), WithAlpha(Lighten(TileSeam, 0.15f), 0.25f));
                }
                if (y < GridSize - 1 && !IsCollapsedVoid(x, y + 1))
                {
                    Raylib.DrawRectangle((int)ox, (int)(oy + size), (int)size, 1, TileSeam);
                    Raylib.DrawRectangle((int)ox, (int)(oy + size), (int)(size * 0.35f), 1, WithAlpha(Lighten(TileSeam, 0.15f), 0.25f));
                }

                if (tile.EventMarked && tile.State != 2)
                {
                    float flash = MathF.Sin(time * 18f + x * 1.7f + y) * 0.5f + 0.5f;
                    float warn = activeEvent != FloorEventType.None && eventCountdown > 0f ? 1.15f : 1f;
                    Raylib.DrawRectangleRounded(bodyRect, 0.12f, 6, WithAlpha(Danger, (0.35f + flash * 0.5f) * warn));
                    Raylib.DrawRectangleRoundedLines(bodyRect, 0.12f, 6, WithAlpha(new Color(255, 80, 60, 255), (0.55f + flash * 0.45f) * warn));
                    DrawPulseFrame(bodyRect, Danger, 0.12f, 14f, 0.18f + flash * 0.35f);

                    float cx2 = ox + size / 2f;
                    float cy2 = oy + size / 2f;
                    float xSize = size * (0.22f + flash * 0.08f);
                    Raylib.DrawLineEx(new Vector2(cx2 - xSize, cy2 - xSize), new Vector2(cx2 + xSize, cy2 + xSize), 2.4f, WithAlpha(Color.White, 0.45f + flash * 0.4f));
                    Raylib.DrawLineEx(new Vector2(cx2 + xSize, cy2 - xSize), new Vector2(cx2 - xSize, cy2 + xSize), 2.4f, WithAlpha(Color.White, 0.45f + flash * 0.4f));
                }
            }
        }
    }

    static void DrawCracks(float cx, float cy, int x, int y, float severity, int crackCount = 3)
    {
        int seed = x * 73856093 ^ y * 19349663;
        Color crack = WithAlpha(ForestShadow, severity * 0.55f);
        int count = Math.Clamp(crackCount, 1, 8);
        for (int k = 0; k < count; k++)
        {
            float a1 = Hash(seed + k) * MathF.PI;
            float a2 = a1 + Hash(seed + k * 7 + 99) * 0.9f;
            float reach = TileSize * (0.28f + Hash(seed + k * 3) * 0.18f) * (0.65f + severity * 0.55f);
            var p1 = new Vector2(cx + MathF.Cos(a1) * 3f, cy + MathF.Sin(a1) * 3f);
            var p2 = new Vector2(cx + MathF.Cos(a2) * reach, cy + MathF.Sin(a2) * reach);
            Raylib.DrawLineEx(p1, p2, 1.4f + severity * 0.5f, crack);

            if (severity > 0.45f)
            {
                var mid = Vector2.Lerp(p1, p2, 0.45f);
                float ba = a2 + Hash(seed + k * 11) * 1.4f;
                var branch = new Vector2(mid.X + MathF.Cos(ba) * reach * 0.35f, mid.Y + MathF.Sin(ba) * reach * 0.35f);
                Raylib.DrawLineEx(mid, branch, 1.1f, WithAlpha(crack, 0.85f));
            }
        }
    }

    static void DrawTrails()
    {
        Color body = BodyColor();
        Color bright = BodyBright();
        foreach (DashTrail t in trails)
        {
            float a = t.Alpha * t.Alpha;
            float rad = t.Radius * (0.35f + a);
            DrawGlow(t.Position, rad * 1.6f, body, a * 0.14f);
            Raylib.DrawCircleV(t.Position, rad, WithAlpha(body, a * 0.55f));
            Raylib.DrawCircleV(t.Position, rad * 0.5f, WithAlpha(bright, a * 0.5f));
        }
    }

    static void DrawParticles()
    {
        foreach (Particle p in particles)
        {
            if (p.Glow)
            {
                DrawGlow(p.Position, p.Size * 2.4f, p.Color, p.Alpha * 0.11f);
                Raylib.DrawCircleV(p.Position, p.Size * 0.5f, WithAlpha(Lighten(p.Color, 0.4f), p.Alpha));
            }
            else
            {
                var origin = new Vector2(p.Size / 2f, p.Size / 2f);
                Raylib.DrawRectanglePro(
                    new Rectangle(p.Position.X + 1.5f, p.Position.Y + 1.5f, p.Size, p.Size),
                    origin, p.Rotation, WithAlpha(ForestShadow, p.Alpha * 0.3f));
                Raylib.DrawRectanglePro(
                    new Rectangle(p.Position.X, p.Position.Y, p.Size, p.Size),
                    origin, p.Rotation, WithAlpha(p.Color, p.Alpha));
            }
        }
    }

    static void DrawProjectiles()
    {
        float time = (float)Raylib.GetTime();
        foreach (Projectile p in projectiles)
        {
            float lifeT = p.SpawnLife > 0.01f ? Math.Clamp(p.Life / p.SpawnLife, 0f, 1f) : 1f;
            float rot = MathF.Atan2(p.Velocity.Y, p.Velocity.X) * 180f / MathF.PI;
            Color hot = Lighten(p.Color, 0.45f);
            Color core = Lighten(p.Color, 0.7f);

            switch (p.Style)
            {
                case GunFireStyle.Laser:
                {
                    float alpha = Math.Clamp(p.Life / 0.28f, 0f, 1f);
                    DrawGlow(p.Position, p.BeamWidth * 4f, p.Color, 0.22f * alpha);
                    DrawGlow(p.BeamEnd, p.BeamWidth * 2.4f, hot, 0.14f * alpha);
                    Raylib.DrawLineEx(p.Position, p.BeamEnd, p.BeamWidth * 1.8f, WithAlpha(p.Color, 0.22f * alpha));
                    Raylib.DrawLineEx(p.Position, p.BeamEnd, p.BeamWidth, WithAlpha(p.Color, 0.42f * alpha));
                    Raylib.DrawLineEx(p.Position, p.BeamEnd, p.BeamWidth * 0.42f, WithAlpha(core, 0.92f * alpha));
                    Raylib.DrawLineEx(p.Position, p.BeamEnd, p.BeamWidth * 0.15f, WithAlpha(Color.White, 0.85f * alpha));
                    break;
                }
                case GunFireStyle.Mortar:
                {
                    float pulse = MathF.Sin(time * 14f + p.Position.X) * 0.5f + 0.5f;
                    DrawGlow(p.Position, p.Size * 2.2f, p.Color, 0.18f + pulse * 0.08f);
                    Raylib.DrawCircleV(p.Position, p.Size * 1.15f, WithAlpha(Darken(p.Color, 0.2f), 0.35f));
                    Raylib.DrawCircleV(p.Position, p.Size, p.Color);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.42f, hot);
                    Raylib.DrawCircleLinesV(p.Position, p.Size + 3f + pulse * 2f, WithAlpha(hot, 0.7f));
                    break;
                }
                case GunFireStyle.Homing:
                {
                    float orbit = time * 8f + p.Position.X * 0.02f;
                    DrawGlow(p.Position, p.Size * 2.4f, p.Color, 0.2f);
                    Raylib.DrawCircleV(p.Position, p.Size, p.Color);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.4f, core);
                    for (int i = 0; i < 3; i++)
                    {
                        float a = orbit + i * 2.1f;
                        Vector2 mote = p.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * (p.Size + 4f);
                        Raylib.DrawCircleV(mote, 2f, WithAlpha(hot, 0.75f));
                    }
                    Raylib.DrawCircleLinesV(p.Position, p.Size + 5f, WithAlpha(hot, 0.45f));
                    break;
                }
                case GunFireStyle.DriftOrb:
                {
                    float pulse = MathF.Sin(time * 6f) * 0.5f + 0.5f;
                    DrawGlow(p.Position, p.Size * 2.6f, p.Color, 0.18f + pulse * 0.1f);
                    Raylib.DrawCircleV(p.Position, p.Size, WithAlpha(p.Color, 0.85f));
                    Raylib.DrawCircleV(p.Position, p.Size * 0.55f, hot);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.22f, WithAlpha(Color.White, 0.65f));
                    Raylib.DrawRing(p.Position, p.Size + 2f, p.Size + 5f + pulse * 3f, 0f, 360f, 24, WithAlpha(hot, 0.35f));
                    break;
                }
                case GunFireStyle.Lance:
                {
                    Vector2 tail = p.Position - SafeNormalize(p.Velocity) * p.Size * 4.5f;
                    Raylib.DrawLineEx(tail, p.Position + SafeNormalize(p.Velocity) * p.Size * 1.2f, p.Size * 0.9f, WithAlpha(p.Color, 0.35f));
                    DrawGlow(p.Position, p.Size * 1.9f, p.Color, 0.18f);
                    var lance = new Rectangle(p.Position.X, p.Position.Y, p.Size * 3.2f, p.Size * 0.65f);
                    Raylib.DrawRectanglePro(lance, new Vector2(p.Size * 1.6f, p.Size * 0.32f), rot, p.Color);
                    Raylib.DrawRectanglePro(lance, new Vector2(p.Size * 1.6f, p.Size * 0.32f), rot, WithAlpha(hot, 0.55f));
                    Raylib.DrawCircleV(p.Position + SafeNormalize(p.Velocity) * p.Size * 1.1f, p.Size * 0.28f, core);
                    break;
                }
                case GunFireStyle.Sniper:
                {
                    Vector2 tail = p.Position - SafeNormalize(p.Velocity) * 42f;
                    Raylib.DrawLineEx(tail, p.Position, 2f, WithAlpha(p.Color, 0.25f * lifeT));
                    Raylib.DrawLineEx(tail, p.Position, 1f, WithAlpha(hot, 0.75f * lifeT));
                    var slug = new Rectangle(p.Position.X, p.Position.Y, p.Size * 2.8f, p.Size * 0.45f);
                    Raylib.DrawRectanglePro(slug, new Vector2(p.Size * 1.4f, p.Size * 0.22f), rot, p.Color);
                    Raylib.DrawCircleV(p.Position + SafeNormalize(p.Velocity) * p.Size * 0.8f, 2.5f, WithAlpha(Color.White, 0.8f * lifeT));
                    break;
                }
                case GunFireStyle.Buckshot:
                {
                    DrawGlow(p.Position, p.Size * 1.3f, p.Color, 0.14f);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.85f, p.Color);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.35f, hot);
                    break;
                }
                case GunFireStyle.RingPulse:
                {
                    float pulse = MathF.Sin(time * 18f) * 0.5f + 0.5f;
                    DrawGlow(p.Position, p.Size * 2f, p.Color, 0.16f + pulse * 0.08f);
                    Raylib.DrawCircleV(p.Position, p.Size, p.Color);
                    Raylib.DrawRing(p.Position, p.Size * 0.5f, p.Size * 0.9f, rot, 220f, 12, WithAlpha(hot, 0.65f));
                    break;
                }
                case GunFireStyle.CrossBurst:
                {
                    float arm = p.Size * 1.1f;
                    Vector2 c = p.Position;
                    Vector2 n = SafeNormalize(p.Velocity);
                    Vector2 perp = new Vector2(-n.Y, n.X);
                    Raylib.DrawLineEx(c - n * arm, c + n * arm, p.Size * 0.55f, WithAlpha(p.Color, 0.9f));
                    Raylib.DrawLineEx(c - perp * arm, c + perp * arm, p.Size * 0.55f, WithAlpha(p.Color, 0.9f));
                    DrawGlow(c, p.Size * 1.6f, hot, 0.16f);
                    Raylib.DrawCircleV(c, p.Size * 0.35f, core);
                    break;
                }
                case GunFireStyle.FlailArc:
                {
                    float spin = time * 18f + p.SpinRate * 4f;
                    DrawGlow(p.Position, p.Size * 1.8f, p.Color, 0.16f);
                    var link = new Rectangle(p.Position.X, p.Position.Y, p.Size * 1.8f, p.Size * 0.9f);
                    Raylib.DrawRectanglePro(link, new Vector2(p.Size * 0.9f, p.Size * 0.45f), spin, p.Color);
                    Raylib.DrawRectanglePro(link, new Vector2(p.Size * 0.9f, p.Size * 0.45f), spin + 90f, WithAlpha(hot, 0.5f));
                    Raylib.DrawCircleV(p.Position, p.Size * 0.4f, core);
                    break;
                }
                case GunFireStyle.ArcFan:
                {
                    DrawGlow(p.Position, p.Size * 1.6f, p.Color, 0.15f);
                    var wedge = new Rectangle(p.Position.X, p.Position.Y, p.Size * 1.9f, p.Size * 0.85f);
                    Raylib.DrawRectanglePro(wedge, new Vector2(p.Size * 0.95f, p.Size * 0.42f), rot, p.Color);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.32f, hot);
                    break;
                }
                case GunFireStyle.Repeater:
                case GunFireStyle.Burst:
                case GunFireStyle.Volley:
                {
                    Vector2 tail = p.Position - SafeNormalize(p.Velocity) * 12f;
                    Raylib.DrawLineEx(tail, p.Position, p.Size * 0.35f, WithAlpha(p.Color, 0.45f));
                    DrawGlow(p.Position, p.Size * 1.5f, p.Color, 0.16f);
                    var bolt = new Rectangle(p.Position.X, p.Position.Y, p.Size * 1.7f, p.Size * 0.75f);
                    Raylib.DrawRectanglePro(bolt, new Vector2(p.Size * 0.85f, p.Size * 0.38f), rot, p.Color);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.3f, hot);
                    break;
                }
                case GunFireStyle.Standard:
                {
                    Vector2 tail = p.Position - SafeNormalize(p.Velocity) * 10f;
                    Raylib.DrawLineEx(tail, p.Position, p.Size * 0.4f, WithAlpha(p.Color, 0.4f * lifeT));
                    DrawGlow(p.Position, p.Size * 1.7f, p.Color, 0.17f);
                    var bolt = new Rectangle(p.Position.X, p.Position.Y, p.Size * 1.8f, p.Size);
                    Raylib.DrawRectanglePro(bolt, new Vector2(p.Size * 0.9f, p.Size * 0.5f), rot, p.Color);
                    Raylib.DrawCircleV(p.Position, p.Size * 0.38f, hot);
                    break;
                }
                default:
                    throw new UnreachableException();
            }
        }
    }

    static void DrawEnemies()
    {
        float time = (float)Raylib.GetTime();
        foreach (Enemy e in enemies)
        {
            Color color = GetEnemyColor(e.Type);
            ref readonly EnemyDef def = ref GetDef(e.Type);
            bool frozen = e.ParalyzeTimer > 0f;
            if (frozen)
            {
                color = LerpColor(color, new Color(138, 152, 172, 255), 0.58f);
            }
            if (e.Hit > 0f) color = LerpColor(color, Color.White, e.Hit / 0.12f);
            if (UhdShadersActive) color = Lighten(color, 0.24f);
            int sides = GetEnemySides(e.Type);
            float grow = EaseOutBack(e.Spawn);
            float r = e.Radius * grow;
            Vector2 p = e.Position;

            if (def.Behavior == EnemyBehavior.Lurker)
            {
                float dist = Vector2.Distance(playerPos, p);
                float stealth = Math.Clamp((dist - 120f) / 140f, 0.25f, 1f);
                if (UhdShadersActive) stealth = MathF.Max(stealth, 0.82f);
                color = WithAlpha(color, stealth * e.Spawn);
            }

            if (e.Spawn < 1f)
            {
                float tr = e.Radius + (1f - e.Spawn) * 34f;
                Raylib.DrawRing(p, tr, tr + 3f, 0f, 360f, 36, WithAlpha(color, e.Spawn * 0.8f));
            }

            float rot = time * def.RotSpeed + e.Wobble * 30f;
            float wob = 1f + MathF.Sin(time * 6f + e.Wobble) * 0.06f;
            float hitSquash = e.Hit > 0f ? (e.Hit / 0.12f) * 0.24f : 0f;
            bool stretched = e.Spawn >= 1f && BeginStretch(p, e.Vel, 0.00135f, 0.34f, hitSquash);

            float glowStrength = UhdShadersActive ? 0.22f : 0.1f;
            if (UhdShadersActive)
            {
                Raylib.DrawPolyLinesEx(p, sides, r * wob + 3.5f, rot, 4f, WithAlpha(new Color(20, 16, 14, 255), 0.82f * e.Spawn));
            }
            DrawGlow(p, r * (UhdShadersActive ? 1.55f : 1.35f), color, glowStrength * e.Spawn);
            Raylib.DrawPoly(p, sides, r * wob, rot, color);
            float lineW = UhdShadersActive ? 3f : 2f;
            float lineA = UhdShadersActive ? 1f : 0.9f;
            Raylib.DrawPolyLinesEx(p, sides, r * wob, rot, lineW, WithAlpha(Lighten(color, UhdShadersActive ? 0.45f : 0.3f), lineA));
            Raylib.DrawPoly(p, sides, r * 0.45f, -rot, WithAlpha(MossLight, (UhdShadersActive ? 0.72f : 0.5f) * e.Spawn));
            if (UhdShadersActive)
            {
                Raylib.DrawPolyLinesEx(p, sides, r * wob + 1.5f, rot, 2f, WithAlpha(Lighten(color, 0.55f), 0.5f * e.Spawn));
            }
            EndStretch(stretched);

            if (frozen)
            {
                float pulse = MathF.Sin(time * 14f + e.Wobble) * 0.5f + 0.5f;
                Color bolt = new Color(196, 214, 232, 255);
                Raylib.DrawRing(p, r + 4f, r + 8f + pulse * 4f, 0f, 360f, 36, WithAlpha(bolt, 0.45f + pulse * 0.4f));
                DrawGlow(p, r * 2.4f, bolt, 0.1f + pulse * 0.12f);
                for (int b = 0; b < 4; b++)
                {
                    float a = time * 9f + e.Wobble + b * 1.57f;
                    Vector2 spark = p + new Vector2(MathF.Cos(a), MathF.Sin(a)) * (r + 7f);
                    Raylib.DrawCircleV(spark, 2.2f, WithAlpha(Color.White, 0.75f));
                }
            }

            if (e.Spawn >= 1f && e.Hp < e.MaxHp)
            {
                float w = IsBoss(e.Type) ? e.Radius * 2.8f : e.Radius * 2f;
                float barH = IsBoss(e.Type) ? 5f : 3f;
                float hpf = Math.Clamp(e.Hp / e.MaxHp, 0f, 1f);
                float bx = p.X - w / 2f;
                float by = p.Y - e.Radius - (IsBoss(e.Type) ? 14f : 8f);
                Raylib.DrawRectangle((int)bx, (int)by, (int)w, (int)barH, WithAlpha(ForestShadow, 0.75f));
                Raylib.DrawRectangle((int)bx, (int)by, (int)(w * hpf), (int)barH, Lighten(color, 0.3f));
            }

            if (IsBoss(e.Type) && e.Spawn >= 0.85f)
            {
                string nm = GetEnemyName(e.Type).ToUpperInvariant();
                ShadowTextCentered(nm, (int)p.X, (int)(p.Y - e.Radius - 24f), 11, WithAlpha(Gold, e.Spawn), 1f);
            }
        }
    }

    static void DrawPlayer()
    {
        float time = (float)Raylib.GetTime();
        bool dashing = dashTimer > 0f;
        Vector2 p = playerPos;
        Color body = BodyColor();
        Color bright = BodyBright();

        float auraPulse = MathF.Sin(time * 6f) * 1.2f;
        float auraR = PlayerRadius * 1.65f + auraPulse + (dashing ? 6f : 0f);
        float bodyR = PlayerRadius + (dashing ? 3f : MathF.Sin(time * 8f) * 1.2f);

        bool stretched = BeginStretch(p, playerVel, dashing ? 0.00092f : 0.00074f, dashing ? 0.55f : 0.3f);
        var accessoryRig = BuildAccessoryRig(p, bodyR);
        DrawAccessoryLayer(accessoryRig, time, accessoryIndex, AccessoryLayer.Back);
        DrawGlow(p, auraR, body, dashing ? 0.08f : 0.045f);
        Raylib.DrawCircleV(p, bodyR, body);
        Raylib.DrawCircleLinesV(p, bodyR, WithAlpha(bright, 0.9f));

        Vector2 iris = p + accessoryRig.Forward * bodyR * 0.34f;
        Raylib.DrawCircleV(iris, bodyR * 0.36f, bright);
        Raylib.DrawCircleV(iris, bodyR * 0.16f, Color.White);

        DrawAccessoryLayer(accessoryRig, time, accessoryIndex, AccessoryLayer.Mid);
        DrawAccessoryLayer(accessoryRig, time, accessoryIndex, AccessoryLayer.Front);
        EndStretch(stretched);
        DrawEquippedWeaponOnPlayer(p, bodyR, time, dashing);

        if (!dashing && dashCooldown <= 0f)
        {
            float rp = MathF.Sin(time * 5f) * 0.5f + 0.5f;
            Raylib.DrawRing(p, bodyR + 5f, bodyR + 7f + rp * 2f, 0f, 360f, 40, WithAlpha(bright, 0.4f + rp * 0.4f));
        }
    }

    static void DrawGunArchetype(int archetype, Vector2 c, float s, float time, Color primary, Color shadow, Color hi,
        float lineMul = 1f)
    {
        float L(float w) => w * lineMul;
        float bob = MathF.Sin(time * 2.4f + archetype) * s * 0.04f;
        c.Y += bob;
        switch (archetype % 10)
        {
            case 0: // pike
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.06f, c.Y - s * 0.72f, s * 0.12f, s * 1.1f), 0.1f, 2, primary);
                Raylib.DrawTriangle(new Vector2(c.X, c.Y - s * 0.82f), new Vector2(c.X - s * 0.1f, c.Y - s * 0.55f), new Vector2(c.X + s * 0.1f, c.Y - s * 0.55f), hi);
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.14f, c.Y + s * 0.2f, s * 0.28f, s * 0.16f), 0.2f, 2, shadow);
                if (lineMul > 1.5f)
                    Raylib.DrawRectangleRoundedLines(new Rectangle(c.X - s * 0.08f, c.Y - s * 0.76f, s * 0.16f, s * 1.18f), 0.1f, 4, WithAlpha(ForestShadow, 0.85f));
                break;
            case 1: // bow
                for (int seg = 0; seg < 8; seg++)
                {
                    float t0 = seg / 8f;
                    float t1 = (seg + 1) / 8f;
                    Vector2 a = new Vector2(c.X - s * 0.42f + t0 * s * 0.84f, c.Y - s * 0.35f + MathF.Sin(t0 * MathF.PI) * s * 0.55f);
                    Vector2 b = new Vector2(c.X - s * 0.42f + t1 * s * 0.84f, c.Y - s * 0.35f + MathF.Sin(t1 * MathF.PI) * s * 0.55f);
                    Raylib.DrawLineEx(a, b, L(1.8f), primary);
                }
                Raylib.DrawLineEx(new Vector2(c.X - s * 0.38f, c.Y - s * 0.3f), new Vector2(c.X + s * 0.38f, c.Y - s * 0.3f), L(1f), hi);
                Raylib.DrawLineEx(new Vector2(c.X, c.Y - s * 0.3f), new Vector2(c.X + s * 0.35f, c.Y + s * 0.1f), L(1.2f), shadow);
                break;
            case 2: // handgun
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.34f, c.Y - s * 0.12f, s * 0.68f, s * 0.24f), 0.15f, 3, primary);
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.08f, c.Y + s * 0.1f, s * 0.16f, s * 0.34f), 0.2f, 2, shadow);
                Raylib.DrawCircleV(new Vector2(c.X + s * 0.28f, c.Y), s * 0.05f * lineMul, hi);
                if (lineMul > 1.5f)
                    Raylib.DrawRectangleRoundedLines(new Rectangle(c.X - s * 0.36f, c.Y - s * 0.14f, s * 0.72f, s * 0.28f), 0.15f, 4, WithAlpha(ForestShadow, 0.8f));
                break;
            case 3: // crossbow
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.34f, c.Y - s * 0.08f, s * 0.68f, s * 0.16f), 0.1f, 2, shadow);
                Raylib.DrawLineEx(new Vector2(c.X - s * 0.42f, c.Y - s * 0.22f), new Vector2(c.X + s * 0.42f, c.Y - s * 0.22f), L(2f), primary);
                Raylib.DrawLineEx(new Vector2(c.X, c.Y - s * 0.22f), new Vector2(c.X + s * 0.38f, c.Y + s * 0.08f), L(1.2f), hi);
                break;
            case 4: // cannon
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.48f, c.Y - s * 0.14f, s * 0.82f, s * 0.28f), 0.2f, 4, primary);
                Raylib.DrawCircleV(new Vector2(c.X + s * 0.34f, c.Y), s * 0.1f * lineMul, Darken(primary, 0.4f));
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.18f, c.Y + s * 0.12f, s * 0.12f, s * 0.22f), 0.1f, 2, shadow);
                if (lineMul > 1.5f)
                    Raylib.DrawRectangleRoundedLines(new Rectangle(c.X - s * 0.5f, c.Y - s * 0.16f, s * 0.86f, s * 0.32f), 0.2f, 4, WithAlpha(ForestShadow, 0.8f));
                break;
            case 5: // flail
                Raylib.DrawLineEx(new Vector2(c.X, c.Y + s * 0.35f), new Vector2(c.X, c.Y - s * 0.15f), L(2.5f), shadow);
                Raylib.DrawLineEx(new Vector2(c.X, c.Y - s * 0.15f), new Vector2(c.X + s * 0.28f, c.Y - s * 0.42f), L(1.2f), hi);
                Raylib.DrawCircleV(new Vector2(c.X + s * 0.32f, c.Y - s * 0.48f), s * 0.14f * lineMul, primary);
                for (int spike = 0; spike < 6; spike++)
                {
                    float ang = spike * MathF.PI / 3f;
                    Raylib.DrawLineEx(new Vector2(c.X + s * 0.32f, c.Y - s * 0.48f),
                        new Vector2(c.X + s * 0.32f + MathF.Cos(ang) * s * 0.16f, c.Y - s * 0.48f + MathF.Sin(ang) * s * 0.16f),
                        L(1f), hi);
                }
                break;
            case 6: // lance
                Raylib.DrawLineEx(new Vector2(c.X - s * 0.45f, c.Y + s * 0.25f), new Vector2(c.X + s * 0.48f, c.Y - s * 0.35f), L(3f), primary);
                Raylib.DrawTriangle(new Vector2(c.X + s * 0.52f, c.Y - s * 0.38f), new Vector2(c.X + s * 0.34f, c.Y - s * 0.28f), new Vector2(c.X + s * 0.4f, c.Y - s * 0.18f), hi);
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.52f, c.Y + s * 0.12f, s * 0.18f, s * 0.2f), 0.15f, 2, shadow);
                break;
            case 7: // rifle
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.46f, c.Y - s * 0.1f, s * 0.92f, s * 0.2f), 0.12f, 3, primary);
                Raylib.DrawRectangleRounded(new Rectangle(c.X - s * 0.12f, c.Y + s * 0.08f, s * 0.14f, s * 0.28f), 0.15f, 2, shadow);
                Raylib.DrawRectangle((int)(c.X + s * 0.18f), (int)(c.Y - s * 0.16f), (int)(s * 0.24f), (int)(s * 0.08f), hi);
                if (lineMul > 1.5f)
                    Raylib.DrawRectangleRoundedLines(new Rectangle(c.X - s * 0.48f, c.Y - s * 0.12f, s * 0.96f, s * 0.24f), 0.12f, 4, WithAlpha(ForestShadow, 0.8f));
                break;
            case 8: // charm orb
            {
                float pulse = MathF.Sin(time * 4f) * 0.5f + 0.5f;
                Raylib.DrawCircleV(c, s * 0.18f * lineMul, WithAlpha(primary, 0.95f));
                Raylib.DrawCircleLinesV(c, s * (0.24f + pulse * 0.04f) * lineMul, WithAlpha(hi, 0.95f));
                Raylib.DrawLineEx(new Vector2(c.X, c.Y - s * 0.34f), new Vector2(c.X, c.Y + s * 0.34f), L(1f), WithAlpha(hi, 0.75f));
                Raylib.DrawLineEx(new Vector2(c.X - s * 0.34f, c.Y), new Vector2(c.X + s * 0.34f, c.Y), L(1f), WithAlpha(hi, 0.75f));
                break;
            }
            default: // scatter pot
                Raylib.DrawCircleV(c, s * 0.2f * lineMul, primary);
                Raylib.DrawCircleLinesV(c, s * 0.24f * lineMul, hi);
                for (int shard = 0; shard < 5; shard++)
                {
                    float ang = shard * 1.25f + time;
                    Raylib.DrawLineEx(c, new Vector2(c.X + MathF.Cos(ang) * s * 0.34f, c.Y + MathF.Sin(ang) * s * 0.34f), L(1.2f), shadow);
                }
                break;
        }
    }

    static float GunIconForwardDeg(int index) => index switch
    {
        0 => -47f,
        2 => 0f,
        _ => 0f,
    };

    static Vector2 GunIconGripOffset(int index, float s) => index switch
    {
        0 => new Vector2(s * 0.18f, s * 0.08f),
        4 => new Vector2(s * 0.12f, 0f),
        5 => new Vector2(s * 0.08f, s * 0.18f),
        7 => new Vector2(s * 0.1f, s * 0.04f),
        _ => new Vector2(s * 0.2f, 0f),
    };

    static Vector2 GunLocalMuzzlePoint(int index, Vector2 localCenter, float s) => index switch
    {
        0 => localCenter + new Vector2(s * 0.5f, -s * 0.52f),
        1 => localCenter + new Vector2(s * 0.42f, -s * 0.08f),
        4 => localCenter + new Vector2(s * 0.48f, 0f),
        5 => localCenter + new Vector2(s * 0.32f, -s * 0.48f),
        8 => localCenter + new Vector2(s * 0.34f, 0f),
        _ => localCenter + new Vector2(s * 0.46f, -s * 0.12f),
    };

    static Vector2 ResolveWeaponAimDir()
    {
        Vector2 aim = weaponAimDir.LengthSquared() > 0.001f ? weaponAimDir : lastMoveDirection;
        if (aim.LengthSquared() < 0.001f) aim = Vector2.UnitY;
        return Vector2.Normalize(aim);
    }

    static (Vector2 grip, Vector2 hand, Vector2 rim, float rot, float scale) ComputeEquippedWeaponPose(
        Vector2 p, float bodyR, float time, bool dashing)
    {
        Vector2 aim = ResolveWeaponAimDir();
        Vector2 tangent = new Vector2(-aim.Y, aim.X);

        float aimDeg = MathF.Atan2(aim.Y, aim.X) * 180f / MathF.PI;
        float rot = aimDeg - GunIconForwardDeg(equippedGun) - weaponRecoil;
        float scale = bodyR * EquippedWeaponScaleMul;

        float bob = MathF.Sin(time * 5.2f) * (dashing ? 0.8f : 2f);
        float breathe = MathF.Sin(time * 7f + equippedGun) * 0.45f;

        // Anchor on the player rim in the aim direction, then orbit with tangential sway.
        Vector2 rim = p + aim * bodyR;
        Vector2 grip = rim + aim * (bodyR * 0.14f + breathe) + tangent * bob;
        Vector2 hand = p + aim * (bodyR * 0.82f) + tangent * bob * 0.55f;

        return (grip, hand, rim, rot, scale);
    }

    static void DrawEquippedWeaponOnPlayer(Vector2 p, float bodyR, float time, bool dashing)
    {
        ref readonly Gun g = ref Guns[equippedGun];
        Vector2 aim = ResolveWeaponAimDir();
        var (grip, hand, rim, rot, scale) = ComputeEquippedWeaponPose(p, bodyR, time, dashing);
        Vector2 muzzle = GetEquippedMuzzleWorld(grip, scale, rot, equippedGun);

        Raylib.DrawLineEx(rim, hand, LerpFloat(3.2f, 4.2f, adrenaline), WithAlpha(BodyColor(), 0.9f));
        Raylib.DrawCircleV(hand, bodyR * 0.2f, BodyColor());
        Raylib.DrawCircleLinesV(hand, bodyR * 0.2f, WithAlpha(BodyBright(), 0.85f));

        DrawGlow(grip, scale * 0.85f, g.Color, 0.12f + adrenaline * 0.05f);
        DrawGlow(muzzle, scale * 0.32f, Lighten(g.Color, 0.5f), 0.1f + MathF.Sin(time * 9f) * 0.03f);

        DrawGunIconAtPivot(equippedGun, grip + new Vector2(3f, 4f), scale * 1.04f, time, rot, 0.92f, worldHeld: true, outline: true);
        DrawGunIconAtPivot(equippedGun, grip, scale, time, rot, 1f, worldHeld: true);

        Raylib.DrawLineEx(grip + aim * scale * 0.08f, muzzle, 3.5f, WithAlpha(Lighten(g.Color, 0.55f), 0.75f));
        Raylib.DrawCircleV(muzzle, 3.5f + MathF.Sin(time * 11f) * 0.8f, WithAlpha(Color.White, 0.9f));
        Raylib.DrawCircleLinesV(muzzle, 5f + MathF.Sin(time * 8f), WithAlpha(g.Color, 0.85f));

        if (weaponRecoil > 0.5f)
        {
            DrawGlow(muzzle, scale * 0.45f, Lighten(g.Color, 0.5f), Math.Min(weaponRecoil * 0.018f, 0.28f));
        }
    }

    static float LerpFloat(float a, float b, float t) => a + (b - a) * Math.Clamp(t, 0f, 1f);

    static Vector2 GetEquippedMuzzleWorld(Vector2 grip, float scale, float rotDeg, int gunIndex)
    {
        float rad = rotDeg * MathF.PI / 180f;
        Vector2 local = GunLocalMuzzlePoint(gunIndex, GunIconGripOffset(gunIndex, scale), scale) - GunIconGripOffset(gunIndex, scale);
        float c = MathF.Cos(rad);
        float s = MathF.Sin(rad);
        return grip + new Vector2(c * local.X - s * local.Y, s * local.X + c * local.Y);
    }

    static void DrawGunIconAtPivot(int index, Vector2 gripWorld, float size, float time, float rotationDeg, float alpha,
        bool worldHeld = false, bool outline = false)
    {
        Rlgl.PushMatrix();
        Rlgl.Translatef(gripWorld.X, gripWorld.Y, 0f);
        Rlgl.Rotatef(rotationDeg, 0f, 0f, 1f);

        Vector2 localCenter = GunIconGripOffset(index, size);
        ref readonly Gun gun = ref Guns[index];
        Color hi = WithAlpha(Lighten(gun.Color, worldHeld ? 0.62f : 0.22f), alpha);

        if (outline)
        {
            Color outlineColor = WithAlpha(ForestShadow, alpha * 0.95f);
            DrawGunIconCore(index, localCenter, size, time, alpha, worldHeld: true, outlineColor: outlineColor);
        }
        else
        {
            DrawGunIconCore(index, localCenter, size, time, alpha, worldHeld);
        }

        if (worldHeld && !outline)
        {
            Vector2 muzzle = GunLocalMuzzlePoint(index, localCenter, size);
            Raylib.DrawLineEx(localCenter + new Vector2(size * 0.05f, 0f), muzzle, 4f, WithAlpha(hi, 0.85f));
            DrawGlow(muzzle, size * 0.2f, hi, 0.28f);
            Raylib.DrawCircleV(muzzle, size * 0.07f, WithAlpha(Color.White, alpha));
        }

        Rlgl.PopMatrix();
    }

    static void DrawGunIcon(int index, Vector2 center, float size, float time, float alpha = 1f)
        => DrawGunIconCore(index, center, size, time, alpha);

    static void DrawGunIconCore(int index, Vector2 center, float size, float time, float alpha = 1f,
        bool worldHeld = false, Color? outlineColor = null)
    {
        ref readonly Gun g = ref Guns[index];
        Color basePrimary = worldHeld ? Lighten(g.Color, 0.42f) : g.Color;
        Color baseShadow = worldHeld ? Darken(g.Color, 0.1f) : Darken(g.Color, 0.35f);
        Color baseHi = worldHeld ? Lighten(g.Color, 0.68f) : Lighten(g.Color, 0.22f);

        Color primary = outlineColor ?? WithAlpha(basePrimary, alpha);
        Color shadow = outlineColor ?? WithAlpha(baseShadow, alpha);
        Color hi = outlineColor ?? WithAlpha(baseHi, alpha);
        float lineMul = worldHeld ? 2.6f : 1f;
        float L(float w) => w * lineMul;
        float s = size;

        switch (index)
        {
            case 0:
                Raylib.DrawLineEx(center + new Vector2(-s * 0.45f, s * 0.28f), center + new Vector2(s * 0.35f, -s * 0.42f), L(2f), shadow);
                Raylib.DrawLineEx(center + new Vector2(s * 0.35f, -s * 0.42f), center + new Vector2(s * 0.48f, -s * 0.52f), L(1.5f), primary);
                Raylib.DrawCircleV(center + new Vector2(s * 0.5f, -s * 0.55f), s * 0.09f * lineMul, hi);
                break;
            case 1:
                DrawGunArchetype(3, center, s, time, primary, shadow, hi, lineMul);
                break;
            case 2:
                Raylib.DrawLineEx(center + new Vector2(-s * 0.22f, s * 0.18f), center + new Vector2(s * 0.22f, -s * 0.18f), L(2.2f), primary);
                Raylib.DrawLineEx(center + new Vector2(s * 0.22f, s * 0.18f), center + new Vector2(-s * 0.22f, -s * 0.18f), L(2.2f), hi);
                Raylib.DrawCircleV(center + new Vector2(-s * 0.28f, -s * 0.24f), s * 0.05f * lineMul, shadow);
                Raylib.DrawCircleV(center + new Vector2(s * 0.28f, s * 0.24f), s * 0.05f * lineMul, shadow);
                break;
            case 3:
                DrawGunArchetype(9, center, s, time, primary, shadow, hi, lineMul);
                break;
            case 4:
                DrawGunArchetype(8, center, s, time, primary, shadow, hi, lineMul);
                break;
            case 5:
                DrawGunArchetype(6, center, s, time, primary, shadow, hi, lineMul);
                break;
            case 6:
                DrawGunArchetype(2, center, s * 1.05f, time, primary, shadow, hi, lineMul);
                Raylib.DrawRectangle((int)(center.X - s * 0.18f), (int)(center.Y + s * 0.08f), (int)(s * 0.36f), (int)(s * 0.06f * lineMul), hi);
                break;
            case 7:
                for (int b = -1; b <= 1; b++)
                    DrawGunArchetype(6, center + new Vector2(b * s * 0.14f, b * s * 0.06f), s * 0.55f, time + b, primary, shadow, hi, lineMul);
                break;
            default:
                DrawGunArchetype(index - 8, center, s, time, primary, shadow, hi, lineMul);
                break;
        }
    }

    enum AccessoryLayer { Back, Mid, Front }

    readonly struct PlayerAccessoryRig
    {
        public readonly Vector2 Center;
        public readonly float Radius;
        public readonly Vector2 Forward;
        public readonly Vector2 Left;

        public PlayerAccessoryRig(Vector2 center, float radius, Vector2 forward)
        {
            Center = center;
            Radius = radius;
            Forward = forward;
            Left = new Vector2(-forward.Y, forward.X);
        }

        public Vector2 At(float forwardMul, float sideMul)
            => Center + Forward * (forwardMul * Radius) + Left * (sideMul * Radius);

        public Vector2 Screen(float xMul, float yMul) => At(yMul, -xMul);

        public float FacingDeg => MathF.Atan2(Forward.Y, Forward.X) * 180f / MathF.PI;
    }

    static PlayerAccessoryRig BuildAccessoryRig(Vector2 center, float radius)
        => new PlayerAccessoryRig(center, radius, ResolveWeaponAimDir());

    static AccessoryLayer AccessoryLayerFor(int idx) => idx switch
    {
        9 or 15 or 21 or 25 or 32 => AccessoryLayer.Back,
        3 or 4 or 7 or 11 or 12 or 14 or 19 or 23 or 24 or 28 or 29 or 34 => AccessoryLayer.Mid,
        _ => AccessoryLayer.Front,
    };

    static void WithAccessoryRigRotation(in PlayerAccessoryRig rig, Action draw)
    {
        Rlgl.PushMatrix();
        Rlgl.Translatef(rig.Center.X, rig.Center.Y, 0f);
        Rlgl.Rotatef(rig.FacingDeg - 90f, 0f, 0f, 1f);
        draw();
        Rlgl.PopMatrix();
    }

    static void DrawAccessory(Vector2 p, float r, float time) => DrawAccessory(p, r, time, accessoryIndex);

    static void DrawAccessory(Vector2 p, float r, float time, int idx)
    {
        if (idx == 0) return;
        var rig = BuildAccessoryRig(p, r);
        DrawAccessoryLayer(rig, time, idx, AccessoryLayer.Back);
        DrawAccessoryLayer(rig, time, idx, AccessoryLayer.Mid);
        DrawAccessoryLayer(rig, time, idx, AccessoryLayer.Front);
    }

    static void DrawAccessoryLayer(in PlayerAccessoryRig rig, float time, int idx, AccessoryLayer layer)
    {
        if (idx == 0 || AccessoryLayerFor(idx) != layer) return;

        float r = rig.Radius;
        Color iron = new Color(118, 114, 108, 255);
        Color ironHi = new Color(158, 152, 146, 255);
        Color ironDark = new Color(68, 64, 62, 255);
        Color cloth = new Color(58, 56, 62, 255);
        Color clothHi = new Color(88, 84, 92, 255);
        Color crimson = new Color(128, 58, 68, 255);
        Color plum = new Color(98, 72, 108, 255);
        Color slate = new Color(82, 92, 108, 255);
        Color copper = new Color(138, 98, 82, 255);
        Color bone = new Color(168, 158, 148, 255);
        float pulse = MathF.Sin(time * 2.2f + idx) * 0.5f + 0.5f;
        float rot = rig.FacingDeg - 90f;

        switch (idx)
        {
            case 1: // Iron Circlet — crown of head
            {
                Vector2 head = rig.At(-0.55f, 0f);
                Raylib.DrawRing(head, r * 0.62f, r * 0.72f, rot + 200f, rot + 340f, 20, iron);
                Raylib.DrawCircleV(rig.At(-0.92f, 0f), 2.5f, ironHi);
                Raylib.DrawLineEx(rig.At(-0.72f, -0.35f), rig.At(-0.72f, 0.35f), 1f, ironDark);
                break;
            }
            case 2: // Hood — over skull, open toward face
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawCircleSector(new Vector2(0f, -r * 0.2f), r * 1.02f, 195f, 345f, 22, cloth);
                    Raylib.DrawCircleSector(new Vector2(0f, -r * 0.2f), r * 0.92f, 200f, 340f, 18, Darken(cloth, 0.15f));
                    Raylib.DrawLineEx(new Vector2(-r * 0.55f, -r * 0.15f), new Vector2(r * 0.55f, -r * 0.15f), 1.2f, clothHi);
                });
                break;
            case 3: // Pauldrons — both shoulders
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawRectangleRounded(new Rectangle(-r * 0.92f, -r * 0.42f, r * 0.55f, r * 0.5f), 0.25f, 4, iron);
                    Raylib.DrawRectangleRounded(new Rectangle(r * 0.37f, -r * 0.42f, r * 0.55f, r * 0.5f), 0.25f, 4, iron);
                    Raylib.DrawLineEx(new Vector2(-r * 0.65f, -r * 0.18f), new Vector2(-r * 0.65f, r * 0.05f), 1.5f, ironHi);
                    Raylib.DrawLineEx(new Vector2(r * 0.65f, -r * 0.18f), new Vector2(r * 0.65f, r * 0.05f), 1.5f, ironHi);
                });
                break;
            case 4: // Cloak Pin — right shoulder clasp
            {
                Vector2 clasp = rig.Screen(0.58f, -0.08f);
                Raylib.DrawLineEx(rig.Screen(-0.15f, -0.35f), clasp, 2f, copper);
                Raylib.DrawCircleV(clasp, 4f, crimson);
                Raylib.DrawCircleV(clasp, 2f, WithAlpha(bone, 0.8f));
                break;
            }
            case 5: // Torch Bearer — off-hand (left when facing)
            {
                Vector2 torch = rig.Screen(-0.78f, -0.12f);
                WithAccessoryRigRotation(rig, () =>
                {
                    Vector2 local = new Vector2(-r * 0.78f, -r * 0.12f);
                    Raylib.DrawRectangleRounded(new Rectangle(local.X - 3f, local.Y, 6f, r * 0.35f), 0.2f, 2, ironDark);
                    Raylib.DrawCircleV(local + new Vector2(0, -4f), 4f, new Color(188, 108, 82, 255));
                    Raylib.DrawCircleV(local + new Vector2(0, -6f), 2f, WithAlpha(bone, 0.7f + pulse * 0.3f));
                });
                break;
            }
            case 6: // Chain Coif — head mesh
                WithAccessoryRigRotation(rig, () =>
                {
                    for (int row = 0; row < 4; row++)
                    {
                        float ry = -r * (0.75f - row * 0.12f);
                        for (int col = -3; col <= 3; col++)
                            Raylib.DrawCircleV(new Vector2(col * r * 0.14f + (row % 2) * r * 0.07f, ry), 2f, WithAlpha(iron, 0.75f));
                    }
                });
                break;
            case 7: // Belt Pouch — hip belt
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawRectangleRounded(new Rectangle(-r * 0.42f, r * 0.18f, r * 0.84f, r * 0.38f), 0.2f, 3, new Color(72, 58, 52, 255));
                    Raylib.DrawLineEx(new Vector2(-r * 0.42f, r * 0.28f), new Vector2(r * 0.42f, r * 0.28f), 1.5f, copper);
                    Raylib.DrawCircleV(new Vector2(0f, r * 0.37f), 3f, iron);
                });
                break;
            case 8: // Signet Ring — off-hand fingers
            {
                Vector2 finger = rig.Screen(-0.58f, 0.12f);
                Raylib.DrawCircleV(finger, 5f, copper);
                Raylib.DrawCircleLinesV(finger, 7f, ironHi);
                Raylib.DrawCircleV(finger, 2.5f, crimson);
                break;
            }
            case 9: // Warden Cape — back
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawTriangle(new Vector2(0f, -r * 0.2f), new Vector2(-r * 0.95f, r * 0.75f), new Vector2(r * 0.95f, r * 0.75f), cloth);
                    Raylib.DrawLineEx(new Vector2(-r * 0.7f, r * 0.1f), new Vector2(r * 0.7f, r * 0.1f), 1.2f, WithAlpha(plum, 0.55f));
                });
                break;
            case 10: // Skull Brooch — shoulder
            {
                Vector2 brooch = rig.Screen(0.62f, -0.05f);
                Raylib.DrawCircleV(brooch, 6f, bone);
                Raylib.DrawCircleV(brooch + rig.Left * 4f, 1.5f, ironDark);
                Raylib.DrawCircleV(brooch - rig.Left * 4f, 1.5f, ironDark);
                Raylib.DrawLineEx(brooch + rig.Forward * 7f - rig.Left * 6f, brooch + rig.Forward * 7f + rig.Left * 6f, 1f, ironDark);
                break;
            }
            case 11: // Battle Scarf — neck drape
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawLineEx(new Vector2(-r * 0.85f, -r * 0.05f), new Vector2(r * 0.85f, r * 0.35f), 5f, crimson);
                    Raylib.DrawLineEx(new Vector2(-r * 0.75f, r * 0.05f), new Vector2(r * 0.75f, r * 0.45f), 3f, Darken(crimson, 0.25f));
                });
                break;
            case 12: // Spiked Collar — neck ring
                Raylib.DrawRing(rig.At(0.05f, 0f), r * 0.72f, r * 0.86f, 0f, 360f, 24, iron);
                for (int spike = 0; spike < 8; spike++)
                {
                    float ang = spike * MathF.PI * 2f / 8f;
                    Vector2 dir = new Vector2(MathF.Cos(ang), MathF.Sin(ang));
                    Vector2 basePt = rig.At(0.05f, 0f) + dir * r * 0.8f;
                    Vector2 tip = rig.At(0.05f, 0f) + dir * r * 1.02f;
                    Raylib.DrawLineEx(basePt, tip, 2f, ironHi);
                }
                break;
            case 13: // Lantern Hook — off-hand hip
                WithAccessoryRigRotation(rig, () =>
                {
                    Vector2 hook = new Vector2(-r * 0.65f, -r * 0.2f);
                    Raylib.DrawLineEx(hook + new Vector2(0, -r * 0.35f), hook, 2f, iron);
                    Raylib.DrawRectangleRounded(new Rectangle(hook.X - 5f, hook.Y, 10f, r * 0.28f), 0.2f, 2, slate);
                    Raylib.DrawCircleV(hook + new Vector2(0, r * 0.1f), 3f, WithAlpha(new Color(168, 108, 82, 255), 0.7f + pulse * 0.3f));
                });
                break;
            case 14: // Prayer Beads — waist
                for (int bead = 0; bead < 7; bead++)
                {
                    float t = bead / 6f;
                    Vector2 bp = rig.Screen(-0.55f + t * 1.1f, 0.22f + MathF.Sin(t * MathF.PI) * 0.18f);
                    Raylib.DrawCircleV(bp, 2.5f, bead % 3 == 0 ? plum : iron);
                }
                break;
            case 15: // Royal Mantle — back
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawTriangle(new Vector2(0f, -r * 0.35f), new Vector2(-r * 1.05f, r * 0.85f), new Vector2(r * 1.05f, r * 0.85f), plum);
                    Raylib.DrawLineEx(new Vector2(-r * 0.5f, r * 0.2f), new Vector2(r * 0.5f, r * 0.2f), 2f, WithAlpha(crimson, 0.8f));
                    Raylib.DrawCircleV(new Vector2(0f, -r * 0.15f), 4f, copper);
                });
                break;
            case 16: // Black Hood
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawCircleSector(new Vector2(0f, -r * 0.15f), r * 1.05f, 190f, 350f, 24, new Color(28, 26, 32, 255));
                    Raylib.DrawLineEx(new Vector2(-r * 0.45f, -r * 0.05f), new Vector2(r * 0.45f, -r * 0.05f), 1f, WithAlpha(clothHi, 0.25f));
                });
                break;
            case 17: // Tower Crest — top of head
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawRectangleRounded(new Rectangle(-r * 0.35f, -r * 0.95f, r * 0.7f, r * 0.55f), 0.1f, 3, slate);
                    Raylib.DrawTriangle(new Vector2(0f, -r * 1.15f), new Vector2(-r * 0.4f, -r * 0.72f), new Vector2(r * 0.4f, -r * 0.72f), ironHi);
                    Raylib.DrawRectangle((int)(-r * 0.12f), (int)(-r * 0.55f), (int)(r * 0.24f), (int)(r * 0.18f), Darken(slate, 0.3f));
                });
                break;
            case 18: // Ash Veil — face veil
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawCircleSector(new Vector2(0f, -r * 0.1f), r * 0.88f, 180f, 360f, 16, WithAlpha(new Color(88, 82, 92, 255), 0.75f));
                    for (int wisp = 0; wisp < 4; wisp++)
                        Raylib.DrawLineEx(new Vector2(-r * 0.4f + wisp * r * 0.25f, -r * 0.5f), new Vector2(-r * 0.3f + wisp * r * 0.25f, r * 0.35f), 1f, WithAlpha(bone, 0.25f));
                });
                break;
            case 19: // Blood Sash — waist diagonal
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawLineEx(new Vector2(-r * 0.75f, r * 0.05f), new Vector2(r * 0.75f, r * 0.35f), 6f, Darken(crimson, 0.2f));
                    Raylib.DrawLineEx(new Vector2(-r * 0.65f, r * 0.15f), new Vector2(r * 0.65f, r * 0.45f), 2f, crimson);
                    Raylib.DrawCircleV(new Vector2(-r * 0.55f, r * 0.1f), 3f, copper);
                });
                break;
            case 20: // Iron Halo — above head
            {
                Vector2 halo = rig.At(-0.75f, 0f);
                Raylib.DrawRing(halo, r * 0.55f, r * 0.62f, 0f, 360f, 28, iron);
                for (int spoke = 0; spoke < 6; spoke++)
                {
                    float ang = spoke * MathF.PI / 3f;
                    Vector2 off = new Vector2(MathF.Cos(ang) * r * 0.48f, MathF.Sin(ang) * r * 0.2f);
                    Raylib.DrawLineEx(halo, halo + off, 1.2f, ironHi);
                }
                break;
            }
            case 21: // Keep Banner — back-mounted pole
                WithAccessoryRigRotation(rig, () =>
                {
                    float wave = MathF.Sin(time * 2.5f) * r * 0.08f;
                    Raylib.DrawLineEx(new Vector2(-r * 0.55f, -r * 0.9f), new Vector2(-r * 0.55f, r * 0.35f), 2f, ironDark);
                    Raylib.DrawTriangle(new Vector2(-r * 0.55f, -r * 0.75f), new Vector2(-r * 0.55f, r * 0.2f), new Vector2(-r * 0.05f + wave, r * 0.05f), slate);
                    Raylib.DrawLineEx(new Vector2(-r * 0.45f, -r * 0.35f), new Vector2(-r * 0.15f + wave * 0.5f, -r * 0.1f), 1.5f, crimson);
                });
                break;
            case 22: // Dungeon Keys — off-hand hip
            {
                Vector2 keyRing = rig.Screen(-0.45f, 0.15f);
                Raylib.DrawCircleV(keyRing, 5f, iron);
                Raylib.DrawCircleLinesV(keyRing, 7f, ironHi);
                Raylib.DrawLineEx(keyRing, rig.Screen(-0.75f, 0.45f), 2f, iron);
                Vector2 bit = rig.Screen(-0.68f, 0.38f);
                Raylib.DrawRectangle((int)bit.X, (int)bit.Y, 5, 8, ironHi);
                break;
            }
            case 23: // Oath Band — forehead
            {
                Vector2 brow = rig.At(-0.45f, 0f);
                Raylib.DrawRing(brow, r * 0.48f, r * 0.56f, rot + 210f, rot + 330f, 16, copper);
                Raylib.DrawCircleV(rig.At(-0.78f, 0f), 3f, bone);
                break;
            }
            case 24: // Siege Gloves — both hands
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawRectangleRounded(new Rectangle(-r * 0.82f, -r * 0.15f, r * 0.38f, r * 0.42f), 0.2f, 3, iron);
                    Raylib.DrawRectangleRounded(new Rectangle(r * 0.44f, -r * 0.15f, r * 0.38f, r * 0.42f), 0.2f, 3, iron);
                    Raylib.DrawLineEx(new Vector2(-r * 0.63f, r * 0.05f), new Vector2(-r * 0.63f, r * 0.18f), 1.2f, ironHi);
                });
                break;
            case 25: // Grave Shawl — back
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawTriangle(new Vector2(0f, -r * 0.25f), new Vector2(-r * 0.85f, r * 0.7f), new Vector2(r * 0.85f, r * 0.7f), new Color(48, 46, 54, 255));
                    for (int stitch = 0; stitch < 5; stitch++)
                        Raylib.DrawCircleV(new Vector2(-r * 0.35f + stitch * r * 0.18f, r * 0.35f), 1.5f, WithAlpha(bone, 0.45f));
                });
                break;
            case 26: // Rampart Pin — chest
            {
                Vector2 pin = rig.Screen(0.62f, 0.05f);
                Raylib.DrawLineEx(rig.Screen(0.2f, -0.25f), pin, 2f, iron);
                Raylib.DrawTriangle(pin, pin - rig.Left * r * 0.14f + rig.Forward * r * 0.13f, pin + rig.Left * r * 0.1f + rig.Forward * r * 0.13f, slate);
                break;
            }
            case 27: // Lord's Mask — over face
            {
                Vector2 face = rig.At(0.15f, 0f);
                Vector2 faceLeft = face - rig.Left * r * 0.18f;
                Vector2 faceRight = face + rig.Left * r * 0.18f;
                Raylib.DrawEllipse((int)face.X, (int)face.Y, (int)(r * 0.55f), (int)(r * 0.42f), ironDark);
                Raylib.DrawEllipse((int)faceLeft.X, (int)faceLeft.Y, 4, 6, new Color(12, 10, 14, 255));
                Raylib.DrawEllipse((int)faceRight.X, (int)faceRight.Y, 4, 6, new Color(12, 10, 14, 255));
                Raylib.DrawLineEx(faceLeft + rig.Forward * r * 0.16f, faceRight + rig.Forward * r * 0.16f, 1.5f, iron);
                break;
            }
            case 28: // Bell Cord — chest to waist
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawLineEx(new Vector2(0f, -r * 0.85f), new Vector2(0f, r * 0.15f), 2f, cloth);
                    Raylib.DrawCircleV(new Vector2(0f, r * 0.22f), 5f, copper);
                    Raylib.DrawCircleV(new Vector2(0f, -r * 0.88f), 3f, ironHi);
                });
                break;
            case 29: // Stone Rosary — waist loop
                for (int bead = 0; bead < 8; bead++)
                {
                    float ang = bead * 0.55f - 1.2f;
                    Vector2 bp = rig.At(0.15f + MathF.Sin(ang) * 0.35f, MathF.Cos(ang) * 0.55f);
                    Raylib.DrawCircleV(bp, bead % 4 == 0 ? 3.5f : 2.5f, bead % 4 == 0 ? slate : bone);
                }
                break;
            case 30: // War Paint — face markings
            {
                Vector2 face = rig.At(0.12f, 0f);
                Vector2 fl = face - rig.Left * r * 0.35f;
                Vector2 fr = face + rig.Left * r * 0.35f;
                Raylib.DrawLineEx(fl + rig.Forward * r * 0.23f, face + rig.Forward * r * 0.05f, 3f, crimson);
                Raylib.DrawLineEx(fr + rig.Forward * r * 0.23f, face + rig.Forward * r * 0.05f, 3f, crimson);
                Raylib.DrawLineEx(face - rig.Left * r * 0.2f + rig.Forward * r * 0.05f, face + rig.Left * r * 0.2f + rig.Forward * r * 0.05f, 2f, Darken(crimson, 0.3f));
                break;
            }
            case 31: // Crown Fragments — broken crown on head
                WithAccessoryRigRotation(rig, () =>
                {
                    for (int frag = 0; frag < 3; frag++)
                    {
                        float fx = -r * 0.35f + frag * r * 0.35f;
                        Raylib.DrawTriangle(new Vector2(fx, -r * 0.85f), new Vector2(fx - r * 0.12f, -r * 0.55f), new Vector2(fx + r * 0.12f, -r * 0.55f), copper);
                    }
                });
                break;
            case 32: // Bastion Wings — back
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawTriangle(new Vector2(-r * 0.2f, -r * 0.15f), new Vector2(-r * 1.05f, r * 0.15f), new Vector2(-r * 0.25f, r * 0.45f), slate);
                    Raylib.DrawTriangle(new Vector2(r * 0.2f, -r * 0.15f), new Vector2(r * 1.05f, r * 0.15f), new Vector2(r * 0.25f, r * 0.45f), slate);
                    Raylib.DrawLineEx(new Vector2(-r * 0.75f, r * 0.05f), new Vector2(r * 0.75f, r * 0.05f), 1.5f, ironHi);
                });
                break;
            case 33: // Crypt Lantern — off-hand
                WithAccessoryRigRotation(rig, () =>
                {
                    Vector2 lantern = new Vector2(-r * 0.55f, -r * 0.25f);
                    Raylib.DrawRectangleRounded(new Rectangle(lantern.X - 6f, lantern.Y - r * 0.2f, 12f, r * 0.4f), 0.15f, 2, ironDark);
                    Raylib.DrawCircleV(lantern, 4f, WithAlpha(new Color(148, 88, 108, 255), 0.65f + pulse * 0.35f));
                    Raylib.DrawLineEx(lantern + new Vector2(0, -r * 0.22f), lantern + new Vector2(0, -r * 0.42f), 1.5f, iron);
                });
                break;
            case 34: // Throne Chain — chest chain
                WithAccessoryRigRotation(rig, () =>
                {
                    for (int link = 0; link < 5; link++)
                    {
                        float ly = -r * 0.65f + link * r * 0.18f;
                        Raylib.DrawEllipse(0, (int)ly, 5, 3, iron);
                    }
                    Raylib.DrawCircleV(new Vector2(0f, r * 0.15f), 5f, copper);
                });
                break;
            case 35: // Last Oath — scroll on chest
                WithAccessoryRigRotation(rig, () =>
                {
                    Raylib.DrawRectangleRounded(new Rectangle(-r * 0.12f, -r * 0.75f, r * 0.24f, r * 0.95f), 0.1f, 2, bone);
                    Raylib.DrawLineEx(new Vector2(-r * 0.05f, -r * 0.55f), new Vector2(r * 0.05f, -r * 0.15f), 1f, ironDark);
                    Raylib.DrawLineEx(new Vector2(-r * 0.04f, -r * 0.35f), new Vector2(r * 0.06f, -r * 0.05f), 1f, ironDark);
                    Raylib.DrawCircleV(new Vector2(0f, -r * 0.82f), 3f, crimson);
                });
                break;
            default:
                throw new ArgumentOutOfRangeException(nameof(idx), idx, "Unexpected accessory index.");
        }
    }

    static void DrawFloaters()
    {
        foreach (FloatingText f in floaters)
        {
            float age = f.MaxLife - f.Life;
            float scale = age < 0.12f ? 0.4f + (age / 0.12f) * 0.7f : 1.1f - Math.Clamp((age - 0.12f) / 0.12f, 0f, 1f) * 0.1f;
            float alpha = Math.Min(1f, f.Life / (f.MaxLife * 0.6f));
            int fs = Math.Max(1, (int)(f.Size * scale));
            int w = Raylib.MeasureText(f.Text, fs);
            int tx = (int)(f.Position.X - w / 2f);
            int ty = (int)(f.Position.Y);
            ShadowText(f.Text, tx, ty, fs, f.Color, alpha);
        }
    }

    static void DrawFlash()
    {
        if (flashEnabled && flash > 0.01f)
        {
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(flashColor, Math.Min(flash, 1f) * 0.45f));
        }
    }

    static void DrawImpactFlash()
    {
        if (!flashEnabled || impactFlash <= 0.008f) return;

        float a = Math.Clamp(impactFlash, 0f, 1f);
        if (impactFlashSharp)
        {
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(Color.White, a * 0.82f));
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(impactFlashColor, a * 0.4f));
            int crush = (int)(16f * a);
            if (crush > 0)
            {
                Color crushCol = WithAlpha(ForestShadow, a * 0.5f);
                Raylib.DrawRectangle(0, 0, WindowWidth, crush, crushCol);
                Raylib.DrawRectangle(0, WindowHeight - crush, WindowWidth, crush, crushCol);
                Raylib.DrawRectangle(0, 0, crush, WindowHeight, crushCol);
                Raylib.DrawRectangle(WindowWidth - crush, 0, crush, WindowHeight, crushCol);
            }
        }
        else
        {
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(impactFlashColor, a * 0.42f));
        }
    }

    static void DrawEntityShadows()
    {
        foreach (Enemy e in enemies)
        {
            if (e.Dead || e.Spawn < 0.15f) continue;
            float grow = EaseOutBack(e.Spawn);
            DrawEntityAoShadow(e.Position, e.Radius * grow, e.Vel);
        }

        if (state == GameState.Playing || state == GameState.GameOver)
        {
            DrawEntityAoShadow(playerPos, PlayerRadius, playerVel);
        }
    }

    static void DrawEntityAoShadow(Vector2 anchor, float radius, Vector2 vel)
    {
        Vector2 baseOffset = new Vector2(radius * 0.12f, radius * 0.42f);
        float speed = vel.Length();
        Vector2 velOffset = speed > 4f
            ? Vector2.Normalize(vel) * Math.Min(speed * 0.009f, radius * 0.24f)
            : Vector2.Zero;
        Vector2 center = anchor + baseOffset + velOffset;
        float speedTilt = Math.Clamp(speed * 0.0016f, 0f, 0.22f);

        const int layers = 6;
        for (int i = layers - 1; i >= 0; i--)
        {
            float t = (i + 1) / (float)layers;
            float rx = radius * (0.42f + t * 0.62f + speedTilt * 0.35f);
            float ry = radius * (0.2f + t * 0.24f);
            float alpha = (0.05f + t * 0.11f) * (1f - (1f - t) * 0.35f);
            Raylib.DrawEllipse((int)center.X, (int)center.Y, rx, ry, WithAlpha(ForestShadow, alpha));
        }
    }

    static void DrawVignette()
    {
        if (state == GameState.MainMenu)
        {
            int side = 110;
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(new Color(2, 2, 4, 255), 0.28f));
            Color edge = WithAlpha(ForestShadow, 0.28f);
            Raylib.DrawRectangleGradientV(0, WindowHeight - side, WindowWidth, side, WithAlpha(ForestShadow, 0f), edge);
            Raylib.DrawRectangleGradientH(0, 0, side, WindowHeight, WithAlpha(ForestShadow, 0.22f), WithAlpha(ForestShadow, 0f));
            Raylib.DrawRectangleGradientH(WindowWidth - side, 0, side, WindowHeight, WithAlpha(ForestShadow, 0f), WithAlpha(ForestShadow, 0.22f));
            return;
        }

        int t = 130;
        float vigStrength = 0.55f + adrenaline * 0.22f + impactFlash * 0.15f;
        Color edgeFull = WithAlpha(ForestShadow, vigStrength);
        Raylib.DrawRectangleGradientV(0, 0, WindowWidth, t, edgeFull, WithAlpha(ForestShadow, 0f));
        Raylib.DrawRectangleGradientV(0, WindowHeight - t, WindowWidth, t, WithAlpha(ForestShadow, 0f), edgeFull);
        Raylib.DrawRectangleGradientH(0, 0, t, WindowHeight, WithAlpha(ForestShadow, vigStrength * 0.9f), WithAlpha(ForestShadow, 0f));
        Raylib.DrawRectangleGradientH(WindowWidth - t, 0, t, WindowHeight, WithAlpha(ForestShadow, 0f), WithAlpha(ForestShadow, vigStrength * 0.9f));

        if (adrenaline > 0.08f)
        {
            Color pulse = WithAlpha(new Color(180, 48, 38, 255), adrenaline * glowPulse * 0.12f);
            Raylib.DrawRectangleGradientV(0, 0, WindowWidth, 90, pulse, WithAlpha(pulse, 0f));
            Raylib.DrawRectangleGradientV(0, WindowHeight - 90, WindowWidth, 90, WithAlpha(pulse, 0f), pulse);
        }
    }

    static void DrawGlow(Vector2 center, float radius, Color color, float intensity)
        => DrawSmoothGlowCore(center, radius, color, intensity, 0.11f, steps: 36);

    static void DrawGlowFast(Vector2 center, float radius, Color color, float intensity)
        => DrawSmoothGlowCore(center, radius, color, intensity, 0.11f, steps: 28);

    static float Approach(float current, float target, float rate, float dt)
        => current + (target - current) * (1f - MathF.Exp(-rate * dt));

    static void ShadowText(string text, int x, int y, int size, Color color, float alpha = 1f, int off = 2)
    {
        Raylib.DrawText(text, x + off, y + off, size, WithAlpha(ForestShadow, alpha * 0.7f));
        Raylib.DrawText(text, x, y, size, WithAlpha(color, alpha));
    }

    static void ShadowTextCentered(string text, int cx, int y, int size, Color color, float alpha = 1f, int off = 2)
    {
        int w = Raylib.MeasureText(text, size);
        ShadowText(text, cx - w / 2, y, size, color, alpha, off);
    }

    static float AngleFromVector(Vector2 primary, Vector2 fallback)
    {
        Vector2 v = primary.LengthSquared() > 1f ? primary : fallback;
        if (v.LengthSquared() < 0.001f) v = Vector2.UnitY;
        return MathF.Atan2(v.Y, v.X) * 180f / MathF.PI;
    }

    static bool BeginStretch(Vector2 center, Vector2 vel, float intensity, float cap, float hitSquash = 0f)
    {
        float speed = vel.Length();
        float stretch = Math.Clamp(speed * intensity + hitSquash, 0f, cap + hitSquash * 0.4f);
        if (stretch < 0.0035f)
        {
            return false;
        }

        float angle = speed > 1.5f
            ? MathF.Atan2(vel.Y, vel.X) * 180f / MathF.PI
            : hitSquash > 0.01f
                ? AngleFromVector(center - playerPos, lastMoveDirection)
                : AngleFromVector(lastMoveDirection, Vector2.UnitY);
        float squashX = 1f + stretch;
        float squashY = 1f - stretch * 0.68f;
        Rlgl.PushMatrix();
        Rlgl.Translatef(center.X, center.Y, 0f);
        Rlgl.Rotatef(angle, 0f, 0f, 1f);
        Rlgl.Scalef(squashX, squashY, 1f);
        Rlgl.Rotatef(-angle, 0f, 0f, 1f);
        Rlgl.Translatef(-center.X, -center.Y, 0f);
        return true;
    }

    static void EndStretch(bool active)
    {
        if (active)
        {
            Rlgl.PopMatrix();
        }
    }

    static void DrawPulseFrame(Rectangle rect, Color color, float roundness, float speed, float baseAlpha)
    {
        float pulse = MathF.Sin((float)Raylib.GetTime() * speed) * 0.5f + 0.5f;
        var outer = new Rectangle(rect.X - 3f, rect.Y - 3f, rect.Width + 6f, rect.Height + 6f);
        Raylib.DrawRectangleRoundedLines(outer, roundness, 6, WithAlpha(color, baseAlpha + pulse * 0.5f));
        Raylib.DrawRectangleRoundedLines(rect, roundness, 6, WithAlpha(color, baseAlpha * 0.6f + pulse * 0.3f));
    }

    static void DrawPulseFrameLite(Rectangle rect, Color color, float roundness, float speed, float baseAlpha)
    {
        float pulse = MathF.Sin((float)Raylib.GetTime() * speed) * 0.5f + 0.5f;
        Raylib.DrawRectangleRoundedLines(rect, roundness, 4, WithAlpha(color, baseAlpha + pulse * 0.55f));
    }

    static void DrawPanel(Rectangle rect, Color fill, Color border, float roundness)
    {
        var outer = new Rectangle(rect.X - 2f, rect.Y - 2f, rect.Width + 4f, rect.Height + 4f);
        Raylib.DrawRectangleRounded(outer, roundness, 6, border);
        Raylib.DrawRectangleRounded(rect, roundness, 6, fill);
    }

    static void DrawScreenVignette(float strength)
    {
        int edge = (int)(WindowWidth * 0.16f);
        Color vignette = WithAlpha(ForestShadow, strength * 0.52f);
        Raylib.DrawRectangleGradientH(0, 0, edge, WindowHeight, vignette, WithAlpha(ForestShadow, 0f));
        Raylib.DrawRectangleGradientH(WindowWidth - edge, 0, edge, WindowHeight, WithAlpha(ForestShadow, 0f), vignette);
        Raylib.DrawRectangleGradientV(0, 0, WindowWidth, edge, WithAlpha(ForestShadow, strength * 0.42f), WithAlpha(ForestShadow, 0f));
        Raylib.DrawRectangleGradientV(0, WindowHeight - edge, WindowWidth, edge, WithAlpha(ForestShadow, 0f), WithAlpha(ForestShadow, strength * 0.42f));
    }

    static void DrawMedievalDivider(float cx, float y, float width)
    {
        float half = width / 2f;
        Raylib.DrawLineEx(new Vector2(cx - half, y), new Vector2(cx - 14f, y), 1.5f, WithAlpha(UiBorder, 0.55f));
        Raylib.DrawLineEx(new Vector2(cx + 14f, y), new Vector2(cx + half, y), 1.5f, WithAlpha(UiBorder, 0.55f));
        Raylib.DrawCircleV(new Vector2(cx, y), 3.2f, WithAlpha(UiBorder, 0.65f));
        Raylib.DrawCircleV(new Vector2(cx, y), 1.6f, WithAlpha(Gold, 0.8f));
    }

    static void DrawRichPanel(Rectangle rect, Color fill, Color border, float roundness, bool accentStripe = false)
    {
        var shadow = new Rectangle(rect.X + 2f, rect.Y + 3f, rect.Width, rect.Height);
        Raylib.DrawRectangleRounded(shadow, roundness, 8, WithAlpha(ForestShadow, 0.46f));
        var outerBevel = new Rectangle(rect.X - 1f, rect.Y - 1f, rect.Width + 2f, rect.Height + 2f);
        Raylib.DrawRectangleRounded(outerBevel, roundness, 8, WithAlpha(Darken(border, 0.3f), 0.55f));
        DrawPanel(rect, fill, border, roundness);

        var innerGrad = new Rectangle(rect.X + 2f, rect.Y + 2f, rect.Width - 4f, rect.Height - 4f);
        if (innerGrad.Width > 2f && innerGrad.Height > 2f)
        {
            Raylib.DrawRectangleGradientV((int)innerGrad.X, (int)innerGrad.Y, (int)innerGrad.Width, (int)innerGrad.Height,
                WithAlpha(Lighten(fill, 0.07f), 0.055f), WithAlpha(Darken(fill, 0.12f), 0.035f));
        }

        var highlight = new Rectangle(rect.X + 4f, rect.Y + 4f, rect.Width - 8f, MathF.Max(8f, rect.Height * 0.38f));
        Raylib.DrawRectangleRounded(highlight, roundness, 4, WithAlpha(Color.White, 0.05f));

        Raylib.DrawRectangleRoundedLines(
            new Rectangle(rect.X + 3f, rect.Y + 3f, rect.Width - 6f, rect.Height - 6f),
            roundness * 0.92f, 6, WithAlpha(UiBorderLight, 0.16f));

        if (accentStripe)
        {
            var stripe = new Rectangle(rect.X + 6f, rect.Y + 5f, rect.Width - 12f, 3f);
            Raylib.DrawRectangleGradientH((int)stripe.X, (int)stripe.Y, (int)stripe.Width, (int)stripe.Height,
                WithAlpha(Darken(border, 0.25f), 0.3f), WithAlpha(UiAccent, 0.68f));
            Raylib.DrawRectangle((int)(stripe.X + stripe.Width / 2f - 1f), (int)stripe.Y, 2, (int)stripe.Height, WithAlpha(Gold, 0.5f));
        }

        if (rect.Width > 120f && rect.Height > 70f)
        {
            Color bossHi = WithAlpha(UiBorderLight, 0.5f);
            Color bossLo = WithAlpha(Darken(border, 0.2f), 0.42f);
            Raylib.DrawCircleV(new Vector2(rect.X + 8f, rect.Y + 8f), 2.2f, bossHi);
            Raylib.DrawCircleV(new Vector2(rect.X + rect.Width - 8f, rect.Y + 8f), 2.2f, bossHi);
            Raylib.DrawCircleV(new Vector2(rect.X + 8f, rect.Y + rect.Height - 8f), 2.2f, bossLo);
            Raylib.DrawCircleV(new Vector2(rect.X + rect.Width - 8f, rect.Y + rect.Height - 8f), 2.2f, bossLo);
        }
    }

    static void DrawHudSection(Rectangle area, string label, string value, Color valueColor, Color iconColor, bool iconCircle = true)
    {
        var inner = new Rectangle(area.X + 6f, area.Y + 4f, area.Width - 12f, area.Height - 8f);
        Raylib.DrawRectangleRounded(inner, 0.25f, 4, WithAlpha(UiPanelDeep, 0.55f));
        Raylib.DrawRectangle((int)inner.X, (int)inner.Y + 6, 2, (int)inner.Height - 12, WithAlpha(iconColor, 0.75f));

        if (iconCircle)
        {
            Raylib.DrawCircleV(new Vector2(area.X + 22f, area.Y + area.Height / 2f), 5f, iconColor);
            Raylib.DrawCircleV(new Vector2(area.X + 22f, area.Y + area.Height / 2f), 2f, WithAlpha(Color.White, 0.35f));
        }

        int labelX = iconCircle ? (int)area.X + 34 : (int)area.X + 14;
        Raylib.DrawText(label, labelX, (int)area.Y + 7, 10, WithAlpha(Color.White, 0.52f));
        ShadowText(value, labelX, (int)area.Y + 19, 20, valueColor);
    }

    static void DrawLevelBar(Rectangle area, bool showLabel, bool ghost = false)
    {
        float dt = Raylib.GetFrameTime();
        int need = XpToNextLevel();
        float target = need > 0 ? playerXp / (float)need : 0f;
        levelBarVis = Approach(levelBarVis, target, 10f, dt);

        const float barH = 8f;
        const float barInset = 12f;
        float barY = area.Y + area.Height - barH - 8f;

        DrawRichPanel(area, WithAlpha(UiPanel, ghost ? 0.32f : 0.82f), ghost ? WithAlpha(UiBorder, 0.35f) : UiBorder, 0.22f);
        if (showLabel)
        {
            int textY = (int)(area.Y + 5f);
            string rank = $"RANK {playerLevel}";
            ShadowText(rank, (int)area.X + (int)barInset, textY, 15, Color.White);
            string prog = $"{playerXp} / {need} xp";
            int pw = Raylib.MeasureText(prog, 12);
            Raylib.DrawText(prog, (int)(area.X + area.Width - pw - barInset), textY + 2, 12, Color.White);
        }

        var barBg = new Rectangle(area.X + barInset, barY, area.Width - barInset * 2f, barH);
        Raylib.DrawRectangleRounded(barBg, 0.8f, 4, WithAlpha(UiPanelDeep, 0.95f));
        var barFill = new Rectangle(barBg.X, barBg.Y, MathF.Max(0f, barBg.Width * levelBarVis), barBg.Height);
        if (barFill.Width > 1f)
        {
            Raylib.DrawRectangleRounded(barFill, 0.8f, 4, Darken(UiAccent, 0.12f));
            Raylib.DrawRectangleGradientV((int)barFill.X, (int)barFill.Y, (int)barFill.Width, (int)barFill.Height,
                WithAlpha(Lighten(Gold, 0.15f), 0.45f), WithAlpha(UiAccent, 0.92f));
            Raylib.DrawRectangle((int)barFill.X, (int)barFill.Y, (int)barFill.Width, 1, WithAlpha(Color.White, 0.18f));
        }
        Raylib.DrawRectangleRoundedLines(barBg, 0.8f, 4, WithAlpha(UiBorder, 0.35f));
    }

    static void DrawLevelUpBanner()
    {
        if (levelUpBannerTimer <= 0f) return;
        float a = Math.Clamp(levelUpBannerTimer / 2.8f, 0f, 1f);
        if (levelUpBannerTimer < 0.6f) a = levelUpBannerTimer / 0.6f;
        int cx = WindowWidth / 2;
        string txt = $"RANK {playerLevel}";
        ShadowTextCentered(txt, cx, 108, 30, Gold, a);
        ShadowTextCentered("new arms and trinkets may be ready", cx, 142, 14, WithAlpha(Color.White, 0.7f), a);
    }

    static void DrawTopHud()
    {
        var panel = new Rectangle(14f, 10f, WindowWidth - 28f, 54f);
        DrawRichPanel(panel, UiPanel, UiBorder, 0.35f, accentStripe: true);

        float third = panel.Width / 3f;
        DrawHudSection(
            new Rectangle(panel.X, panel.Y, third, panel.Height),
            "SCORE", ((int)scoreDisplay).ToString("N0"), Color.White, UiAccent);
        DrawHudSection(
            new Rectangle(panel.X + third, panel.Y, third, panel.Height),
            waveInProgress ? "SWARM" : "WAVE",
            waveInProgress ? $"{waveSwarmIndex}/{waveSwarmTotal}" : waveNumber.ToString(),
            Color.White, MossLight);
        DrawHudSection(
            new Rectangle(panel.X + third * 2f, panel.Y, third, panel.Height),
            "FABLES", fables.ToString("N0"), Gold, Gold);

        for (int d = 1; d < 3; d++)
        {
            float dx = panel.X + third * d;
            Raylib.DrawLineEx(new Vector2(dx, panel.Y + 10f), new Vector2(dx, panel.Y + panel.Height - 10f), 1f, WithAlpha(UiBorder, 0.42f));
            Raylib.DrawLineEx(new Vector2(dx + 1f, panel.Y + 10f), new Vector2(dx + 1f, panel.Y + panel.Height - 10f), 1f, WithAlpha(UiBorderLight, 0.1f));
        }

        var rankBar = new Rectangle(panel.X + 12f, panel.Y + panel.Height + 6f, panel.Width - 24f, 36f);
        DrawLevelBar(rankBar, true);
    }

    static void DrawComboMeter()
    {
        if (combo < 2 || state != GameState.Playing) return;

        float dt = Raylib.GetFrameTime();
        Color col = ComboColor(combo);
        string txt = $"COMBO  x{combo}";
        float fresh = Math.Clamp(comboTimer / ComboWindow, 0f, 1f);
        comboFillVis = Approach(comboFillVis, fresh, 14f, dt);
        float pop = 1f + (comboTimer > ComboWindow - 0.12f ? 0.25f : 0f);
        int fs = (int)(24 * pop);
        int cx = WindowWidth / 2;
        int y = 70;

        ShadowTextCentered(txt, cx, y, fs, col);

        int barW = 160;
        int barH = 6;
        var barBg = new Rectangle(cx - barW / 2f, y + fs + 6, barW, barH);
        Raylib.DrawRectangleRounded(barBg, 0.8f, 4, WithAlpha(ForestShadow, 0.5f));
        var barFill = new Rectangle(barBg.X, barBg.Y, MathF.Max(0f, barW * comboFillVis), barH);
        Raylib.DrawRectangleRounded(barFill, 0.8f, 4, col);
        if (comboFillVis > 0.02f)
        {
            DrawGlow(new Vector2(barFill.X + barFill.Width, barFill.Y + barH / 2f), 8f, col, 0.6f);
        }
    }

    static void DrawWaveBanner()
    {
        if (waveBannerTimer <= 0f) return;

        float since = WaveBannerTime - waveBannerTimer;
        float a = 1f;
        if (since < 0.3f) a = since / 0.3f;
        else if (waveBannerTimer < 0.5f) a = waveBannerTimer / 0.5f;

        float slide = (1f - a) * 20f;
        string txt = $"WAVE {waveNumber}";
        int fs = 52;
        int w = Raylib.MeasureText(txt, fs);
        int cx = WindowWidth / 2;
        int y = (int)(175f - slide);

        var banner = new Rectangle(cx - w / 2f - 28f, y - 12f, w + 56f, fs + 44f);
        DrawRichPanel(banner, WithAlpha(UiPanel, a * 0.92f), WithAlpha(UiBorder, a), 0.2f, accentStripe: true);

        ShadowTextCentered(txt, cx, y, fs, Gold, a);

        string sub = waveSubtext.Length > 0 ? waveSubtext : "FOOTSTEPS ON THE STONE";
        int sw = Raylib.MeasureText(sub, 16);
        Raylib.DrawText(sub, cx - sw / 2, y + fs + 6, 16, WithAlpha(UiAccent, a * 0.85f));
    }

    static void DrawFloorEventHud()
    {
        if (activeEvent == FloorEventType.None || state != GameState.Playing) return;

        float time = (float)Raylib.GetTime();
        int cx = WindowWidth / 2;
        string name = FloorEventNames[(int)activeEvent];
        float pulse = MathF.Sin(time * 8f) * 0.5f + 0.5f;
        float urgency = eventStartCountdown > 0.01f
            ? Math.Clamp(1f - eventCountdown / eventStartCountdown, 0.25f, 1f)
            : 0.5f;

        bool tall = activeEvent is FloorEventType.SafeZoneRush or FloorEventType.CenterSnare or FloorEventType.MossRot
            or FloorEventType.EmberGate or FloorEventType.EmberTide or FloorEventType.EmberCage
            or FloorEventType.CryptVeil or FloorEventType.CryptMist
            or FloorEventType.CrownEdict or FloorEventType.CrownThrone or FloorEventType.CrownRot;
        var panel = new Rectangle(cx - 240f, 104f, 480f, tall ? 108f : 88f);
        Color accent = EventAccentColor(activeEvent);
        DrawRichPanel(panel, WithAlpha(UiPanel, 0.92f), WithAlpha(accent, 0.45f + pulse * 0.4f * urgency), 0.22f, accentStripe: true);
        DrawPulseFrame(panel, accent, 0.18f, 10f, 0.12f + pulse * 0.2f * urgency);
        ShadowTextCentered(name, cx, 116, 24, accent, 1f);

        bool timed = activeEvent is FloorEventType.SafeZoneRush or FloorEventType.CenterSnare
            or FloorEventType.CrimsonCrumble or FloorEventType.Checkerfall or FloorEventType.RingCollapse
            or FloorEventType.StoneIslands or FloorEventType.ScatterPits or FloorEventType.MarkedStrike
            or FloorEventType.BlightStorm or FloorEventType.MossRot
            or FloorEventType.EmberRain or FloorEventType.EmberGate or FloorEventType.EmberPulse
            or FloorEventType.EmberCross or FloorEventType.EmberBridge or FloorEventType.EmberFury
            or FloorEventType.EmberSnake or FloorEventType.EmberHive or FloorEventType.EmberTide
            or FloorEventType.EmberCage or FloorEventType.EmberQuake or FloorEventType.EmberBloom
            or FloorEventType.EmberAltar
            or FloorEventType.CryptSeal or FloorEventType.CryptWail or FloorEventType.CryptTorch
            or FloorEventType.CryptChains or FloorEventType.CryptMist or FloorEventType.CryptTomb
            or FloorEventType.CryptShroud or FloorEventType.CryptGlimpse or FloorEventType.CryptRattle
            or FloorEventType.CryptEcho or FloorEventType.CryptGrave or FloorEventType.CryptLantern
            or FloorEventType.CryptVeil
            or FloorEventType.CrownTrial or FloorEventType.CrownFall or FloorEventType.CrownShard
            or FloorEventType.CrownThrone or FloorEventType.CrownEdict or FloorEventType.CrownRot
            or FloorEventType.CrownBolt or FloorEventType.CrownRing or FloorEventType.CrownIsles
            or FloorEventType.CrownStorm or FloorEventType.CrownCoronation or FloorEventType.CrownUsurpation
            or FloorEventType.CrownReckoning;

        if (timed && (eventCountdown > 0f || eventPhase == 1))
        {
            string cd = eventPhase == 1 ? "NOW!" : FormatEventCountdown(eventCountdown);
            ShadowTextCentered(cd + (eventPhase == 1 ? "" : "s"), cx, 148, 28, WithAlpha(Color.White, 0.95f), 1f);
            string action = activeEvent switch
            {
                FloorEventType.StoneIslands => "REACH AN ISLAND",
                FloorEventType.SafeZoneRush => "REACH SAFE BAND",
                FloorEventType.CenterSnare => "HUG THE WALLS",
                FloorEventType.MarkedStrike => $"STRIKE {eventStep + 1}/{markedStrikeCount}",
                FloorEventType.BlightStorm => "WEATHER THE STORM",
                FloorEventType.TideSurge => "FLEE THE SURGE",
                FloorEventType.TideRift => "LEAP THE RIFT",
                FloorEventType.TideRecede => "HUG THE RIM",
                FloorEventType.TideColumn => "DODGE THE COLUMNS",
                FloorEventType.TideEcho => "ESCAPE THE RIPPLES",
                FloorEventType.TideUndertow => "FLEE THE CENTER",
                FloorEventType.TideCrest => "RIDE THE CRESTS",
                FloorEventType.TideWall => TideWallHint(),
                FloorEventType.TideAnchor => "REACH AN ANCHOR",
                FloorEventType.TideFoam => "WEATHER THE FOAM",
                FloorEventType.TideWhirlpool => "FLEE THE VORTEX",
                FloorEventType.TideBeacon => "REACH THE BEACON",
                FloorEventType.TideStrike => $"SALVO {eventStep + 1}/{markedStrikeCount}",
                FloorEventType.MossRot => floorRotSide < 0.5f ? "FLEE LEFT ROT" : "FLEE RIGHT ROT",
                FloorEventType.EmberRain => eventSide == 0 ? "DODGE RIGHT RAIN" : "DODGE LEFT RAIN",
                FloorEventType.EmberGate => "THROUGH THE GATE",
                FloorEventType.EmberPulse => "FLEE THE PULSES",
                FloorEventType.EmberCross => "AVOID THE CROSS",
                FloorEventType.EmberBridge => "CROSS THE BRIDGES",
                FloorEventType.EmberFury => "KEEP MOVING!",
                FloorEventType.EmberSnake => "OUTRUN THE SERPENT",
                FloorEventType.EmberHive => "REACH THE HIVE",
                FloorEventType.EmberTide => eventSide == 2 ? "CLIMB ABOVE TIDE" : "BELOW THE SURGE",
                FloorEventType.EmberCage => "HOLD THE CENTER",
                FloorEventType.EmberQuake => "SURVIVE THE SHAKES",
                FloorEventType.EmberBloom => "FLEE THE BLOOMS",
                FloorEventType.EmberAltar => "SEIZE THE ALTAR",
                FloorEventType.CrownTrial => "SURVIVE THE GAUNTLET",
                FloorEventType.CrownFall => "FLEE GILDED TILES",
                FloorEventType.CrownShard => "DODGE THE SHARDS",
                FloorEventType.CrownThrone => "SEIZE THE THRONE",
                FloorEventType.CrownEdict => "OBEY THE EDICT",
                FloorEventType.CrownRot => floorRotSide < 0.5f ? "FLEE USURPER ROT" : "FLEE CROWN ROT",
                FloorEventType.CrownBolt => $"JUDGMENT {eventStep + 1}/{markedStrikeCount}",
                FloorEventType.CrownRing => "ESCAPE THE RING",
                FloorEventType.CrownIsles => "REACH A BASTION",
                FloorEventType.CrownStorm => "WEATHER THE TEMPEST",
                FloorEventType.CrownCoronation => "REACH THE DAIS",
                FloorEventType.CrownUsurpation => "FLEE THE CROSS",
                FloorEventType.CrownReckoning => "OUTRUN RECKONING",
                _ => "GET CLEAR",
            };
            ShadowTextCentered(action, cx, 176, 14, WithAlpha(Gold, 0.7f + pulse * 0.3f), 1f);

            if (urgency > 0.55f)
            {
                ShadowTextCentered("HURRY!", cx, 194, 13, WithAlpha(accent, 0.65f + pulse * 0.35f), 1f);
            }
        }

        if (activeEvent is FloorEventType.SafeZoneRush or FloorEventType.CenterSnare)
        {
            string hint = activeEvent == FloorEventType.SafeZoneRush ? SafeZoneRushHint() : "SAFE: KEEP WALL";
            Color hintColor = playerInEventSafeZone ? UiAccent : Danger;
            ShadowTextCentered(hint, cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
            if (playerInEventSafeZone)
            {
                ShadowTextCentered("IN SAFE ZONE", cx, tall ? 204 : 184, 13, WithAlpha(UiAccent, 0.85f), 1f);
            }
        }
        else if (activeEvent == FloorEventType.StoneIslands && eventCountdown > 0f)
        {
            bool onIsland = PlayerOnSafeIsland();
            Color hintColor = onIsland ? UiAccent : Danger;
            ShadowTextCentered("SAFE: STONE ISLAND", cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
            if (onIsland)
            {
                ShadowTextCentered("ON SOLID GROUND", cx, tall ? 204 : 184, 13, WithAlpha(UiAccent, 0.85f), 1f);
            }
        }
        else if (activeEvent is FloorEventType.EmberGate or FloorEventType.EmberTide or FloorEventType.EmberCage or FloorEventType.EmberAltar)
        {
            Color hintColor = playerInEventSafeZone ? UiAccent : Danger;
            string hint = activeEvent switch
            {
                FloorEventType.EmberGate => "SAFE: FIRE CORRIDOR",
                FloorEventType.EmberTide => "SAFE: DRY GROUND",
                FloorEventType.EmberCage => "SAFE: INNER CAGE",
                FloorEventType.EmberAltar => "SAFE: ALTAR TILE",
                _ => "SAFE ZONE",
            };
            ShadowTextCentered(hint, cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent == FloorEventType.EmberHive && eventCountdown > 0f)
        {
            bool onHive = PlayerOnSafeIsland();
            Color hintColor = onHive ? UiAccent : Danger;
            ShadowTextCentered("SAFE: EMBER HIVE", cx, 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent is FloorEventType.CryptVeil or FloorEventType.CryptSeal)
        {
            bool inSafe = activeEvent == FloorEventType.CryptVeil
                ? PlayerInSafeRect(eventSafeRect)
                : PlayerInCenterSnareSafe();
            Color hintColor = inSafe ? UiAccent : Danger;
            string hint = activeEvent == FloorEventType.CryptVeil ? "SAFE: LIT QUADRANT" : "SAFE: OUTER RING";
            ShadowTextCentered(hint, cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent == FloorEventType.CryptLantern && eventCountdown > 0f)
        {
            bool onPath = TryGetTileUnder(playerPos, out int lx, out int ly) && !tiles[lx, ly].EventMarked;
            Color hintColor = onPath ? UiAccent : Danger;
            ShadowTextCentered("SAFE: LANTERN PATH", cx, 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent is FloorEventType.TideAnchor && eventCountdown > 0f)
        {
            bool onAnchor = PlayerOnSafeIsland();
            Color hintColor = onAnchor ? UiAccent : Danger;
            ShadowTextCentered("SAFE: TIDE ANCHOR", cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent is FloorEventType.TideBeacon or FloorEventType.TideWhirlpool)
        {
            string hint = activeEvent == FloorEventType.TideBeacon ? TideBeaconHint() : "SAFE: OUTSIDE VORTEX";
            Color hintColor = playerInEventSafeZone ? UiAccent : Danger;
            ShadowTextCentered(hint, cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent is FloorEventType.CrownEdict or FloorEventType.CrownThrone)
        {
            string hint = activeEvent == FloorEventType.CrownEdict ? SafeZoneRushHint() : "SAFE: THRONE DAIS";
            Color hintColor = playerInEventSafeZone ? UiAccent : Danger;
            ShadowTextCentered(hint, cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
            if (playerInEventSafeZone)
            {
                ShadowTextCentered("ROYAL SANCTUARY", cx, tall ? 204 : 184, 13, WithAlpha(UiAccent, 0.85f), 1f);
            }
        }
        else if (activeEvent == FloorEventType.CrownIsles && eventCountdown > 0f)
        {
            bool onIsland = PlayerOnSafeIsland();
            Color hintColor = onIsland ? UiAccent : Danger;
            ShadowTextCentered("SAFE: CROWN BASTION", cx, tall ? 188 : 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
        else if (activeEvent == FloorEventType.CrownCoronation && eventCountdown > 0f)
        {
            bool onDais = PlayerInCrownCenter(2);
            Color hintColor = onDais ? UiAccent : Danger;
            ShadowTextCentered("SAFE: CORONATION DAIS", cx, 168, 15, WithAlpha(hintColor, 0.95f), 1f);
        }
    }

    static void DrawFloorEventWarningBorder()
    {
        if (activeEvent == FloorEventType.None || state != GameState.Playing) return;

        float time = (float)Raylib.GetTime();
        float pulse = MathF.Sin(time * 9f) * 0.5f + 0.5f;
        Color accent = EventAccentColor(activeEvent);
        float urgency = eventStartCountdown > 0.01f
            ? Math.Clamp(1f - eventCountdown / eventStartCountdown, 0.2f, 1f)
            : eventPhase == 1 ? 1f : 0.35f;
        bool subtle = activeEvent == FloorEventType.SafeZoneRush;
        int thickness = subtle ? 4 + (int)(pulse * 3f * urgency) : 10 + (int)(pulse * 18f * urgency);
        Color c = WithAlpha(accent, subtle ? 0.08f + pulse * 0.1f * urgency : 0.24f + pulse * 0.32f * urgency);

        Raylib.DrawRectangle(0, 0, WindowWidth, thickness, c);
        Raylib.DrawRectangle(0, WindowHeight - thickness, WindowWidth, thickness, c);
        Raylib.DrawRectangle(0, 0, thickness, WindowHeight, c);
        Raylib.DrawRectangle(WindowWidth - thickness, 0, thickness, WindowHeight, c);
    }

    static void DrawMarkedStrikeLasers()
    {
        if (state != GameState.Playing) return;
        if (activeEvent is not (FloorEventType.MarkedStrike or FloorEventType.CryptGrave or FloorEventType.CrownBolt)) return;
        if (eventSkyBeams.Count == 0) return;

        float time = (float)Raylib.GetTime();
        Color accent = EventAccentColor(activeEvent);
        Color hotWhite = activeEvent == FloorEventType.CryptGrave
            ? new Color(232, 228, 248, 255)
            : new Color(255, 252, 244, 255);
        Color plasma = activeEvent == FloorEventType.CryptGrave
            ? new Color(168, 148, 196, 255)
            : new Color(255, 148, 72, 255);
        Color ember = activeEvent == FloorEventType.CryptGrave
            ? new Color(88, 72, 108, 255)
            : new Color(220, 52, 28, 255);

        foreach (EventSkyBeam beam in eventSkyBeams)
        {
            DrawMarkedStrikeBeam(beam, time, accent, hotWhite, plasma, ember);
        }
    }

    static void DrawMarkedStrikeBeam(in EventSkyBeam beam, float time, Color accent, Color hotWhite, Color plasma,
        Color ember)
    {
        float lifeT = beam.MaxLife > 0.001f ? beam.Life / beam.MaxLife : 0f;
        Vector2 ground = beam.Ground;
        Vector2 top = new Vector2(ground.X, -80f);
        Vector2 dir = SafeNormalize(ground - top);
        Vector2 side = new Vector2(-dir.Y, dir.X);

        if (beam.Charging)
        {
            float charge = 1f - lifeT;
            float flicker = 0.82f + MathF.Sin(time * 48f) * 0.12f + MathF.Sin(time * 73f + ground.X) * 0.06f;
            float chargeAlpha = (0.2f + charge * 0.65f) * flicker;
            float width = beam.Width * (0.35f + charge * 0.85f);

            Raylib.DrawLineEx(top, ground, width * 2.4f, WithAlpha(ember, chargeAlpha * 0.22f));
            Raylib.DrawLineEx(top, ground, width * 1.35f, WithAlpha(plasma, chargeAlpha * 0.42f));
            Raylib.DrawLineEx(top, ground, width * 0.45f, WithAlpha(hotWhite, chargeAlpha * 0.55f));

            float ringR = 10f + charge * 22f;
            float pulse = MathF.Sin(time * 28f) * 0.5f + 0.5f;
            Raylib.DrawCircleLinesV(ground, ringR, WithAlpha(plasma, chargeAlpha * 0.75f));
            Raylib.DrawCircleLinesV(ground, ringR * 0.62f, WithAlpha(hotWhite, chargeAlpha * (0.45f + pulse * 0.35f)));
            DrawGlowFast(ground, ringR * 1.2f, plasma, chargeAlpha * 0.14f);

            for (int i = 0; i < 4; i++)
            {
                float sparkT = (time * 2.8f + i * 0.37f + ground.X * 0.01f) % 1f;
                Vector2 spark = Vector2.Lerp(ground, top, sparkT);
                Raylib.DrawCircleV(spark, 1.5f + charge * 2f, WithAlpha(hotWhite, chargeAlpha * (1f - sparkT) * 0.7f));
            }

            Raylib.DrawLineEx(ground - side * 16f, ground + side * 16f, 2f, WithAlpha(hotWhite, chargeAlpha * 0.65f));
            Raylib.DrawLineEx(ground - dir * 10f, ground + dir * 10f, 2f, WithAlpha(hotWhite, chargeAlpha * 0.65f));
            return;
        }

        float strike = lifeT;
        float impact = MathF.Pow(strike, 0.55f);
        float strikeAlpha = impact * 0.98f;
        float coreW = beam.Width * (0.18f + impact * 0.22f);
        float midW = beam.Width * (0.55f + impact * 0.35f);
        float outerW = beam.Width * (1.1f + impact * 0.65f);

        Raylib.BeginBlendMode(BlendMode.Additive);
        Raylib.DrawLineEx(top, ground, outerW, WithAlpha(ember, strikeAlpha * 0.28f));
        Raylib.DrawLineEx(top, ground, midW, WithAlpha(plasma, strikeAlpha * 0.52f));
        Raylib.DrawLineEx(top, ground, coreW * 1.8f, WithAlpha(Lighten(plasma, 0.35f), strikeAlpha * 0.72f));
        Raylib.DrawLineEx(top, ground, coreW, WithAlpha(hotWhite, strikeAlpha * 0.95f));

        for (int layer = 0; layer < 3; layer++)
        {
            float off = (layer - 1) * 3.5f;
            Vector2 o = side * off;
            Raylib.DrawLineEx(top + o, ground + o, coreW * 0.35f, WithAlpha(plasma, strikeAlpha * 0.18f));
        }
        Raylib.EndBlendMode();

        float scorchR = 18f + impact * 34f;
        DrawGlowFast(ground, scorchR * 1.2f, ember, strikeAlpha * 0.2f);
        DrawGlowFast(ground, scorchR * 0.6f, hotWhite, strikeAlpha * 0.15f);
        Raylib.DrawCircleV(ground, 5f + impact * 6f, WithAlpha(hotWhite, strikeAlpha));
        Raylib.DrawCircleLinesV(ground, scorchR, WithAlpha(plasma, strikeAlpha * 0.7f));
        Raylib.DrawCircleLinesV(ground, scorchR * 0.55f, WithAlpha(hotWhite, strikeAlpha * 0.55f));

        for (int ray = 0; ray < 6; ray++)
        {
            float ang = ray * MathF.PI / 3f + time * 2.2f;
            Vector2 rayEnd = ground + new Vector2(MathF.Cos(ang), MathF.Sin(ang)) * (scorchR * 0.85f);
            Raylib.DrawLineEx(ground, rayEnd, 2.5f, WithAlpha(plasma, strikeAlpha * 0.35f));
        }

        var spill = new Rectangle(ground.X - scorchR, ground.Y - 4f, scorchR * 2f, 8f);
        Raylib.DrawRectangleGradientH((int)spill.X, (int)spill.Y, (int)spill.Width, (int)spill.Height,
            WithAlpha(ember, 0f), WithAlpha(ember, strikeAlpha * 0.35f));
        Raylib.DrawRectangleGradientH((int)spill.X, (int)spill.Y, (int)spill.Width, (int)spill.Height,
            WithAlpha(ember, strikeAlpha * 0.35f), WithAlpha(ember, 0f));
    }

    static void DrawEventVfx()
    {
        if (activeEvent == FloorEventType.None || state != GameState.Playing) return;

        float time = (float)Raylib.GetTime();
        Color accent = EventAccentColor(activeEvent);

        foreach (EventShockwave sw in eventShockwaves)
        {
            float t = 1f - sw.Life / sw.MaxLife;
            float alpha = (1f - t) * 0.62f;
            Raylib.DrawCircleLinesV(sw.Center, sw.Radius, WithAlpha(sw.Color, alpha));
            Raylib.DrawCircleLinesV(sw.Center, sw.Radius * 0.72f, WithAlpha(Lighten(sw.Color, 0.35f), alpha * 0.75f));
            if (t < 0.35f)
            {
                DrawGlowFast(sw.Center, sw.Radius * 0.3f, sw.Color, alpha * 0.16f);
            }
        }

        foreach (EventSkyBeam beam in eventSkyBeams)
        {
            if (activeEvent is FloorEventType.MarkedStrike or FloorEventType.CryptGrave) continue;

            float lifeT = beam.Life / beam.MaxLife;
            Vector2 top = new Vector2(beam.Ground.X, -40f);
            float alpha = beam.Charging
                ? 0.28f + (1f - lifeT) * 0.58f
                : lifeT * 0.98f;
            float width = beam.Width * (beam.Charging ? 0.5f + (1f - lifeT) * 0.8f : lifeT);

            Raylib.DrawLineEx(top, beam.Ground, width * 1.45f, WithAlpha(beam.Color, alpha * 0.28f));
            Raylib.DrawLineEx(top, beam.Ground, width, WithAlpha(Lighten(beam.Color, 0.45f), alpha * 0.82f));
            Raylib.DrawLineEx(top, beam.Ground, width * 0.3f, WithAlpha(Color.White, alpha * 0.92f));
            DrawGlowFast(beam.Ground, width * 1.4f, beam.Color, alpha * 0.18f);

            if (beam.Charging)
            {
                float pulse = MathF.Sin(time * 24f) * 0.5f + 0.5f;
                Raylib.DrawCircleLinesV(beam.Ground, 14f + pulse * 8f, WithAlpha(beam.Color, alpha));
            }
            else
            {
                Raylib.DrawCircleV(beam.Ground, 6f, WithAlpha(Color.White, alpha));
            }
        }

        if (activeEvent == FloorEventType.CrimsonCrumble && eventPhase == 0)
        {
            float pulse = MathF.Sin(time * 10f) * 0.5f + 0.5f;
            DrawGlowFast(eventEpicenter, 36f + pulse * 20f, accent, 0.1f + pulse * 0.08f);
            Raylib.DrawCircleLinesV(eventEpicenter, 22f + pulse * 16f, WithAlpha(accent, 0.58f));
        }

        if (activeEvent == FloorEventType.CenterSnare)
        {
            float cx = WindowWidth / 2f;
            float cy = WindowHeight / 2f;
            float urgency = eventStartCountdown > 0.01f
                ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
                : 0f;
            float vortexR = 60f + urgency * 120f;
            for (int i = 0; i < 4; i++)
            {
                float a = time * (2.5f + urgency * 3f) + i * 1.57f;
                Vector2 p = new Vector2(cx + MathF.Cos(a) * vortexR, cy + MathF.Sin(a) * vortexR * 0.75f);
                Raylib.DrawCircleV(p, 4.5f + urgency * 3f, WithAlpha(Danger, 0.32f + urgency * 0.24f));
            }
            DrawGlowFast(new Vector2(cx, cy), vortexR, Danger, 0.06f + urgency * 0.08f);
        }

        if (activeEvent == FloorEventType.BlightStorm || activeEvent == FloorEventType.CrownStorm)
        {
            int streaks = 5;
            for (int i = 0; i < streaks; i++)
            {
                float x = Hash(i * 97) * WindowWidth;
                float y = (time * 220f + i * 90f) % (WindowHeight + 80f) - 40f;
                Raylib.DrawLineEx(new Vector2(x, y), new Vector2(x + 30f, y + 70f), 2f, WithAlpha(accent, 0.16f));
            }
        }

        if (activeEvent == FloorEventType.CrownThrone && eventPhase == 0)
        {
            Vector2 throne = new Vector2(WindowWidth / 2f, WindowHeight / 2f);
            float pulse = MathF.Sin(time * 7f) * 0.5f + 0.5f;
            DrawGlowFast(throne, 40f + pulse * 24f, accent, 0.12f + pulse * 0.08f);
            Raylib.DrawCircleLinesV(throne, 28f + pulse * 14f, WithAlpha(accent, 0.55f));
        }

        if (activeEvent == FloorEventType.CrownCoronation && eventPhase == 0)
        {
            Vector2 dais = new Vector2(WindowWidth / 2f, WindowHeight / 2f);
            float pulse = MathF.Sin(time * 6f) * 0.5f + 0.5f;
            for (int ray = 0; ray < 8; ray++)
            {
                float ang = ray * MathF.PI / 4f + time * 0.8f;
                Vector2 end = dais + new Vector2(MathF.Cos(ang), MathF.Sin(ang)) * (80f + pulse * 40f);
                Raylib.DrawLineEx(dais, end, 1.5f, WithAlpha(accent, 0.14f + pulse * 0.1f));
            }
        }

        if (activeEvent == FloorEventType.SafeZoneRush && eventCountdown > 0f)
        {
            Vector2 beacon = new Vector2(
                eventSafeRect.X + eventSafeRect.Width * 0.5f,
                eventSafeRect.Y + eventSafeRect.Height * 0.5f);
            DrawGlow(beacon, 36f, new Color(108, 132, 102, 255), 0.06f + MathF.Sin(time * 6f) * 0.5f * 0.02f);
        }

        if (activeEvent == FloorEventType.EmberRain)
        {
            for (int i = 0; i < 6; i++)
            {
                float x = (time * 180f + i * 73f) % (WindowWidth + 40f) - 20f;
                float y = (time * 260f + i * 41f) % (WindowHeight + 60f) - 30f;
                Raylib.DrawLineEx(new Vector2(x, y), new Vector2(x + 8f, y + 22f), 2f, WithAlpha(accent, 0.2f));
            }
        }

        if (activeEvent == FloorEventType.EmberPulse && eventPhase == 0)
        {
            float ringR = (eventStep + MathF.Sin(time * 8f) * 0.3f) * TileSize;
            Raylib.DrawCircleLinesV(eventEpicenter, ringR, WithAlpha(accent, 0.45f));
            DrawGlowFast(eventEpicenter, ringR * 0.4f, accent, 0.08f);
        }

        if (activeEvent == FloorEventType.EmberSnake && eventStep > 0 && eventStep <= markedStrikeCount)
        {
            int idx = markedStrikeOrder[eventStep - 1];
            Vector2 head = TileCenter(idx % GridSize, idx / GridSize);
            DrawGlowFast(head, 18f, accent, 0.12f + MathF.Sin(time * 14f) * 0.04f);
        }
    }

    static void DrawOutsideSafeZoneDimming(Rectangle safe, Color dim)
    {
        if (safe.Width <= 0f || safe.Height <= 0f) return;

        if (safe.X <= 1f)
        {
            Raylib.DrawRectangleRec(new Rectangle(safe.Width, 0f, WindowWidth - safe.Width, WindowHeight), dim);
        }
        else if (safe.X + safe.Width >= WindowWidth - 1f)
        {
            Raylib.DrawRectangleRec(new Rectangle(0f, 0f, WindowWidth - safe.Width, WindowHeight), dim);
        }
        else if (safe.Y <= 1f)
        {
            Raylib.DrawRectangleRec(new Rectangle(0f, safe.Height, WindowWidth, WindowHeight - safe.Height), dim);
        }
        else
        {
            Raylib.DrawRectangleRec(new Rectangle(0f, 0f, WindowWidth, WindowHeight - safe.Height), dim);
        }
    }

    static void DrawSafeZoneRushWorldBand()
    {
        if (activeEvent != FloorEventType.SafeZoneRush || eventCountdown <= 0f || state != GameState.Playing) return;

        float time = (float)Raylib.GetTime();
        float pulse = MathF.Sin(time * 6f) * 0.5f + 0.5f;
        Color safeEdge = new Color(108, 132, 102, 255);
        Color safeFill = new Color(92, 112, 88, 255);

        Raylib.DrawRectangleRec(eventSafeRect, WithAlpha(safeFill, 0.04f + pulse * 0.02f));
        DrawGradientWash(eventSafeRect, WithAlpha(safeEdge, 0.055f), WithAlpha(safeFill, 0.008f),
            new Vector2(0.5f, 0.5f), 2.8f);

        float edgeThickness = 2f + pulse * 1f;
        Rectangle edge = eventSide switch
        {
            0 => new Rectangle(eventSafeRect.Width - edgeThickness * 0.5f, 0f, edgeThickness, WindowHeight),
            1 => new Rectangle(eventSafeRect.X - edgeThickness * 0.5f, 0f, edgeThickness, WindowHeight),
            2 => new Rectangle(0f, eventSafeRect.Height - edgeThickness * 0.5f, WindowWidth, edgeThickness),
            3 => new Rectangle(0f, eventSafeRect.Y - edgeThickness * 0.5f, WindowWidth, edgeThickness),
            _ => eventSafeRect,
        };
        Raylib.DrawRectangleRec(edge, WithAlpha(safeEdge, 0.22f + pulse * 0.1f));
        DrawGradientWash(edge, WithAlpha(safeEdge, 0.18f), WithAlpha(safeFill, 0f), new Vector2(0.5f, 0.5f), 1.8f);
    }

    static void DrawFloorEventOverlay()
    {
        if (activeEvent == FloorEventType.None || state != GameState.Playing) return;

        float time = (float)Raylib.GetTime();
        float pulse = MathF.Sin(time * 8f) * 0.5f + 0.5f;
        Color accent = EventAccentColor(activeEvent);
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 0f;

        if (activeEvent == FloorEventType.SafeZoneRush)
        {
            Color safeEdge = new Color(108, 132, 102, 255);
            Color dangerDim = WithAlpha(ForestShadow, 0.22f + urgency * 0.06f);
            DrawOutsideSafeZoneDimming(eventSafeRect, dangerDim);

            Vector2 beacon = new Vector2(
                eventSafeRect.X + eventSafeRect.Width * 0.5f,
                eventSafeRect.Y + eventSafeRect.Height * 0.5f);

            if (!PlayerInSafeRect(eventSafeRect))
            {
                float dist = Vector2.Distance(playerPos, beacon);
                Raylib.DrawLineEx(playerPos, beacon, 1.2f, WithAlpha(safeEdge, 0.14f + pulse * 0.08f));
                string hint = SafeZoneRushHint() + "  ·  " + dist.ToString("0") + "u";
                ShadowTextCentered(hint, WindowWidth / 2, WindowHeight - 58, 13, WithAlpha(safeEdge, 0.72f), 1f);
            }
        }
        else if (activeEvent == FloorEventType.CenterSnare)
        {
            Raylib.DrawRectangleRec(eventDangerRect, WithAlpha(Danger, 0.22f + MathF.Sin(time * 11f) * 0.1f + urgency * 0.12f));
            DrawPulseFrame(eventDangerRect, Danger, 0.04f, 10f, 0.35f + urgency * 0.25f);
            DrawCenterSnareSafeBands(time);

            if (PlayerInCenterSnareSafe())
            {
                DrawGlow(playerPos, PlayerRadius * 2.2f, UiAccent, 0.1f);
            }

            ShadowTextCentered("RUN FOR THE BATTLEMENTS", WindowWidth / 2, WindowHeight - 132, 20, WithAlpha(Danger, 0.95f), 1f);
        }
        else if (activeEvent == FloorEventType.MossRot || floorRotTimer > 0f)
        {
            float half = WindowWidth / 2f;
            var rotRect = floorRotSide < 0.5f
                ? new Rectangle(0f, 0f, half + MathF.Sin(time * 3f) * 6f, WindowHeight)
                : new Rectangle(half - MathF.Sin(time * 3f) * 6f, 0f, half, WindowHeight);
            Raylib.DrawRectangleRec(rotRect, WithAlpha(new Color(72, 88, 48, 255), 0.14f + MathF.Sin(time * 5f) * 0.06f));
            DrawGradientWash(rotRect, WithAlpha(new Color(96, 108, 58, 255), 0.2f), WithAlpha(ForestShadow, 0f),
                floorRotSide < 0.5f ? new Vector2(1f, 0.5f) : new Vector2(0f, 0.5f), 1.5f);

            for (int i = 0; i < 8; i++)
            {
                float px = floorRotSide < 0.5f ? Hash(i) * half : half + Hash(i) * half;
                float py = (time * 40f + i * 47f) % WindowHeight;
                Raylib.DrawCircleV(new Vector2(px, py), 2.5f + Hash(i + 5), WithAlpha(new Color(108, 128, 72, 255), 0.38f));
            }
        }
        else if (activeEvent is FloorEventType.CryptVeil or FloorEventType.CryptMist or FloorEventType.CryptWail)
        {
            if (activeEvent == FloorEventType.CryptVeil)
            {
                DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(ForestShadow, 0.22f + urgency * 0.08f));
                DrawPulseFrame(eventSafeRect, accent, 0.06f, 9f, 0.28f + pulse * 0.22f);
            }
            else if (activeEvent == FloorEventType.CryptMist)
            {
                float half = WindowWidth / 2f;
                var mistRect = floorRotSide < 0.5f
                    ? new Rectangle(0f, 0f, half + MathF.Sin(time * 4f) * 8f, WindowHeight)
                    : new Rectangle(half - MathF.Sin(time * 4f) * 8f, 0f, half, WindowHeight);
                Raylib.DrawRectangleRec(mistRect, WithAlpha(accent, 0.12f + MathF.Sin(time * 5f) * 0.05f));
            }
            else
            {
                float wavePos = eventSide switch
                {
                    0 => (1f - eventCountdown / Math.Max(eventStartCountdown, 0.01f)) * WindowWidth,
                    1 => eventCountdown / Math.Max(eventStartCountdown, 0.01f) * WindowWidth,
                    2 => (1f - eventCountdown / Math.Max(eventStartCountdown, 0.01f)) * WindowHeight,
                    _ => eventCountdown / Math.Max(eventStartCountdown, 0.01f) * WindowHeight,
                };
                var wailBand = eventSide < 2
                    ? new Rectangle(wavePos - 24f, 0f, 48f, WindowHeight)
                    : new Rectangle(0f, wavePos - 24f, WindowWidth, 48f);
                Raylib.DrawRectangleRec(wailBand, WithAlpha(accent, 0.14f + pulse * 0.1f));
            }
        }
        else if (activeEvent is FloorEventType.CrimsonCrumble or FloorEventType.Checkerfall
            or FloorEventType.RingCollapse or FloorEventType.StoneIslands or FloorEventType.ScatterPits
            or FloorEventType.MarkedStrike or FloorEventType.BlightStorm
            or FloorEventType.TideSurge or FloorEventType.TideRift or FloorEventType.TideRecede
            or FloorEventType.TideColumn or FloorEventType.TideEcho or FloorEventType.TideUndertow
            or FloorEventType.TideCrest or FloorEventType.TideWall or FloorEventType.TideAnchor
            or FloorEventType.TideFoam or FloorEventType.TideStrike
            or FloorEventType.EmberRain or FloorEventType.EmberPulse or FloorEventType.EmberCross
            or FloorEventType.EmberBridge or FloorEventType.EmberFury or FloorEventType.EmberSnake
            or FloorEventType.EmberHive or FloorEventType.EmberQuake or FloorEventType.EmberBloom
            or FloorEventType.CryptSeal or FloorEventType.CryptTorch or FloorEventType.CryptChains
            or FloorEventType.CryptTomb or FloorEventType.CryptShroud or FloorEventType.CryptGlimpse
            or FloorEventType.CryptRattle or FloorEventType.CryptEcho or FloorEventType.CryptLantern)
        {
            float tint = 0.06f + urgency * 0.1f;
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(accent, tint * (0.7f + MathF.Sin(time * 6f) * 0.3f)));
        }
        else if (activeEvent is FloorEventType.CrownTrial or FloorEventType.CrownFall
            or FloorEventType.CrownShard or FloorEventType.CrownRing or FloorEventType.CrownUsurpation
            or FloorEventType.CrownReckoning or FloorEventType.CrownBolt)
        {
            float tint = 0.06f + urgency * 0.1f;
            Raylib.DrawRectangle(0, 0, WindowWidth, WindowHeight, WithAlpha(accent, tint * (0.7f + MathF.Sin(time * 6f) * 0.3f)));
        }
        else if (activeEvent == FloorEventType.CrownEdict)
        {
            DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(ForestShadow, 0.22f + urgency * 0.06f));
            DrawPulseFrame(eventSafeRect, accent, 0.06f, 8f, 0.28f + pulse * 0.18f);
        }
        else if (activeEvent == FloorEventType.CrownThrone)
        {
            DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(ForestShadow, 0.2f + urgency * 0.08f));
            DrawGlow(new Vector2(WindowWidth / 2f, WindowHeight / 2f), 32f + pulse * 16f, accent, 0.1f);
            DrawPulseFrame(eventSafeRect, accent, 0.08f, 10f, 0.32f + urgency * 0.2f);
        }
        else if (activeEvent == FloorEventType.CrownRot || (floorRotTimer > 0f && activeEvent == FloorEventType.CrownRot))
        {
            float half = WindowWidth / 2f;
            var rotRect = floorRotSide < 0.5f
                ? new Rectangle(0f, 0f, half + MathF.Sin(time * 3f) * 6f, WindowHeight)
                : new Rectangle(half - MathF.Sin(time * 3f) * 6f, 0f, half, WindowHeight);
            Raylib.DrawRectangleRec(rotRect, WithAlpha(new Color(98, 118, 62, 255), 0.14f + MathF.Sin(time * 5f) * 0.06f));
        }
        else if (activeEvent == FloorEventType.EmberGate)
        {
            DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(ForestShadow, 0.2f + urgency * 0.08f));
            DrawPulseFrame(eventSafeRect, accent, 0.06f, 8f, 0.3f + pulse * 0.2f);
        }
        else if (activeEvent == FloorEventType.EmberTide)
        {
            Raylib.DrawRectangleRec(eventDangerRect, WithAlpha(accent, 0.18f + urgency * 0.14f));
            DrawPulseFrame(eventSafeRect, accent, 0.04f, 6f, 0.25f + urgency * 0.2f);
        }
        else if (activeEvent == FloorEventType.EmberCage)
        {
            DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(accent, 0.14f + urgency * 0.1f));
            DrawPulseFrame(eventSafeRect, accent, 0.08f, 10f, 0.35f + urgency * 0.25f);
        }
        else if (activeEvent == FloorEventType.EmberAltar)
        {
            DrawGlow(eventEpicenter, 28f + pulse * 12f, accent, 0.1f + urgency * 0.08f);
            DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(ForestShadow, 0.24f + urgency * 0.06f));
        }
        else if (activeEvent == FloorEventType.TideWall)
        {
            float half = WindowWidth / 2f;
            var wallRect = eventSide switch
            {
                0 => new Rectangle(0f, 0f, half, WindowHeight),
                1 => new Rectangle(half, 0f, half, WindowHeight),
                2 => new Rectangle(0f, 0f, WindowWidth, half),
                _ => new Rectangle(0f, half, WindowWidth, half),
            };
            Raylib.DrawRectangleRec(wallRect, WithAlpha(accent, 0.12f + pulse * 0.06f));
        }
        else if (activeEvent == FloorEventType.TideBeacon)
        {
            DrawOutsideSafeZoneDimming(eventSafeRect, WithAlpha(ForestShadow, 0.2f + urgency * 0.06f));
            DrawPulseFrame(eventSafeRect, accent, 0.06f, 8f, 0.28f + pulse * 0.18f);
        }
        else if (activeEvent == FloorEventType.TideWhirlpool)
        {
            Raylib.DrawRectangleRec(eventDangerRect, WithAlpha(accent, 0.2f + pulse * 0.12f + urgency * 0.1f));
            DrawPulseFrame(eventDangerRect, accent, 0.05f, 9f, 0.32f + urgency * 0.2f);
        }
    }

    static void DrawRushArrow(Vector2 pos, float degrees, Color color, float scale = 1f, bool lite = false)
    {
        float rad = degrees * MathF.PI / 180f;
        Vector2 dir = new Vector2(MathF.Cos(rad), MathF.Sin(rad));
        Vector2 side = new Vector2(-dir.Y, dir.X);
        var tip = pos + dir * (14f * scale);
        var left = pos - dir * (8f * scale) + side * (7f * scale);
        var right = pos - dir * (8f * scale) - side * (7f * scale);
        Raylib.DrawTriangle(tip, left, right, WithAlpha(color, 0.95f));
        if (!lite)
        {
            DrawGlow(pos, 10f * scale, color, 0.08f);
        }
        Raylib.DrawCircleV(pos, 3f * scale, WithAlpha(Color.White, 0.82f));
    }

    static void DrawFloorEventTileWarnings()
    {
        if (activeEvent == FloorEventType.None || state != GameState.Playing) return;
        if (eventCountdown <= 0f && eventPhase == 0
            && activeEvent is not (FloorEventType.MarkedStrike or FloorEventType.CryptGrave or FloorEventType.TideStrike or FloorEventType.CrownBolt)) return;

        float time = (float)Raylib.GetTime();
        float pulse = MathF.Sin(time * 14f) * 0.5f + 0.5f;
        float urgency = eventStartCountdown > 0.01f
            ? 1f - Math.Clamp(eventCountdown / eventStartCountdown, 0f, 1f)
            : 0.5f;
        Color accent = EventAccentColor(activeEvent);

        for (int y = 0; y < GridSize; y++)
        {
            for (int x = 0; x < GridSize; x++)
            {
                if (tiles[x, y].State == 2) continue;

                var r = new Rectangle(x * TileSize + 1f, y * TileSize + 1f, TileSize - 2f, TileSize - 2f);
                Vector2 center = TileCenter(x, y);

                if (tiles[x, y].EventMarked)
                {
                    float distEpic = Vector2.Distance(center, eventEpicenter);
                    float wave = activeEvent == FloorEventType.CrimsonCrumble
                        ? MathF.Sin(time * 8f - distEpic * 0.08f) * 0.5f + 0.5f
                        : pulse;

                    Color warn = activeEvent is FloorEventType.BlightStorm or FloorEventType.TideFoam
                        or FloorEventType.CrownStorm
                        ? LerpColor(accent, Danger, pulse)
                        : accent;

                    Raylib.DrawRectangleRec(r, WithAlpha(warn, 0.2f + wave * 0.36f + urgency * 0.14f));
                    DrawPulseFrameLite(r, warn, 0.1f, 14f, 0.28f + wave * 0.38f);

                    if (activeEvent == FloorEventType.Checkerfall)
                    {
                        float diag = (x + y) * 0.3f;
                        Raylib.DrawLineEx(
                            new Vector2(r.X + 4f, r.Y + 4f),
                            new Vector2(r.X + r.Width - 4f, r.Y + r.Height - 4f),
                            1.5f, WithAlpha(warn, 0.35f + MathF.Sin(time * 10f + diag) * 0.2f));
                    }

                    if (activeEvent == FloorEventType.RingCollapse)
                    {
                        int edge = TileEdgeDistance(x, y);
                        Raylib.DrawRectangleRoundedLines(r, 0.1f, 4, WithAlpha(warn, 0.3f + edge * 0.08f));
                    }

                    if (activeEvent == FloorEventType.ScatterPits)
                    {
                        Raylib.DrawCircleV(center, 4f + pulse * 3f, WithAlpha(warn, 0.4f));
                    }

                    if (activeEvent is FloorEventType.MarkedStrike or FloorEventType.CryptGrave or FloorEventType.TideStrike or FloorEventType.CrownBolt && eventStep < markedStrikeCount)
                    {
                        int idx = markedStrikeOrder[eventStep];
                        if (idx % GridSize == x && idx / GridSize == y)
                        {
                            Color hot = activeEvent switch
                            {
                                FloorEventType.CryptGrave => new Color(220, 210, 240, 255),
                                FloorEventType.CrownBolt => new Color(255, 248, 220, 255),
                                _ => Color.White,
                            };
                            DrawPulseFrame(r, hot, 0.14f, 18f, 0.5f + pulse * 0.4f);
                            Raylib.DrawCircleV(center, 6f + pulse * 4f, WithAlpha(hot, 0.55f));
                        }
                    }

                    if (activeEvent == FloorEventType.CrownFall)
                    {
                        float diag = (x + y) * 0.3f;
                        Raylib.DrawLineEx(
                            new Vector2(r.X + 4f, r.Y + 4f),
                            new Vector2(r.X + r.Width - 4f, r.Y + r.Height - 4f),
                            1.5f, WithAlpha(warn, 0.35f + MathF.Sin(time * 10f + diag) * 0.2f));
                    }

                    if (activeEvent == FloorEventType.CrownShard)
                    {
                        Raylib.DrawCircleV(center, 4f + pulse * 3f, WithAlpha(warn, 0.4f));
                    }

                    if (activeEvent == FloorEventType.CrownUsurpation && (x == GridSize / 2 || y == GridSize / 2))
                    {
                        Raylib.DrawRectangleRoundedLines(r, 0.12f, 4, WithAlpha(warn, 0.42f + pulse * 0.2f));
                    }

                    if (activeEvent == FloorEventType.CryptShroud)
                    {
                        Raylib.DrawLineEx(
                            new Vector2(r.X + 2f, r.Y + 2f),
                            new Vector2(r.X + r.Width - 2f, r.Y + r.Height - 2f),
                            1.2f, WithAlpha(warn, 0.35f + pulse * 0.2f));
                    }

                    if (activeEvent == FloorEventType.CryptTomb)
                    {
                        Raylib.DrawCircleLinesV(center, 8f + pulse * 4f, WithAlpha(warn, 0.55f));
                    }

                    if (activeEvent == FloorEventType.TideColumn)
                    {
                        Raylib.DrawLineEx(
                            new Vector2(center.X, r.Y + 2f),
                            new Vector2(center.X, r.Y + r.Height - 2f),
                            1.5f, WithAlpha(warn, 0.4f + pulse * 0.2f));
                    }

                    if (activeEvent == FloorEventType.TideEcho)
                    {
                        Raylib.DrawLineEx(
                            new Vector2(r.X + 4f, r.Y + 4f),
                            new Vector2(r.X + r.Width - 4f, r.Y + r.Height - 4f),
                            1.2f, WithAlpha(warn, 0.35f + pulse * 0.15f));
                    }

                    if (activeEvent == FloorEventType.TideRift)
                    {
                        Raylib.DrawLineEx(
                            new Vector2(r.X + r.Width * 0.5f, r.Y + 2f),
                            new Vector2(r.X + r.Width * 0.5f, r.Y + r.Height - 2f),
                            1.2f, WithAlpha(warn, 0.35f));
                        Raylib.DrawLineEx(
                            new Vector2(r.X + 2f, r.Y + r.Height * 0.5f),
                            new Vector2(r.X + r.Width - 2f, r.Y + r.Height * 0.5f),
                            1.2f, WithAlpha(warn, 0.35f));
                    }

                    if (activeEvent == FloorEventType.EmberCross)
                    {
                        Raylib.DrawLineEx(
                            new Vector2(r.X + r.Width * 0.5f, r.Y + 2f),
                            new Vector2(r.X + r.Width * 0.5f, r.Y + r.Height - 2f),
                            1.5f, WithAlpha(warn, 0.4f + pulse * 0.2f));
                    }

                    if (activeEvent == FloorEventType.EmberFury)
                    {
                        Raylib.DrawCircleV(center, 3f + pulse * 2f, WithAlpha(warn, 0.5f));
                    }
                }
                else if (activeEvent is FloorEventType.StoneIslands or FloorEventType.TideAnchor or FloorEventType.EmberHive or FloorEventType.EmberBridge
                    or FloorEventType.CrownIsles or FloorEventType.CryptTorch or FloorEventType.CryptLantern)
                {
                    Color safeGlow = activeEvent is FloorEventType.EmberHive or FloorEventType.CryptLantern
                        ? accent
                        : UiAccent;
                    Raylib.DrawRectangleRec(r, WithAlpha(safeGlow, 0.12f + pulse * 0.16f));
                    DrawPulseFrameLite(r, safeGlow, 0.08f, 10f, 0.18f + pulse * 0.24f);
                }
                else if (activeEvent == FloorEventType.CryptGlimpse && eventCountdown > 0f)
                {
                    Raylib.DrawRectangleRec(r, WithAlpha(UiAccent, 0.08f + pulse * 0.14f));
                    DrawPulseFrameLite(r, UiAccent, 0.06f, 12f, 0.15f + pulse * 0.2f);
                }
            }
        }
    }

    static string FormatEventCountdown(float seconds)
    {
        if (seconds <= 0.05f) return "0.0";
        return seconds.ToString("0.0", CultureInfo.InvariantCulture);
    }

    static (string cause, string tip) GetDeathCauseCopy()
    {
        return lastDeathCause switch
        {
            DeathCause.FellThrough => (
                "The void swallowed you.",
                "Tip: Stay on solid tiles. Wind Step can leap gaps in a pinch."),
            DeathCause.FloorGaveWay => (
                "The floor collapsed beneath you.",
                "Tip: Keep moving—worn tiles crumble. Seek fresh, sturdy ground."),
            DeathCause.EnemyGrasp => (
                string.IsNullOrEmpty(lastDeathDetail)
                    ? "A foe caught you."
                    : lastDeathDetail + " struck you down.",
                "Tip: Wind Step grants brief invulnerability—dash through danger."),
            DeathCause.SafeZoneFailed => (
                "You missed the safe zone.",
                "Tip: Watch the glowing band and reach it before the timer hits zero."),
            DeathCause.CenterSnare => (
                "The keep's heart gave way.",
                "Tip: When the rim glows safe, sprint for the outer wall."),
            DeathCause.TideDrowned => (
                "The whirlpool dragged you under.",
                "Tip: Flee the shrinking center before the tide closes."),
            DeathCause.TideBeaconLost => (
                "You never reached the tide beacon.",
                "Tip: Sprint for the glowing corner shrine before the flood."),
            _ => (
                "The stones took you.",
                "Tip: Move often, read the cracks, and save your dash for panic."),
        };
    }

    static void DrawTileAttackTelegraph(int tx, int ty, float intensity, float time, string label, Color color)
    {
        if (tx < 0 || tx >= GridSize || ty < 0 || ty >= GridSize) return;
        if (tiles[tx, ty].State == 2) return;

        var r = new Rectangle(tx * TileSize + 1f, ty * TileSize + 1f, TileSize - 2f, TileSize - 2f);
        float pulse = MathF.Sin(time * 16f) * 0.5f + 0.5f;
        float alpha = 0.28f + intensity * 0.52f + pulse * 0.22f;
        Raylib.DrawRectangleRec(r, WithAlpha(color, alpha));
        DrawPulseFrame(r, color, 0.14f, 14f, 0.3f + intensity * 0.5f);

        Vector2 a = new Vector2(r.X + 4f, r.Y + 4f);
        Vector2 b = new Vector2(r.X + r.Width - 4f, r.Y + r.Height - 4f);
        Vector2 c = new Vector2(r.X + r.Width - 4f, r.Y + 4f);
        Vector2 d = new Vector2(r.X + 4f, r.Y + r.Height - 4f);
        Raylib.DrawLineEx(a, b, 2.8f, WithAlpha(color, 0.75f + pulse * 0.2f));
        Raylib.DrawLineEx(c, d, 2.8f, WithAlpha(color, 0.75f + pulse * 0.2f));

        if (label.Length > 0)
        {
            ShadowTextCentered(label, (int)(r.X + r.Width / 2f), (int)(r.Y - 8f), 11, WithAlpha(color, 0.95f), 1f);
        }
    }

    static void DrawEnemyAttackTelegraphs()
    {
        float time = (float)Raylib.GetTime();
        float touchDist = PlayerRadius;

        foreach (Enemy e in enemies)
        {
            if (e.Dead || e.Spawn < 1f) continue;
            ref readonly EnemyDef def = ref GetDef(e.Type);
            float dist = Vector2.Distance(playerPos, e.Position);
            float pulse = MathF.Sin(time * 14f + e.Wobble) * 0.5f + 0.5f;

            if (def.Behavior == EnemyBehavior.BossSmash)
            {
                DrawGroveTitanTelegraphs(e, time);
                continue;
            }

            // --- Tile crush (Rootbeast, Moss Golem) ---
            if (def.Behavior == EnemyBehavior.CrushTiles && e.AbilityStep == 1 && e.AbilityTimer > 0f)
            {
                float intensity = 1f - e.AbilityTimer / CrushTelegraphTime;
                DrawTileAttackTelegraph(e.StrikeTx, e.StrikeTy, intensity, time, "BREAK!", Danger);
                DrawGlow(TileCenter(e.StrikeTx, e.StrikeTy), 34f, Danger, 0.2f + intensity * 0.45f);
                ShadowTextCentered("STONE BREAK", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 34f), 13, WithAlpha(Danger, 0.85f + intensity * 0.15f), 1f);
                continue;
            }

            // --- Boss blight / dash ---
            if (def.Boss)
            {
                if (def.Behavior == EnemyBehavior.BossBlight && e.AbilityTimer > 0f && e.AbilityTimer <= EnemyTelegraphTime)
                {
                    float t = 1f - e.AbilityTimer / EnemyTelegraphTime;
                    Color warn = WithAlpha(Danger, 0.35f + t * 0.5f + pulse * 0.2f);
                    DrawGlow(e.Position, TileSize * 2.6f, Danger, 0.22f + t * 0.35f);
                    Raylib.DrawCircleLines((int)e.Position.X, (int)e.Position.Y, TileSize * 2f * (0.88f + t * 0.18f), warn);
                    ShadowTextCentered("BLIGHT!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 36f), 14, warn, 1f);
                    continue;
                }

                if (def.Behavior == EnemyBehavior.BossDash && e.AbilityStep == 1 && e.AbilityTimer > 0f)
                {
                    float t = 1f - e.AbilityTimer / BossTelegraphTime;
                    Color warn = WithAlpha(Danger, 0.35f + t * 0.5f + pulse * 0.2f);
                    Vector2 toP = playerPos - e.Position;
                    if (toP.LengthSquared() > 1f)
                    {
                        Vector2 dir = Vector2.Normalize(toP);
                        float len = MathF.Min(toP.Length(), 320f);
                        Vector2 end = e.Position + dir * len;
                        Raylib.DrawLineEx(e.Position, end, 5f + t * 6f, warn);
                        DrawGlow(end, 32f, Danger, 0.3f + t * 0.4f);
                    }
                    ShadowTextCentered("DASH!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 36f), 14, warn, 1f);
                    continue;
                }
            }

            // --- Charge wind-up / active ---
            if (def.Behavior == EnemyBehavior.Charge)
            {
                if (e.AbilityStep == 2 && e.AbilityTimer > 0f)
                {
                    float t = 1f - e.AbilityTimer / ChargeTelegraphTime;
                    Color warn = WithAlpha(Danger, 0.4f + t * 0.45f + pulse * 0.2f);
                    Vector2 toP = playerPos - e.Position;
                    if (toP.LengthSquared() > 1f)
                    {
                        Vector2 dir = Vector2.Normalize(toP);
                        Vector2 end = e.Position + dir * MathF.Min(toP.Length(), 220f);
                        Raylib.DrawLineEx(e.Position, end, 4f + t * 4f, warn);
                        DrawGlow(end, 24f, Danger, 0.25f + t * 0.35f);
                    }
                    Raylib.DrawCircleLines((int)e.Position.X, (int)e.Position.Y, e.Radius + 8f + t * 10f, warn);
                    ShadowTextCentered("CHARGE!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 30f), 12, warn, 1f);
                    continue;
                }
                if (e.AbilityStep == 3 && e.Phase > 0f)
                {
                    Color warn = WithAlpha(Danger, 0.65f + pulse * 0.25f);
                    Raylib.DrawCircleLines((int)e.Position.X, (int)e.Position.Y, e.Radius + 6f, warn);
                    ShadowTextCentered("RUSHING", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 28f), 11, warn, 0.9f);
                    continue;
                }
            }

            // --- Hop / blink destination ---
            if (def.Behavior == EnemyBehavior.Hop && e.AbilityStep == 1)
            {
                float t = 1f - e.AbilityTimer / 0.42f;
                DrawTileAttackTelegraph(e.StrikeTx, e.StrikeTy, t, time, "LEAP!", new Color(196, 148, 88, 255));
                Vector2 dest = TileCenter(e.StrikeTx, e.StrikeTy);
                Raylib.DrawLineEx(e.Position, dest, 3f, WithAlpha(new Color(196, 148, 88, 255), 0.5f + t * 0.4f));
                DrawGlow(dest, 22f, new Color(196, 148, 88, 255), 0.3f + t * 0.35f);
                continue;
            }

            if (def.Behavior == EnemyBehavior.Phaser && e.AbilityStep == 1)
            {
                float t = 1f - e.AbilityTimer / 0.48f;
                DrawTileAttackTelegraph(e.StrikeTx, e.StrikeTy, t, time, "BLINK!", new Color(120, 188, 198, 255));
                Vector2 dest = TileCenter(e.StrikeTx, e.StrikeTy);
                DrawGlow(dest, 26f, new Color(120, 188, 198, 255), 0.35f + t * 0.4f);
                ShadowTextCentered("BLINK!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 28f), 11, WithAlpha(new Color(120, 188, 198, 255), 0.9f), 1f);
                continue;
            }

            // --- Blight pulse ---
            if ((def.Behavior == EnemyBehavior.PulseBlight || def.Behavior == EnemyBehavior.BossBlight)
                && e.AbilityTimer > 0f && e.AbilityTimer <= EnemyTelegraphTime)
            {
                float t = 1f - e.AbilityTimer / EnemyTelegraphTime;
                Color warn = WithAlpha(ActiveTheme.BlightSick, 0.35f + t * 0.45f + pulse * 0.15f);
                float rad = TileSize * (def.Boss ? 2.2f : 1.35f) * (0.85f + t * 0.2f);
                DrawGlow(e.Position, rad, ActiveTheme.BlightSick, 0.2f + t * 0.3f);
                Raylib.DrawCircleLines((int)e.Position.X, (int)e.Position.Y, rad, warn);
                ShadowTextCentered("BLIGHT!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 28f), 11, warn, 0.95f);
                continue;
            }

            // --- Blight trail drop ---
            if (def.Behavior == EnemyBehavior.BlightTrail && e.AbilityTimer > 0f && e.AbilityTimer <= 0.32f
                && TryGetTileUnder(e.Position, out int btx, out int bty))
            {
                float t = 1f - e.AbilityTimer / 0.32f;
                DrawTileAttackTelegraph(btx, bty, t, time, "ROT", ActiveTheme.BlightSick);
                continue;
            }

            // --- Sapper aura (3x3) ---
            if (def.Behavior == EnemyBehavior.Sapper && TryGetTileUnder(e.Position, out int sx, out int sy))
            {
                for (int j = -1; j <= 1; j++)
                {
                    for (int i = -1; i <= 1; i++)
                    {
                        DrawTileAttackTelegraph(sx + i, sy + j, 0.35f + pulse * 0.25f, time, i == 0 && j == 0 ? "SAP" : "", Danger);
                    }
                }
                ShadowTextCentered("SAP!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 26f), 10, WithAlpha(Danger, 0.75f), 0.9f);
                continue;
            }

            // --- Tile leech / decay aura ---
            if (def.Behavior == EnemyBehavior.TileLeech && TryGetTileUnder(e.Position, out int ltx, out int lty))
            {
                DrawTileAttackTelegraph(ltx, lty, 0.4f + pulse * 0.2f, time, "LEECH", new Color(140, 88, 108, 255));
            }

            // --- Contact threat (chase, fast, lurker close, orbit near) ---
            bool contactThreat = def.Behavior is EnemyBehavior.Chase or EnemyBehavior.FastChase
                or EnemyBehavior.Lurker or EnemyBehavior.Zigzag or EnemyBehavior.Orbit
                or EnemyBehavior.Kite;
            if (contactThreat || def.TileDecay > 0f && !def.InstaCollapse && def.Behavior != EnemyBehavior.CrushTiles)
            {
                float warnR = (touchDist + e.Radius) * ContactWarnMul;
                if (dist <= warnR)
                {
                    float t = 1f - dist / warnR;
                    Color warn = WithAlpha(Danger, 0.25f + t * 0.45f + pulse * 0.15f);
                    Raylib.DrawCircleLines((int)e.Position.X, (int)e.Position.Y, e.Radius + 6f + t * 8f, warn);
                    if (dist <= touchDist + e.Radius + 6f)
                    {
                        ShadowTextCentered("!", (int)e.Position.X, (int)(e.Position.Y - e.Radius - 22f), 16, warn, 1f);
                    }
                }
            }
        }
    }

    static void DrawGroveTitanTelegraphs(Enemy e, float time)
    {
        if (e.AbilityStep <= 0 || e.AbilityTimer <= 0f) return;

        float intensity = 1f - e.AbilityTimer / BossCutTelegraphTime;
        float pulse = MathF.Sin(time * 14f) * 0.5f + 0.5f;
        Color warn = WithAlpha(Danger, 0.35f + intensity * 0.45f + pulse * 0.2f);

        switch (e.AbilityStep)
        {
            case 1:
                DrawBossCutLaneTelegraph(e.StrikeTx, e.StrikeTy, 0, 1, e.StrikeDepth, time, intensity);
                ShadowTextCentered("CUT BELOW", WindowWidth / 2, 52, 16, warn, 0.9f);
                break;
            case 2:
                DrawBossCutLaneTelegraph(e.StrikeTx, e.StrikeTy, 0, -1, e.StrikeDepth, time, intensity);
                ShadowTextCentered("CUT ABOVE", WindowWidth / 2, 52, 16, warn, 0.9f);
                break;
            case 3:
                DrawBossCutLaneTelegraph(e.StrikeTx, e.StrikeTy, -1, 0, e.StrikeDepth, time, intensity);
                DrawBossCutLaneTelegraph(e.StrikeTx, e.StrikeTy, 1, 0, e.StrikeDepth, time, intensity);
                ShadowTextCentered("CUT SIDES", WindowWidth / 2, 52, 16, warn, 0.9f);
                break;
            default:
                break;
        }
    }

    static string GroveTitanHudWarning(Enemy b)
    {
        if (b.AbilityStep == 1) return "CUT BELOW INCOMING";
        if (b.AbilityStep == 2) return "CUT ABOVE INCOMING";
        if (b.AbilityStep == 3) return "CUT SIDES INCOMING";
        if (b.AbilityTimer > 0f && b.AbilityTimer <= BossTelegraphTime) return "STONE CUT INCOMING";
        return "";
    }

    static void DrawBossHud()
    {
        if (state != GameState.Playing) return;

        Enemy? bossEnemy = null;
        foreach (Enemy e in enemies)
        {
            if (!e.Dead && e.Spawn >= 0.8f && IsBoss(e.Type))
            {
                if (bossEnemy == null || e.MaxHp > bossEnemy.MaxHp) bossEnemy = e;
            }
        }

        if (bossEnemy == null) return;

        Enemy b = bossEnemy;
        int cx = WindowWidth / 2;
        float w = 420f;
        float hpf = Math.Clamp(b.Hp / b.MaxHp, 0f, 1f);
        var panel = new Rectangle(cx - w / 2f - 16f, 58f, w + 32f, 48f);
        DrawRichPanel(panel, WithAlpha(UiPanel, 0.9f), Danger, 0.2f, accentStripe: true);
        DrawPulseFrame(panel, Danger, 0.16f, 6f, 0.15f);

        string label = GetEnemyName(b.Type).ToUpperInvariant();
        ShadowTextCentered(label, cx, 66, 16, Gold, 1f);

        string warnText = GetDef(b.Type).Behavior == EnemyBehavior.BossSmash
            ? GroveTitanHudWarning(b)
            : GetDef(b.Type).Behavior == EnemyBehavior.BossDash && b.AbilityStep == 1 && b.AbilityTimer > 0f
                ? "DASH INCOMING"
            : b.AbilityTimer > 0f && b.AbilityTimer <= EnemyTelegraphTime
                ? GetDef(b.Type).Behavior switch
                {
                    EnemyBehavior.BossBlight => "BLIGHT INCOMING",
                    EnemyBehavior.BossDash => "DASH INCOMING",
                    _ => "ATTACK INCOMING",
                }
                : "";

        if (warnText.Length > 0)
        {
            float pulse = MathF.Sin((float)Raylib.GetTime() * 12f) * 0.5f + 0.5f;
            ShadowTextCentered(warnText, cx, 84, 13, WithAlpha(Danger, 0.7f + pulse * 0.3f), 1f);
        }
        else
        {
            ShadowTextCentered(GetEnemyDesc(b.Type), cx, 84, 11, WithAlpha(Color.White, 0.55f), 1f);
        }

        var barBg = new Rectangle(cx - w / 2f, 96f, w, 10f);
        Raylib.DrawRectangleRounded(barBg, 0.8f, 4, WithAlpha(ForestShadow, 0.7f));
        var barFill = new Rectangle(barBg.X, barBg.Y, w * hpf, 10f);
        if (barFill.Width > 1f)
        {
            Raylib.DrawRectangleRounded(barFill, 0.8f, 4, LerpColor(Danger, Gold, hpf));
        }
    }

    static void DrawAbilityHud()
    {
        const int barW = 196;
        const int barH = 13;
        const int gap = 12;
        int totalW = barW * 2 + gap;
        int panelPad = 12;
        int barY = WindowHeight - 30;
        int labelY = barY - 26;
        int panelY = labelY - 8;
        int panelH = barY + barH + 10 - panelY;
        int panelX = WindowWidth - (totalW + panelPad * 2) - 14;
        float time = (float)Raylib.GetTime();

        var panel = new Rectangle(panelX, panelY, totalW + panelPad * 2, panelH);
        DrawRichPanel(panel, UiPanel, UiBorder, 0.32f);

        int slot1Cx = panelX + panelPad + barW / 2;
        int slot2Cx = slot1Cx + barW + gap;
        DrawEquippedAbilityBar(0, abilitySlot1, abilityKey1, slot1Cx, labelY, barY, barW, barH, time);
        DrawEquippedAbilityBar(1, abilitySlot2, abilityKey2, slot2Cx, labelY, barY, barW, barH, time);
    }

    static void DrawEquippedAbilityBar(int slot, AbilityType ability, KeyboardKey key, int cx, int labelY, int barY,
        int barW, int barH, float time)
    {
        const int iconPad = 22;
        SyncAbilitySlotHud(slot);
        ability = slot == 0 ? abilitySlot1 : abilitySlot2;

        float readiness = AbilityReadiness(ability);
        abilityFillVis[slot] = Approach(abilityFillVis[slot], readiness, 14f, Raylib.GetFrameTime());
        bool ready = readiness >= 0.995f;
        Color accent = AbilityAccent(ability);
        string name = AbilityHudName[(int)ability];
        string keyLabel = "[" + KeyName(key) + "]";
        Color? fillTint = ability == AbilityType.WindStep ? BodyColor() : null;

        Vector2 iconPos = new Vector2(cx - barW / 2f + 14f, barY + barH / 2f);
        var iconBg = new Rectangle(iconPos.X - 11f, iconPos.Y - 11f, 22f, 22f);
        Raylib.DrawRectangleRounded(iconBg, 0.35f, 4, WithAlpha(UiPanelDeep, 0.85f));
        DrawAbilityIcon(ability, iconPos, 0.72f, time, ready ? 1f : 0.72f);

        int textCx = cx + iconPad / 2;
        ShadowTextCentered(name, textCx, labelY, 10, ready ? Color.White : WithAlpha(Color.White, 0.72f), ready ? 1f : 0.9f);

        string subLabel = keyLabel;
        if (ability == AbilityType.OathOfTheBailey && oathUsedThisRun) subLabel = "SPENT";
        else if (ability == AbilityType.Verdict && verdictHaltTimer > 0f) subLabel = "HALTING " + Math.Ceiling(verdictHaltTimer).ToString("0") + "s";
        else if (ability == AbilityType.Verdict && !IsVerdictUnlocked()) subLabel = runKillCount + "/" + VerdictUnlockKills + " KILLS";
        else if (!ready) subLabel = keyLabel + "  ·  COOLDOWN";

        Color subCol = ability == AbilityType.OathOfTheBailey && oathUsedThisRun
            ? WithAlpha(Color.White, 0.42f)
            : WithAlpha(accent, ready ? 0.95f : 0.62f);
        ShadowTextCentered(subLabel, textCx, labelY + 12, 8, subCol, 0.9f);

        int barX = cx - barW / 2 + iconPad;
        int innerW = barW - iconPad;
        var track = new Rectangle(barX, barY, innerW, barH);
        Raylib.DrawRectangleRounded(track, 0.5f, 6, WithAlpha(UiPanelDeep, 0.92f));

        var fill = new Rectangle(barX + 2f, barY + 2f, (innerW - 4f) * abilityFillVis[slot], barH - 4f);
        Color baseFill = fillTint ?? accent;
        Color fillColor = ready
            ? Lighten(baseFill, (MathF.Sin(time * 5f) * 0.5f + 0.5f) * 0.22f)
            : LerpColor(new Color(48, 52, 58, 255), baseFill, abilityFillVis[slot]);
        if (fill.Width > 1f) Raylib.DrawRectangleRounded(fill, 0.5f, 6, fillColor);
        if (ready) DrawPulseFrame(track, accent, 0.45f, 5f, 0.12f);
    }

    static void DrawAbilityBar(int cx, int labelY, int barY, int barW, int barH, float fillVis, bool ready,
        string label, string readyLabel, Color accent, float time, float pulseSpeed, Color? fillTint = null)
    {
        int barX = cx - barW / 2;
        var track = new Rectangle(barX, barY, barW, barH);
        Raylib.DrawRectangleRounded(track, 0.5f, 6, WithAlpha(UiPanelDeep, 0.9f));

        var fill = new Rectangle(barX + 2f, barY + 2f, (barW - 4f) * fillVis, barH - 4f);
        Color baseFill = fillTint ?? accent;
        Color fillColor = ready
            ? Lighten(baseFill, (MathF.Sin(time * pulseSpeed) * 0.5f + 0.5f) * 0.24f)
            : LerpColor(new Color(48, 52, 58, 255), baseFill, fillVis);
        if (fill.Width > 1f) Raylib.DrawRectangleRounded(fill, 0.5f, 6, fillColor);
        if (ready)
        {
            DrawPulseFrame(track, accent, 0.5f, pulseSpeed, 0.14f);
        }

        Color labelColor = ready ? Color.White : WithAlpha(Color.White, 0.65f);
        ShadowTextCentered(ready ? readyLabel : label, cx, labelY, 11, labelColor, ready ? 1f : 0.85f);
    }

    static void DrawWeaponHud()
    {
        ref readonly Gun g = ref Guns[equippedGun];
        int mag = GetMagazineSize(in g);
        bool reloading = reloadTimer > 0f;
        const float panelH = 64f;
        var panel = new Rectangle(14f, WindowHeight - panelH - 14f, 278f, panelH);
        DrawRichPanel(panel, UiPanel, UiBorder, 0.28f, accentStripe: true);

        var iconBg = new Rectangle(panel.X + 10f, panel.Y + 10f, 32f, 32f);
        Raylib.DrawRectangleRounded(iconBg, 0.3f, 4, WithAlpha(UiPanelDeep, 0.8f));
        DrawGunIcon(equippedGun, new Vector2(iconBg.X + 16f, iconBg.Y + 16f), 13f, (float)Raylib.GetTime());

        Raylib.DrawText(g.Name, (int)panel.X + 50, (int)panel.Y + 8, 15, Color.White);

        string ammoText = reloading
            ? "RELOADING " + Math.Ceiling(reloadTimer).ToString("0") + "s"
            : ammoInMag + " / " + mag;
        Color ammoCol = reloading ? Gold : ammoInMag <= mag / 4 ? Danger : WithAlpha(UiAccent, 0.95f);
        Raylib.DrawText(ammoText, (int)panel.X + 50, (int)panel.Y + 26, 12, ammoCol);

        string mode = autoFire ? "AUTO-FIRE" : "LMB · RMB reload";
        Raylib.DrawText(mode, (int)panel.X + 50, (int)panel.Y + 40, 10, WithAlpha(Color.White, 0.5f));

        float ammoFill = mag > 0 ? ammoInMag / (float)mag : 0f;
        var ammoTrack = new Rectangle(panel.X + 50f, panel.Y + panelH - 12f, panel.Width - 60f, 5f);
        Raylib.DrawRectangleRounded(ammoTrack, 0.8f, 4, WithAlpha(ForestShadow, 0.75f));
        if (reloading)
        {
            float reloadTotal = GetReloadTime(in g);
            float prog = 1f - reloadTimer / reloadTotal;
            var fill = new Rectangle(ammoTrack.X, ammoTrack.Y, ammoTrack.Width * prog, ammoTrack.Height);
            if (fill.Width > 1f)
            {
                Raylib.DrawRectangleRounded(fill, 0.8f, 4, Gold);
            }
        }
        else if (ammoFill > 0f)
        {
            Color fillCol = ammoInMag <= mag / 4 ? Danger : UiAccent;
            var fill = new Rectangle(ammoTrack.X, ammoTrack.Y, ammoTrack.Width * ammoFill, ammoTrack.Height);
            Raylib.DrawRectangleRounded(fill, 0.8f, 4, fillCol);
        }
        Raylib.DrawRectangleRoundedLines(ammoTrack, 0.8f, 4, WithAlpha(UiBorder, 0.35f));
    }

    // ---------------------------------------------------------------- Menu

    // Perfectly centers all text and buttons, removes messy rule lines.
    static void DrawMainMenu()
    {
        int cx = WindowWidth / 2;
        float time = (float)Raylib.GetTime();

        DrawMedievalMenuPlaque(cx, time);

        int yStart = 136;
        int gap = 16;

        yStart += DrawMedievalMenuTitle(cx, yStart, time) + 6;

        string subtitle = "Stand the stones. Outlast the siege.";
        int fsSubtitle = 15;
        int twSubtitle = Raylib.MeasureText(subtitle, fsSubtitle);
        ShadowText(subtitle, cx - twSubtitle / 2, yStart, fsSubtitle, WithAlpha(new Color(196, 192, 184, 255), 0.72f));
        yStart += fsSubtitle + gap;

        DrawMedievalMenuDivider(cx, yStart);
        yStart += gap + 2;

        float chipW = 98f;
        float chipH = 40f;
        float chipGap = 8f;
        float chipsTotal = chipW * 3f + chipGap * 2f;
        float chipX = cx - chipsTotal / 2f;
        DrawUiStatChip(new Rectangle(chipX, yStart, chipW, chipH), "RANK", playerLevel.ToString(), UiAccent, ghost: true);
        DrawUiStatChip(new Rectangle(chipX + chipW + chipGap, yStart, chipW, chipH), "FABLES", fables.ToString("N0"), Gold, ghost: true);
        string bestVal = highScore > 0 ? highScore.ToString("N0") : "—";
        DrawUiStatChip(new Rectangle(chipX + (chipW + chipGap) * 2f, yStart, chipW, chipH), "BEST", bestVal, MossLight, ghost: true);
        yStart += (int)chipH + gap;

        var levelRect = new Rectangle(cx - 176f, yStart, 352f, 38f);
        DrawLevelBar(levelRect, true, ghost: true);
        yStart += 44;

        // Vertical stack centered under the title block.
        float btnY = yStart + 4f;
        if (MenuTextButton(cx, btnY, "Play", "enter", true, primary: true)) ResetGame();
        btnY += 48f;
        if (MenuTextButton(cx, btnY, "Armory", "c", true)) state = GameState.Customize;
        btnY += 44f;
        if (MenuTextButton(cx, btnY, "Settings", "s", true)) state = GameState.Settings;

        DrawUiHintBar("WASD move", "LMB fire · RMB reload", "F3 fps");
    }

    static int DrawMedievalMenuTitle(int cx, int y, float time)
    {
        const string title = "FABLE";
        const int fs = 70;
        int tw = Raylib.MeasureText(title, fs);
        int x = cx - tw / 2;

        Color stoneDeep = new Color(22, 20, 18, 255);
        Color stoneMid = new Color(88, 84, 76, 255);
        Color stoneHi = new Color(176, 168, 152, 255);
        Color gold = new Color(196, 184, 148, 255);
        float pulse = MathF.Sin(time * 1.1f) * 0.5f + 0.5f;
        Color face = LerpColor(stoneMid, stoneHi, 0.28f + pulse * 0.12f);

        Raylib.DrawText(title, x + 4, y + 5, fs, WithAlpha(stoneDeep, 0.9f));
        Raylib.DrawText(title, x + 2, y + 3, fs, WithAlpha(Darken(stoneMid, 0.35f), 0.85f));
        for (int ox = -2; ox <= 2; ox++)
        {
            for (int oy = -2; oy <= 2; oy++)
            {
                if (ox == 0 && oy == 0) continue;
                float dist = MathF.Sqrt(ox * ox + oy * oy);
                if (dist > 2.2f) continue;
                Raylib.DrawText(title, x + ox, y + oy, fs, WithAlpha(stoneDeep, 0.22f));
            }
        }
        Raylib.DrawText(title, x, y - 1, fs, WithAlpha(stoneHi, 0.22f + pulse * 0.08f));
        Raylib.DrawText(title, x, y, fs, face);

        float ruleY = y + fs + 12f;
        float wing = tw * 0.5f + 36f;
        Color ruleHi = WithAlpha(gold, 0.55f);
        Color ruleLo = WithAlpha(stoneHi, 0.28f);
        Raylib.DrawLineEx(new Vector2(cx - wing, ruleY), new Vector2(cx - 18f, ruleY), 1.5f, ruleLo);
        Raylib.DrawLineEx(new Vector2(cx + 18f, ruleY), new Vector2(cx + wing, ruleY), 1.5f, ruleLo);
        Raylib.DrawLineEx(new Vector2(cx - wing, ruleY + 1f), new Vector2(cx - 18f, ruleY + 1f), 1f, WithAlpha(stoneDeep, 0.35f));
        Raylib.DrawLineEx(new Vector2(cx + 18f, ruleY + 1f), new Vector2(cx + wing, ruleY + 1f), 1f, WithAlpha(stoneDeep, 0.35f));

        Vector2 gemTop = new Vector2(cx, ruleY - 7f);
        Vector2 gemLeft = new Vector2(cx - 7f, ruleY + 1f);
        Vector2 gemRight = new Vector2(cx + 7f, ruleY + 1f);
        Raylib.DrawTriangle(gemTop, gemLeft, gemRight, WithAlpha(gold, 0.7f + pulse * 0.15f));
        Raylib.DrawLineEx(gemTop, gemLeft, 1f, WithAlpha(stoneHi, 0.5f));
        Raylib.DrawLineEx(gemTop, gemRight, 1f, WithAlpha(stoneHi, 0.5f));
        Raylib.DrawLineEx(gemLeft, gemRight, 1f, WithAlpha(stoneDeep, 0.45f));
        Raylib.DrawCircleV(new Vector2(cx, ruleY - 1f), 2f, WithAlpha(stoneHi, 0.35f + pulse * 0.2f));

        float tickY = y + fs * 0.72f;
        for (int i = 0; i < 5; i++)
        {
            float tx = cx - wing * 0.55f + i * (wing * 1.1f / 4f);
            Raylib.DrawLineEx(new Vector2(tx, tickY), new Vector2(tx, tickY + 5f), 1f, WithAlpha(gold, 0.18f + Hash(i * 9) * 0.12f));
        }

        return fs + 18;
    }

    static void DrawMedievalMenuPlaque(int cx, float time)
    {
        var plaque = new Rectangle(cx - 268f, 110f, 536f, 132f);
        Color stoneMid = new Color(48, 46, 44, 255);
        Color stoneLight = new Color(98, 96, 92, 255);
        Color mortar = new Color(28, 26, 26, 255);
        DrawRichPanel(plaque, WithAlpha(stoneMid, 0.52f), WithAlpha(stoneLight, 0.28f), 0.12f);
        DrawStoneMasonry(plaque, stoneMid, mortar, 4, 10, 0.45f);
        DrawQuoinStripes(plaque, stoneLight, MossLight);

        float pulse = MathF.Sin(time * 1.5f) * 0.5f + 0.5f;
        Raylib.DrawRectangleLinesEx(plaque, 1f, WithAlpha(stoneLight, 0.22f));
        var innerFrame = new Rectangle(plaque.X + 10f, plaque.Y + 8f, plaque.Width - 20f, plaque.Height - 16f);
        Raylib.DrawRectangleLinesEx(innerFrame, 1f, WithAlpha(MossLight, 0.14f + pulse * 0.06f));

        // Corner flourishes
        float inset = 12f;
        Raylib.DrawLineEx(new Vector2(plaque.X + inset, plaque.Y + inset), new Vector2(plaque.X + inset + 22f, plaque.Y + inset), 1.5f, WithAlpha(MossLight, 0.4f));
        Raylib.DrawLineEx(new Vector2(plaque.X + inset, plaque.Y + inset), new Vector2(plaque.X + inset, plaque.Y + inset + 22f), 1.5f, WithAlpha(MossLight, 0.4f));
        Raylib.DrawLineEx(new Vector2(plaque.X + plaque.Width - inset, plaque.Y + inset), new Vector2(plaque.X + plaque.Width - inset - 22f, plaque.Y + inset), 1.5f, WithAlpha(MossLight, 0.4f));
        Raylib.DrawLineEx(new Vector2(plaque.X + plaque.Width - inset, plaque.Y + inset), new Vector2(plaque.X + plaque.Width - inset, plaque.Y + inset + 22f), 1.5f, WithAlpha(MossLight, 0.4f));
    }

